--
-- Name: fn_pcp_materializar_excecoes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_materializar_excecoes() RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE v int;
BEGIN
  DELETE FROM pcp_bom_excecoes WHERE disposicao IS NULL;
  INSERT INTO pcp_bom_excecoes (pai_codigo, componente_codigo, papel, pai_descricao,
    componente_descricao, observado, esperado, unidade, status)
  SELECT pai_codigo, coalesce(componente_codigo, 0), papel, pai_descricao,
    componente_descricao, observado, esperado, unidade, status
  FROM vw_pcp_bom_validacao
  WHERE status IN ('excecao','sem_regra','unidade_inesperada','papel_desconhecido','sem_quantidade','sem_base_cola','regra_instavel','cola_ambigua')
  ON CONFLICT (pai_codigo, papel, componente_codigo) DO UPDATE
    SET observado = EXCLUDED.observado, esperado = EXCLUDED.esperado,
        status = EXCLUDED.status, materializado_em = now();
  GET DIAGNOSTICS v = ROW_COUNT;
  RETURN v;
END $$;


--
-- Name: fn_pcp_num(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_num(p_raw text) RETURNS numeric
    LANGUAGE sql IMMUTABLE
    AS $_$
SELECT CASE
  WHEN v ~ '^-?\d+(\.\d+)?$' THEN v::numeric
END
FROM (SELECT replace(trim(coalesce(p_raw,'')), ',', '.') AS v) t
$_$;


--
-- Name: fn_pcp_papel_componente(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_papel_componente(p_descricao text, p_familia text) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $$
SELECT CASE
  WHEN upper(coalesce(p_descricao,'')) ~ '^(ROLO|JUMBO)\s'                      THEN 'abrasivo_base'
  WHEN upper(coalesce(p_descricao,'')) ~ 'DESMODUR|CATALISADOR'
    OR coalesce(p_familia,'') ILIKE '%catalisador%'                             THEN 'catalisador'
  -- FITA antes de cola (painel Codex): "FITA ADESIVA" tem que ser fita, não cola.
  -- MYLAR (2768/2769) é a fita de emenda alternativa à Sheldahl (mesma unidade CM, razão ~0,11) — validado nos dados reais.
  WHEN upper(coalesce(p_descricao,'')) ~ '\mFITA\M|MYLAR'                       THEN 'fita'
  WHEN upper(coalesce(p_descricao,'')) ~ 'A455|ADESIVO|\mCOLA\M'
    OR coalesce(p_familia,'') ILIKE '%cola%' OR coalesce(p_familia,'') ILIKE '%adesivo%' THEN 'cola'
  ELSE 'outro'
END $$;


--
-- Name: fn_pcp_parse_dimensoes(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_parse_dimensoes(p_descricao text) RETURNS TABLE(largura_mm integer, comprimento_mm integer, grao integer, diametro_mm integer, formato text)
    LANGUAGE sql IMMUTABLE
    AS $$
WITH d AS (SELECT upper(coalesce(p_descricao,'')) AS s),
dims AS (SELECT regexp_match((SELECT s FROM d), '\m(\d{2,4})X(\d{3,6})MM\M') AS m),
gr   AS (SELECT regexp_match((SELECT s FROM d), '\mP(\d{2,4})\M') AS m),
diam AS (SELECT regexp_match((SELECT s FROM d), '\m(\d{2,3})MM\M') AS m)
SELECT
  (SELECT m[1]::int FROM dims),
  (SELECT m[2]::int FROM dims),
  (SELECT m[1]::int FROM gr),
  CASE WHEN (SELECT m FROM dims) IS NULL AND (SELECT s FROM d) ~ '^(DISCO|BLOCO)'
       THEN (SELECT m[1]::int FROM diam) END,
  CASE WHEN (SELECT m FROM dims) IS NOT NULL THEN 'dimensional'
       WHEN (SELECT s FROM d) ~ '^(DISCO|BLOCO)' AND (SELECT m FROM diam) IS NOT NULL THEN 'disco'
       ELSE 'sem_match' END
$$;


--
-- Name: fn_pcp_projetar_op(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_projetar_op(p_op_id uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  ev record;
  estado text := 'aguardando';
  anomalia boolean := false;
  t_inicio timestamptz;
  concluida_server_ts timestamptz;
BEGIN
  PERFORM pg_advisory_xact_lock(hashtextextended(p_op_id::text, 0));   -- C1
  FOR ev IN
    SELECT tipo, client_ts, server_ts FROM pcp_eventos_producao
    WHERE op_id = p_op_id
    ORDER BY client_ts, device_seq, server_ts,
      array_position(ARRAY['iniciar_op','retomar','pausar','refugo','consumo_mp','finalizar_op'], tipo)
  LOOP
    CASE ev.tipo
      WHEN 'iniciar_op' THEN
        IF estado = 'aguardando' THEN estado := 'em_producao'; t_inicio := ev.client_ts;
        ELSE anomalia := true; END IF;                                 -- iniciar duplo
      WHEN 'pausar' THEN
        IF estado = 'em_producao' THEN estado := 'pausada'; ELSE anomalia := true; END IF;
      WHEN 'retomar' THEN
        IF estado = 'pausada' THEN estado := 'em_producao'; ELSE anomalia := true; END IF;
      WHEN 'finalizar_op' THEN
        IF estado IN ('em_producao','pausada') THEN estado := 'concluida'; concluida_server_ts := ev.server_ts;
        ELSE anomalia := true; END IF;                                 -- finalizar sem iniciar / duplo (não avança)
      WHEN 'refugo' THEN
        IF estado NOT IN ('em_producao','pausada') THEN anomalia := true; END IF;
      WHEN 'consumo_mp' THEN                                           -- C6: só faz sentido em produção
        IF estado NOT IN ('em_producao','pausada') THEN anomalia := true; END IF;
    END CASE;
  END LOOP;

  -- C4: late-arrival — evento stock-impacting cujo server_ts (chegada REAL) é posterior ao fecho.
  -- Passagem separada da FSM: a ordenação por client_ts (adulterável) reordena o evento para antes do
  -- fecho, mas a ordem de chegada denuncia. Independe de onde o client_ts o colocou no loop.
  IF concluida_server_ts IS NOT NULL AND EXISTS (
    SELECT 1 FROM pcp_eventos_producao
    WHERE op_id = p_op_id AND tipo IN ('consumo_mp','refugo') AND server_ts > concluida_server_ts
  ) THEN anomalia := true; END IF;

  UPDATE public.production_orders                                      -- C2: só colunas próprias
     SET estado_projetado = CASE WHEN anomalia THEN estado || '_anomalo' ELSE estado END,
         iniciada_em = t_inicio
   WHERE id = p_op_id;
  RETURN CASE WHEN anomalia THEN estado || '_anomalo' ELSE estado END;
END $$;


--
-- Name: fn_pcp_ratear_corte(bigint, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_ratear_corte(p_rota_id bigint, p_custo_base numeric) RETURNS TABLE(largura_saida_mm integer, papel text, quantidade integer, custo_total numeric, custo_unitario numeric)
    LANGUAGE plpgsql STABLE
    SET search_path TO 'public'
    AS $$
BEGIN
  IF p_custo_base IS NULL OR p_custo_base < 0 THEN
    RAISE EXCEPTION 'fn_pcp_ratear_corte: custo base invalido (%)', p_custo_base USING ERRCODE='check_violation';
  END IF;
  RETURN QUERY
  WITH boas AS (
    SELECT s.largura_saida_mm AS w, s.papel AS pp, s.quantidade AS q, s.fracao_rateio AS f,
           row_number() OVER (ORDER BY s.largura_saida_mm * s.quantidade DESC, s.largura_saida_mm DESC) AS rn
      FROM pcp_bom_rota_saidas s WHERE s.rota_id = p_rota_id AND s.papel <> 'perda'
  ),
  tot AS (SELECT sum(f) AS sf FROM boas),
  rateado AS (
    SELECT b.w, b.pp, b.q, b.rn,
           round(p_custo_base * b.f / NULLIF((SELECT sf FROM tot), 0), 4) AS ct
      FROM boas b
  ),
  resid AS (SELECT round(p_custo_base - COALESCE(sum(ct), 0), 4) AS resto FROM rateado)
  SELECT rt.w, rt.pp, rt.q,
         (rt.ct + CASE WHEN rt.rn = 1 THEN (SELECT resto FROM resid) ELSE 0 END),
         round((rt.ct + CASE WHEN rt.rn = 1 THEN (SELECT resto FROM resid) ELSE 0 END) / rt.q, 4)
    FROM rateado rt ORDER BY rt.w DESC;
END $$;


--
-- Name: fn_pcp_recompute_custo_padrao(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_recompute_custo_padrao(p_data_posicao date) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_account text := (SELECT value#>>'{}' FROM pcp_config WHERE key = 'custo_cmc_account');
  v_versao  text := (SELECT value#>>'{}' FROM pcp_config WHERE key = 'custo_versao_regra');
  v int;
BEGIN
  -- FIX 6: serializa recomputes concorrentes da MESMA data (upsert sem corrida) — padrão da 1B-M1 (fn_pcp_projetar_op).
  PERFORM pg_advisory_xact_lock(hashtextextended('pcp_custo_'||p_data_posicao::text, 0));
  IF v_account IS NULL OR v_versao IS NULL THEN
    RAISE EXCEPTION 'fn_pcp_recompute_custo_padrao: config custo_cmc_account/custo_versao_regra ausente';
  END IF;
  -- Valida a data contra a grade CMC: data fora da grade zeraria o custo em massa (todo cmc NULL) sem avisar.
  IF NOT EXISTS (SELECT 1 FROM cmc_snapshot WHERE account = v_account AND data_posicao = p_data_posicao) THEN
    RAISE EXCEPTION 'fn_pcp_recompute_custo_padrao: data-posição % inexistente na grade CMC (conta %)', p_data_posicao, v_account;
  END IF;

  WITH comp AS (
    SELECT
      s.omie_codigo_produto AS pai_cod,
      -- FIX 4: idProdMalha só vira bigint se for inteiro PURO e caber (length<=18); decimal ('1.5') ou gigante → NULL
      --   (LEFT JOIN não acha CMC → componente cai em falta/incompleto), NUNCA aborta o recompute. Fallbacks de chave preservados.
      CASE WHEN coalesce(it2->'ident'->>'idProdMalha', it2->'ident'->>'idMalha', it2->>'idProdMalha') ~ '^[0-9]+$'
            AND length(coalesce(it2->'ident'->>'idProdMalha', it2->'ident'->>'idMalha', it2->>'idProdMalha')) <= 18
           THEN coalesce(it2->'ident'->>'idProdMalha', it2->'ident'->>'idMalha', it2->>'idProdMalha')::bigint
      END AS comp_cod,
      coalesce(it2->'ident'->>'descrProdMalha', it2->>'descrProdMalha') AS comp_desc,
      fn_pcp_num(coalesce(it2->>'quantProdMalha', it2->>'quantidade')) AS qtd,
      upper(coalesce(it2->>'unidProdMalha', it2->>'unidade')) AS uom
    FROM pcp_malha_staging s
    CROSS JOIN LATERAL jsonb_array_elements(s.payload->'itens') AS it2
    WHERE jsonb_typeof(s.payload->'itens') = 'array'
  ),
  enrich AS (
    SELECT c.*,
      upper(op.unidade) AS uom_estoque,
      fn_pcp_cmc_vigente(c.comp_cod, p_data_posicao) AS cmc,
      fn_pcp_papel_componente(c.comp_desc, op.familia) AS papel
    FROM comp c
    LEFT JOIN omie_products op ON op.omie_codigo_produto = c.comp_cod AND op.account = 'colacor'
  ),
  calc AS (
    SELECT e.*,
      (e.cmc IS NULL OR e.qtd IS NULL OR e.qtd <= 0 OR (e.cmc IS NOT NULL AND e.uom_estoque IS NULL)) AS falta,
      (e.uom_estoque IS NOT NULL AND e.uom IS NOT NULL AND e.uom <> e.uom_estoque) AS unidade_diverge,
      CASE
        WHEN e.cmc IS NULL OR e.qtd IS NULL OR e.qtd <= 0 THEN NULL                                    -- incompleto: NUNCA fabrica 0 (FIX 3: qtd<=0 tb)
        WHEN e.cmc IS NOT NULL AND e.uom_estoque IS NULL THEN NULL                                     -- FIX 2: cmc sem unidade de estoque confirmada → falta
        WHEN e.uom_estoque IS NOT NULL AND e.uom IS NOT NULL AND e.uom <> e.uom_estoque THEN NULL      -- guard de unidade
        ELSE e.qtd * e.cmc
      END AS custo
    FROM enrich e
  ),
  agg AS (
    SELECT pai_cod,
      sum(custo) FILTER (WHERE papel = 'abrasivo_base') AS custo_abrasivo,
      sum(custo) FILTER (WHERE papel = 'cola')          AS custo_cola,
      sum(custo) FILTER (WHERE papel = 'catalisador')   AS custo_catalisador,
      sum(custo) FILTER (WHERE papel = 'fita')          AS custo_fita,
      sum(custo) FILTER (WHERE papel = 'outro')         AS custo_outros,
      count(*)                        AS n_comp,
      count(*) FILTER (WHERE falta)   AS n_falta,
      count(*) FILTER (WHERE unidade_diverge) AS n_div,
      jsonb_agg(jsonb_build_object('cod', comp_cod, 'desc', comp_desc, 'qtd', qtd,
                                   'uom', uom, 'cmc', cmc, 'papel', papel, 'custo', custo)) AS detalhe
    FROM calc
    GROUP BY pai_cod
  )
  INSERT INTO pcp_custo_padrao_resultados (
    omie_codigo_produto, data_posicao, versao_regra, tipo_item,
    custo_abrasivo, custo_cola, custo_catalisador, custo_fita, custo_outros,
    custo_total, custo_status, n_componentes, n_incompletos, detalhe, derivado_em)
  SELECT
    s.omie_codigo_produto,
    p_data_posicao,
    v_versao,
    it.tipo_item,
    a.custo_abrasivo, a.custo_cola, a.custo_catalisador, a.custo_fita, a.custo_outros,
    CASE
      WHEN jsonb_typeof(s.payload->'itens') = 'array' AND a.pai_cod IS NOT NULL AND coalesce(a.n_div, 0) = 0 AND coalesce(a.n_falta, 0) = 0
      THEN coalesce(a.custo_abrasivo,0) + coalesce(a.custo_cola,0) + coalesce(a.custo_catalisador,0)
         + coalesce(a.custo_fita,0) + coalesce(a.custo_outros,0)
      ELSE NULL
    END AS custo_total,
    CASE
      WHEN jsonb_typeof(s.payload->'itens') IS DISTINCT FROM 'array' THEN 'ambiguo'
      WHEN a.pai_cod IS NULL THEN 'sem_estrutura'                                                    -- FIX 7: array vazio (itens=[], 0 componentes) → custo DESCONHECIDO, nunca 0
      WHEN coalesce(a.n_div, 0)   > 0 THEN 'unidade_divergente'
      WHEN coalesce(a.n_falta, 0) > 0 THEN 'incompleto'
      ELSE 'ok'
    END AS custo_status,
    coalesce(a.n_comp, 0),
    coalesce(a.n_falta, 0),
    coalesce(a.detalhe, '[]'::jsonb),
    now()
  FROM pcp_malha_staging s
  LEFT JOIN pcp_itens it ON it.omie_codigo_produto = s.omie_codigo_produto
  LEFT JOIN agg a        ON a.pai_cod = s.omie_codigo_produto
  ON CONFLICT (omie_codigo_produto, data_posicao, versao_regra) DO UPDATE SET
    tipo_item = EXCLUDED.tipo_item,
    custo_abrasivo = EXCLUDED.custo_abrasivo, custo_cola = EXCLUDED.custo_cola,
    custo_catalisador = EXCLUDED.custo_catalisador, custo_fita = EXCLUDED.custo_fita,
    custo_outros = EXCLUDED.custo_outros, custo_total = EXCLUDED.custo_total,
    custo_status = EXCLUDED.custo_status, n_componentes = EXCLUDED.n_componentes,
    n_incompletos = EXCLUDED.n_incompletos, detalhe = EXCLUDED.detalhe, derivado_em = now();

  GET DIAGNOSTICS v = ROW_COUNT;
  RETURN v;
END $_$;


--
-- Name: fn_pcp_recompute_excecoes(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_recompute_excecoes(p_data_posicao date) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_versao text    := (SELECT value#>>'{}' FROM pcp_config WHERE key = 'custo_versao_regra');
  v_tol    numeric := (SELECT (value#>>'{}')::numeric FROM pcp_config WHERE key = 'custo_tolerancia_pct');
  v_drift  numeric := (SELECT (value#>>'{}')::numeric FROM pcp_config WHERE key = 'custo_drift_pct');
  v int;
BEGIN
  -- FIX 6: serializa recomputes concorrentes da MESMA data (DELETE+INSERT da fila sem corrida) — padrão da 1B-M1.
  PERFORM pg_advisory_xact_lock(hashtextextended('pcp_custo_'||p_data_posicao::text, 0));
  -- FIX 5: valida config (como a fn de custo já faz) — versao/tol/drift ausentes zerariam/quebrariam a fila silenciosamente.
  IF v_versao IS NULL OR v_tol IS NULL OR v_drift IS NULL THEN
    RAISE EXCEPTION 'fn_pcp_recompute_excecoes: config custo_versao_regra/custo_tolerancia_pct/custo_drift_pct ausente';
  END IF;
  -- Reconstrói a fila da (data, versão) do zero: sem fila fantasma (o que regularizou some).
  DELETE FROM pcp_custo_excecoes WHERE data_posicao = p_data_posicao AND versao_regra = v_versao;

  WITH src AS (
    SELECT r.*,
      fn_pcp_cmc_vigente(r.omie_codigo_produto, p_data_posicao) AS ncmc,   -- MESMA data (coerência temporal)
      NULLIF(coalesce(r.custo_abrasivo,0) + coalesce(r.custo_cola,0) + coalesce(r.custo_catalisador,0)
           + coalesce(r.custo_fita,0) + coalesce(r.custo_outros,0), 0) AS custo_parcial
    FROM pcp_custo_padrao_resultados r
    WHERE r.data_posicao = p_data_posicao AND r.versao_regra = v_versao
      AND r.tipo_item IN ('cinta','disco','folha','rolo')
  ),
  calc AS (
    SELECT s.*,
      CASE WHEN s.custo_total IS NOT NULL AND s.ncmc IS NOT NULL THEN abs(s.custo_total - s.ncmc) END AS div_abs
    FROM src s
  ),
  cls AS (
    SELECT c.*,
      (c.div_abs / NULLIF(c.ncmc, 0)) AS div_pct,
      CASE
        WHEN c.custo_status = 'incompleto' THEN 'cmc_incompleto'                          -- entra na fila (total NULL)
        WHEN c.custo_status = 'unidade_divergente' THEN 'unidade_divergente'              -- FIX 1: entra na fila (não some p/ NULL)
        WHEN c.custo_status = 'ambiguo' THEN 'estrutura_ambigua'                          -- FIX 1: entra na fila (não some p/ NULL)
        WHEN c.custo_status = 'sem_estrutura' THEN 'sem_estrutura'                        -- FIX 7: estrutura Omie vazia → entra na fila (falta receita, não erro de custo)
        WHEN c.custo_status = 'ok' AND c.ncmc IS NULL THEN 'ncmc_ausente'                 -- ativo NÃO custeado
        WHEN c.custo_status = 'ok' AND c.ncmc IS NOT NULL
             AND (c.div_abs / NULLIF(c.ncmc, 0)) > v_tol THEN
          CASE
            WHEN coalesce(c.custo_outros, 0) > 0 THEN 'material_fora_bucket'
            WHEN EXISTS (SELECT 1 FROM pcp_bom_excecoes be
                          WHERE be.pai_codigo = c.omie_codigo_produto
                            AND be.status = 'excecao' AND be.disposicao IS NULL)
              THEN 'possivel_erro_receita'                                                -- PROVADO: cruza a 1A (oráculo)
            WHEN EXISTS (SELECT 1 FROM jsonb_array_elements(c.detalhe) d
                          WHERE fn_pcp_componente_tem_drift((d->>'cod')::bigint, p_data_posicao, v_drift))
              THEN 'drift_preco_provavel'
            ELSE 'causa_indeterminada'                                                    -- default HONESTO (nunca acusa sem oráculo)
          END
        ELSE NULL                                                                        -- dentro da banda / ambiguo / unidade_divergente: fora da fila
      END AS classe
    FROM calc c
  )
  INSERT INTO pcp_custo_excecoes (
    omie_codigo_produto, data_posicao, versao_regra, tipo_item,
    custo_padrao_total, ncmc_acabado, divergencia_abs, divergencia_pct,
    impacto_r, classe_causa, custo_status, derivado_em)
  SELECT
    omie_codigo_produto, data_posicao, versao_regra, tipo_item,
    custo_total AS custo_padrao_total,
    ncmc        AS ncmc_acabado,
    div_abs     AS divergencia_abs,
    div_pct     AS divergencia_pct,
    CASE classe
      WHEN 'cmc_incompleto'     THEN coalesce(custo_parcial, ncmc, 0)
      WHEN 'unidade_divergente' THEN coalesce(custo_parcial, ncmc, 0)   -- FIX 1
      WHEN 'estrutura_ambigua'  THEN coalesce(custo_parcial, ncmc, 0)   -- FIX 1
      WHEN 'sem_estrutura'      THEN coalesce(ncmc, 0)                   -- FIX 7: único valor conhecido é o CMC do acabado (se houver)
      WHEN 'ncmc_ausente'       THEN coalesce(custo_total, 0)
      ELSE coalesce(div_abs, custo_total, ncmc, 0)
    END AS impacto_r,
    classe AS classe_causa,
    custo_status,
    now()
  FROM cls
  WHERE classe IS NOT NULL;

  GET DIAGNOSTICS v = ROW_COUNT;
  RETURN v;
END $$;


--
-- Name: fn_pcp_refresh_itens(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_refresh_itens() RETURNS TABLE(total integer, dimensionais integer, discos integer, sem_match integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  INSERT INTO pcp_itens (omie_codigo_produto, empresa, codigo, descricao, familia, tipo_produto,
    tipo_item, linha_modelo, largura_mm, comprimento_mm, grao, diametro_mm, formato_parse, refreshed_at)
  SELECT p.omie_codigo_produto, 'colacor', p.codigo, p.descricao, p.familia, p.tipo_produto,
    CASE WHEN upper(p.descricao) LIKE 'CINTA %'  THEN 'cinta'
         WHEN upper(p.descricao) LIKE 'ROLO %'   THEN 'rolo'
         WHEN upper(p.descricao) LIKE 'JUMBO %'  THEN 'jumbo'
         WHEN p.familia ILIKE '%disco%'          THEN 'disco'
         WHEN p.familia = 'Tingidor Tingimix'    THEN 'tingidor'
         WHEN p.familia ILIKE '%folha%'          THEN 'folha'
         ELSE 'outro' END,
    COALESCE(NULLIF(trim(p.metadata->>'modelo'), ''),
             (regexp_match(p.descricao, '^(?:CINTA|ROLO|JUMBO)\s+(\S+)'))[1]),
    d.largura_mm, d.comprimento_mm, d.grao, d.diametro_mm, d.formato, now()
  FROM omie_products p
  CROSS JOIN LATERAL fn_pcp_parse_dimensoes(p.descricao) d
  WHERE p.account = 'colacor'
  ON CONFLICT (omie_codigo_produto) DO UPDATE SET
    codigo = EXCLUDED.codigo, descricao = EXCLUDED.descricao, familia = EXCLUDED.familia,
    tipo_produto = EXCLUDED.tipo_produto, tipo_item = EXCLUDED.tipo_item,
    linha_modelo = EXCLUDED.linha_modelo, largura_mm = EXCLUDED.largura_mm,
    comprimento_mm = EXCLUDED.comprimento_mm, grao = EXCLUDED.grao,
    diametro_mm = EXCLUDED.diametro_mm, formato_parse = EXCLUDED.formato_parse, refreshed_at = now();

  RETURN QUERY SELECT count(*)::int,
    count(*) FILTER (WHERE pcp_itens.formato_parse = 'dimensional')::int,
    count(*) FILTER (WHERE pcp_itens.formato_parse = 'disco')::int,
    count(*) FILTER (WHERE pcp_itens.formato_parse = 'sem_match')::int
  FROM pcp_itens;
END $$;


--
-- Name: fn_pcp_registrar_evento(uuid, uuid, text, text, bigint, timestamp with time zone, text, bigint, numeric, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_registrar_evento(p_event_id uuid, p_op_id uuid, p_tipo text, p_device_id text, p_device_seq bigint, p_client_ts timestamp with time zone, p_motivo text DEFAULT NULL::text, p_componente bigint DEFAULT NULL::bigint, p_quantidade numeric DEFAULT NULL::numeric, p_unidade text DEFAULT NULL::text, p_etapa text DEFAULT NULL::text, p_nota text DEFAULT NULL::text) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_uid uuid := (SELECT auth.uid());
  v_exist record;
  v_rows int := 0;
BEGIN
  -- C3: fail-closed. Sem JWT (uid NULL) OU não-staff ⇒ barra. REVOKE de PUBLIC (abaixo) impede anon alcançar.
  IF v_uid IS NULL
     OR NOT (has_role(v_uid,'master'::app_role) OR has_role(v_uid,'employee'::app_role)) THEN
    RAISE EXCEPTION 'fn_pcp_registrar_evento: apenas staff';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM production_orders WHERE id = p_op_id) THEN
    RAISE EXCEPTION 'OP % inexistente', p_op_id;
  END IF;
  -- C6: invariantes de eventos stock-impacting (money-path — baixa de estoque/yield).
  IF p_tipo = 'consumo_mp' THEN
    IF p_motivo IS NULL THEN RAISE EXCEPTION 'consumo_mp exige motivo'; END IF;
    IF p_componente IS NULL OR p_quantidade IS NULL OR p_quantidade <= 0 OR p_unidade IS NULL THEN
      RAISE EXCEPTION 'consumo_mp exige componente_codigo, quantidade>0 e unidade';
    END IF;
  END IF;
  IF p_tipo = 'refugo' AND (p_quantidade IS NULL OR p_quantidade <= 0) THEN
    RAISE EXCEPTION 'refugo exige quantidade>0';
  END IF;
  -- C5: idempotência atômica + validação de payload. Replay idêntico = no-op; reuse divergente = erro.
  INSERT INTO pcp_eventos_producao (id, op_id, tipo, motivo, etapa, componente_codigo,
    quantidade, unidade, nota, device_id, device_seq, criado_por, client_ts)
  VALUES (p_event_id, p_op_id, p_tipo, p_motivo, p_etapa, p_componente,
    p_quantidade, p_unidade, p_nota, p_device_id, p_device_seq, v_uid, p_client_ts)
  ON CONFLICT (id) DO NOTHING;
  GET DIAGNOSTICS v_rows = ROW_COUNT;
  IF v_rows = 0 THEN                                                   -- já existia: valida payload imutável
    SELECT op_id, tipo, componente_codigo, quantidade INTO v_exist
      FROM pcp_eventos_producao WHERE id = p_event_id;
    IF v_exist.op_id IS DISTINCT FROM p_op_id OR v_exist.tipo IS DISTINCT FROM p_tipo
       OR v_exist.componente_codigo IS DISTINCT FROM p_componente
       OR v_exist.quantidade IS DISTINCT FROM p_quantidade THEN
      RAISE EXCEPTION 'idempotency_key_reuse: event_id % reusado com payload diferente', p_event_id;
    END IF;
  END IF;
  RETURN fn_pcp_projetar_op(p_op_id);                                  -- D1: projeção deriva o estado
END $$;


--
-- Name: fn_pcp_rota_fracao_default(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_rota_fracao_default(p_rota_id bigint) RETURNS TABLE(saida_id bigint, fracao numeric)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  WITH base AS (
    SELECT id, (largura_saida_mm * quantidade)::numeric AS area, papel
      FROM pcp_bom_rota_saidas WHERE rota_id = p_rota_id
  ), uteis AS (SELECT sum(area) AS tot FROM base WHERE papel <> 'perda')
  SELECT b.id, CASE WHEN b.papel = 'perda' THEN 0
                    ELSE round(b.area / NULLIF(u.tot, 0), 6) END
    FROM base b CROSS JOIN uteis u;
$$;


--
-- Name: fn_pcp_rota_imutavel(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_rota_imutavel() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.largura_base_mm <> OLD.largura_base_mm OR NEW.largura_alvo_mm <> OLD.largura_alvo_mm THEN
    RAISE EXCEPTION 'rota %: largura_base/alvo sao imutaveis (recadastre a rota)', OLD.id USING ERRCODE='check_violation';
  END IF;
  RETURN NEW;
END $$;


--
-- Name: fn_pcp_ultima_data_posicao(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_ultima_data_posicao() RETURNS date
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT max(data_posicao) FROM cmc_snapshot
   WHERE account = (SELECT value#>>'{}' FROM pcp_config WHERE key = 'custo_cmc_account');
$$;


--
-- Name: fn_pcp_validar_rota(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_pcp_validar_rota() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  v_rotas bigint[] := ARRAY(SELECT DISTINCT x FROM unnest(ARRAY[NEW.rota_id, OLD.rota_id]) x WHERE x IS NOT NULL);
  v_rota bigint;
  v_base int; v_alvo int; v_area int; v_frac numeric; v_princ int;
BEGIN
  FOREACH v_rota IN ARRAY v_rotas LOOP
    SELECT largura_base_mm, largura_alvo_mm INTO v_base, v_alvo FROM pcp_bom_rotas WHERE id = v_rota;
    IF v_base IS NULL THEN CONTINUE; END IF;                   -- rota apagada (cascade)
    SELECT COALESCE(sum(largura_saida_mm * quantidade), 0),
           COALESCE(sum(fracao_rateio) FILTER (WHERE papel <> 'perda'), 0),
           COALESCE(count(*) FILTER (WHERE papel = 'principal' AND largura_saida_mm = v_alvo), 0)
      INTO v_area, v_frac, v_princ
      FROM pcp_bom_rota_saidas WHERE rota_id = v_rota;
    IF v_princ < 1 THEN
      RAISE EXCEPTION 'rota %: exige >=1 saida principal na largura-alvo %mm', v_rota, v_alvo USING ERRCODE='check_violation';
    END IF;
    IF v_area <> v_base THEN
      RAISE EXCEPTION 'rota %: Σsaidas (%mm) <> base (%mm) — refilo deve virar sobra/perda explicita', v_rota, v_area, v_base USING ERRCODE='check_violation';
    END IF;
    IF round(v_frac, 4) <> 1.0000 THEN
      RAISE EXCEPTION 'rota %: soma fracao das boas=% (<>1, custo nao conservado)', v_rota, v_frac USING ERRCODE='check_violation';
    END IF;
  END LOOP;
  RETURN NULL;
END $$;


--
-- Name: fornecedor_operacional(text, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fornecedor_operacional(p_empresa text, p_fornecedor text, p_timestamp timestamp with time zone DEFAULT now()) RETURNS TABLE(opera boolean, motivo text, calendario_validado boolean)
    LANGUAGE plpgsql STABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_data DATE := (p_timestamp AT TIME ZONE 'America/Sao_Paulo')::date;
  v_hora TIME := (p_timestamp AT TIME ZONE 'America/Sao_Paulo')::time;
  v_dia_semana INT := EXTRACT(DOW FROM v_data);
  v_calendario RECORD;
  v_eh_feriado BOOLEAN;
BEGIN
  SELECT EXISTS (SELECT 1 FROM calendario_feriados WHERE data = v_data) 
  INTO v_eh_feriado;
  
  IF v_eh_feriado THEN 
    RETURN QUERY SELECT false, 'Feriado nacional'::text, true;
    RETURN;
  END IF;
  
  SELECT * INTO v_calendario
  FROM fornecedor_calendario_operacao
  WHERE empresa = p_empresa 
    AND fornecedor_nome = p_fornecedor
    AND dia_semana = v_dia_semana;
  
  IF NOT FOUND THEN
    RETURN QUERY SELECT true, 'Calendário não configurado'::text, false;
    RETURN;
  END IF;
  
  IF v_calendario.hora_abertura IS NULL THEN
    RETURN QUERY SELECT false, 'Fornecedor não opera neste dia'::text, 
                        v_calendario.validado_com_fornecedor;
    RETURN;
  END IF;
  
  IF v_hora BETWEEN v_calendario.hora_abertura AND v_calendario.hora_fechamento THEN
    RETURN QUERY SELECT true, 'Dentro da janela operacional'::text,
                        v_calendario.validado_com_fornecedor;
  ELSE
    RETURN QUERY SELECT false, 'Fora da janela operacional'::text,
                        v_calendario.validado_com_fornecedor;
  END IF;
END;
$$;


--
-- Name: fornecedor_polling_pendente(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fornecedor_polling_pendente(p_intervalo_min integer DEFAULT 60) RETURNS TABLE(config_id bigint, empresa text, fornecedor_nome text, remetente_email text, assunto_contem text[], assunto_suspensao text[], tipo_documento text, aceitar_pdf boolean, aceitar_imagem boolean, ultimo_email_processado_id text, notificar_email text, notificar_calendar_id text)
    LANGUAGE sql STABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
  SELECT 
    id, empresa, fornecedor_nome, remetente_email,
    assunto_contem, assunto_suspensao, tipo_documento,
    aceitar_pdf, aceitar_imagem,
    ultimo_email_processado_id,
    notificar_email, notificar_calendar_id
  FROM fornecedor_email_polling
  WHERE ativo = true
    AND (
      ultimo_poll_em IS NULL 
      OR ultimo_poll_em < (now() - (p_intervalo_min::text || ' minutes')::interval)
    )
  ORDER BY ultimo_poll_em NULLS FIRST;
$$;


--
-- Name: generate_tool_internal_code(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_tool_internal_code() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
  category_prefix TEXT;
  seq_num INTEGER;
  new_code TEXT;
BEGIN
  -- Get first 3 chars of category name uppercased
  SELECT UPPER(LEFT(REGEXP_REPLACE(name, '[^A-Za-z]', '', 'g'), 3))
  INTO category_prefix
  FROM public.tool_categories
  WHERE id = NEW.tool_category_id;

  IF category_prefix IS NULL OR category_prefix = '' THEN
    category_prefix := 'FER';
  END IF;

  -- Count existing tools in this category for sequential numbering
  SELECT COUNT(*) + 1
  INTO seq_num
  FROM public.user_tools
  WHERE tool_category_id = NEW.tool_category_id;

  new_code := category_prefix || '-' || LPAD(seq_num::TEXT, 4, '0');

  -- Handle uniqueness conflicts
  WHILE EXISTS (SELECT 1 FROM public.user_tools WHERE internal_code = new_code) LOOP
    seq_num := seq_num + 1;
    new_code := category_prefix || '-' || LPAD(seq_num::TEXT, 4, '0');
  END LOOP;

  NEW.internal_code := new_code;
  RETURN NEW;
END;
$$;


--
-- Name: gerar_pedidos_oportunidade_ciclo(text, date, text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.gerar_pedidos_oportunidade_ciclo(p_empresa text DEFAULT 'OBEN'::text, p_data_ciclo date DEFAULT CURRENT_DATE, p_cenarios text[] DEFAULT ARRAY['promo_flat'::text, 'promo_volume'::text, 'promo_e_aumento'::text, 'aumento_apenas'::text]) RETURNS TABLE(pedidos_gerados integer, skus_incluidos integer, valor_total numeric, economia_bruta numeric, cenarios_cobertos text[])
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_pedidos int := 0;
  v_skus int := 0;
  v_valor numeric := 0;
  v_economia numeric := 0;
  v_cenarios_encontrados text[];
BEGIN
  -- Remove pedidos oportunidade pendentes do mesmo ciclo (idempotente)
  DELETE FROM pedido_compra_sugerido
  WHERE empresa = p_empresa
    AND data_ciclo = p_data_ciclo
    AND tipo_ciclo LIKE 'oportunidade_%'
    AND status = 'pendente_aprovacao';

  -- Identifica cenários presentes
  SELECT array_agg(DISTINCT cenario) INTO v_cenarios_encontrados
  FROM v_oportunidade_economica_hoje
  WHERE empresa = p_empresa
    AND cenario = ANY(p_cenarios)
    AND economia_bruta_estimada > 0;

  -- Gera um pedido por (fornecedor, cenário_tipo)
  -- cenário_tipo: 'promo' (inclui flat, volume, promo_e_aumento) ou 'aumento'
  WITH oportunidades AS (
    SELECT *,
      CASE
        WHEN cenario IN ('promo_flat', 'promo_volume', 'promo_e_aumento')
          THEN 'oportunidade_promo'
        ELSE 'oportunidade_aumento'
      END AS tipo_ciclo_dest,
      CASE
        WHEN cenario IN ('promo_flat', 'promo_volume', 'promo_e_aumento')
          THEN campanha_id
        ELSE NULL
      END AS evento_promo_id,
      CASE
        WHEN cenario = 'aumento_apenas'
          THEN (aumentos_json -> 0 -> 0 ->> 'aumento_id')::bigint
        ELSE NULL
      END AS evento_aumento_id
    FROM v_oportunidade_economica_hoje voeh
    WHERE voeh.empresa = p_empresa
      AND voeh.cenario = ANY(p_cenarios)
      AND voeh.economia_bruta_estimada > 0
      AND voeh.qtde_oportunidade > 0
      -- [SIMETRIA-NORMAL] não oferecer SKU que JÁ está em pedido NORMAL economicamente ativo
      -- (espelha o NOT EXISTS 4/4 da RPC normal, na direção inversa — anti compra dupla).
      AND NOT EXISTS (
            SELECT 1
            FROM pedido_compra_item pcin
            JOIN pedido_compra_sugerido pcsn ON pcsn.id = pcin.pedido_id
            WHERE pcsn.empresa = p_empresa
              AND COALESCE(pcsn.tipo_ciclo, 'normal') = 'normal'
              AND pcsn.status IN ('pendente_aprovacao','bloqueado_guardrail','aprovado_aguardando_disparo','falha_envio','disparado','concluido_recebido')
              AND pcsn.data_ciclo >= (p_data_ciclo - INTERVAL '7 days')
              AND pcin.sku_codigo_omie = voeh.sku_codigo_omie::text
          )
  ),
  pedidos_criados AS (
    INSERT INTO pedido_compra_sugerido (
      empresa, fornecedor_nome, grupo_codigo, data_ciclo,
      horario_corte_planejado, valor_total, num_skus, status,
      tipo_ciclo, origem_evento_id, origem_evento_tipo
    )
    SELECT
      o.empresa,
      o.fornecedor_nome,
      NULL,  -- oportunidade não respeita grupo; é um pedido único por fornecedor
      p_data_ciclo,
      (p_data_ciclo + TIME '18:00')::timestamptz,
      SUM(o.qtde_oportunidade * o.preco_item_eoq),
      COUNT(*),
      'pendente_aprovacao',
      o.tipo_ciclo_dest,
      COALESCE(o.evento_promo_id, o.evento_aumento_id),
      CASE WHEN o.evento_promo_id IS NOT NULL THEN 'campanha_promocao' ELSE 'aumento_anunciado' END
    FROM oportunidades o
    GROUP BY o.empresa, o.fornecedor_nome, o.tipo_ciclo_dest, o.evento_promo_id, o.evento_aumento_id
    RETURNING id, fornecedor_nome, tipo_ciclo, origem_evento_id, origem_evento_tipo
  )
  INSERT INTO pedido_compra_item (
    pedido_id, sku_codigo_omie, sku_descricao,
    estoque_atual, ponto_pedido, estoque_maximo,
    qtde_sugerida, qtde_final, preco_unitario, valor_linha, primeira_compra,
    modo_promocao, promocao_item_id, preco_sem_desconto, desconto_perc_aplicado,
    economia_estimada_valor
  )
  SELECT
    pc.id,
    o.sku_codigo_omie,
    o.sku_descricao,
    NULL, NULL, NULL,  -- não aplicável em oportunidade
    o.qtde_oportunidade,
    o.qtde_oportunidade,
    o.preco_item_eoq * (1 - o.desconto_total_perc / 100),
    o.qtde_oportunidade * o.preco_item_eoq * (1 - o.desconto_total_perc / 100),
    false,
    CASE
      WHEN o.cenario IN ('promo_flat') THEN 'flat'
      WHEN o.cenario IN ('promo_volume', 'promo_e_aumento') THEN 'forward_buying'
      ELSE NULL
    END,
    o.promo_item_id,
    o.preco_item_eoq,
    o.desconto_total_perc,
    o.economia_bruta_estimada
  FROM v_oportunidade_economica_hoje o
  JOIN pedidos_criados pc ON (
    pc.fornecedor_nome = o.fornecedor_nome
    AND pc.tipo_ciclo = CASE
      WHEN o.cenario IN ('promo_flat', 'promo_volume', 'promo_e_aumento')
        THEN 'oportunidade_promo'
      ELSE 'oportunidade_aumento'
    END
  )
  WHERE o.empresa = p_empresa
    AND o.cenario = ANY(p_cenarios)
    AND o.economia_bruta_estimada > 0
    AND o.qtde_oportunidade > 0
    -- [SIMETRIA-NORMAL] mesmo filtro do CTE — o INSERT de itens re-lê a view; sem o espelho,
    -- um SKU excluído do header entraria como item de pedido criado por outros SKUs.
    AND NOT EXISTS (
          SELECT 1
          FROM pedido_compra_item pcin
          JOIN pedido_compra_sugerido pcsn ON pcsn.id = pcin.pedido_id
          WHERE pcsn.empresa = p_empresa
            AND COALESCE(pcsn.tipo_ciclo, 'normal') = 'normal'
            AND pcsn.status IN ('pendente_aprovacao','bloqueado_guardrail','aprovado_aguardando_disparo','falha_envio','disparado','concluido_recebido')
            AND pcsn.data_ciclo >= (p_data_ciclo - INTERVAL '7 days')
            AND pcin.sku_codigo_omie = o.sku_codigo_omie::text
        );

  -- Agrega retorno
  -- [FIX-AMBIGUIDADE] o corpo do snapshot fazia SUM(valor_total) sem qualificar — colide com a
  -- coluna OUT homônima do RETURNS TABLE → "column reference valor_total is ambiguous" em
  -- RUNTIME (late-bound; o CREATE passa). Como o wrapper ciclo_oportunidade_do_dia só chama
  -- esta função em dia de corte de campanha/véspera de aumento, a falha era SILENCIOSA e
  -- ocorria exatamente nos dias com evento (rollback no cron — pedido de oportunidade nunca
  -- nascia). Mesmo modo-de-falha do incidente aplicar_promocoes (§10). Pego pelo PG17 que
  -- EXECUTA a função, não só a cria.
  SELECT
    COUNT(*),
    COALESCE(SUM(pcs0.num_skus), 0),
    COALESCE(SUM(pcs0.valor_total), 0)
  INTO v_pedidos, v_skus, v_valor
  FROM pedido_compra_sugerido pcs0
  WHERE pcs0.empresa = p_empresa
    AND pcs0.data_ciclo = p_data_ciclo
    AND pcs0.tipo_ciclo LIKE 'oportunidade_%'
    AND pcs0.status = 'pendente_aprovacao';

  SELECT COALESCE(SUM(economia_estimada_valor), 0)
  INTO v_economia
  FROM pedido_compra_item pci
  JOIN pedido_compra_sugerido pcs ON pcs.id = pci.pedido_id
  WHERE pcs.empresa = p_empresa
    AND pcs.data_ciclo = p_data_ciclo
    AND pcs.tipo_ciclo LIKE 'oportunidade_%'
    AND pcs.status = 'pendente_aprovacao';

  RETURN QUERY SELECT v_pedidos, v_skus, v_valor, v_economia, v_cenarios_encontrados;
END;
$$;


--
-- Name: gerar_pedidos_sugeridos_ciclo(text, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.gerar_pedidos_sugeridos_ciclo(p_empresa text DEFAULT 'OBEN'::text, p_data_ciclo date DEFAULT CURRENT_DATE) RETURNS TABLE(pedidos_gerados integer, skus_incluidos integer, valor_total_ciclo numeric, bloqueados integer)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    SET statement_timeout TO '120s'
    AS $_$
DECLARE
  v_pedidos INT := 0;
  v_skus INT := 0;
  v_valor NUMERIC := 0;
  v_bloqueados INT := 0;
  v_stale_dias INT := 45;  -- motor confia no preço-app por N dias (painel usa 24h; manual precisa folga). Config abaixo.
  v_run_id uuid := gen_random_uuid();  -- [GATE estoque-não-confirmado] carimba os suprimidos desta execução no log
BEGIN
  -- [INTRADAY 1/4] serializa execuções concorrentes (cron 2/2h × botão "Recalcular" × retry).
  PERFORM pg_advisory_xact_lock(hashtext('gerar_pedidos_sugeridos_ciclo:' || lower(p_empresa)));

  IF (SELECT count(*) FILTER (WHERE tipo_produto IS NOT NULL) FROM public.omie_products WHERE account = lower(p_empresa)) = 0 THEN
    RAISE EXCEPTION 'tipo_produto_unhealthy: sinal de classificação ausente em omie_products(account=%) — recusando gerar compras p/ não tratar Produto Acabado como comprável', lower(p_empresa);
  END IF;

  -- Janela de frescor do preço-app que o motor aceita p/ trocar a embalagem (decisão B da spec). Global.
  SELECT COALESCE((SELECT NULLIF(btrim(value), '')::int
                   FROM company_config WHERE key = 'embalagem_preco_motor_stale_dias' LIMIT 1), 45)
    INTO v_stale_dias;

  -- [INTRADAY 2/4] expira pendentes NORMAIS de ciclos anteriores (zumbis pós-corte).
  UPDATE pedido_compra_sugerido
  SET status = 'expirado_sem_aprovacao', atualizado_em = now()
  WHERE empresa = p_empresa
    AND data_ciclo < p_data_ciclo
    AND status = 'pendente_aprovacao'
    AND COALESCE(tipo_ciclo, 'normal') = 'normal';

  -- [INTRADAY 3/4] limpeza do dia: só ciclo NORMAL (preserva oportunidade/promoção pendentes) e
  -- INCLUI bloqueado_guardrail do dia (re-avaliado a cada rodada; anti compra dupla).
  DELETE FROM pedido_compra_sugerido
  WHERE empresa = p_empresa AND data_ciclo = p_data_ciclo
    AND status IN ('pendente_aprovacao', 'bloqueado_guardrail')
    AND COALESCE(tipo_ciclo, 'normal') = 'normal';

  WITH em_transito AS (
    SELECT pcs2.empresa, pci.sku_codigo_omie::text AS sku_codigo_omie, SUM(pci.qtde_final) AS qtde
    FROM pedido_compra_item pci
    JOIN pedido_compra_sugerido pcs2 ON pcs2.id = pci.pedido_id
    WHERE pcs2.empresa = p_empresa
      AND (
        (pcs2.status IN ('aprovado_aguardando_disparo','disparado','concluido_recebido') AND pcs2.data_ciclo >= (p_data_ciclo - INTERVAL '7 days'))
        OR (pcs2.status_envio_portal IN ('sucesso_portal','enviado_portal') AND pcs2.portal_protocolo IS NOT NULL AND pcs2.omie_pedido_compra_numero IS NULL AND pcs2.status NOT IN ('cancelado','expirado_sem_aprovacao'))
      )
    GROUP BY pcs2.empresa, pci.sku_codigo_omie
  ),
  -- [DEDUP-NFE] 1 obs por (empresa, NFe, SKU); antes: 1 por LINHA de sku_leadtime_history, o que
  -- ponderava o AVG pela multiplicidade (NFe que fatura N pedidos regravava o item N×).
  -- [2 CONSUMIDORES] O filtro de preço saiu do WHERE e virou FILTER na agregação — de propósito.
  -- Esta CTE serve a DOIS consumidores, que fazem perguntas DIFERENTES:
  --   · preco_unitario → "quanto custou?"  ⇒ agrega só a obs precificável (FILTER). Sem nenhuma
  --     ⇒ NULL, e o COALESCE(cmc, …) decide. Ausente ≠ zero.
  --   · n (lido SÓ como `pm.n IS NULL` ⇒ primeira_compra) → "já foi comprado?" ⇒ conta TODA obs.
  --     COMPRAR ≠ SABER QUANTO CUSTOU. Com o filtro no WHERE, a obs cuja quantidade a view NULLa
  --     (cópias divergem) derrubaria o SKU INTEIRO da CTE ⇒ o badge mentiria "primeira compra"
  --     num SKU já comprado. Não é hipótese: medido ZERO no pré-flight e DOIS poucas horas
  --     depois, na MESMA sessão — o resíduo se move (o sync grava). Com o FILTER, o conjunto de
  --     primeira_compra fica IDÊNTICO ao de hoje (medido nos dois sentidos: nenhum SKU entra,
  --     nenhum sai), enquanto o preço passa a ser o deduplicado. É o único ponto em que esta
  --     migration se afasta do "trocar só o FROM" — e é o que a impede de trocar viés por mentira.
  preco_medio AS (
    SELECT slh.empresa::text AS empresa, slh.sku_codigo_omie::text AS sku_codigo_omie,
           AVG(slh.valor_total / NULLIF(slh.quantidade_recebida, 0))
             FILTER (WHERE slh.quantidade_recebida > 0 AND slh.valor_total > 0) AS preco_unitario,
           COUNT(*) AS n
    FROM v_sku_leadtime_efetivo slh
    GROUP BY slh.empresa, slh.sku_codigo_omie
  ),
  -- ── EMBALAGEM (novo) ─────────────────────────────────────────────────────────────────────
  -- Membros ativos dos grupos de equivalência (empresa = lower).
  equiv AS (
    SELECT grupo_id, sku_codigo_omie::text AS sku, fator_para_base
    FROM sku_embalagem_equivalencia
    WHERE empresa = lower(p_empresa) AND ativo = TRUE AND fator_para_base > 0
  ),
  -- Só grupos com >= 2 membros têm decisão de embalagem.
  equiv_grupos AS (
    SELECT grupo_id FROM equiv GROUP BY grupo_id HAVING count(*) >= 2
  ),
  -- Preço-app mais recente por SKU (empresa = lower), líquido e > 0.
  preco_app AS (
    SELECT DISTINCT ON (sku_codigo_omie) sku_codigo_omie::text AS sku, preco, capturado_em
    FROM sku_preco_fornecedor_capturado
    WHERE empresa = lower(p_empresa) AND status = 'ok' AND preco > 0
    ORDER BY sku_codigo_omie, capturado_em DESC
  ),
  -- Portal-map ativo por SKU (empresa = upper). Sem map → não dá pra emitir ao portal → inelegível.
  portal_map AS (
    SELECT DISTINCT sku_omie::text AS sku
    FROM sku_fornecedor_externo
    WHERE empresa = p_empresa AND ativo = TRUE AND sku_portal IS NOT NULL AND btrim(sku_portal) <> ''
  ),
  -- [P0-a] Saldo físico do Omie por SKU (account-aware; 1 linha/SKU, a mais recente). As 2 fontes de estoque
  -- DIVERGEM: inventory_position tem alguns galões (WP87/WP04), sku_estoque_atual tem outros (WP01). GREATEST
  -- (adiante) pega o galão real de onde estiver.
  inv_saldo AS (
    SELECT DISTINCT ON (omie_codigo_produto) omie_codigo_produto::text AS sku, saldo
    FROM inventory_position
    WHERE account = ANY (CASE lower(p_empresa)
            WHEN 'oben' THEN ARRAY['vendas'::text,'oben'::text]
            WHEN 'colacor' THEN ARRAY['colacor_vendas'::text,'colacor'::text]
            WHEN 'colacor_sc' THEN ARRAY['servicos'::text,'colacor_sc'::text]
            ELSE ARRAY[lower(p_empresa)] END)
    ORDER BY omie_codigo_produto, synced_at DESC NULLS LAST
  ),
  -- [P1-f] Membro ELEGÍVEL p/ a decisão: preço-app FRESCO + portal-map + CATÁLOGO OK (ativo, tipo≠04, família
  -- comprável, ativo_no_omie) — os MESMOS filtros que protegem a âncora, agora também no SKU que pode ser escolhido.
  membro_elegivel AS (
    SELECT e.grupo_id, e.sku, e.fator_para_base, pa.preco,
           (pa.preco / e.fator_para_base) AS custo_base
    FROM equiv e
    JOIN equiv_grupos eg ON eg.grupo_id = e.grupo_id
    JOIN preco_app pa ON pa.sku = e.sku AND pa.capturado_em >= now() - make_interval(days => v_stale_dias)
    JOIN portal_map pm ON pm.sku = e.sku
    JOIN omie_products opm ON opm.omie_codigo_produto::text = e.sku AND opm.account = lower(p_empresa)
    LEFT JOIN sku_status_omie ssom ON ssom.empresa = p_empresa AND ssom.sku_codigo_omie = e.sku
    LEFT JOIN familia_nao_comprada fncm ON fncm.empresa = p_empresa AND fncm.familia = opm.familia
    WHERE COALESCE(opm.ativo, TRUE) = TRUE
      AND COALESCE(ssom.ativo_no_omie, TRUE) = TRUE
      AND fncm.id IS NULL
      AND COALESCE(opm.tipo_produto, opm.metadata->>'tipo_produto', '') <> '04'
      AND COALESCE(opm.descricao, '') NOT ILIKE '%450ML'   -- [P1-f] os MESMOS filtros de catálogo da âncora
      AND COALESCE(opm.descricao, '') NOT ILIKE '%405ML'
  ),
  -- Melhor embalagem do grupo (menor custo_base; empate → embalagem maior).
  embalagem_escolhida AS (
    SELECT DISTINCT ON (grupo_id)
           grupo_id, sku AS sku_escolhido, fator_para_base AS fator_escolhido,
           preco AS preco_escolhido, custo_base AS custo_base_escolhido
    FROM membro_elegivel
    ORDER BY grupo_id, custo_base ASC, fator_para_base DESC
  ),
  -- [P0-a/P0-b] Estoque consolidado por grupo (escala unidades-âncora):
  --   físico = Σ GREATEST(inv.saldo, sea.estoque_fisico)   ← pega o galão real de onde estiver
  --   a caminho = Σ [pendente(sea) + em_transito × fator]  ← galão em voo conta em unidades-base (2 GL = 8), não cru
  grupo_estoque AS (
    SELECT e.grupo_id,
           SUM(GREATEST(COALESCE(inv.saldo, 0), COALESCE(sea.estoque_fisico, 0)))                              AS fisico_grupo,
           SUM(COALESCE(sea.estoque_pendente_entrada, 0) + COALESCE(et.qtde, 0) * e.fator_para_base)           AS acaminho_grupo,
           SUM(GREATEST(COALESCE(inv.saldo, 0), COALESCE(sea.estoque_fisico, 0))
               + COALESCE(sea.estoque_pendente_entrada, 0) + COALESCE(et.qtde, 0) * e.fator_para_base)         AS estoque_grupo,
           -- [GATE estoque-não-confirmado] grupo NÃO-CONFIRMADO se QUALQUER membro ATIVO tem seed (cold_start_seed)
           -- sem inventory_position — pode ter saldo real que mudaria a decisão. NÃO conta "sem linha de sea" (galão
           -- legitimamente vive sem sea próprio; o estoque vem de outro membro — só a LINHA isolada gateia sea ausente).
           -- inv por PRESENÇA da linha (não saldo, que pode ser NULL — Codex P1, casa a LINHA); membro INATIVO no Omie
           -- NÃO vota — senão um galão descontinuado seed-only envenenaria o grupo ativo p/ sempre (Codex P1).
           bool_or(COALESCE(sea.fonte_sync, '') = 'cold_start_seed'
                   AND inv.sku IS NULL
                   AND COALESCE(ssg.ativo_no_omie, true) = true)                                               AS grupo_nao_confirmado
    FROM equiv e
    LEFT JOIN sku_estoque_atual sea ON sea.empresa = p_empresa AND sea.sku_codigo_omie = e.sku
    LEFT JOIN inv_saldo inv        ON inv.sku = e.sku
    LEFT JOIN em_transito et       ON et.sku_codigo_omie = e.sku
    LEFT JOIN sku_status_omie ssg  ON ssg.empresa = p_empresa AND ssg.sku_codigo_omie = e.sku  -- [GATE] inativo não vota
    GROUP BY e.grupo_id
  ),
  -- ── BASE: 1 linha por ÂNCORA (SKU com sku_parametros, i.e. o quartinho) que dispara ──────────
  sku_base AS (
    SELECT sp.empresa, sp.sku_codigo_omie::text AS ancora_sku, sp.sku_descricao, sp.fornecedor_nome,
           sg.grupo_codigo, sp.ponto_pedido, sp.estoque_maximo, sp.minimo_forcado_manual,
           COALESCE(sea.estoque_fisico, 0) AS estoque_fisico_proprio,
           (COALESCE(sea.estoque_pendente_entrada, 0) + COALESCE(et.qtde, 0)) AS acaminho_proprio,
           ea.grupo_id AS equiv_grupo,
           ge.estoque_grupo, ge.fisico_grupo, ge.acaminho_grupo,
           -- estoque efetivo: do GRUPO quando a âncora pertence a um grupo; senão o próprio (no-op p/ a maioria).
           COALESCE(ge.estoque_grupo,
                    COALESCE(sea.estoque_fisico, 0) + COALESCE(sea.estoque_pendente_entrada, 0) + COALESCE(et.qtde, 0)) AS estoque_efetivo,
           ee.sku_escolhido, ee.fator_escolhido, ee.preco_escolhido, ee.custo_base_escolhido,
           me_anc.custo_base AS ancora_custo_base,  -- NULL = âncora não-elegível → estrito (não troca)
           -- custo da linha p/ a ÂNCORA: cmc account-aware, senão preço médio histórico, senão NULL.
           -- [PRECO-AUSENTE] ausente≠zero — NÃO fabrica R$0 (o gate de auto-aprovação e o disparo já barram custo desconhecido).
           COALESCE(
             ( SELECT ipc.cmc FROM inventory_position ipc
               WHERE ipc.omie_codigo_produto::text = sp.sku_codigo_omie::text
                 AND ipc.account = ANY (CASE lower(p_empresa)
                       WHEN 'oben' THEN ARRAY['vendas'::text,'oben'::text]
                       WHEN 'colacor' THEN ARRAY['colacor_vendas'::text,'colacor'::text]
                       WHEN 'colacor_sc' THEN ARRAY['servicos'::text,'colacor_sc'::text]
                       ELSE ARRAY[lower(p_empresa)] END)
                 AND ipc.cmc > 0
               ORDER BY ipc.synced_at DESC NULLS LAST
               LIMIT 1 ),
             pm.preco_unitario) AS preco_unitario_ancora,   -- [PRECO-AUSENTE] sem fallback 0
           (pm.n IS NULL) AS primeira_compra,
           fh.horario_corte_pedido, fh.valor_maximo_mensal, fh.delta_max_perc,
           -- [GATE estoque-não-confirmado] confirmação por LINHA (SKU isolado): seed-only OU sem linha de estoque
           -- (Codex P1: sea AUSENTE é estoque desconhecido, não zero confirmado), sem inventory_position.
           -- inv via isl = inv_saldo (account-aware ['vendas','oben']), NÃO o ip órfão (account=lower(empresa) só):
           -- o estoque da OBEN vive em 'vendas'; PRESENÇA da linha de inv (isl.sku), p/ casar o gate de grupo.
           ((sea.sku_codigo_omie IS NULL OR COALESCE(sea.fonte_sync, '') = 'cold_start_seed') AND isl.sku IS NULL) AS linha_nao_confirmada,
           ge.grupo_nao_confirmado,
           sea.fonte_sync AS linha_fonte_sync
    FROM sku_parametros sp
    LEFT JOIN sku_grupo_producao sg ON sg.empresa = sp.empresa AND sg.sku_codigo_omie = sp.sku_codigo_omie::text
    LEFT JOIN sku_estoque_atual sea ON sea.empresa = sp.empresa AND sea.sku_codigo_omie = sp.sku_codigo_omie::text
    LEFT JOIN fornecedor_habilitado_reposicao fh ON fh.empresa = sp.empresa AND fh.fornecedor_nome = sp.fornecedor_nome
    LEFT JOIN omie_products op ON op.omie_codigo_produto::text = sp.sku_codigo_omie::text AND op.account = lower(p_empresa)
    LEFT JOIN familia_nao_comprada fnc ON fnc.empresa = sp.empresa AND fnc.familia = op.familia
    LEFT JOIN em_transito et ON et.empresa = sp.empresa AND et.sku_codigo_omie = sp.sku_codigo_omie::text
    LEFT JOIN preco_medio pm ON pm.empresa = sp.empresa AND pm.sku_codigo_omie = sp.sku_codigo_omie::text
    LEFT JOIN inventory_position ip ON ip.omie_codigo_produto::text = sp.sku_codigo_omie::text AND ip.account = lower(p_empresa)
    LEFT JOIN inv_saldo isl ON isl.sku = sp.sku_codigo_omie::text   -- [GATE] confirmação por inventory_position (account-aware)
    LEFT JOIN sku_status_omie sso ON sso.empresa = sp.empresa AND sso.sku_codigo_omie = sp.sku_codigo_omie::text
    -- equivalência da âncora + estoque consolidado + escolha de embalagem (NULL p/ SKU sem grupo).
    LEFT JOIN equiv ea ON ea.sku = sp.sku_codigo_omie::text
    LEFT JOIN grupo_estoque ge ON ge.grupo_id = ea.grupo_id
    LEFT JOIN embalagem_escolhida ee ON ee.grupo_id = ea.grupo_id
    LEFT JOIN membro_elegivel me_anc ON me_anc.grupo_id = ea.grupo_id AND me_anc.sku = sp.sku_codigo_omie::text
    WHERE sp.empresa = p_empresa
      AND sp.habilitado_reposicao_automatica = TRUE
      AND COALESCE(sp.tipo_reposicao, 'automatica') = 'automatica'
      AND sp.fornecedor_nome IS NOT NULL
      AND btrim(sp.fornecedor_nome) <> ''
      AND fnc.id IS NULL
      AND COALESCE(op.ativo, true) = true
      AND COALESCE(sso.ativo_no_omie, true) = true
      AND COALESCE(op.descricao, '') NOT ILIKE '%450ML'
      AND COALESCE(op.descricao, '') NOT ILIKE '%405ML'
      AND COALESCE((
            SELECT COALESCE(op04.tipo_produto, op04.metadata->>'tipo_produto')
            FROM omie_products op04
            WHERE op04.omie_codigo_produto::text = sp.sku_codigo_omie::text
              AND op04.account = lower(p_empresa)
            LIMIT 1
          ), '') <> '04'
      -- [P1-c] A âncora NÃO pode ser um galão (membro fator>1 de um grupo): senão um GL com ponto/max viraria
      -- âncora E seria escolhido por outro membro → 2 linhas do mesmo GL (uma com custo CMC/0). A âncora é
      -- sempre a unidade-base (fator 1). (Hoje no-op: galões têm ponto/max NULL; isto blinda o futuro.)
      AND NOT EXISTS (
            SELECT 1 FROM equiv eg2
            WHERE eg2.sku = sp.sku_codigo_omie::text AND eg2.fator_para_base > 1
          )
      -- [INTRADAY 4/4] o anti-dup de oportunidade foi MOVIDO p/ depois da decisão (skus_necessitando), porque
      -- precisa olhar o SKU FINAL (âncora OU galão escolhido), não o candidato — senão bloquearia o quartinho
      -- mantido por causa de uma oportunidade do galão que nem vai ser comprado. [P1-d, refinado pós-re-Codex]
      AND sp.ponto_pedido IS NOT NULL
      AND sp.estoque_maximo IS NOT NULL
      -- GATILHO consolidado: estoque do GRUPO (ou próprio) <= ponto_pedido da âncora.
      AND COALESCE(ge.estoque_grupo,
                   COALESCE(sea.estoque_fisico, 0) + COALESCE(sea.estoque_pendente_entrada, 0) + COALESCE(et.qtde, 0)) <= sp.ponto_pedido
  ),
  -- ── DECISÃO: troca p/ galão só se ESTRITAMENTE mais barato/base e a âncora também é elegível ──
  skus_necessitando AS (
    SELECT b.empresa,
           CASE WHEN trocou THEN b.sku_escolhido ELSE b.ancora_sku END AS sku_codigo_omie,
           CASE WHEN trocou
                THEN COALESCE((SELECT op2.descricao FROM omie_products op2
                               WHERE op2.omie_codigo_produto::text = b.sku_escolhido
                                 AND op2.account = lower(p_empresa) LIMIT 1), b.sku_descricao)
                ELSE b.sku_descricao END AS sku_descricao,
           b.fornecedor_nome, b.grupo_codigo, b.ponto_pedido, b.estoque_maximo,
           COALESCE(b.fisico_grupo, b.estoque_fisico_proprio)  AS estoque_fisico,
           COALESCE(b.acaminho_grupo, b.acaminho_proprio)      AS estoque_a_caminho,
           b.estoque_efetivo,
           ceil(b.estoque_maximo - b.estoque_efetivo) AS qtde_sugerida,  -- gate >0 (unidades-âncora)
           -- nº de embalagens do SKU escolhido: galão = ceil(necessidade / fator); quartinho = lógica atual.
           -- [P1-e] minimo_forcado_manual (unidades-âncora) aplicado como piso ANTES de dividir pelo fator.
           CASE
             WHEN trocou THEN ceil(GREATEST(b.estoque_maximo - b.estoque_efetivo,
                                            COALESCE(b.minimo_forcado_manual, 0)) / b.fator_escolhido)
             WHEN b.minimo_forcado_manual IS NOT NULL AND b.minimo_forcado_manual > 0
                  THEN ceil(GREATEST(b.estoque_maximo - b.estoque_efetivo, b.minimo_forcado_manual))
             ELSE ceil(b.estoque_maximo - b.estoque_efetivo)
           END AS qtde_final,
           -- custo da linha: galão → preço-app (R$/embalagem, nunca 0); quartinho → cmc atual.
           CASE WHEN trocou THEN b.preco_escolhido ELSE b.preco_unitario_ancora END AS preco_unitario,
           b.primeira_compra, b.horario_corte_pedido, b.valor_maximo_mensal, b.delta_max_perc,
           -- [GATE estoque-não-confirmado] espelha estoque_efetivo=COALESCE(grupo,linha): decisão pelo grupo usa a
           -- confirmação do grupo; pela linha, a da linha. Suprime quando a fonte é só seed (ausente≠zero, precisão>recall).
           COALESCE(b.grupo_nao_confirmado, b.linha_nao_confirmada) AS suprimido,
           CASE WHEN b.grupo_nao_confirmado THEN 'grupo_membro_seed_only'
                WHEN b.linha_nao_confirmada THEN 'linha_seed_only'
                ELSE NULL END AS motivo,
           b.linha_fonte_sync
    FROM (
      SELECT b0.*,
             ( b0.sku_escolhido IS NOT NULL
               AND b0.sku_escolhido <> b0.ancora_sku
               AND b0.ancora_custo_base IS NOT NULL                 -- âncora elegível (comparável)
               AND b0.custo_base_escolhido < b0.ancora_custo_base   -- galão estritamente mais barato/base
             ) AS trocou
      FROM sku_base b0
    ) b
    -- [P1-d] [INTRADAY 4/4] anti-dup de oportunidade sobre o SKU FINAL (o que SERÁ gravado: âncora ou galão).
    -- Aqui já se sabe "trocou", então não bloqueia o quartinho mantido por uma oportunidade do galão não-usado.
    WHERE NOT EXISTS (
      SELECT 1
      FROM pedido_compra_item pci9
      JOIN pedido_compra_sugerido pcs9 ON pcs9.id = pci9.pedido_id
      WHERE pcs9.empresa = b.empresa
        AND pcs9.status IN ('pendente_aprovacao', 'bloqueado_guardrail')
        AND COALESCE(pcs9.tipo_ciclo, 'normal') <> 'normal'
        AND pci9.sku_codigo_omie = CASE WHEN b.trocou THEN b.sku_escolhido ELSE b.ancora_sku END
    )
  ),
  -- [GATE estoque-não-confirmado] LOG dos suprimidos ANTES de inserir o pedido — senão vira subcompra silenciosa.
  log_ins AS (
    INSERT INTO public.reposicao_estoque_nao_confirmado_log
      (run_id, empresa, sku_codigo_omie, sku_descricao, grupo_codigo, motivo, estoque_efetivo, ponto_pedido, fonte_sync)
    SELECT v_run_id, sn.empresa, sn.sku_codigo_omie, sn.sku_descricao, sn.grupo_codigo, sn.motivo,
           sn.estoque_efetivo, sn.ponto_pedido, sn.linha_fonte_sync
    FROM skus_necessitando sn
    WHERE sn.suprimido AND sn.qtde_sugerida > 0
    RETURNING 1
  ),
  pedidos_por_fornecedor_grupo AS (
    INSERT INTO pedido_compra_sugerido (
      empresa, fornecedor_nome, grupo_codigo, data_ciclo, horario_corte_planejado,
      valor_total, num_skus, status, condicao_pagamento_codigo, condicao_pagamento_descricao,
      num_parcelas, dias_parcelas, condicao_origem
    )
    SELECT sn.empresa, sn.fornecedor_nome, sn.grupo_codigo, p_data_ciclo,
           (p_data_ciclo + MAX(sn.horario_corte_pedido))::timestamptz,
           COALESCE(SUM(sn.qtde_final * sn.preco_unitario), 0), COUNT(*),   -- [PRECO-AUSENTE] valor_total é NOT NULL; item.valor_linha segue NULL (honesto)
           'pendente_aprovacao', '000', 'À Vista', 1, NULL, 'default_a_vista'
    FROM skus_necessitando sn
    WHERE sn.qtde_sugerida > 0 AND NOT sn.suprimido   -- [GATE] não gera pedido com estoque não-confirmado
    GROUP BY sn.empresa, sn.fornecedor_nome, sn.grupo_codigo
    RETURNING id, fornecedor_nome, grupo_codigo
  )
  INSERT INTO pedido_compra_item (
    pedido_id, sku_codigo_omie, sku_descricao, estoque_atual, ponto_pedido, estoque_maximo,
    qtde_sugerida, qtde_final, preco_unitario, valor_linha, primeira_compra,
    estoque_fisico, estoque_a_caminho
  )
  SELECT pfg.id, sn.sku_codigo_omie, sn.sku_descricao, sn.estoque_efetivo, sn.ponto_pedido, sn.estoque_maximo,
         sn.qtde_sugerida, sn.qtde_final, sn.preco_unitario, sn.qtde_final * sn.preco_unitario, sn.primeira_compra,
         sn.estoque_fisico, sn.estoque_a_caminho
  FROM skus_necessitando sn
  JOIN pedidos_por_fornecedor_grupo pfg
    ON pfg.fornecedor_nome = sn.fornecedor_nome AND COALESCE(pfg.grupo_codigo,'') = COALESCE(sn.grupo_codigo,'')
  WHERE sn.qtde_sugerida > 0 AND NOT sn.suprimido;   -- [GATE] espelha o filtro do pedido

  SELECT COUNT(*), COALESCE(SUM(num_skus),0), COALESCE(SUM(valor_total),0)
  INTO v_pedidos, v_skus, v_valor
  FROM pedido_compra_sugerido
  WHERE empresa = p_empresa AND data_ciclo = p_data_ciclo AND status = 'pendente_aprovacao';

  -- [FILA estoque-não-confirmado] carimba ESTE run (limpo OU com supressão) em reposicao_motor_run, p/ a fila da
  -- tela ancorar no ÚLTIMO recálculo — não no último recálculo QUE TEVE supressão. Um run limpo não grava no log de
  -- suprimidos → sem este marcador a mensagem "N fora da compra" grudava por até 24h após o sync já ter confirmado o
  -- estoque (Codex 2026-07-08: é bug de FONTE-DE-VERDADE, não de render). Aditivo, FORA dos CTEs de decisão; mesmo
  -- role/caminho do INSERT no log acima (authenticated já escreve lá, RLS INSERT WITH CHECK true) → NÃO aborta a compra.
  INSERT INTO public.reposicao_motor_run (run_id, empresa, data_ciclo, pedidos_gerados, skus_incluidos, suprimidos_n)
  VALUES (v_run_id, p_empresa, p_data_ciclo, v_pedidos, v_skus,
          (SELECT count(*) FROM public.reposicao_estoque_nao_confirmado_log WHERE run_id = v_run_id));

  RETURN QUERY SELECT v_pedidos, v_skus, v_valor, v_bloqueados;
END;
$_$;


--
-- Name: get_carteira_saude(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_carteira_saude() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  uid uuid := auth.uid();
  result jsonb;
BEGIN
  IF uid IS NULL THEN RETURN NULL; END IF;
  IF NOT (has_role(uid, 'master'::app_role) OR has_role(uid, 'employee'::app_role)) THEN
    RETURN NULL;
  END IF;

  SELECT jsonb_build_object(
    'crons', COALESCE((
      SELECT jsonb_agg(jsonb_build_object(
        'jobname', j.jobname,
        'last_status', COALESCE(r.status,
                                CASE WHEN ef.effect_at IS NOT NULL THEN 'succeeded' END),
        'last_run_at', COALESCE(r.start_time, ef.effect_at),
        'age_hours', CASE WHEN COALESCE(r.start_time, ef.effect_at) IS NULL THEN NULL
                          ELSE round(extract(epoch FROM (now() - COALESCE(r.start_time, ef.effect_at))) / 3600.0, 1) END,
        'last_error', CASE WHEN lower(coalesce(r.status, '')) IN ('failed','failure','error')
                           THEN r.return_message ELSE NULL END
      ) ORDER BY j.jobname)
      FROM cron.job j
      LEFT JOIN LATERAL (
        SELECT d.status, d.start_time, d.return_message
        FROM cron.job_run_details d
        WHERE d.jobid = j.jobid
        ORDER BY d.start_time DESC NULLS LAST
        LIMIT 1
      ) r ON true
      LEFT JOIN LATERAL (
        -- Fallback por EFEITO (só o cron mensal): o purge diário de
        -- job_run_details apaga o run mensal na maior parte do mês; o
        -- snapshot gravado é a verdade de que ele rodou.
        SELECT max(s.created_at) AS effect_at
        FROM public.carteira_positivacao_snapshot s
        WHERE j.jobname = 'carteira-positivacao-snapshot-mensal'
      ) ef ON true
      WHERE j.jobname IN (
        'carteira-rebuild-nightly',
        'scoring-recalc-batch-nightly',
        'visit-score-recalc-batch-nightly',
        'carteira-positivacao-snapshot-mensal'
      )
    ), '[]'::jsonb),
    'sync', (
      SELECT jsonb_build_object(
        'max_last_synced_at', max(last_synced_at),
        'age_hours', CASE WHEN max(last_synced_at) IS NULL THEN NULL
                          ELSE round(extract(epoch FROM (now() - max(last_synced_at))) / 3600.0, 1) END,
        'stale_count', count(*) FILTER (
          WHERE last_synced_at IS NULL OR last_synced_at < now() - interval '48 hours')
      )
      FROM public.carteira_assignments
      WHERE eligible
    ),
    'score_coverage', jsonb_build_object(
      'carteira', (SELECT count(*) FROM public.carteira_assignments WHERE eligible),
      'fcs_clientes', (
        SELECT count(*) FROM public.carteira_assignments ca
        WHERE ca.eligible
          AND EXISTS (SELECT 1 FROM public.farmer_client_scores f WHERE f.customer_user_id = ca.customer_user_id)
      ),
      'cvs_clientes', (
        SELECT count(*) FROM public.carteira_assignments ca
        WHERE ca.eligible
          AND EXISTS (SELECT 1 FROM public.customer_visit_scores c WHERE c.customer_user_id = ca.customer_user_id)
      )
    )
  ) INTO result;

  RETURN result;
END;
$$;


