--
-- Name: kb_extraction_draft_claim(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.kb_extraction_draft_claim(p_document_id uuid, p_claim_token uuid) RETURNS boolean
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_claimed uuid;
BEGIN
  INSERT INTO public.kb_extraction_drafts (document_id, status, claim_token, started_at, updated_at)
  VALUES (p_document_id, 'extracting', p_claim_token, now(), now())
  ON CONFLICT (document_id) DO UPDATE
    SET status      = 'extracting',
        claim_token = p_claim_token,
        started_at  = now(),
        last_error  = NULL,
        updated_at  = now()
    WHERE kb_extraction_drafts.status <> 'extracting'
       OR kb_extraction_drafts.started_at < now() - interval '5 minutes'
  RETURNING claim_token INTO v_claimed;
  RETURN v_claimed IS NOT DISTINCT FROM p_claim_token;
END;
$$;


--
-- Name: kb_normalizar_catalisador(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.kb_normalizar_catalisador(p text) RETURNS text
    LANGUAGE sql IMMUTABLE
    AS $$
  SELECT upper(regexp_replace(coalesce(p, ''), '[^a-zA-Z0-9]', '', 'g'));
$$;


--
-- Name: kb_specs_normalize(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.kb_specs_normalize() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  NEW.product_code_normalized :=
    btrim(regexp_replace(upper(normalize(coalesce(NEW.product_code, ''), NFKC)), '\s+', '', 'g'));
  NEW.supplier := lower(btrim(coalesce(NEW.supplier, 'sayerlack')));
  RETURN NEW;
END;
$$;


--
-- Name: kbv_block_mutation(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.kbv_block_mutation() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'DELETE' THEN
    RAISE EXCEPTION 'kb_product_spec_versions é append-only: DELETE proibido (versão %)', OLD.id;
  END IF;
  IF (to_jsonb(NEW) - 'superseded_at') IS DISTINCT FROM (to_jsonb(OLD) - 'superseded_at') THEN
    RAISE EXCEPTION 'kb_product_spec_versions é append-only: só superseded_at pode mudar (versão %)', OLD.id;
  END IF;
  IF OLD.superseded_at IS NOT NULL AND NEW.superseded_at IS NULL THEN
    RAISE EXCEPTION 'kb_product_spec_versions: não é permitido reviver versão supersedida (versão %)', OLD.id;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: leadtime_t1_e_data_de_pedido(timestamp with time zone, timestamp with time zone, timestamp with time zone, bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.leadtime_t1_e_data_de_pedido(p_hist_t1 timestamp with time zone, p_hist_t2 timestamp with time zone, p_tracking_t1 timestamp with time zone, p_omie_codigo_pedido bigint) RETURNS boolean
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
  SELECT NOT (
    -- (a) ÓRFÃ = NFe sem pedido de compra casado. NUNCA existe data de pedido: o
    --     "t1_data_pedido" do tracking dela é a data da NFe. Isto é PROVENIÊNCIA, e por
    --     isso é CATEGÓRICO — não depende das datas. Auditado: 55 órfãs têm t1 <> t2 e
    --     escapariam de um gate que só olhasse a coincidência de datas (11 delas já
    --     fechadas mentindo). Achado do Codex 2026-07-16.
    COALESCE(p_omie_codigo_pedido, 0) < 0
    -- (b) FALLBACK PROVADO da edge: ela grava `t1 = pedidoCasado?.t1_data_pedido ??
    --     nfe.t2_data_faturamento`. Quando o t1 gravado É o faturamento E existe um t1 real
    --     DIFERENTE no tracking, o fallback está provado — o item não casou pedido e a data
    --     de pedido dele é desconhecida. Recomputar faria lt_bruto == lt_logistica, ou seja,
    --     o leadtime de COMPRA confundido com o de LOGÍSTICA: mentira que SUBESTIMA e faz
    --     pedir tarde (medido: 2,2 d.u. contra 10,0 das honestas).
    OR (p_hist_t1 = p_hist_t2 AND p_hist_t1 IS DISTINCT FROM p_tracking_t1)
  );
$$;


--
-- Name: FUNCTION leadtime_t1_e_data_de_pedido(p_hist_t1 timestamp with time zone, p_hist_t2 timestamp with time zone, p_tracking_t1 timestamp with time zone, p_omie_codigo_pedido bigint); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.leadtime_t1_e_data_de_pedido(p_hist_t1 timestamp with time zone, p_hist_t2 timestamp with time zone, p_tracking_t1 timestamp with time zone, p_omie_codigo_pedido bigint) IS 'TRUE quando o t1_data_pedido gravado em sku_leadtime_history é comprovadamente uma data de PEDIDO (e não o faturamento ou a data de uma NFe órfã). Gate de honestidade do leadtime: só com TRUE o lt_bruto/lt_faturamento pode existir. Preserva o pedido legitimamente faturado no mesmo dia (t1=t2=tracking.t1 com pedido real) — recusar esse seria destruir dado bom por ausência de prova, não por prova de fabricação.';


--
-- Name: limpar_sugestoes_antigas(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.limpar_sugestoes_antigas() RETURNS TABLE(expiradas integer, deletadas integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_expiradas int;
  v_deletadas int;
BEGIN
  -- Marca como expiradas sugestões abandonadas (nova/visualizada há 90+ dias)
  UPDATE sugestao_negociacao_paralela
  SET status = 'ignorada',
      observacoes = COALESCE(observacoes || ' | ', '') || 
                    'Expirada automaticamente em ' || to_char(now(), 'DD/MM/YYYY')
  WHERE status IN ('nova', 'visualizada')
    AND data_geracao < CURRENT_DATE - interval '90 days';
  
  GET DIAGNOSTICS v_expiradas = ROW_COUNT;
  
  -- Deleta sugestões antigas em status final há mais de 365 dias (limpa o lixo)
  DELETE FROM sugestao_negociacao_paralela
  WHERE status IN ('fechada_sem_acordo', 'ignorada')
    AND data_geracao < CURRENT_DATE - interval '365 days';
  
  GET DIAGNOSTICS v_deletadas = ROW_COUNT;
  
  RETURN QUERY SELECT v_expiradas, v_deletadas;
END;
$$;


--
-- Name: FUNCTION limpar_sugestoes_antigas(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.limpar_sugestoes_antigas() IS 'Manutenção mensal: expira sugestões abandonadas há 90+ dias e deleta sugestões fechadas sem acordo/ignoradas há 365+ dias. Preserva apenas sugestões que viraram campanha (histórico útil).';


--
-- Name: list_impersonation_targets(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.list_impersonation_targets() RETURNS TABLE(user_id uuid, nome text, commercial_role text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NOT has_role(auth.uid(), 'master'::app_role) THEN
    RAISE EXCEPTION 'forbidden: master only';
  END IF;

  RETURN QUERY
  SELECT DISTINCT ON (ca.owner_user_id)
         ca.owner_user_id                                              AS user_id,
         COALESCE(p.name, p.razao_social, ca.owner_user_id::text)     AS nome,
         cr.commercial_role::text                                      AS commercial_role
    FROM public.carteira_assignments ca
    LEFT JOIN public.profiles p        ON p.user_id  = ca.owner_user_id
    LEFT JOIN public.commercial_roles cr ON cr.user_id = ca.owner_user_id
   ORDER BY ca.owner_user_id, nome;
END;
$$;


--
-- Name: listar_pedidos_a_separar(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.listar_pedidos_a_separar(p_account text) RETURNS TABLE(id uuid, customer_user_id uuid, total numeric, status text, data date, items jsonb)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NOT (has_role(auth.uid(),'employee'::app_role) OR has_role(auth.uid(),'master'::app_role)) THEN
    RAISE EXCEPTION 'forbidden: staff only';
  END IF;
  RETURN QUERY
    SELECT so.id, so.customer_user_id, so.total, so.status,
           COALESCE(so.order_date_kpi, so.created_at::date) AS data, so.items
    FROM sales_orders so
    WHERE lower(so.account) = lower(p_account)
      AND so.deleted_at IS NULL
      AND so.status NOT IN ('cancelado','rascunho','orcamento')
      AND COALESCE(so.order_date_kpi, so.created_at::date) >= current_date - 60
      AND NOT EXISTS (SELECT 1 FROM picking_tasks pt WHERE pt.sales_order_id = so.id)
    ORDER BY COALESCE(so.order_date_kpi, so.created_at::date) DESC
    LIMIT 100;
END $$;


--
-- Name: listar_skus_por_codigo_fornecedor(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.listar_skus_por_codigo_fornecedor(p_empresa text, p_codigo_fornecedor text) RETURNS TABLE(omie_codigo_produto bigint, codigo_interno text, descricao text, familia text)
    LANGUAGE sql STABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
  SELECT 
    op.omie_codigo_produto,
    op.codigo,
    op.descricao,
    op.familia
  FROM omie_products op
  WHERE LOWER(op.account) = LOWER(p_empresa)
    AND COALESCE(op.ativo, true) = true
    AND p_codigo_fornecedor IS NOT NULL
    AND TRIM(p_codigo_fornecedor) <> ''
    AND op.descricao ILIKE '%' || p_codigo_fornecedor || '%'
  ORDER BY op.descricao;
$$;


--
-- Name: FUNCTION listar_skus_por_codigo_fornecedor(p_empresa text, p_codigo_fornecedor text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.listar_skus_por_codigo_fornecedor(p_empresa text, p_codigo_fornecedor text) IS 'Retorna TODOS os produtos Omie cuja descrição contém o código do fornecedor. Usado para expansão automática de variantes de embalagem em promoções. Se retornar zero linhas, o código não foi encontrado (tratar como erro).';


--
-- Name: log_impersonation_start(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_impersonation_start(p_target uuid, p_reason text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE new_id uuid;
BEGIN
  IF NOT has_role(auth.uid(),'master'::app_role) THEN RAISE EXCEPTION 'forbidden: master only'; END IF;
  IF p_target IS NULL THEN RAISE EXCEPTION 'target required'; END IF;
  INSERT INTO public.impersonation_audit (actor_user_id, target_user_id, reason)
  VALUES (auth.uid(), p_target, p_reason)
  RETURNING id INTO new_id;
  RETURN new_id;
END; $$;


--
-- Name: mapear_status_etapa(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.mapear_status_etapa(p_status text) RETURNS text
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'public'
    AS $$
  SELECT CASE p_status
    WHEN 'pedido_recebido'    THEN '10'
    WHEN 'aguardando_coleta'  THEN '10'
    WHEN 'orcamento_enviado'  THEN '10'
    WHEN 'aprovado'           THEN '10'
    WHEN 'em_triagem'         THEN '20'
    WHEN 'em_afiacao'         THEN '20'
    WHEN 'controle_qualidade' THEN '20'
    WHEN 'pronto_entrega'     THEN '30'
    WHEN 'em_rota'            THEN '30'
    ELSE NULL  -- 'entregue' + desconhecido → mantém a OS como está
  END;
$$;


--
-- Name: marcar_alerta_notificado(bigint, boolean, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.marcar_alerta_notificado(p_alerta_id bigint, p_email_enviado boolean DEFAULT false, p_calendar_evento_id text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  UPDATE fornecedor_alerta
  SET 
    email_enviado = CASE WHEN p_email_enviado THEN true ELSE email_enviado END,
    email_enviado_em = CASE WHEN p_email_enviado THEN now() ELSE email_enviado_em END,
    calendar_evento_id = COALESCE(p_calendar_evento_id, calendar_evento_id)
  WHERE id = p_alerta_id;
  
  RETURN FOUND;
END;
$$;


--
-- Name: mark_mixgap_feedback(uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.mark_mixgap_feedback(p_customer uuid, p_familia text, p_status text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NOT (has_role(auth.uid(),'master'::app_role) OR has_role(auth.uid(),'employee'::app_role)) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  IF p_status NOT IN ('ofertado','convertido','recusado') THEN
    RAISE EXCEPTION 'invalid status';
  END IF;
  IF p_customer IS NULL OR p_familia IS NULL THEN RAISE EXCEPTION 'customer e familia required'; END IF;
  INSERT INTO public.farmer_mixgap_feedback (seller_user_id, customer_user_id, familia, status)
  VALUES (auth.uid(), p_customer, p_familia, p_status)
  ON CONFLICT (seller_user_id, customer_user_id, familia)
  DO UPDATE SET status = EXCLUDED.status, updated_at = now();
END; $$;


--
-- Name: medir_abaixo_piso_tier(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.medir_abaixo_piso_tier(p_dias integer DEFAULT 90) RETURNS TABLE(company text, tier text, itens_abaixo bigint, total_itens bigint, folga_negativa_reais numeric)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- E2/FU4: era `pode_ver_carteira_completa`. Os parênteses ao redor do COALESCE não são
  -- estilo: `scripts/authz-gate-check.ts` só reconhece como BLOQUEIO as formas
  -- `IF NOT <gate>(…)` e `IF NOT ( … <gate>(…) … )`. Escrito como
  -- `IF NOT COALESCE(<gate>(…), false)` o CI classifica como gate DECORATIVO e falha.
  IF NOT (COALESCE(private.cap_custo_ler(auth.uid()), false)) THEN
    RAISE EXCEPTION 'forbidden: medir_abaixo_piso_tier exige capability de custo' USING errcode = '42501';
  END IF;
  RETURN QUERY
  WITH itens AS (
    SELECT so.account AS company, ctp.tier, oi.unit_price, oi.quantity, oi.omie_codigo_produto, op.familia,
      (SELECT ip.cmc FROM inventory_position ip
        WHERE ip.omie_codigo_produto = oi.omie_codigo_produto AND ip.cmc > 0 AND ip.cmc <> 'NaN'::numeric
          AND ip.account = ANY(CASE so.account WHEN 'oben' THEN ARRAY['vendas','oben']
                WHEN 'colacor' THEN ARRAY['colacor_vendas','colacor'] ELSE ARRAY[so.account] END)
        ORDER BY ip.synced_at DESC NULLS LAST LIMIT 1) AS cmc
    FROM public.order_items oi JOIN public.sales_orders so ON so.id = oi.sales_order_id
    LEFT JOIN public.cliente_tier_preco ctp ON ctp.company = so.account AND ctp.customer_user_id = so.customer_user_id
    LEFT JOIN public.omie_products op ON op.omie_codigo_produto = oi.omie_codigo_produto AND op.account = so.account
    WHERE so.deleted_at IS NULL AND COALESCE(so.status, '') NOT IN ('cancelado', 'orcamento')
      AND so.omie_numero_pedido IS NOT NULL AND so.omie_numero_pedido::text <> ''
      AND so.account IN ('oben', 'colacor')
      AND COALESCE(so.order_date_kpi, (so.created_at AT TIME ZONE 'America/Sao_Paulo')::date) >= current_date - p_dias
      AND oi.unit_price > 0
  ),
  avaliado AS (
    SELECT i.company, i.tier, i.unit_price, i.quantity, i.cmc, rp.piso_markup FROM itens i
    LEFT JOIN LATERAL public.resolve_markup_policy(i.company, i.omie_codigo_produto, i.familia, i.tier) rp ON true
    WHERE i.cmc IS NOT NULL AND i.cmc > 0
  )
  SELECT a.company, a.tier,
    count(*) FILTER (WHERE a.piso_markup IS NOT NULL AND a.unit_price < a.cmc * (1 + a.piso_markup/100)) AS itens_abaixo,
    count(*) AS total_itens,
    COALESCE(SUM((a.cmc * (1 + a.piso_markup/100) - a.unit_price) * a.quantity)
             FILTER (WHERE a.piso_markup IS NOT NULL AND a.unit_price < a.cmc * (1 + a.piso_markup/100)), 0) AS folga_negativa_reais
  FROM avaliado a GROUP BY a.company, a.tier ORDER BY a.company, a.tier NULLS FIRST;
END; $$;


--
-- Name: melhoria_clientes_por_produto(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.melhoria_clientes_por_produto(p_termo text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public', 'private'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_full boolean;
  v_result jsonb;
begin
  if v_uid is null or not (has_role(v_uid,'employee'::app_role) or has_role(v_uid,'master'::app_role)) then
    raise exception 'Apenas staff pode consultar';
  end if;
  if length(trim(coalesce(p_termo,''))) < 3 then
    raise exception 'Termo de busca muito curto (mínimo 3 caracteres)';
  end if;
  v_full := pode_ver_carteira_completa(v_uid);

  with prods as (
    select id, descricao, codigo, account
    from omie_products
    where coalesce(ativo, true) = true
      and (descricao ilike '%' || trim(p_termo) || '%' or codigo ilike '%' || trim(p_termo) || '%')
    order by descricao
    limit 5
  ),
  compras as (
    select oi.customer_user_id,
           count(distinct oi.sales_order_id) as n_pedidos,
           max(coalesce(so.order_date_kpi, so.created_at::date)) as ultima_compra,
           sum(oi.quantity * oi.unit_price) as valor_12m
    from order_items oi
    join sales_orders so on so.id = oi.sales_order_id
    join prods p on p.id = oi.product_id
    where so.status not in ('cancelado','rascunho','pendente')
      and so.deleted_at is null
      and coalesce(so.order_date_kpi, so.created_at::date) >= current_date - interval '12 months'
    group by oi.customer_user_id
  ),
  visiveis as (
    select c.* from compras c
    where v_full or carteira_visivel_para(c.customer_user_id, v_uid)
  ),
  top50 as (
    select * from visiveis order by valor_12m desc limit 50
  )
  select jsonb_build_object(
    'produtos_casados', (select coalesce(jsonb_agg(jsonb_build_object(
        'descricao', descricao, 'codigo', codigo, 'account', account)), '[]'::jsonb) from prods),
    'clientes', (select coalesce(jsonb_agg(jsonb_build_object(
        'cliente', coalesce(pr.razao_social, pr.name),
        'n_pedidos', t.n_pedidos,
        'ultima_compra', t.ultima_compra,
        'valor_12m', round(t.valor_12m::numeric, 2)
      ) order by t.valor_12m desc), '[]'::jsonb)
      from top50 t join profiles pr on pr.user_id = t.customer_user_id),
    'total_clientes_visiveis', (select count(*) from visiveis),
    'escopo', case when v_full then 'todos' else 'minha_carteira' end
  ) into v_result;

  return v_result;
end $$;


