--
-- Name: omie_sync_identity_snapshot(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.omie_sync_identity_snapshot(p_account text) RETURNS jsonb
    LANGUAGE sql STABLE
    SET search_path TO ''
    BEGIN ATOMIC
 WITH doc_valid AS (
          SELECT regexp_replace(p.document, '\D'::text, ''::text, 'g'::text) AS doc,
             p.user_id
            FROM public.profiles p
           WHERE ((p.document IS NOT NULL) AND (length(regexp_replace(p.document, '\D'::text, ''::text, 'g'::text)) >= 11))
         ), doc_agg AS (
          SELECT doc_valid.doc,
             count(DISTINCT doc_valid.user_id) AS n_users,
             min((doc_valid.user_id)::text) AS user_id
            FROM doc_valid
           GROUP BY doc_valid.doc
         )
  SELECT jsonb_build_object('doc_to_user', COALESCE(( SELECT jsonb_object_agg(doc_agg.doc, doc_agg.user_id) AS jsonb_object_agg
            FROM doc_agg
           WHERE (doc_agg.n_users = 1)), '{}'::jsonb), 'ambiguous_docs', COALESCE(( SELECT jsonb_agg(doc_agg.doc ORDER BY doc_agg.doc) AS jsonb_agg
            FROM doc_agg
           WHERE (doc_agg.n_users > 1)), '[]'::jsonb), 'client_to_user', '{}'::jsonb) AS jsonb_build_object;
END;


--
-- Name: FUNCTION omie_sync_identity_snapshot(p_account text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.omie_sync_identity_snapshot(p_account text) IS 'PR-1/A1: identidade doc→user num snapshot atômico (sql STABLE). Retorna {doc_to_user, ambiguous_docs, client_to_user}. doc ambíguo (2+ users) fica FORA de doc_to_user (fail-closed). client_to_user preenchido no PR-2. Só service_role executa.';


--
-- Name: order_items_herdar_created_at_omie(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.order_items_herdar_created_at_omie() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
DECLARE
  v_pai_created_at timestamptz;
  v_pai_hash       text;
BEGIN
  SELECT created_at, hash_payload
    INTO v_pai_created_at, v_pai_hash
    FROM public.sales_orders
   WHERE id = NEW.sales_order_id;

  -- Só pedido Omie com pai conhecido: o filho nasce com a DATA DO PEDIDO (= created_at do pai =
  -- meio-dia UTC do order_date_kpi), nunca now() da carga. LIKE 'omie\_%' com escape literal (mesmo
  -- predicado do índice parcial uniq_sales_orders_omie_hash). Pai ausente/não-Omie -> NEW intacto.
  IF v_pai_hash LIKE 'omie\_%' AND v_pai_created_at IS NOT NULL THEN
    NEW.created_at := v_pai_created_at;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: FUNCTION order_items_herdar_created_at_omie(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.order_items_herdar_created_at_omie() IS 'Trigger BEFORE INSERT order_items: pedido Omie (hash omie_) herda created_at do PAI (data do pedido, nunca now() da carga). Universaliza o G6 da RPC criar_pedidos_com_itens p/ TODOS os writers (sync-reprocess, omie-analytics-sync). Money-path/recência — migration 20260624170000.';


--
-- Name: pedido_compra_split(bigint, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pedido_compra_split(p_pedido_id bigint, p_chunk_size integer DEFAULT 4) RETURNS TABLE(filho_id bigint, lote integer, total integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_status text;
  v_split_parent bigint;
  v_itens_total integer;
  v_total_chunks integer;
  v_chunk_idx integer;
  v_filho_id bigint;
BEGIN
  IF auth.uid() IS NOT NULL THEN
    IF NOT (public.has_role(auth.uid(), 'employee'::app_role) OR public.has_role(auth.uid(), 'master'::app_role)) THEN
      RAISE EXCEPTION 'Acesso negado: requer perfil staff' USING ERRCODE = '42501';
    END IF;
  END IF;

  IF p_chunk_size < 1 THEN
    RAISE EXCEPTION 'chunk_size deve ser >= 1';
  END IF;

  SELECT status, split_parent_id INTO v_status, v_split_parent
  FROM public.pedido_compra_sugerido
  WHERE id = p_pedido_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Pedido % não encontrado', p_pedido_id;
  END IF;

  IF v_status <> 'aprovado_aguardando_disparo' THEN
    RAISE EXCEPTION 'Pedido % com status=% não pode ser dividido (esperado: aprovado_aguardando_disparo)', p_pedido_id, v_status;
  END IF;

  IF v_split_parent IS NOT NULL THEN
    RAISE EXCEPTION 'Pedido % já é filho de um split (parent=%)', p_pedido_id, v_split_parent;
  END IF;

  SELECT count(*) INTO v_itens_total FROM public.pedido_compra_item WHERE pedido_id = p_pedido_id;

  IF v_itens_total <= p_chunk_size THEN
    RETURN;
  END IF;

  v_total_chunks := ceil(v_itens_total::numeric / p_chunk_size)::integer;

  FOR v_chunk_idx IN 1..v_total_chunks LOOP
    INSERT INTO public.pedido_compra_sugerido (
      empresa, fornecedor_nome, grupo_codigo, data_ciclo,
      horario_geracao, horario_corte_planejado,
      valor_total, num_skus,
      status,
      condicao_pagamento_codigo, condicao_pagamento_descricao,
      num_parcelas, dias_parcelas, condicao_origem,
      aprovado_em, aprovado_por,
      criado_em, atualizado_em,
      split_parent_id, split_lote, split_total
    )
    SELECT
      p.empresa, p.fornecedor_nome, p.grupo_codigo, p.data_ciclo,
      p.horario_geracao, p.horario_corte_planejado,
      0, 0,
      'aprovado_aguardando_disparo',
      p.condicao_pagamento_codigo, p.condicao_pagamento_descricao,
      p.num_parcelas, p.dias_parcelas, p.condicao_origem,
      p.aprovado_em, p.aprovado_por,
      now(), now(),
      p_pedido_id, v_chunk_idx, v_total_chunks
    FROM public.pedido_compra_sugerido p
    WHERE p.id = p_pedido_id
    RETURNING id INTO v_filho_id;

    WITH lote_ids AS (
      SELECT id FROM public.pedido_compra_item
      WHERE pedido_id = p_pedido_id
      ORDER BY id
      LIMIT p_chunk_size
    )
    UPDATE public.pedido_compra_item pci
    SET pedido_id = v_filho_id
    FROM lote_ids
    WHERE pci.id = lote_ids.id;

    UPDATE public.pedido_compra_sugerido f
    SET
      num_skus = (SELECT count(*) FROM public.pedido_compra_item WHERE pedido_id = f.id),
      valor_total = COALESCE(
        (SELECT sum(COALESCE(valor_linha, qtde_final * preco_unitario, 0))
         FROM public.pedido_compra_item WHERE pedido_id = f.id),
        0
      )
    WHERE f.id = v_filho_id;

    filho_id := v_filho_id;
    lote := v_chunk_idx;
    total := v_total_chunks;
    RETURN NEXT;
  END LOOP;

  UPDATE public.pedido_compra_sugerido SET
    status = 'split_em_filhos',
    status_envio_portal = 'nao_aplicavel',
    split_total = v_total_chunks,
    atualizado_em = now()
  WHERE id = p_pedido_id;
END;
$$;


--
-- Name: pedidos_programados_watchdog_claims(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pedidos_programados_watchdog_claims() RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  n integer;
BEGIN
  UPDATE public.pedidos_programados_envios
     SET status = 'erro',
         erro_motivo = '[OMIE-INCERTO] Runner morreu no meio do envio (claim ''processando'' órfão há mais de 15 min). O pedido PODE existir no Omie sem registro aqui — confira no Omie ou use "Enviar agora" (idempotente). Não cancele sem conferir.'
   WHERE status = 'processando'
     AND updated_at < now() - interval '15 minutes';
  GET DIAGNOSTICS n = ROW_COUNT;
  RETURN n;
END;
$$;


