--
-- Name: pp_bloqueia_cancel_com_claim(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.pp_bloqueia_cancel_com_claim() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.status = 'cancelado' AND OLD.status IS DISTINCT FROM 'cancelado' AND EXISTS (
    SELECT 1 FROM public.pedidos_programados_envios e
    WHERE e.pedido_programado_id = NEW.id AND e.status = 'processando'
  ) THEN
    RAISE EXCEPTION 'Pedido programado tem envio em processamento (claim ativo) — aguarde o resultado antes de cancelar.'
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: preencher_parametros_faltantes_skus(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.preencher_parametros_faltantes_skus(p_empresa text) RETURNS integer
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  atualizados int := 0;
BEGIN
  UPDATE sku_parametros sp
  SET
    demanda_media_diaria       = v.demanda_media_diaria,
    demanda_desvio_padrao      = v.demanda_sigma_diario,
    demanda_coef_variacao      = v.coef_variacao_ordem,
    demanda_dias_com_movimento = v.num_ordens,
    valor_vendido_90d          = v.valor_total_90d,
    lt_medio_dias_uteis        = v.lead_time_medio,
    lt_desvio_padrao_dias      = v.lead_time_desvio,
    lt_p95_dias                = v.lt_p95_dias,
    fonte_leadtime             = v.fonte_leadtime,
    z_score                    = v.z_aplicado,
    estoque_seguranca   = COALESCE(sp.estoque_seguranca, v.estoque_seguranca_sugerido),
    ponto_pedido        = COALESCE(sp.ponto_pedido, v.ponto_pedido_sugerido),
    estoque_minimo      = COALESCE(sp.estoque_minimo, v.estoque_minimo_sugerido),
    cobertura_alvo_dias = COALESCE(sp.cobertura_alvo_dias, v.cobertura_alvo_dias),
    estoque_maximo      = COALESCE(sp.estoque_maximo, v.estoque_maximo_sugerido),
    ultima_atualizacao_calculo = NOW()
  FROM v_sku_parametros_sugeridos v
  WHERE sp.empresa = v.empresa
    AND sp.sku_codigo_omie = v.sku_codigo_omie
    AND sp.empresa = p_empresa
    AND (sp.ponto_pedido IS NULL OR sp.estoque_maximo IS NULL);
  GET DIAGNOSTICS atualizados = ROW_COUNT;
  RETURN atualizados;
END;
$$;


--
-- Name: preserve_tipo_produto(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.preserve_tipo_produto() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.tipo_produto IS NULL AND OLD.tipo_produto IS NOT NULL THEN
    NEW.tipo_produto := OLD.tipo_produto;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: prevent_self_approval(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prevent_self_approval() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NOT NULL AND NOT (
       public.has_role(auth.uid(), 'master'::app_role)
    OR public.has_role(auth.uid(), 'employee'::app_role)
    OR EXISTS (SELECT 1 FROM public.commercial_roles WHERE user_id = auth.uid())
  ) THEN
    IF TG_OP = 'INSERT' THEN
      NEW.is_approved := false;
    ELSE
      NEW.is_approved := OLD.is_approved;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: prime_assinatura_sem_sobreposicao(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prime_assinatura_sem_sobreposicao() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM public.prime_assinaturas a
    WHERE a.customer_user_id = NEW.customer_user_id
      AND a.id <> NEW.id
      AND date_trunc('month', COALESCE(a.data_fim::timestamp, 'infinity'::timestamp))
          >= date_trunc('month', NEW.data_inicio::timestamp)
  ) THEN
    RAISE EXCEPTION 'cliente já tem assinatura cobrindo o mês de início (competência não pode duplicar no extrato)'
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END $$;


--
-- Name: prime_assinatura_update_guard(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prime_assinatura_update_guard() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.id IS DISTINCT FROM OLD.id
     OR NEW.customer_user_id IS DISTINCT FROM OLD.customer_user_id
     OR NEW.plano_id IS DISTINCT FROM OLD.plano_id
     OR NEW.preco_contratado IS DISTINCT FROM OLD.preco_contratado
     OR NEW.franquia_dentes_contratada IS DISTINCT FROM OLD.franquia_dentes_contratada
     OR NEW.created_by IS DISTINCT FROM OLD.created_by
     OR NEW.created_at IS DISTINCT FROM OLD.created_at
  THEN
    RAISE EXCEPTION 'campos contratuais da assinatura são imutáveis (grandfathering) — mudança de condição = cancelar e abrir novo ciclo'
      USING ERRCODE = 'P0001';
  END IF;
  IF EXISTS (
    SELECT 1 FROM public.prime_beneficio_uso u
    WHERE u.assinatura_id = NEW.id
      AND u.estornado_em IS NULL
      AND (u.competencia < date_trunc('month', NEW.data_inicio::timestamp)::date
           OR u.competencia > date_trunc('month', COALESCE(NEW.data_fim::timestamp, 'infinity'::timestamp))::date
           OR u.competencia > date_trunc('month', COALESCE(NEW.suspensa_em::timestamp, 'infinity'::timestamp))::date)
  ) THEN
    RAISE EXCEPTION 'a janela da assinatura deixaria uso VIVO fora do extrato — estorne os usos fora do período antes'
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END $$;


--
-- Name: prime_uso_so_estorno(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prime_uso_so_estorno() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Comparação estrutural (review final): coluna FUTURA fica protegida por construção —
  -- enumeração manual deixaria campo novo editável em silêncio.
  IF (to_jsonb(NEW) - 'estornado_em' - 'estornado_por')
     IS DISTINCT FROM (to_jsonb(OLD) - 'estornado_em' - 'estornado_por') THEN
    RAISE EXCEPTION 'registro monetário é append-only — correção é ESTORNO, nunca edição'
      USING ERRCODE = 'P0001';
  END IF;
  IF OLD.estornado_em IS NOT NULL THEN
    RAISE EXCEPTION 'registro já estornado é imutável' USING ERRCODE = 'P0001';
  END IF;
  IF NEW.estornado_em IS NULL OR NEW.estornado_por IS NULL
     OR NEW.estornado_por IS DISTINCT FROM auth.uid() THEN
    RAISE EXCEPTION 'estorno exige estornado_em e estornado_por = usuário autenticado'
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END $$;


--
-- Name: prime_uso_vigencia(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prime_uso_vigencia() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE a record;
BEGIN
  SELECT status, data_inicio, data_fim INTO a
    FROM public.prime_assinaturas WHERE id = NEW.assinatura_id;
  IF a.status IS NULL THEN
    RAISE EXCEPTION 'assinatura inexistente' USING ERRCODE = 'P0001';
  END IF;
  IF a.status <> 'ativa' THEN
    RAISE EXCEPTION 'assinatura % — uso bloqueado (suspensa/cancelada congela franquia)', a.status
      USING ERRCODE = 'P0001';
  END IF;
  IF NEW.competencia < date_trunc('month', a.data_inicio::timestamp)::date
     OR NEW.competencia > date_trunc('month', (now() AT TIME ZONE 'America/Sao_Paulo'))::date
  THEN
    RAISE EXCEPTION 'competência fora da vigência da assinatura' USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END $$;


--
-- Name: processar_alertas_pendentes_notificacao(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.processar_alertas_pendentes_notificacao(p_empresa text DEFAULT 'OBEN'::text) RETURNS TABLE(alerta_id bigint, empresa text, tipo text, severidade text, titulo text, mensagem text, email_destino text, calendar_id text, deve_criar_calendar_evento boolean, calendar_evento_titulo text, calendar_evento_data timestamp with time zone, calendar_evento_duracao_minutos integer, campanha_id bigint, aumento_id bigint, deve_enviar_email boolean, payload_json jsonb)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  WITH alertas_candidatos AS (
    SELECT 
      a.id AS alerta_id,
      a.empresa,
      a.tipo,
      a.severidade,
      a.titulo,
      a.mensagem,
      a.campanha_id,
      a.aumento_id,
      a.email_enviado,
      a.calendar_evento_id,
      pc.data_corte_pedido,
      pc.data_fim AS campanha_data_fim,
      fa.data_vigencia AS aumento_data_vigencia,
      -- Config do fornecedor (pega a primeira config ativa como fallback)
      (SELECT fep.notificar_email 
       FROM fornecedor_email_polling fep 
       WHERE fep.empresa = a.empresa 
         AND fep.fornecedor_nome = a.fornecedor_nome
         AND fep.ativo = true 
       LIMIT 1) AS email_destino,
      (SELECT fep.notificar_calendar_id 
       FROM fornecedor_email_polling fep 
       WHERE fep.empresa = a.empresa 
         AND fep.fornecedor_nome = a.fornecedor_nome
         AND fep.ativo = true 
       LIMIT 1) AS calendar_id
    FROM fornecedor_alerta a
    LEFT JOIN promocao_campanha pc ON pc.id = a.campanha_id
    LEFT JOIN fornecedor_aumento_anunciado fa ON fa.id = a.aumento_id
    WHERE a.empresa = p_empresa
      AND NOT a.resolvido
      AND (
        (a.severidade = 'urgente' AND NOT a.email_enviado) OR
        (a.tipo IN ('promocao_nova', 'aumento_anunciado') AND a.calendar_evento_id IS NULL) OR
        (a.tipo = 'promocao_suspensa' AND NOT a.email_enviado)
      )
  )
  SELECT 
    ac.alerta_id,
    ac.empresa,
    ac.tipo,
    ac.severidade,
    ac.titulo,
    ac.mensagem,
    COALESCE(ac.email_destino, 'lucascoelhosardenberg@gmail.com') AS email_destino,
    COALESCE(ac.calendar_id, 'primary') AS calendar_id,
    -- Criar evento calendar: nova promoção ou aumento cria evento agendado
    (ac.tipo IN ('promocao_nova', 'aumento_anunciado')) AS deve_criar_calendar_evento,
    -- Título do evento
    CASE ac.tipo
      WHEN 'promocao_nova' THEN 'Revisar pedidos oportunidade — ' || ac.titulo
      WHEN 'aumento_anunciado' THEN 'Antecipar compras antes de aumento — ' || ac.titulo
      ELSE ac.titulo
    END AS calendar_evento_titulo,
    -- Data do evento: dia útil anterior ao corte (promoção) ou à vigência (aumento)
    CASE ac.tipo
      WHEN 'promocao_nova' THEN (COALESCE(ac.data_corte_pedido, ac.campanha_data_fim) - INTERVAL '1 day')::timestamptz + TIME '08:00'
      WHEN 'aumento_anunciado' THEN (ac.aumento_data_vigencia - INTERVAL '1 day')::timestamptz + TIME '08:00'
      ELSE NULL
    END AS calendar_evento_data,
    120 AS calendar_evento_duracao_minutos,  -- 2 horas para revisar
    ac.campanha_id,
    ac.aumento_id,
    -- Enviar email: urgente sempre, novas sempre, suspensões sempre
    (ac.severidade = 'urgente' OR ac.tipo IN ('promocao_nova', 'aumento_anunciado', 'promocao_suspensa')) 
      AS deve_enviar_email,
    -- Payload completo para debug/auditoria
    jsonb_build_object(
      'alerta_id', ac.alerta_id,
      'tipo', ac.tipo,
      'severidade', ac.severidade,
      'titulo', ac.titulo,
      'mensagem', ac.mensagem,
      'campanha_id', ac.campanha_id,
      'aumento_id', ac.aumento_id
    ) AS payload_json
  FROM alertas_candidatos ac;
END;
$$;


--
-- Name: FUNCTION processar_alertas_pendentes_notificacao(p_empresa text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.processar_alertas_pendentes_notificacao(p_empresa text) IS 'Retorna alertas pendentes de notificação com payload pronto. A edge function de notificação itera sobre o resultado, chama Resend (email) e MCP Calendar para cada linha, e depois marca cada alerta como notificado via marcar_alerta_notificado.';


--
-- Name: promover_candidato_primeira_compra(text, bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.promover_candidato_primeira_compra(p_empresa text, p_sku bigint) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_atualizados int := 0;
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.user_roles
    WHERE user_id = auth.uid() AND role IN ('master', 'employee')
  ) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;

  UPDATE public.sku_parametros sp
  SET
    demanda_media_diaria       = c.demanda_media_diaria,
    demanda_desvio_padrao      = c.demanda_sigma_diario,
    demanda_coef_variacao      = c.coef_variacao_ordem,
    demanda_dias_com_movimento = c.dias_com_movimento,
    valor_vendido_90d          = c.valor_total_90d,
    lt_medio_dias_uteis        = c.lead_time_medio,
    lt_desvio_padrao_dias      = c.lead_time_desvio,
    lt_p95_dias                = c.lt_p95_dias,
    fonte_leadtime             = c.fonte_leadtime,
    z_score                    = c.z_aplicado,
    estoque_seguranca          = 0,
    ponto_pedido               = c.primeira_compra_ponto_pedido,
    estoque_maximo             = c.primeira_compra_estoque_maximo,
    cobertura_alvo_dias        = c.primeira_compra_cap_dias,
    habilitado_reposicao_automatica = TRUE,
    tipo_reposicao             = 'automatica',
    aprovado_em                = now(),
    aprovado_por               = COALESCE((SELECT email FROM public.profiles WHERE user_id = auth.uid()),
                                          'primeira_compra:' || COALESCE(auth.uid()::text, 'sistema')),
    justificativa_aprovacao    = 'Primeira compra (cold-start): qtde-teste capada, promovida pra reposição',
    ultima_atualizacao_calculo = now()
  FROM public.v_sku_candidatos_primeira_compra c
  WHERE sp.empresa = c.empresa
    AND sp.sku_codigo_omie = c.sku_codigo_omie
    AND sp.empresa = p_empresa
    AND sp.sku_codigo_omie = p_sku
    AND sp.ponto_pedido IS NULL
    AND sp.estoque_maximo IS NULL;

  GET DIAGNOSTICS v_atualizados = ROW_COUNT;
  RETURN v_atualizados;
END;
$$;


--
-- Name: propagar_habilitacao_fornecedor(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.propagar_habilitacao_fornecedor() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Se fornecedor foi habilitado (ou já era habilitado), marca todos os SKUs com parâmetros
  IF NEW.habilitado = TRUE AND (OLD.habilitado IS NULL OR OLD.habilitado = FALSE) THEN
    UPDATE sku_parametros sp
    SET 
      habilitado_reposicao_automatica = TRUE,
      aprovado_em = COALESCE(aprovado_em, NOW()),
      aprovado_por = COALESCE(aprovado_por, 'trigger_habilitacao_fornecedor')
    WHERE sp.empresa = NEW.empresa
      AND sp.fornecedor_nome = NEW.fornecedor_nome
      AND sp.estoque_maximo IS NOT NULL
      AND sp.habilitado_reposicao_automatica = FALSE;
  END IF;
  
  -- Se fornecedor foi DESABILITADO, tira a flag automática dos SKUs
  IF NEW.habilitado = FALSE AND OLD.habilitado = TRUE THEN
    UPDATE sku_parametros sp
    SET habilitado_reposicao_automatica = FALSE
    WHERE sp.empresa = NEW.empresa
      AND sp.fornecedor_nome = NEW.fornecedor_nome
      AND sp.habilitado_reposicao_automatica = TRUE;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: protect_master_config(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_master_config() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Se a key sendo alterada é sensível (master_cpf/master_cnpj),
  -- exigir que quem está alterando seja super_admin.
  IF (TG_OP IN ('UPDATE', 'DELETE'))
     AND (OLD.key IN ('master_cpf', 'master_cnpj'))
     AND NOT private.is_super_admin(auth.uid())
  THEN
    RAISE EXCEPTION 'Somente super admin pode alterar master_cpf ou master_cnpj';
  END IF;

  -- Também bloqueia INSERT de uma key 'master_cpf' ou 'master_cnpj' se ela
  -- já existe (evita contornar com DELETE + INSERT separados).
  IF TG_OP = 'INSERT'
     AND NEW.key IN ('master_cpf', 'master_cnpj')
     AND EXISTS (SELECT 1 FROM public.company_config WHERE key = NEW.key)
     AND NOT private.is_super_admin(auth.uid())
  THEN
    RAISE EXCEPTION 'Somente super admin pode redefinir master_cpf ou master_cnpj';
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: proxima_janela_operacional(text, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.proxima_janela_operacional(p_empresa text, p_fornecedor text, p_a_partir timestamp with time zone DEFAULT now()) RETURNS timestamp with time zone
    LANGUAGE plpgsql STABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_check_data DATE := (p_a_partir AT TIME ZONE 'America/Sao_Paulo')::date;
  v_dia_semana INT;
  v_calendario RECORD;
  v_eh_feriado BOOLEAN;
  v_max_iter INT := 14;
BEGIN
  WHILE v_max_iter > 0 LOOP
    v_max_iter := v_max_iter - 1;
    v_dia_semana := EXTRACT(DOW FROM v_check_data);
    
    SELECT EXISTS (SELECT 1 FROM calendario_feriados WHERE data = v_check_data) 
    INTO v_eh_feriado;
    
    IF NOT v_eh_feriado THEN
      SELECT * INTO v_calendario
      FROM fornecedor_calendario_operacao
      WHERE empresa = p_empresa 
        AND fornecedor_nome = p_fornecedor
        AND dia_semana = v_dia_semana
        AND hora_abertura IS NOT NULL;
      
      IF FOUND THEN
        -- Tem janela nesse dia. Se ainda dá tempo hoje, retorna agora.
        IF v_check_data = (p_a_partir AT TIME ZONE 'America/Sao_Paulo')::date 
           AND (p_a_partir AT TIME ZONE 'America/Sao_Paulo')::time < v_calendario.hora_fechamento THEN
          RETURN p_a_partir;
        END IF;
        -- Senão, retorna abertura do próximo dia operacional
        RETURN (v_check_data + 1 + (v_calendario.hora_abertura)::interval) 
               AT TIME ZONE 'America/Sao_Paulo';
      END IF;
    END IF;
    
    v_check_data := v_check_data + 1;
  END LOOP;
  
  RETURN NULL;  -- 14 dias sem janela = inconsistência
END;
$$;


--
-- Name: push_sla_tick(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.push_sla_tick() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_limiar int;
  v_agora_sp timestamp;
  v_ini time;
  v_fim time;
  v_dias int[];
  r record;
BEGIN
  SELECT
    COALESCE((SELECT value::int  FROM public.company_config WHERE key='whatsapp_sla_atrasado_min'), 30),
    COALESCE((SELECT value::time FROM public.company_config WHERE key='whatsapp_sla_hora_inicio'), '07:30'),
    COALESCE((SELECT value::time FROM public.company_config WHERE key='whatsapp_sla_hora_fim'),    '17:30'),
    COALESCE((SELECT string_to_array(value, ',')::int[] FROM public.company_config WHERE key='whatsapp_sla_dias'),
             ARRAY[1,2,3,4,5])
    INTO v_limiar, v_ini, v_fim, v_dias;

  v_agora_sp := now() AT TIME ZONE 'America/Sao_Paulo';
  IF NOT (EXTRACT(isodow FROM v_agora_sp)::int = ANY(v_dias)
          AND v_agora_sp::time >= v_ini AND v_agora_sp::time < v_fim) THEN
    RETURN;
  END IF;

  FOR r IN
    SELECT s.owner_user_id,
           count(*) AS qtd,
           string_agg(COALESCE(NULLIF(trim(s.contact_name), ''), s.phone_e164), ', '
                      ORDER BY s.minutos_uteis_aguardando DESC) AS nomes
    FROM public.v_whatsapp_sla s
    WHERE s.nivel = 'vermelho'
      AND s.owner_user_id IS NOT NULL
      AND s.minutos_uteis_aguardando >= v_limiar
      AND s.minutos_uteis_aguardando <  v_limiar + 20
    GROUP BY s.owner_user_id
  LOOP
    BEGIN
      PERFORM public._push_enviar(
        ARRAY[r.owner_user_id],
        'Cliente aguardando resposta',
        CASE WHEN r.qtd = 1
          THEN left(r.nomes, 160) || ' está sem resposta há ' || v_limiar || '+ min'
          ELSE r.qtd || ' clientes sem resposta há ' || v_limiar || '+ min: ' || left(r.nomes, 140)
        END,
        '/whatsapp',
        'sla'
      );
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING '[push] falha no push de SLA pra dona %: %', r.owner_user_id, SQLERRM;
    END;
  END LOOP;
END;
$$;


--
-- Name: push_tarefa_nova(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.push_tarefa_nova() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_cliente text;
BEGIN
  IF NEW.assigned_to = NEW.created_by THEN
    RETURN NEW;
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.tarefas t
    WHERE t.assigned_to = NEW.assigned_to
      AND t.id <> NEW.id
      AND t.created_at > now() - interval '2 minutes'
  ) THEN
    RETURN NEW;
  END IF;

  SELECT COALESCE(NULLIF(trim(p.razao_social), ''), p.name)
    INTO v_cliente
  FROM public.profiles p
  WHERE p.user_id = NEW.customer_user_id
  LIMIT 1;

  PERFORM public._push_enviar(
    ARRAY[NEW.assigned_to],
    'Nova tarefa pra você',
    initcap(NEW.categoria) || COALESCE(' — ' || v_cliente, ''),
    '/meu-dia',
    'tarefa-' || NEW.id::text
  );
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING '[push] falha no push de tarefa nova (%): %', NEW.id, SQLERRM;
  RETURN NEW;
END;
$$;


--
-- Name: push_whatsapp_inbound(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.push_whatsapp_inbound() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_conv record;
  v_dona uuid;
  v_nome text;
BEGIN
  IF public.wa_is_stop_keyword(NEW.body) THEN
    RETURN NEW;
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.whatsapp_messages m
    WHERE m.conversation_id = NEW.conversation_id
      AND m.direction = 'in'
      AND m.id <> NEW.id
      AND m.created_at > now() - interval '10 minutes'
  ) THEN
    RETURN NEW;
  END IF;

  SELECT c.customer_user_id, c.contact_name, c.phone_e164
    INTO v_conv
  FROM public.whatsapp_conversations c
  WHERE c.id = NEW.conversation_id;

  IF v_conv IS NULL OR v_conv.customer_user_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_dona := public.wa_owner_efetivo(v_conv.customer_user_id);
  IF v_dona IS NULL THEN
    RETURN NEW;
  END IF;

  v_nome := COALESCE(NULLIF(trim(v_conv.contact_name), ''), v_conv.phone_e164, 'Cliente');

  PERFORM public._push_enviar(
    ARRAY[v_dona],
    'Nova mensagem no WhatsApp',
    v_nome || ' respondeu — toque para abrir a conversa',
    '/whatsapp',
    'wa-' || NEW.conversation_id::text
  );
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING '[push] falha no push de whatsapp inbound (msg %): %', NEW.id, SQLERRM;
  RETURN NEW;
END;
$$;


--
-- Name: radar_atribuir_tarefa(text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.radar_atribuir_tarefa(p_cnpj text, p_dias_retomada integer DEFAULT 7) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_uid uuid := (SELECT auth.uid());
  v_razao text; v_fantasia text; v_municipio text; v_uf text; v_tel text;
  v_existing uuid; v_id uuid; v_desc text;
  v_dias integer := GREATEST(1, LEAST(COALESCE(p_dias_retomada, 7), 90));
BEGIN
  IF NOT COALESCE(public.pode_ver_carteira_completa(v_uid), false) THEN
    RAISE EXCEPTION 'forbidden: gestor/master only';
  END IF;
  IF p_cnpj IS NULL OR p_cnpj !~ '^[0-9]{14}$' THEN RAISE EXCEPTION 'cnpj inválido'; END IF;

  SELECT razao_social, nome_fantasia, municipio_nome, uf, telefone1
    INTO v_razao, v_fantasia, v_municipio, v_uf, v_tel
    FROM public.radar_empresas WHERE cnpj = p_cnpj;
  IF NOT FOUND THEN RAISE EXCEPTION 'empresa não encontrada: %', p_cnpj; END IF;

  PERFORM pg_advisory_xact_lock(hashtextextended(v_uid::text||':'||p_cnpj||':tarefa:radar', 0));
  SELECT id INTO v_existing FROM public.tarefas
   WHERE created_by = v_uid AND empresa = 'oben' AND customer_user_id IS NULL
     AND status = 'aberta' AND descricao LIKE '%CNPJ '||p_cnpj||'%'
     AND created_at > now() - interval '2 minutes'
   ORDER BY created_at DESC LIMIT 1;
  IF v_existing IS NOT NULL THEN
    RETURN jsonb_build_object('id', v_existing, 'deduped', true);
  END IF;

  v_desc := 'Prospecção: ' || COALESCE(NULLIF(v_fantasia,''), NULLIF(v_razao,''), p_cnpj)
            || ' · ' || COALESCE(v_municipio,'?') || '/' || COALESCE(v_uf,'?')
            || COALESCE(' · tel ' || NULLIF(v_tel,''), '')
            || ' · CNPJ ' || p_cnpj;

  INSERT INTO public.tarefas (
    descricao, categoria, customer_user_id, assigned_to, created_by, empresa,
    modo, due_date, interacao_tipo, auto_satisfy_mode, status
  ) VALUES (
    v_desc, 'ligar', NULL, v_uid, v_uid, 'oben',
    'data', (current_date + v_dias), NULL, 'off', 'aberta'
  ) RETURNING id INTO v_id;

  RETURN jsonb_build_object('id', v_id, 'deduped', false);
END $_$;


--
-- Name: radar_contagem_por_municipio(text, text, text, text, boolean, date, date, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.radar_contagem_por_municipio(p_uf text DEFAULT NULL::text, p_cnae_prefix text DEFAULT NULL::text, p_cnae_exato text DEFAULT NULL::text, p_status text DEFAULT NULL::text, p_incluir_ja_clientes boolean DEFAULT false, p_data_abertura_min date DEFAULT NULL::date, p_data_abertura_max date DEFAULT NULL::date, p_limit integer DEFAULT 500) RETURNS TABLE(municipio_codigo text, municipio_nome text, uf text, lat double precision, lng double precision, total bigint, com_telefone bigint, a_contatar bigint)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
BEGIN
  IF NOT COALESCE(public.pode_ver_carteira_completa((SELECT auth.uid())), false) THEN
    RAISE EXCEPTION 'forbidden: gestor/master only';
  END IF;
  IF p_cnae_prefix IS NOT NULL AND p_cnae_prefix !~ '^[0-9]{1,7}$' THEN RAISE EXCEPTION 'cnae_prefix inválido'; END IF;
  IF p_cnae_exato  IS NOT NULL AND p_cnae_exato  !~ '^[0-9]{7}$'   THEN RAISE EXCEPTION 'cnae_exato inválido';  END IF;

  -- FAST PATH: caso DEFAULT (todos os params no default) — o caso quente.
  -- Predicados literais → casa o índice parcial covering → index-only scan.
  IF p_uf IS NULL AND p_cnae_prefix IS NULL AND p_cnae_exato IS NULL
     AND p_status IS NULL AND p_incluir_ja_clientes = false
     AND p_data_abertura_min IS NULL AND p_data_abertura_max IS NULL THEN
    RETURN QUERY
    WITH agg AS MATERIALIZED (
      SELECT re.municipio_codigo AS mc, re.uf AS u, re.municipio_nome AS mn,
             count(*)::bigint AS t,
             count(*) FILTER (WHERE re.telefone1 IS NOT NULL OR re.telefone2 IS NOT NULL)::bigint AS ct,
             count(*) FILTER (WHERE re.prospeccao_status = 'a_contatar')::bigint AS ac
        FROM public.radar_empresas re
       WHERE re.ja_cliente = false AND re.prospeccao_status <> 'descartado'
       GROUP BY re.municipio_codigo, re.uf, re.municipio_nome
    )
    SELECT a.mc, COALESCE(m.nome, a.mn), a.u, m.lat, m.lng,
           sum(a.t)::bigint, sum(a.ct)::bigint, sum(a.ac)::bigint
      FROM agg a
      LEFT JOIN public.radar_municipios m ON m.codigo = a.mc
     GROUP BY a.mc, COALESCE(m.nome, a.mn), a.u, m.lat, m.lng
     ORDER BY sum(a.t) DESC, a.mc
     LIMIT GREATEST(1, LEAST(COALESCE(p_limit, 500), 2000));
    RETURN;
  END IF;

  -- SLOW PATH: com filtros (subset menor, já aceitável) — VERBATIM do original.
  RETURN QUERY
  SELECT re.municipio_codigo,
         COALESCE(m.nome, re.municipio_nome) AS municipio_nome,
         re.uf,
         m.lat, m.lng,
         count(*)::bigint AS total,
         count(*) FILTER (WHERE re.telefone1 IS NOT NULL OR re.telefone2 IS NOT NULL)::bigint AS com_telefone,
         count(*) FILTER (WHERE re.prospeccao_status = 'a_contatar')::bigint AS a_contatar
    FROM public.radar_empresas re
    LEFT JOIN public.radar_municipios m ON m.codigo = re.municipio_codigo
   WHERE (p_uf IS NULL OR re.uf = p_uf)
     AND (p_cnae_exato  IS NULL OR re.cnae_principal = p_cnae_exato)
     AND (p_cnae_prefix IS NULL OR re.cnae_principal LIKE p_cnae_prefix || '%')
     AND ((p_status IS NOT NULL AND re.prospeccao_status = p_status)
          OR (p_status IS NULL AND re.prospeccao_status <> 'descartado'))
     AND (p_incluir_ja_clientes OR re.ja_cliente = false)
     AND (p_data_abertura_min IS NULL OR re.data_abertura >= p_data_abertura_min)
     AND (p_data_abertura_max IS NULL OR re.data_abertura <= p_data_abertura_max)
   GROUP BY re.municipio_codigo, COALESCE(m.nome, re.municipio_nome), re.uf, m.lat, m.lng
   ORDER BY total DESC
   LIMIT GREATEST(1, LEAST(COALESCE(p_limit, 500), 2000));
END $_$;


--
-- Name: radar_kpis(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.radar_kpis() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_lote text;
  v_novos integer;
  v_a_contatar integer;
  v_em_conversa integer;
  v_virou_mes integer;
BEGIN
  IF NOT COALESCE(public.pode_ver_carteira_completa(v_uid), false) THEN
    RAISE EXCEPTION 'forbidden: gestor/master only';
  END IF;

  SELECT mes_referencia, COALESCE(novos, 0) INTO v_lote, v_novos
    FROM public.radar_ingest_state
   WHERE status = 'complete'
   ORDER BY mes_referencia DESC LIMIT 1;

  SELECT count(*) INTO v_a_contatar FROM public.radar_empresas
   WHERE prospeccao_status = 'a_contatar' AND ja_cliente = false
     AND (v_lote IS NULL OR ultimo_lote = v_lote);
  SELECT count(*) INTO v_em_conversa FROM public.radar_empresas
   WHERE prospeccao_status = 'em_conversa';
  SELECT count(*) INTO v_virou_mes FROM public.radar_empresas
   WHERE prospeccao_status = 'virou_cliente'
     AND prospeccao_atualizado_em >= date_trunc('month', now());

  RETURN jsonb_build_object(
    'lote', v_lote, 'novos', COALESCE(v_novos, 0),
    'a_contatar', v_a_contatar, 'em_conversa', v_em_conversa,
    'virou_cliente_mes', v_virou_mes);
END $$;


--
-- Name: radar_prospects_para_rota(text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.radar_prospects_para_rota(p_municipio_codigo text, p_limit integer DEFAULT 30) RETURNS TABLE(cnpj text, razao_social text, nome_fantasia text, logradouro text, numero text, complemento text, bairro text, municipio_nome text, uf text, cep text, telefone1 text, telefone2 text, prospeccao_status text, lat double precision, lng double precision, geocode_status text, "precision" text)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NOT COALESCE(public.pode_ver_carteira_completa((SELECT auth.uid())), false) THEN
    RAISE EXCEPTION 'forbidden: gestor/master only';
  END IF;
  IF p_municipio_codigo IS NULL OR btrim(p_municipio_codigo) = '' THEN
    RAISE EXCEPTION 'municipio_codigo obrigatório';
  END IF;

  RETURN QUERY
  SELECT re.cnpj, re.razao_social, re.nome_fantasia,
         re.logradouro, re.numero, re.complemento, re.bairro,
         re.municipio_nome, re.uf, re.cep,
         re.telefone1, re.telefone2,
         re.prospeccao_status,
         COALESCE(cg.lat, re.lat, mg.lat),
         COALESCE(cg.lng, re.lng, mg.lng),
         re.geocode_status,
         CASE WHEN cg.cep IS NOT NULL THEN cg.precision
              WHEN re.lat IS NOT NULL THEN 'street'
              WHEN mg.lat IS NOT NULL THEN 'city_centroid' END
    FROM public.radar_empresas re
    LEFT JOIN cep_geo cg ON cg.cep = public.normalizar_cep(re.cep)
    LEFT JOIN municipio_geo mg ON mg.municipio_codigo = re.municipio_codigo
   WHERE re.municipio_codigo = p_municipio_codigo
     AND re.ja_cliente = false
     AND re.prospeccao_status IN ('a_contatar','contatado_sem_resposta','em_conversa')
   ORDER BY (re.prospeccao_status = 'a_contatar') DESC,
            re.data_abertura DESC NULLS LAST,
            re.cnpj
   LIMIT GREATEST(1, LEAST(COALESCE(p_limit, 30), 2000));
END $$;


--
-- Name: radar_recruzar_ja_cliente(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.radar_recruzar_ja_cliente() RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_marcados integer;
BEGIN
  DROP TABLE IF EXISTS tmp_docs_clientes;
  CREATE TEMP TABLE tmp_docs_clientes ON COMMIT DROP AS
    SELECT DISTINCT regexp_replace(document, '[^0-9]', '', 'g') AS doc
    FROM public.profiles
    WHERE document IS NOT NULL
      AND length(regexp_replace(document, '[^0-9]', '', 'g')) = 14
    UNION
    SELECT DISTINCT regexp_replace(cnpj_cpf, '[^0-9]', '', 'g') AS doc
    FROM public.omie_clientes_nao_vinculados
    WHERE cnpj_cpf IS NOT NULL
      AND length(regexp_replace(cnpj_cpf, '[^0-9]', '', 'g')) = 14;

  UPDATE public.radar_empresas re
  SET ja_cliente = true, updated_at = now()
  WHERE re.ja_cliente = false
    AND EXISTS (SELECT 1 FROM tmp_docs_clientes d WHERE d.doc = re.cnpj);

  GET DIAGNOSTICS v_marcados = ROW_COUNT;
  RETURN v_marcados;
END;
$$;


--
-- Name: radar_registrar_cadastro_omie(text, text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.radar_registrar_cadastro_omie(p_cnpj text, p_codigo_cliente text, p_ja_existia boolean DEFAULT false) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_uid uuid := (SELECT auth.uid());
  v_status_atual text;
BEGIN
  IF NOT COALESCE(public.pode_ver_carteira_completa(v_uid), false) THEN
    RAISE EXCEPTION 'forbidden: gestor/master only';
  END IF;
  IF p_cnpj IS NULL OR p_cnpj !~ '^[0-9]{14}$' THEN RAISE EXCEPTION 'cnpj inválido'; END IF;

  SELECT prospeccao_status INTO v_status_atual
    FROM public.radar_empresas WHERE cnpj = p_cnpj FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'empresa não encontrada: %', p_cnpj; END IF;

  UPDATE public.radar_empresas SET
    omie_codigo_cliente = COALESCE(NULLIF(p_codigo_cliente,''), omie_codigo_cliente),
    omie_cadastrado_em = now(),
    prospeccao_status = 'virou_cliente',
    prospeccao_atualizado_em = now(),
    ja_cliente = true,
    updated_at = now()
  WHERE cnpj = p_cnpj;

  INSERT INTO public.radar_contatos (cnpj, acao, nota, criado_por, status_anterior)
  VALUES (p_cnpj, 'virou_cliente',
    CASE WHEN p_ja_existia
      THEN 'Já cadastrado no Omie/Oben (cód. ' || COALESCE(NULLIF(p_codigo_cliente,''),'?') || ')'
      ELSE 'Cadastrado no Omie/Oben (cód. ' || COALESCE(NULLIF(p_codigo_cliente,''),'?') || ')' END,
    v_uid, v_status_atual);

  RETURN jsonb_build_object('ok', true);
END $_$;


--
-- Name: radar_salvar_geocode(text, double precision, double precision, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.radar_salvar_geocode(p_cnpj text, p_lat double precision DEFAULT NULL::double precision, p_lng double precision DEFAULT NULL::double precision, p_status text DEFAULT 'ok'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_uid uuid := (SELECT auth.uid());
BEGIN
  IF NOT COALESCE(public.pode_ver_carteira_completa(v_uid), false) THEN
    RAISE EXCEPTION 'forbidden: gestor/master only';
  END IF;
  IF p_cnpj IS NULL OR p_cnpj !~ '^[0-9]{14}$' THEN RAISE EXCEPTION 'cnpj inválido'; END IF;
  IF p_status IS NULL OR p_status NOT IN ('ok','falhou') THEN RAISE EXCEPTION 'status inválido'; END IF;
  IF p_status = 'ok' THEN
    IF p_lat IS NULL OR p_lng IS NULL
       OR p_lat < -90 OR p_lat > 90 OR p_lng < -180 OR p_lng > 180 THEN
      RAISE EXCEPTION 'lat/lng inválidos para status ok';
    END IF;
  END IF;
  UPDATE public.radar_empresas SET
    lat            = CASE WHEN p_status = 'ok' THEN p_lat ELSE NULL END,
    lng            = CASE WHEN p_status = 'ok' THEN p_lng ELSE NULL END,
    geocoded_em    = now(),
    geocode_status = p_status,
    updated_at     = now()
  WHERE cnpj = p_cnpj;
  IF NOT FOUND THEN RAISE EXCEPTION 'empresa não encontrada: %', p_cnpj; END IF;
  RETURN jsonb_build_object('ok', true, 'status', p_status);
END $_$;


--
-- Name: rank_precisao(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rank_precisao(p text) RETURNS integer
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'public'
    AS $$
  SELECT CASE p
    WHEN 'rooftop'           THEN 4
    WHEN 'street'            THEN 3
    WHEN 'postcode_centroid' THEN 2
    WHEN 'city_centroid'     THEN 1
    ELSE 0 END
$$;


--
-- Name: recalcular_picking_task(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.recalcular_picking_task(p_task_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE v_uid uuid := auth.uid(); v_total numeric; v_done numeric; v_status text;
BEGIN
  IF NOT (has_role(v_uid,'employee'::app_role) OR has_role(v_uid,'master'::app_role)) THEN
    RAISE EXCEPTION 'forbidden: staff only';
  END IF;
  PERFORM pg_advisory_xact_lock(hashtextextended('picking_task:'||p_task_id::text, 0));
  SELECT COALESCE(sum(quantidade),0), COALESCE(sum(quantidade_separada),0)
    INTO v_total, v_done FROM picking_task_items WHERE picking_task_id = p_task_id;
  IF v_done <= 0 THEN v_status := 'pendente';
  ELSIF v_total > 0 AND v_done >= v_total THEN v_status := 'concluido';
  ELSE v_status := 'em_andamento'; END IF;
  UPDATE picking_tasks SET status = v_status,
    started_at = COALESCE(started_at, CASE WHEN v_status <> 'pendente' THEN now() END),
    completed_at = CASE WHEN v_status = 'concluido' THEN COALESCE(completed_at, now()) ELSE NULL END
  WHERE id = p_task_id;
  RETURN jsonb_build_object('status', v_status);
END $$;


--
-- Name: recomputar_leadtime_derivado(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.recomputar_leadtime_derivado(p_empresa text) RETURNS TABLE(etapa text, valor bigint)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_recomputadas bigint := 0;
  v_anuladas     bigint := 0;
  v_sem_t4       bigint := 0;
  v_datas_ruins  bigint := 0;
BEGIN
  -- Fail-closed: empresa vazia varreria a tabela inteira das duas empresas.
  IF p_empresa IS NULL OR btrim(p_empresa) = '' THEN
    RAISE EXCEPTION 'recomputar_leadtime_derivado: p_empresa é obrigatório'
      USING ERRCODE = '22023';
  END IF;

  -- ── (1) ANULA o derivado cujo t1 não é data de pedido ──────────────────────
  -- lt_bruto e lt_faturamento derivam de t1 ⇒ com t1 fabricado, ambos são mentira.
  -- lt_logistica NÃO é tocado: ele deriva de t2 e t4, que são reais mesmo na órfã. Anular
  -- o que ainda é verdade seria destruir dado bom.
  UPDATE public.sku_leadtime_history s
  SET lt_bruto_dias_uteis       = NULL,
      lt_faturamento_dias_uteis = NULL
  FROM public.purchase_orders_tracking p
  WHERE p.id = s.tracking_id
    AND s.empresa::text = p_empresa
    AND NOT public.leadtime_t1_e_data_de_pedido(
          s.t1_data_pedido, s.t2_data_faturamento, p.t1_data_pedido, p.omie_codigo_pedido)
    -- Idempotência: sem isto, a 2ª rodada reescreveria NULL sobre NULL todo dia (bloat +
    -- trigger de updated_at à toa).
    AND (s.lt_bruto_dias_uteis IS NOT NULL OR s.lt_faturamento_dias_uteis IS NOT NULL);
  GET DIAGNOSTICS v_anuladas = ROW_COUNT;

  -- ── (2) RECOMPUTA o derivado das linhas cujo t1 é confiável ────────────────
  -- Convergente por DIVERGÊNCIA, não por `lt_bruto IS NULL`. Motivo (achado do Codex): com
  -- `IS NULL`, uma correção posterior de t1/t2/t4 na fonte NUNCA se propaga — a linha já
  -- tem valor, some da fila e CONGELA o erro. Auditado: 4 linhas do backfill têm t2 ANTES
  -- de t1 e lt_bruto = 0 gravado (o backfill castava ::date antes de comparar; a edge em TS
  -- compara os timestamps e devolveria NULL) — só o IS DISTINCT FROM as alcança.
  --
  -- t4 vem do TRACKING (a fonte), não da linha: é o dado que chega tarde e destrava tudo.
  -- Onde as datas são inconsistentes (t4 < t1), dias_uteis_entre já devolve NULL sozinha —
  -- degradação honesta sem predicado extra. Ausente ≠ zero.
  UPDATE public.sku_leadtime_history s
  SET t4_data_recebimento       = p.t4_data_recebimento,
      lt_bruto_dias_uteis       = public.dias_uteis_entre(s.t1_data_pedido, p.t4_data_recebimento),
      lt_faturamento_dias_uteis = public.dias_uteis_entre(s.t1_data_pedido, s.t2_data_faturamento),
      lt_logistica_dias_uteis   = public.dias_uteis_entre(s.t2_data_faturamento, p.t4_data_recebimento)
  FROM public.purchase_orders_tracking p
  WHERE p.id = s.tracking_id
    AND s.empresa::text = p_empresa
    AND public.leadtime_t1_e_data_de_pedido(
          s.t1_data_pedido, s.t2_data_faturamento, p.t1_data_pedido, p.omie_codigo_pedido)
    AND (
          s.t4_data_recebimento       IS DISTINCT FROM p.t4_data_recebimento
       OR s.lt_bruto_dias_uteis       IS DISTINCT FROM public.dias_uteis_entre(s.t1_data_pedido, p.t4_data_recebimento)
       OR s.lt_faturamento_dias_uteis IS DISTINCT FROM public.dias_uteis_entre(s.t1_data_pedido, s.t2_data_faturamento)
       OR s.lt_logistica_dias_uteis   IS DISTINCT FROM public.dias_uteis_entre(s.t2_data_faturamento, p.t4_data_recebimento)
    );
  GET DIAGNOSTICS v_recomputadas = ROW_COUNT;

  -- ── (3) O que sobrou NULL, e por quê (observabilidade: NULL é decisão, não bug) ──
  SELECT
    count(*) FILTER (WHERE p.t4_data_recebimento IS NULL),
    count(*) FILTER (WHERE p.t4_data_recebimento IS NOT NULL
                       AND p.t4_data_recebimento < s.t1_data_pedido)
  INTO v_sem_t4, v_datas_ruins
  FROM public.sku_leadtime_history s
  JOIN public.purchase_orders_tracking p ON p.id = s.tracking_id
  WHERE s.empresa::text = p_empresa
    AND s.lt_bruto_dias_uteis IS NULL
    AND public.leadtime_t1_e_data_de_pedido(
          s.t1_data_pedido, s.t2_data_faturamento, p.t1_data_pedido, p.omie_codigo_pedido);

  etapa := 'leadtime_recomputado';        valor := v_recomputadas; RETURN NEXT;
  etapa := 'leadtime_anulado_t1_nao_e_pedido'; valor := v_anuladas; RETURN NEXT;
  etapa := 'null_honesto_aguardando_t4';  valor := v_sem_t4;       RETURN NEXT;
  etapa := 'null_honesto_datas_invertidas'; valor := v_datas_ruins; RETURN NEXT;
  RETURN;
END;
$$;


--
-- Name: FUNCTION recomputar_leadtime_derivado(p_empresa text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.recomputar_leadtime_derivado(p_empresa text) IS 'Recompute LOCAL (zero Omie) dos leadtimes derivados de sku_leadtime_history. Fecha o lt_* que nasceu NULL porque o t4 só chegou ao tracking dias após o faturamento, e anula o lt_bruto/lt_faturamento cujo t1 não é data de pedido (órfã ou fallback provado). Idempotente e convergente (atualiza por divergência: correção posterior de t1/t2/t4 na fonte se propaga). Chamada no INÍCIO do run de omie-sync-sku-items, antes de qualquer chamada Omie — assim roda mesmo quando a fila está vazia ou o guard de 50s corta o run.';


--
-- Name: reconcile_score_owner_from_carteira(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reconcile_score_owner_from_carteira() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  INSERT INTO public.farmer_client_scores (customer_user_id, farmer_id)
  VALUES (NEW.customer_user_id, NEW.owner_user_id)
  ON CONFLICT (customer_user_id) DO UPDATE
    SET farmer_id = EXCLUDED.farmer_id,
        updated_at = now()
    WHERE public.farmer_client_scores.farmer_id IS DISTINCT FROM EXCLUDED.farmer_id;
  RETURN NEW;
END;
$$;


--
-- Name: reconcile_visita_agendada(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reconcile_visita_agendada() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  UPDATE public.visitas_agendadas va
  SET status = 'realizada',
      route_visit_id = NEW.id,
      updated_at = now()
  WHERE va.id = (
    SELECT v.id FROM public.visitas_agendadas v
    WHERE v.customer_user_id = NEW.customer_user_id
      AND v.scheduled_by    = NEW.visited_by
      AND v.status = 'pendente'
      AND v.route_visit_id IS NULL
      AND v.scheduled_date <= NEW.visit_date
    ORDER BY v.scheduled_date ASC
    LIMIT 1
  )
  AND va.status = 'pendente'
  AND va.route_visit_id IS NULL
  AND NOT EXISTS (
    SELECT 1 FROM public.visitas_agendadas v2 WHERE v2.route_visit_id = NEW.id
  );
  RETURN NEW;
END;
$$;


--
-- Name: refresh_customer_metrics(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_customer_metrics() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
BEGIN
  IF NOT pg_catalog.pg_try_advisory_xact_lock(pg_catalog.hashtext('refresh_customer_metrics')) THEN
    RAISE NOTICE 'refresh_customer_metrics: refresh já em curso, pulando';
    RETURN;
  END IF;
  REFRESH MATERIALIZED VIEW CONCURRENTLY private.customer_metrics_mv;
END;
$$;


--
-- Name: refresh_oportunidade_badge(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_oportunidade_badge() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'private'
    AS $$
BEGIN
  -- Advisory lock de TRANSAÇÃO (auto-libera no commit/rollback — NÃO vaza em
  -- cancelamento/statement_timeout, ≠ lock de sessão; achado Codex xhigh). Sem
  -- fallback non-concurrent cego: stale-served > travar o badge; erro propaga +
  -- watchdog alerta.
  IF NOT pg_try_advisory_xact_lock(hashtext('refresh_oportunidade_badge')) THEN
    RAISE NOTICE 'refresh_oportunidade_badge: refresh já em curso, pulando';
    RETURN;
  END IF;
  REFRESH MATERIALIZED VIEW CONCURRENTLY private.mv_oportunidade_badge;
END;
$$;


--
-- Name: refresh_sku_ranking_negociacao(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.refresh_sku_ranking_negociacao() RETURNS TABLE(skus_ranqueados integer, atualizado_em timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'private'
    AS $$
BEGIN
  -- SEM gate auth.uid() interno: matava o cron (postgres sem JWT → 42501). A proteção é
  -- o REVOKE/GRANT abaixo (NÃO um gate runtime). Lição reposicao.md.
  REFRESH MATERIALIZED VIEW CONCURRENTLY private.mv_sku_ranking_negociacao_paralela;
  RETURN QUERY SELECT COUNT(*)::int, now() FROM private.mv_sku_ranking_negociacao_paralela;
END;
$$;


--
-- Name: register_carteira_member(uuid, text, bigint, bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.register_carteira_member(p_user_id uuid, p_account text, p_omie_codigo_cliente bigint, p_omie_codigo_vendedor bigint DEFAULT NULL::bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF p_user_id IS NULL OR p_omie_codigo_cliente IS NULL THEN
    RAISE EXCEPTION 'register_carteira_member: user_id e omie_codigo_cliente são obrigatórios'
      USING ERRCODE = 'null_value_not_allowed';
  END IF;

  -- Membership (acumulador). DO NOTHING preserva first_seen_at E identity_state de quem já é membro:
  -- um quarantinado (ambiguous/conflict) NÃO volta a verified por re-chamada.
  INSERT INTO public.carteira_membership_ledger (user_id, identity_state, first_seen_at, source, updated_at)
  VALUES (p_user_id, 'verified', now(), 'rpc', now())
  ON CONFLICT (user_id) DO NOTHING;

  -- Proof account-correta. `source='rpc'` (NÃO 'manual'): diz a verdade sobre a procedência e mantém a
  -- linha alcançável pelo delete de ambiguidade do sync — 'manual' é reservado a override HUMANO, que é
  -- o único que merece imunidade ao fail-closed.
  -- `p_account` é validado pelo CHECK `chk_ocam_account` ('oben'|'colacor'|'colacor_sc'): o slug INTERNO
  -- do sync ('vendas'|'servicos'|'colacor_vendas') levanta 23514 em vez de gravar conta errada.
  -- Vendedor ausente NUNCA é fabricado como 0 — COALESCE preserva o vendedor já conhecido.
  INSERT INTO public.omie_customer_account_map (
    user_id, account, omie_codigo_cliente, omie_codigo_vendedor, source, updated_at
  )
  VALUES (
    p_user_id, p_account, p_omie_codigo_cliente, p_omie_codigo_vendedor, 'rpc', now()
  )
  ON CONFLICT (user_id, account) DO UPDATE SET
    omie_codigo_cliente  = EXCLUDED.omie_codigo_cliente,
    omie_codigo_vendedor = COALESCE(EXCLUDED.omie_codigo_vendedor, omie_customer_account_map.omie_codigo_vendedor),
    -- NÃO rebaixa um override humano: se a linha já é 'manual', permanece 'manual'.
    source               = CASE WHEN omie_customer_account_map.source = 'manual' THEN 'manual' ELSE 'rpc' END,
    updated_at           = now();
END
$$;


--
-- Name: FUNCTION register_carteira_member(p_user_id uuid, p_account text, p_omie_codigo_cliente bigint, p_omie_codigo_vendedor bigint); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.register_carteira_member(p_user_id uuid, p_account text, p_omie_codigo_cliente bigint, p_omie_codigo_vendedor bigint) IS 'P0-B-bis Fatia 4 (+hotfix source=rpc): admite membro na carteira escrevendo ledger (membership acumuladora) + omie_customer_account_map (proof account-correta, source=rpc). SECURITY INVOKER de propósito: a RLS staff-only das duas tabelas é o gate — DEFINER abriria escrita que a RLS hoje fecha. source=rpc e NAO manual: manual é imune ao delete de ambiguidade do sync (reservado a override humano); writer automatizado precisa continuar alcançável pelo fail-closed. Nunca rebaixa identity_state (não ressuscita quarantinado); UNIQUE(codigo,account) fail-closed contra roubo de vínculo cross-user.';


--
-- Name: registrar_aplicacao_regua(uuid, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.registrar_aplicacao_regua(p_log_id uuid, p_preco_final numeric) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_uid uuid := (SELECT auth.uid());
  v_n   int;
BEGIN
  IF NOT private.cap_regua_log_escrever(v_uid) THEN
    RAISE EXCEPTION 'forbidden: registrar_aplicacao_regua exige staff' USING ERRCODE = '42501';
  END IF;

  -- é o VALOR do desfecho: NaN aqui envenena qualquer análise de aceite depois.
  IF NOT private.regua_num_finito(p_preco_final) OR p_preco_final <= 0 THEN
    RAISE EXCEPTION 'registrar_aplicacao_regua: preco_final nao finito ou <= 0'
      USING ERRCODE = '22023';
  END IF;

  -- só o DONO do registro fecha o próprio loop. Sem isto, staff qualquer sobrescreveria o outcome
  -- de outra vendedora (a RPC é SECDEF, então a RLS não estaria lá para impedir).
  UPDATE public.regua_preco_log
     SET preco_final = p_preco_final, aplicou = true,
         outcome_status = 'aplicado', outcome_at = now()
   WHERE id = p_log_id AND salesperson_id = v_uid;

  GET DIAGNOSTICS v_n = ROW_COUNT;
  RETURN v_n = 1;
END;
$$;


--
-- Name: registrar_aumento_via_vision(text, text, text, date, date, jsonb, text, text, text, text, timestamp with time zone, numeric, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.registrar_aumento_via_vision(p_empresa text, p_fornecedor_nome text, p_nome text, p_data_vigencia date, p_data_anuncio date, p_categorias jsonb, p_origem_arquivo_url text DEFAULT NULL::text, p_origem_arquivo_tipo text DEFAULT 'pdf'::text, p_origem_email_assunto text DEFAULT NULL::text, p_origem_email_remetente text DEFAULT NULL::text, p_origem_email_data timestamp with time zone DEFAULT NULL::timestamp with time zone, p_extracao_confianca numeric DEFAULT NULL::numeric, p_extracao_observacoes text DEFAULT NULL::text, p_criado_por text DEFAULT 'extrator_vision'::text) RETURNS bigint
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_aumento_id bigint;
  v_categoria jsonb;
BEGIN
  INSERT INTO fornecedor_aumento_anunciado (
    empresa, fornecedor_nome, nome, 
    data_vigencia, data_anuncio, estado,
    origem_arquivo_url, origem_arquivo_tipo,
    origem_email_assunto, origem_email_remetente, origem_email_data,
    extracao_confianca, extracao_observacoes, extraido_em,
    criado_por
  ) VALUES (
    p_empresa, p_fornecedor_nome, p_nome,
    p_data_vigencia, p_data_anuncio, 'rascunho',
    p_origem_arquivo_url, p_origem_arquivo_tipo,
    p_origem_email_assunto, p_origem_email_remetente, p_origem_email_data,
    p_extracao_confianca, p_extracao_observacoes, now(),
    p_criado_por
  ) RETURNING id INTO v_aumento_id;
  
  FOR v_categoria IN SELECT * FROM jsonb_array_elements(p_categorias) LOOP
    INSERT INTO fornecedor_aumento_item (
      aumento_id, 
      categoria_fornecedor, 
      aumento_perc,
      data_vigencia_especifica,
      confirmado, ativo
    ) VALUES (
      v_aumento_id,
      v_categoria->>'categoria_fornecedor',
      (v_categoria->>'aumento_perc')::numeric,
      (v_categoria->>'data_vigencia_especifica')::date,
      false, true
    )
    ON CONFLICT (aumento_id, categoria_fornecedor) DO NOTHING;
  END LOOP;
  
  RETURN v_aumento_id;
END;
$$;


--
-- Name: registrar_contato_radar(text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.registrar_contato_radar(p_cnpj text, p_acao text, p_nota text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
  v_uid uuid := auth.uid();
  v_status_atual text;
  v_existing uuid;
  v_id uuid;
BEGIN
  IF NOT COALESCE(public.pode_ver_carteira_completa(v_uid), false) THEN
    RAISE EXCEPTION 'forbidden: gestor/master only';
  END IF;
  IF p_cnpj IS NULL OR p_cnpj !~ '^[0-9]{14}$' THEN
    RAISE EXCEPTION 'cnpj inválido';
  END IF;
  IF p_acao NOT IN ('a_contatar','contatado_sem_resposta','em_conversa','descartado','virou_cliente') THEN
    RAISE EXCEPTION 'ação inválida: %', p_acao;
  END IF;

  SELECT prospeccao_status INTO v_status_atual
    FROM public.radar_empresas WHERE cnpj = p_cnpj FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'empresa não encontrada: %', p_cnpj; END IF;

  PERFORM pg_advisory_xact_lock(hashtextextended(v_uid::text||':'||p_cnpj||':'||p_acao||':radar', 0));
  SELECT id INTO v_existing FROM public.radar_contatos
   WHERE criado_por = v_uid AND cnpj = p_cnpj AND acao = p_acao
     AND created_at > now() - interval '2 minutes'
   ORDER BY created_at DESC LIMIT 1;
  IF v_existing IS NOT NULL THEN
    RETURN jsonb_build_object('id', v_existing, 'deduped', true);
  END IF;

  INSERT INTO public.radar_contatos (cnpj, acao, nota, criado_por, status_anterior)
  VALUES (p_cnpj, p_acao, p_nota, v_uid, v_status_atual)
  RETURNING id INTO v_id;

  UPDATE public.radar_empresas SET
    prospeccao_status = p_acao,
    prospeccao_atualizado_em = now(),
    descarte_motivo = CASE WHEN p_acao = 'descartado' THEN p_nota ELSE NULL END,
    updated_at = now()
  WHERE cnpj = p_cnpj;

  RETURN jsonb_build_object('id', v_id, 'deduped', false);
END $_$;


--
-- Name: registrar_contato_rota(uuid, text, date, text, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.registrar_contato_rota(p_customer_user_id uuid, p_status text, p_data_rota date, p_bucket text DEFAULT NULL::text, p_valor numeric DEFAULT NULL::numeric) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE v_uid uuid := auth.uid(); v_existing uuid; v_id uuid;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM public.user_roles ur WHERE ur.user_id = v_uid AND ur.role IN ('employee','master')) THEN
    RAISE EXCEPTION 'forbidden: staff only';
  END IF;
  IF p_customer_user_id IS NULL THEN RAISE EXCEPTION 'customer_user_id required'; END IF;
  IF p_data_rota IS NULL THEN RAISE EXCEPTION 'data_rota required'; END IF;
  IF p_status NOT IN ('convertido','respondido','sem_resposta','opt_out') THEN
    RAISE EXCEPTION 'invalid status: %', p_status;
  END IF;
  -- staff responde "é staff?", não "pode afetar ESTE cliente?" — exige visibilidade de carteira.
  IF NOT (COALESCE(public.pode_ver_carteira_completa(v_uid), false)
          OR private.carteira_visivel_para(p_customer_user_id, v_uid)) THEN
    RAISE EXCEPTION 'forbidden: customer not visible';
  END IF;
  -- serializa o dedupe por chave lógica (evita race do SELECT→INSERT em double-click concorrente).
  PERFORM pg_advisory_xact_lock(hashtextextended(
    v_uid::text||':'||p_customer_user_id::text||':'||p_data_rota::text||':'||p_status||':ligacao', 0));
  -- dedupe idempotente: mesmo vendedor+cliente+rota+status nos últimos 2 min → devolve o existente.
  SELECT id INTO v_existing FROM public.route_contact_log
   WHERE farmer_id = v_uid AND customer_user_id = p_customer_user_id
     AND data_rota = p_data_rota AND status = p_status AND canal = 'ligacao'
     AND created_at > now() - interval '2 minutes'
   ORDER BY created_at DESC LIMIT 1;
  IF v_existing IS NOT NULL THEN
    RETURN jsonb_build_object('id', v_existing, 'deduped', true);
  END IF;
  INSERT INTO public.route_contact_log (data_rota, customer_user_id, farmer_id, canal, valor_da_ligacao, bucket, status)
  VALUES (p_data_rota, p_customer_user_id, v_uid, 'ligacao', p_valor, p_bucket, p_status)
  RETURNING id INTO v_id;
  RETURN jsonb_build_object('id', v_id, 'deduped', false);
END $$;


--
-- Name: registrar_exibicao_regua(text, uuid, uuid, numeric, numeric, text, text, numeric, numeric, numeric, boolean, text[], numeric[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.registrar_exibicao_regua(p_account text, p_customer_user_id uuid, p_product_id uuid, p_quantity numeric, p_preco_atual numeric, p_sinal_exibido text, p_confianca text, p_preco_referencia numeric DEFAULT NULL::numeric, p_observed_gap_pct numeric DEFAULT NULL::numeric, p_suggested_gap_pct numeric DEFAULT NULL::numeric, p_cap_limitou boolean DEFAULT false, p_reason_codes text[] DEFAULT NULL::text[], p_prazo_dias numeric[] DEFAULT NULL::numeric[]) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_uid      uuid := (SELECT auth.uid());
  v_cmc      numeric;
  v_aliquota numeric;
  v_taxa     numeric;
  v_piso     numeric;
  v_id       uuid;
BEGIN
  -- capability de ESCRITA — NUNCA cap_custo_ler (§4.2; bloqueador P1 do Codex na fase 1)
  IF NOT private.cap_regua_log_escrever(v_uid) THEN
    RAISE EXCEPTION 'forbidden: registrar_exibicao_regua exige staff' USING ERRCODE = '42501';
  END IF;

  IF p_customer_user_id IS NULL OR p_product_id IS NULL OR p_preco_atual IS NULL
     OR p_sinal_exibido IS NULL OR p_confianca IS NULL OR p_account IS NULL THEN
    RAISE EXCEPTION 'registrar_exibicao_regua: campos obrigatorios ausentes' USING ERRCODE = '22004';
  END IF;

  -- fronteira de CONFIANÇA: estes numeric vêm do cliente e `numeric` aceita NaN/±Infinity. Uma
  -- linha com NaN contamina média, ordenação e o closed-loop inteiro depois. Obrigatório inválido
  -- REJEITA (a linha toda seria lixo); opcional inválido vira NULL — ausente ≠ número inventado.
  IF NOT private.regua_num_finito(p_preco_atual) OR p_preco_atual <= 0 THEN
    RAISE EXCEPTION 'registrar_exibicao_regua: preco_atual nao finito ou <= 0'
      USING ERRCODE = '22023';
  END IF;
  IF p_quantity IS NOT NULL AND NOT private.regua_num_finito(p_quantity) THEN
    RAISE EXCEPTION 'registrar_exibicao_regua: quantity nao finita' USING ERRCODE = '22023';
  END IF;

  -- custo apurado NO SERVIDOR (o cliente não o recebe mais, então não pode informá-lo)
  SELECT ip.cmc INTO v_cmc FROM public.inventory_position ip
   WHERE ip.product_id = p_product_id AND ip.account IN ('oben', 'vendas')
     AND private.regua_num_finito(ip.cmc) AND ip.cmc > 0
   ORDER BY (ip.account = 'oben') DESC LIMIT 1;

  SELECT COALESCE(
           (SELECT cc.value::numeric FROM public.company_config cc
             WHERE cc.key = 'regua_preco_aliquota_venda_oben'), 0.15) INTO v_aliquota;

  IF p_prazo_dias IS NOT NULL AND array_length(p_prazo_dias, 1) IS NOT NULL THEN
    v_taxa := public.fin_regua_custo_capital('oben');
  END IF;

  SELECT piso INTO v_piso FROM private.regua_piso_calc(v_cmc, v_aliquota, p_prazo_dias, v_taxa);

  INSERT INTO public.regua_preco_log (
    account, customer_user_id, product_id, salesperson_id, quantity, preco_atual,
    sinal_exibido, confianca, preco_referencia, observed_gap_pct, suggested_gap_pct,
    piso_mc, cap_limitou, cmc_usado, cmc_confianca, aliquota_usada, reason_codes,
    outcome_status, aplicou
  ) VALUES (
    p_account, p_customer_user_id, p_product_id, v_uid, p_quantity, p_preco_atual,
    p_sinal_exibido, p_confianca,
    -- opcionais: não-finito degrada para NULL em vez de persistir NaN
    CASE WHEN private.regua_num_finito(p_preco_referencia)  THEN p_preco_referencia  END,
    CASE WHEN private.regua_num_finito(p_observed_gap_pct)  THEN p_observed_gap_pct  END,
    CASE WHEN private.regua_num_finito(p_suggested_gap_pct) THEN p_suggested_gap_pct END,
    CASE WHEN v_piso IS NOT NULL THEN round(ceil(v_piso * 10000) / 10000, 4) END,
    COALESCE(p_cap_limitou, false), v_cmc,
    CASE WHEN v_cmc IS NOT NULL THEN 'real' ELSE 'proxy' END, v_aliquota,
    COALESCE(p_reason_codes, ARRAY[]::text[]),
    'pendente', false
  )
  RETURNING id INTO v_id;

  RETURN v_id;   -- só o id: nenhuma coluna de custo volta pro cliente
END;
$$;


--
-- Name: registrar_historico_sku_parametros(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.registrar_historico_sku_parametros() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  -- Só registra se houve mudança em campos relevantes
  IF (OLD.estoque_minimo IS DISTINCT FROM NEW.estoque_minimo)
     OR (OLD.ponto_pedido IS DISTINCT FROM NEW.ponto_pedido)
     OR (OLD.estoque_maximo IS DISTINCT FROM NEW.estoque_maximo)
     OR (OLD.aprovado_em IS DISTINCT FROM NEW.aprovado_em)
     OR (OLD.aplicar_no_omie IS DISTINCT FROM NEW.aplicar_no_omie) THEN
    INSERT INTO public.sku_parametros_historico (
      sku_parametro_id, snapshot_em, classe_consolidada,
      demanda_media_diaria, lt_medio_dias_uteis, z_score,
      estoque_seguranca, ponto_pedido, trigger
    ) VALUES (
      NEW.id, now(), NEW.classe_consolidada,
      NEW.demanda_media_diaria, NEW.lt_medio_dias_uteis, NEW.z_score,
      NEW.estoque_seguranca, NEW.ponto_pedido,
      CASE
        WHEN OLD.aprovado_em IS DISTINCT FROM NEW.aprovado_em AND NEW.aprovado_em IS NOT NULL THEN 'aprovacao_humana'
        WHEN OLD.estoque_minimo IS DISTINCT FROM NEW.estoque_minimo
          OR OLD.ponto_pedido IS DISTINCT FROM NEW.ponto_pedido
          OR OLD.estoque_maximo IS DISTINCT FROM NEW.estoque_maximo THEN 'edicao_manual'
        ELSE 'atualizacao'
      END
    );
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: registrar_polling_resultado(bigint, integer, integer, integer, integer, integer, integer, text, text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.registrar_polling_resultado(p_config_id bigint, p_emails_encontrados integer, p_emails_processados integer, p_anexos_extraidos integer, p_campanhas_criadas integer, p_aumentos_criados integer, p_alertas_suspensao integer, p_ultimo_email_id text DEFAULT NULL::text, p_erro text DEFAULT NULL::text, p_detalhes jsonb DEFAULT NULL::jsonb) RETURNS bigint
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_log_id bigint;
BEGIN
  -- Log
  INSERT INTO fornecedor_email_polling_log (
    polling_config_id, 
    emails_encontrados, emails_processados, anexos_extraidos,
    campanhas_criadas, aumentos_criados, alertas_suspensao,
    erro, detalhes
  ) VALUES (
    p_config_id,
    p_emails_encontrados, p_emails_processados, p_anexos_extraidos,
    p_campanhas_criadas, p_aumentos_criados, p_alertas_suspensao,
    p_erro, p_detalhes
  ) RETURNING id INTO v_log_id;
  
  -- Atualiza checkpoint
  UPDATE fornecedor_email_polling
  SET 
    ultimo_poll_em = now(),
    ultimo_email_processado_id = COALESCE(p_ultimo_email_id, ultimo_email_processado_id)
  WHERE id = p_config_id;
  
  -- Se deu erro, gera alerta de polling
  IF p_erro IS NOT NULL THEN
    INSERT INTO fornecedor_alerta (
      empresa, fornecedor_nome, tipo, severidade,
      titulo, mensagem
    )
    SELECT 
      empresa, fornecedor_nome, 'polling_erro', 'atencao',
      'Falha no polling de emails: ' || fornecedor_nome,
      'Erro ao processar emails de ' || remetente_email || ': ' || p_erro
    FROM fornecedor_email_polling
    WHERE id = p_config_id;
  END IF;
  
  RETURN v_log_id;
END;
$$;


--
-- Name: registrar_resultado_plano(uuid, boolean, text, numeric, integer, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.registrar_resultado_plano(_plan_id uuid, _plan_followed boolean, _call_result text, _actual_margin numeric, _call_duration_seconds integer, _objection_type text DEFAULT NULL::text, _notes text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  _uid        uuid    := auth.uid();
  _is_service boolean := COALESCE(auth.role() = 'service_role', false);
  _customer   uuid;
  _status     text;
  _eligible   boolean;
BEGIN
  SELECT p.customer_user_id, p.status INTO _customer, _status
  FROM public.farmer_tactical_plans p
  WHERE p.id = _plan_id;

  IF _customer IS NULL THEN
    RAISE EXCEPTION 'Plano % inexistente', _plan_id;
  END IF;

  IF NOT _is_service THEN
    IF _uid IS NULL THEN
      RAISE EXCEPTION 'Não autenticado' USING ERRCODE = '42501';
    END IF;
    IF NOT private.carteira_visivel_para(_customer, _uid) THEN
      RAISE EXCEPTION 'Plano fora da sua carteira' USING ERRCODE = '42501';
    END IF;
  END IF;

  -- [#1422 — máscara eligible] plano criado elegível e mascarado DEPOIS não recebe resultado.
  SELECT a.eligible INTO _eligible
  FROM public.carteira_assignments a
  WHERE a.customer_user_id = _customer;

  IF _eligible IS NOT TRUE THEN
    RAISE EXCEPTION 'Cliente do plano % está mascarado na carteira (eligible) — resultado não é registrado', _plan_id
      USING ERRCODE = '42501';
  END IF;

  -- [Codex #5] resultado de plano JÁ concluído não é reescrito.
  IF _status = 'concluido' THEN
    RAISE EXCEPTION 'Plano % já concluído — resultado não pode ser reescrito', _plan_id;
  END IF;

  UPDATE public.farmer_tactical_plans
  SET plan_followed         = _plan_followed,
      call_result           = _call_result,
      actual_margin         = _actual_margin,
      call_duration_seconds = _call_duration_seconds,
      objection_type        = _objection_type,
      notes                 = _notes,
      status                = 'concluido',
      completed_at          = now(),
      updated_at            = now()
  WHERE id = _plan_id;
END;
$$;


--
-- Name: FUNCTION registrar_resultado_plano(_plan_id uuid, _plan_followed boolean, _call_result text, _actual_margin numeric, _call_duration_seconds integer, _objection_type text, _notes text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.registrar_resultado_plano(_plan_id uuid, _plan_followed boolean, _call_result text, _actual_margin numeric, _call_duration_seconds integer, _objection_type text, _notes text) IS 'Grava resultado pós-call; gate carteira_visivel_para OR service_role; RECUSA cliente mascarado (eligible IS NOT TRUE) p/ todo caller; recusa se status=concluido (resultado imutável após conclusão).';


--
-- Name: registrar_substituicao_sku(text, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.registrar_substituicao_sku(p_empresa text, p_codigo_antigo text, p_codigo_novo text, p_acao_parametros text, p_motivo text, p_usuario text) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_resultado JSONB;
  v_count_novo INT;
BEGIN
  -- Validar ação
  IF p_acao_parametros NOT IN ('transferir', 'recalcular_do_zero', 'manter_ambos') THEN
    RETURN jsonb_build_object('error', 'ação inválida: ' || p_acao_parametros);
  END IF;
  
  -- Verificar se código novo existe
  SELECT COUNT(*) INTO v_count_novo
  FROM sku_parametros
  WHERE empresa = p_empresa AND sku_codigo_omie::text = p_codigo_novo;
  
  IF v_count_novo = 0 THEN
    RETURN jsonb_build_object('error', 'Código novo ' || p_codigo_novo || ' não encontrado em sku_parametros');
  END IF;
  
  -- Registra substituição
  INSERT INTO sku_substituicao (
    empresa, sku_codigo_antigo, sku_codigo_novo,
    acao_parametros, data_substituicao, motivo, criado_por
  ) VALUES (
    p_empresa, p_codigo_antigo, p_codigo_novo,
    p_acao_parametros, CURRENT_DATE, p_motivo, p_usuario
  )
  ON CONFLICT (empresa, sku_codigo_antigo, status) 
  DO UPDATE SET 
    sku_codigo_novo = EXCLUDED.sku_codigo_novo,
    acao_parametros = EXCLUDED.acao_parametros,
    motivo = EXCLUDED.motivo,
    criado_por = EXCLUDED.criado_por,
    criado_em = NOW();
  
  -- Se ação for 'transferir', copia parâmetros do antigo pro novo
  IF p_acao_parametros = 'transferir' THEN
    UPDATE sku_parametros novo
    SET 
      estoque_minimo = antigo.estoque_minimo,
      ponto_pedido = antigo.ponto_pedido,
      estoque_maximo = antigo.estoque_maximo,
      aplicar_no_omie = TRUE,
      ultima_atualizacao_calculo = NOW()
    FROM sku_parametros antigo
    WHERE novo.empresa = p_empresa AND novo.sku_codigo_omie::text = p_codigo_novo
      AND antigo.empresa = p_empresa AND antigo.sku_codigo_omie::text = p_codigo_antigo;
  END IF;
  
  -- Desativa aplicação no código antigo
  UPDATE sku_parametros
  SET aplicar_no_omie = FALSE
  WHERE empresa = p_empresa AND sku_codigo_omie::text = p_codigo_antigo;
  
  RETURN jsonb_build_object(
    'status', 'ok',
    'mensagem', 'Substituição registrada. Código antigo desativado da fila, código novo atualizado.'
  );
END;
$$;


--
-- Name: rejeitar_sugestao(uuid, text, bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rejeitar_sugestao(p_kb_product_spec_id uuid, p_account text, p_omie_codigo_produto bigint) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NOT public.has_role(auth.uid(), 'master'::app_role) THEN
    RAISE EXCEPTION 'forbidden: somente master';
  END IF;
  INSERT INTO public.omie_product_spec_links
    (account, omie_codigo_produto, kb_product_spec_id, status, confirmed_by)
  VALUES (p_account, p_omie_codigo_produto, p_kb_product_spec_id, 'rejected', auth.uid())
  ON CONFLICT (account, omie_codigo_produto, kb_product_spec_id, status) DO NOTHING;
END;
$$;


--
-- Name: reposicao__po_id(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao__po_id(p text) RETURNS bigint
    LANGUAGE plpgsql IMMUTABLE PARALLEL SAFE
    AS $_$
DECLARE t text; b text := '[[:space:]\u0085\u00a0\u1680\u2000-\u200b\u2028\u2029\u202f\u205f\u3000\ufeff]';
BEGIN
  IF p IS NULL THEN RETURN NULL; END IF;
  t := regexp_replace(regexp_replace(p, '^' || b || '+', ''), b || '+$', '');
  IF t !~ '^[0-9]+$' THEN RETURN NULL; END IF;   -- inclui whitespace interno e vazio
  t := ltrim(t, '0');
  IF t = '' THEN RETURN 0; END IF;
  IF length(t) > 19 OR (length(t) = 19 AND t > '9223372036854775807') THEN RETURN NULL; END IF;
  RETURN t::bigint;
END $_$;


--
-- Name: reposicao__trim(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao__trim(p text) RETURNS text
    LANGUAGE sql IMMUTABLE PARALLEL SAFE
    AS $_$ SELECT COALESCE(regexp_replace(regexp_replace(p,
       '^[[:space:]\u0085\u00a0\u1680\u2000-\u200b\u2028\u2029\u202f\u205f\u3000\ufeff]+', ''),
       '[[:space:]\u0085\u00a0\u1680\u2000-\u200b\u2028\u2029\u202f\u205f\u3000\ufeff]+$', ''), '') $_$;


--
-- Name: reposicao_alerta_pedido_minimo_tick(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_alerta_pedido_minimo_tick() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $_$
DECLARE
  v_threshold numeric;
  v_fornecedor text;
  r RECORD;
  -- [AUTO 1/4] estado do braço de auto-aprovação (v2: SEM janela de horário)
  v_txt text;
  v_auto_on boolean := false;
  v_delta_max numeric;
  v_cooldown numeric;
  v_suspenso boolean := false;
  v_elig jsonb;
  v_auto_ok boolean;
  v_valor_auto numeric;  -- [AUTO] valor REAL (soma dos itens) do pedido auto-aprovado
BEGIN
  -- [AUTO 1/4] Codex P2.9: serializa execuções do tick (cron */30 + hook pós-geração).
  -- Sem isto, dois ticks concorrentes não duplicam compra/log (o claim condicional cobre),
  -- mas o perdedor pode re-inserir estado ativo e mandar CTA "pronto pra aprovar" pra um
  -- pedido que o vencedor já auto-aprovou. xact-lock libera no COMMIT. Benigno pro alerta.
  PERFORM pg_advisory_xact_lock(hashtext('reposicao_alerta_pedido_minimo_tick'));

  SELECT value::numeric INTO v_threshold
  FROM public.company_config WHERE key = 'reposicao_alerta_pedido_valor_minimo';
  SELECT value INTO v_fornecedor
  FROM public.company_config WHERE key = 'reposicao_alerta_pedido_fornecedor_ilike';

  -- Config ausente/inválida = alerta DESLIGADO (régua comercial, não segurança). Sem alerta
  -- fabricado com régua 0.
  IF v_threshold IS NULL OR v_threshold <= 0
     OR v_fornecedor IS NULL OR btrim(v_fornecedor) = '' THEN
    RETURN;
  END IF;

  -- [AUTO 1/4] configs do braço de auto-aprovação. Config quebrada → braço OFF
  -- (fail-safe: o alerta call-to-action continua; nunca aprova com parâmetro inválido).
  SELECT value INTO v_txt FROM public.company_config WHERE key = 'reposicao_auto_aprovacao_ativa';
  v_auto_on := (v_txt = 'true');
  IF v_auto_on THEN
    SELECT value INTO v_txt FROM public.company_config WHERE key = 'reposicao_auto_aprovacao_delta_max';
    IF v_txt ~ '^[0-9]+(\.[0-9]+)?$' THEN v_delta_max := v_txt::numeric; END IF;
    SELECT value INTO v_txt FROM public.company_config WHERE key = 'reposicao_auto_aprovacao_cooldown_falha_horas';
    IF v_txt ~ '^[0-9]+(\.[0-9]+)?$' THEN v_cooldown := v_txt::numeric; END IF;
    -- Codex P1.5: CLAMP de faixa segura. delta_max fora de (0, 0.30] ou cooldown < 1 → braço
    -- OFF (um typo '30'=3000% ou '0' não liga a automação). v2: corte_utc NÃO é mais lido —
    -- sem janela de horário; a config fica órfã no banco, inócua.
    IF v_delta_max IS NULL OR v_delta_max <= 0 OR v_delta_max > 0.30
       OR v_cooldown IS NULL OR v_cooldown < 1 THEN
      v_auto_on := false;
    END IF;
  END IF;

  IF v_auto_on THEN
    -- Auto-suspensão: autonomia NÃO roda com o vigia acusando problema no domínio
    -- (spec §4.5). O tipo 'reposicao_pedido_minimo' (este próprio fluxo) NÃO suspende.
    v_suspenso := EXISTS (
      SELECT 1 FROM public.fin_alertas fa
      WHERE fa.dismissed_at IS NULL
        AND fa.tipo IN ('data_health_reposicao_disparo',
                        'data_health_reposicao_portal_pipeline',
                        'data_health_reposicao_portal_humano',
                        'data_health_reposicao_sugestoes')
    );
    -- v2: SEM janela de horário. Auto-aprova a qualquer hora que cruzar a régua; a compra
    -- dispara no próximo corte (a edge disparar-pedidos-aprovados pega o backlog de
    -- auto-aprovados de data_ciclo anterior — ver nota DISPARO no fim da migration).
  END IF;

  -- 1) NOVOS: pedido pendente ≥ régua do fornecedor configurado, sem alerta ativo → grava
  -- estado + enfileira e-mail (só na transição). Agrupo por (empresa, fornecedor, grupo)
  -- por defesa (a identidade pode ter 2 linhas transitórias: zumbi de ontem + hoje, pré-PR2).
  FOR r IN
    SELECT pcs.empresa, pcs.fornecedor_nome,
           COALESCE(pcs.grupo_codigo, '') AS grupo_codigo,
           MAX(pcs.valor_total) AS valor,
           SUM(COALESCE(pcs.num_skus, 0)) AS num_skus,
           MAX(pcs.id) AS pedido_id,
           COUNT(*) AS qtd_pendentes  -- [AUTO 2/4] >1 = estado anômalo (zumbi) → humano
    FROM public.pedido_compra_sugerido pcs
    WHERE pcs.status = 'pendente_aprovacao'
      AND pcs.fornecedor_nome ILIKE v_fornecedor
      AND pcs.valor_total >= v_threshold
    GROUP BY 1, 2, 3
  LOOP
    -- [AUTO 3/4] tenta a auto-aprovação ANTES de decidir qual e-mail sai. Claim
    -- condicional: corrida com aprovação humana → quem chegar primeiro vence; o
    -- perdedor não loga nem manda e-mail duplicado (FOUND = false).
    v_auto_ok := false;
    v_valor_auto := NULL;
    IF v_auto_on AND NOT v_suspenso AND r.qtd_pendentes = 1 THEN   -- v2: sem v_dentro_janela
      -- passa a régua (threshold) — a função valida a soma dos ITENS contra ela (P1.2).
      v_elig := public.reposicao_pedido_auto_aprovavel(r.pedido_id, v_threshold, v_delta_max, v_cooldown);
      IF COALESCE((v_elig->>'elegivel')::boolean, false) THEN
        UPDATE public.pedido_compra_sugerido
        SET aprovado_em = now(),
            aprovado_por = 'auto:sayerlack-v2',
            status = 'aprovado_aguardando_disparo'
        WHERE id = r.pedido_id
          AND status = 'pendente_aprovacao'
          AND aprovado_em IS NULL
          AND cancelado_em IS NULL;
        IF FOUND THEN
          v_auto_ok := true;
          -- valor REAL = soma dos itens (P1.2), não o cabeçalho r.valor que pode divergir.
          v_valor_auto := COALESCE((v_elig->>'valor_itens')::numeric, r.valor);
          INSERT INTO public.reposicao_auto_aprovacao_log
            (pedido_id, empresa, fornecedor_nome, grupo_codigo, valor_total,
             valor_anterior, delta_pct, regua)
          VALUES
            (r.pedido_id, r.empresa, r.fornecedor_nome, r.grupo_codigo, v_valor_auto,
             (v_elig->>'valor_anterior')::numeric, (v_elig->>'delta_pct')::numeric, v_threshold);
        END IF;
      END IF;
    END IF;

    INSERT INTO public.reposicao_alerta_pedido_minimo
      (empresa, fornecedor_nome, grupo_codigo, pedido_id, valor_alertado, valor_ultimo)
    VALUES (r.empresa, r.fornecedor_nome, r.grupo_codigo, r.pedido_id, r.valor, r.valor)
    ON CONFLICT (empresa, fornecedor_nome, grupo_codigo) WHERE resolvido_em IS NULL
    DO NOTHING;

    IF FOUND THEN
      -- [AUTO 4/4] transição: informativo (máquina aprovou) OU call-to-action (fluxo atual).
      IF v_auto_ok THEN
        INSERT INTO public.fornecedor_alerta (empresa, tipo, severidade, titulo, mensagem, status)
        VALUES (
          lower(r.empresa),
          'reposicao_pedido_minimo',
          'atencao',
          '[Compras] Auto-aprovado: pedido ' || r.fornecedor_nome || ' de R$ ' || round(COALESCE(v_valor_auto, r.valor))::text,
          'O pedido sugerido de ' || r.fornecedor_nome
            || CASE WHEN r.grupo_codigo <> '' THEN ' (grupo ' || r.grupo_codigo || ')' ELSE '' END
            || ' atingiu R$ ' || round(COALESCE(v_valor_auto, r.valor))::text
            || ' (' || r.num_skus::text || ' SKUs) e foi APROVADO AUTOMATICAMENTE — piloto: delta '
            || COALESCE((v_elig->>'delta_pct')::text, '?') || '% vs último disparo do grupo (R$ '
            || COALESCE(round((v_elig->>'valor_anterior')::numeric)::text, '?')
            || '), dentro do limite. Dispara no próximo corte automático. Para VETAR, cancele em '
            || 'Reposição → Pedidos (https://steu.lovable.app/admin/reposicao/pedidos) antes do corte. '
            || 'Fusível: company_config → reposicao_auto_aprovacao_ativa = false desliga o piloto.',
          'pendente_notificacao'
        );
      ELSE
        -- Transição: 1 e-mail. Link GENÉRICO pra tela (deep-link ?id= morreria na regeneração).
        INSERT INTO public.fornecedor_alerta (empresa, tipo, severidade, titulo, mensagem, status)
        VALUES (
          lower(r.empresa),
          'reposicao_pedido_minimo',
          'atencao',
          '[Compras] Pedido ' || r.fornecedor_nome || ' atingiu R$ ' || round(r.valor)::text
            || ' — pronto pra aprovar',
          'O pedido sugerido de ' || r.fornecedor_nome
            || CASE WHEN r.grupo_codigo <> '' THEN ' (grupo ' || r.grupo_codigo || ')' ELSE '' END
            || ' acumulou R$ ' || round(r.valor)::text
            || ' (' || r.num_skus::text || ' SKUs) — acima do mínimo de faturamento (R$ '
            || round(v_threshold)::text || '). Aprovar dispara na hora: '
            || 'Reposição → Pedidos (https://steu.lovable.app/admin/reposicao/pedidos). '
            || 'Quando você aprovar (ou o pedido sair da régua), este aviso re-arma sozinho.',
          'pendente_notificacao'
        );
      END IF;
    ELSE
      IF v_auto_ok THEN
        -- [AUTO 4/4] alerta call-to-action já estava ativo e a máquina aprovou AGORA
        -- (ex.: fusível ligado depois do alerta) → informativo é transição real.
        INSERT INTO public.fornecedor_alerta (empresa, tipo, severidade, titulo, mensagem, status)
        VALUES (
          lower(r.empresa),
          'reposicao_pedido_minimo',
          'atencao',
          '[Compras] Auto-aprovado: pedido ' || r.fornecedor_nome || ' de R$ ' || round(COALESCE(v_valor_auto, r.valor))::text,
          'O pedido sugerido de ' || r.fornecedor_nome
            || CASE WHEN r.grupo_codigo <> '' THEN ' (grupo ' || r.grupo_codigo || ')' ELSE '' END
            || ' (R$ ' || round(COALESCE(v_valor_auto, r.valor))::text || ', ' || r.num_skus::text
            || ' SKUs) foi APROVADO AUTOMATICAMENTE — piloto: delta '
            || COALESCE((v_elig->>'delta_pct')::text, '?') || '% vs último disparo do grupo (R$ '
            || COALESCE(round((v_elig->>'valor_anterior')::numeric)::text, '?')
            || '). Dispara no próximo corte automático. Para VETAR, cancele em '
            || 'Reposição → Pedidos (https://steu.lovable.app/admin/reposicao/pedidos) antes do corte. '
            || 'Fusível: company_config → reposicao_auto_aprovacao_ativa = false desliga o piloto.',
          'pendente_notificacao'
        );
      ELSE
        -- Alerta já ativo: só atualiza o último valor visto (3.2k→10k NÃO re-spamma; o valor
        -- vivo está no cockpit).
        UPDATE public.reposicao_alerta_pedido_minimo a
        SET valor_ultimo = r.valor, pedido_id = r.pedido_id
        WHERE a.empresa = r.empresa AND a.fornecedor_nome = r.fornecedor_nome
          AND a.grupo_codigo = r.grupo_codigo AND a.resolvido_em IS NULL;
      END IF;
    END IF;
  END LOOP;

  -- 2) RESOLVE (re-arma): alerta ativo sem pedido pendente ≥ régua correspondente — o founder
  -- aprovou/cancelou, o corte expirou, ou o valor caiu. O próximo pedido do grupo que cruzar a
  -- régua gera e-mail NOVO. (Sem filtro de fornecedor aqui de propósito: se o pattern da config
  -- mudar, alertas órfãos do pattern antigo resolvem sozinhos.)
  -- [AUTO] nota: pedido auto-aprovado sai de pendente NESTA execução → o estado da identidade
  -- resolve aqui embaixo no mesmo tick (vida curta, consistente; o informativo já saiu acima).
  UPDATE public.reposicao_alerta_pedido_minimo a
  SET resolvido_em = now()
  WHERE a.resolvido_em IS NULL
    AND NOT EXISTS (
      SELECT 1 FROM public.pedido_compra_sugerido pcs
      WHERE pcs.empresa = a.empresa
        AND pcs.fornecedor_nome = a.fornecedor_nome
        AND COALESCE(pcs.grupo_codigo, '') = a.grupo_codigo
        AND pcs.status = 'pendente_aprovacao'
        AND pcs.valor_total >= v_threshold
    );
END;
$_$;


--
-- Name: reposicao_alocar_run_seq(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_alocar_run_seq() RETURNS bigint
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$ SELECT nextval('public.reposicao_run_seq'); $$;


--
-- Name: reposicao_aplicar_depara_sayerlack_auto(jsonb, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_aplicar_depara_sayerlack_auto(p_candidatos jsonb, p_parser_version integer DEFAULT NULL::integer, p_run_id uuid DEFAULT NULL::uuid) RETURNS TABLE(inseridos integer, colisao_destino integer, ja_existe integer, nao_elegivel integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_ins int := 0; v_col int := 0; v_exi int := 0; v_nel int := 0;
  c record; v_res text; v_det text;
BEGIN
  -- Gate: só service_role (edge/cron). Usuário via PostgREST é barrado (42501).
  IF COALESCE(auth.role(), '') <> 'service_role' THEN
    RAISE EXCEPTION 'acesso negado: reposicao_aplicar_depara_sayerlack_auto requer service_role'
      USING ERRCODE = '42501';
  END IF;

  FOR c IN
    SELECT * FROM jsonb_to_recordset(COALESCE(p_candidatos, '[]'::jsonb))
      AS x(sku_omie text, sku_portal text, unidade_portal text, sku_descricao text)
  LOOP
    v_det := NULL;
    -- candidato inválido (sem sku_omie/sku_portal) -> não-elegível, auditado
    IF c.sku_omie IS NULL OR btrim(c.sku_omie) = '' OR c.sku_portal IS NULL OR btrim(c.sku_portal) = '' THEN
      v_res := 'nao_elegivel'; v_nel := v_nel + 1; v_det := 'candidato sem sku_omie/sku_portal';
    -- (1) já existe (ativo OU inativo) p/ o SKU -> nunca sobrescreve (mapa manual / inativo intencional)
    ELSIF EXISTS (
        SELECT 1 FROM public.sku_fornecedor_externo fe
        WHERE fe.empresa = 'OBEN' AND fe.fornecedor_nome ILIKE '%SAYERLACK%' AND fe.sku_omie = c.sku_omie
      ) THEN
      v_res := 'ja_existe'; v_exi := v_exi + 1;
    -- (2) COLISÃO DE DESTINO: o sku_portal já está ativo p/ OUTRO sku_omie (Codex P2)
    ELSIF EXISTS (
        SELECT 1 FROM public.sku_fornecedor_externo fe
        WHERE fe.empresa = 'OBEN' AND fe.fornecedor_nome ILIKE '%SAYERLACK%'
          AND fe.ativo = true
          AND upper(btrim(fe.sku_portal)) = upper(btrim(c.sku_portal))
          AND fe.sku_omie <> c.sku_omie
      ) THEN
      v_res := 'colisao_destino'; v_col := v_col + 1; v_det := 'sku_portal já mapeado p/ outro SKU';
    -- (3) re-valida elegibilidade no momento da escrita (defesa: catálogo pode ter mudado)
    ELSIF NOT EXISTS (
        SELECT 1 FROM public.v_reposicao_depara_sayerlack_elegivel e WHERE e.sku_omie = c.sku_omie
      ) THEN
      v_res := 'nao_elegivel'; v_nel := v_nel + 1; v_det := 'fora da view de elegibilidade';
    -- (4) insere
    ELSE
      INSERT INTO public.sku_fornecedor_externo
        (empresa, fornecedor_nome, sku_omie, sku_portal, unidade_portal, fator_conversao, ativo, observacoes)
      VALUES
        ('OBEN', 'RENNER SAYERLACK S/A', c.sku_omie, c.sku_portal,
         COALESCE(NULLIF(c.unidade_portal, ''), 'UN'), 1, true,
         'extraído automaticamente (parser v' || COALESCE(p_parser_version::text, '?') || ', cold-start)')
      ON CONFLICT (empresa, fornecedor_nome, sku_omie) DO NOTHING;
      IF FOUND THEN
        v_res := 'inserido'; v_ins := v_ins + 1;
      ELSE
        v_res := 'ja_existe'; v_exi := v_exi + 1;   -- corrida com outro writer
      END IF;
    END IF;

    INSERT INTO public.reposicao_depara_auto_log
      (run_id, empresa, sku_omie, sku_descricao, sku_portal_extraido, parser_version, resultado, detalhe)
    VALUES
      (p_run_id, 'OBEN', c.sku_omie, c.sku_descricao, c.sku_portal, p_parser_version, v_res, v_det);
  END LOOP;

  RETURN QUERY SELECT v_ins, v_col, v_exi, v_nel;
END $$;


--
-- Name: reposicao_cold_start_parametros(text, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_cold_start_parametros(p_empresa text DEFAULT 'OBEN'::text, p_limite integer DEFAULT 50, p_run_id uuid DEFAULT NULL::uuid) RETURNS TABLE(graduados integer, criados integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_grad int := 0; v_cri int := 0;
BEGIN
  -- SEM gate auth.role(): o pg_cron roda como postgres SEM JWT (auth.role()=NULL) e o gate
  -- 'service_role' o bloquearia. Proteção via REVOKE/GRANT abaixo (anon/authenticated barrados).

  -- ── (1) GRADUAR: cold-start que ganhou demanda OK → aplica o parâmetro REAL ──
  WITH grad AS (
    UPDATE public.sku_parametros sp SET
      estoque_minimo      = v.estoque_minimo_sugerido,
      ponto_pedido        = v.ponto_pedido_sugerido,
      estoque_maximo      = v.estoque_maximo_sugerido,
      estoque_seguranca   = v.estoque_seguranca_sugerido,
      cobertura_alvo_dias = v.cobertura_alvo_dias,
      parametro_cold_start = false,
      ultima_atualizacao_calculo = now()
    FROM public.v_sku_parametros_sugeridos v
    WHERE sp.empresa = v.empresa AND sp.sku_codigo_omie = v.sku_codigo_omie
      AND sp.empresa = p_empresa AND sp.parametro_cold_start = true
      AND v.status_sugestao = 'OK'
      AND v.ponto_pedido_sugerido IS NOT NULL AND v.estoque_maximo_sugerido IS NOT NULL
    RETURNING sp.sku_codigo_omie, sp.sku_descricao
  )
  INSERT INTO public.reposicao_cold_start_log (run_id, empresa, sku_codigo_omie, sku_descricao, acao, detalhe)
  SELECT p_run_id, p_empresa, g.sku_codigo_omie::text, g.sku_descricao, 'graduado', 'ganhou demanda (status OK)'
  FROM grad g;
  GET DIAGNOSTICS v_grad = ROW_COUNT;

  -- ── (2) CRIAR: comprável + de-para, sem linha, sem demanda OK → fallback conservador ──
  DROP TABLE IF EXISTS tmp_cold_cand;
  CREATE TEMP TABLE tmp_cold_cand ON COMMIT DROP AS
  SELECT e.sku_codigo_omie, e.sku_descricao, e.fornecedor_nome, e.estoque_catalogo
  FROM public.v_reposicao_cold_start_elegivel e
  WHERE e.estoque_catalogo IS NOT NULL
    AND NOT EXISTS (SELECT 1 FROM public.sku_parametros sp
                    WHERE sp.empresa = p_empresa AND sp.sku_codigo_omie = e.sku_codigo_omie)
    AND NOT EXISTS (SELECT 1 FROM public.v_sku_parametros_sugeridos v
                    WHERE v.empresa = p_empresa AND v.sku_codigo_omie = e.sku_codigo_omie
                      AND v.status_sugestao = 'OK')
  ORDER BY e.estoque_catalogo ASC, e.sku_codigo_omie
  LIMIT GREATEST(p_limite, 0);

  INSERT INTO public.sku_estoque_atual
    (empresa, sku_codigo_omie, estoque_fisico, estoque_disponivel, estoque_pendente_entrada, ultima_sincronizacao, fonte_sync)
  SELECT p_empresa, c.sku_codigo_omie::text, c.estoque_catalogo, c.estoque_catalogo, 0, now(), 'cold_start_seed'
  FROM tmp_cold_cand c
  ON CONFLICT (empresa, sku_codigo_omie) DO NOTHING;

  WITH ins AS (
    INSERT INTO public.sku_parametros
      (empresa, sku_codigo_omie, sku_descricao, fornecedor_nome,
       classe_abc, classe_xyz,
       estoque_minimo, ponto_pedido, estoque_maximo, estoque_seguranca, cobertura_alvo_dias,
       habilitado_reposicao_automatica, tipo_reposicao, ativo, parametro_cold_start)
    SELECT p_empresa, c.sku_codigo_omie, c.sku_descricao, c.fornecedor_nome,
       'C', 'Z',
       1, 1, 1 + 1, 0, 30,
       true, 'automatica', true, true
    FROM tmp_cold_cand c
    ON CONFLICT (empresa, sku_codigo_omie) DO NOTHING
    RETURNING sku_codigo_omie, sku_descricao
  )
  INSERT INTO public.reposicao_cold_start_log (run_id, empresa, sku_codigo_omie, sku_descricao, acao, habilitado, detalhe)
  SELECT p_run_id, p_empresa, i.sku_codigo_omie::text, i.sku_descricao, 'criado', true,
         'fallback conservador (pp=1/max=2) + estoque semeado do catálogo'
  FROM ins i;
  GET DIAGNOSTICS v_cri = ROW_COUNT;

  RETURN QUERY SELECT v_grad, v_cri;
END $$;


--
-- Name: reposicao_param_auto_resumo_tick(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_param_auto_resumo_tick() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $_$
DECLARE
  r record;
  v_hoje date := (now() AT TIME ZONE 'America/Sao_Paulo')::date;
  v_corpo text;
  v_altas text;
  v_reducoes text;
  v_segurados text;
  v_sem_efeito int;
BEGIN
  PERFORM pg_advisory_xact_lock(hashtext('param_auto_resumo'));
  SELECT * INTO r FROM public.reposicao_param_auto_run
    WHERE data_negocio_brt=v_hoje AND status='completo' AND resumo_enviado_em IS NULL
    ORDER BY concluido_em DESC LIMIT 1;
  IF NOT FOUND THEN RETURN; END IF;
  IF COALESCE(r.total_aplicados,0)=0 AND COALESCE(r.total_segurados,0)=0 THEN
    UPDATE public.reposicao_param_auto_run SET resumo_enviado_em=now() WHERE id=r.id;
    RETURN;
  END IF;

  SELECT string_agg(format('• %s: PP %s→%s, máx %s→%s (R$ +%s)',
            coalesce(nullif(btrim(sku_descricao), ''), sku_codigo_omie),
            coalesce(ponto_pedido_antes::text,'—'), coalesce(ponto_pedido_depois::text,'—'),
            coalesce(estoque_maximo_antes::text,'—'), coalesce(estoque_maximo_depois::text,'—'),
            round(impacto_rs)::text), E'\n' ORDER BY impacto_rs DESC)
    INTO v_altas FROM (
      SELECT * FROM public.reposicao_param_auto_log
      WHERE run_id=r.id AND status='aplicado' AND impacto_rs > 0
      ORDER BY impacto_rs DESC LIMIT 5) t;

  SELECT string_agg(format('• %s: PP %s→%s, máx %s→%s (R$ %s)',
            coalesce(nullif(btrim(sku_descricao), ''), sku_codigo_omie),
            coalesce(ponto_pedido_antes::text,'—'), coalesce(ponto_pedido_depois::text,'—'),
            coalesce(estoque_maximo_antes::text,'—'), coalesce(estoque_maximo_depois::text,'—'),
            round(impacto_rs)::text), E'\n' ORDER BY impacto_rs ASC)
    INTO v_reducoes FROM (
      SELECT * FROM public.reposicao_param_auto_log
      WHERE run_id=r.id AND status='aplicado' AND impacto_rs < 0
      ORDER BY impacto_rs ASC LIMIT 5) t;

  -- Segurados: mostra O QUE o fusível barrou (máx atual → sugerido). Se o sugerido faltar (run gravado
  -- pelo core antigo), cai no formato só-nome — nunca "→ ?".
  SELECT string_agg(
           CASE WHEN estoque_maximo_sugerido IS NOT NULL THEN
             format(E'• %s\n  quis subir máx %s → %s (barrado; giro %s/dia)',
               coalesce(nullif(btrim(sku_descricao), ''), sku_codigo_omie),
               coalesce(estoque_maximo_antes::text,'—'), estoque_maximo_sugerido::text,
               coalesce(round(demanda_media_diaria, 2)::text,'?'))
           ELSE
             format('• %s (máx atual %s, giro %s/dia)',
               coalesce(nullif(btrim(sku_descricao), ''), sku_codigo_omie),
               coalesce(estoque_maximo_antes::text,'—'),
               coalesce(round(demanda_media_diaria, 2)::text,'?'))
           END, E'\n' ORDER BY estoque_maximo_sugerido DESC NULLS LAST, estoque_maximo_antes DESC NULLS LAST)
    INTO v_segurados FROM (
      SELECT * FROM public.reposicao_param_auto_log
      WHERE run_id=r.id AND status='segurado'
      ORDER BY estoque_maximo_sugerido DESC NULLS LAST, estoque_maximo_antes DESC NULLS LAST LIMIT 5) t;

  SELECT count(*) INTO v_sem_efeito FROM public.reposicao_param_auto_log
    WHERE run_id=r.id AND status='aplicado' AND impacto_rs = 0;

  v_corpo :=
       format('%s parâmetros mudaram hoje (OBEN).', r.total_aplicados)
    || format(E'\nImpacto estimado total: R$ %s%s', round(COALESCE(r.impacto_total_rs,0)),
         CASE WHEN COALESCE(r.impacto_desconhecido_n,0)>0 THEN ' (+'||r.impacto_desconhecido_n||' sem custo)' ELSE '' END)
    || CASE WHEN v_altas    IS NOT NULL THEN E'\n\nMaiores altas:\n'    || v_altas    ELSE '' END
    || CASE WHEN v_reducoes IS NOT NULL THEN E'\n\nMaiores reduções:\n' || v_reducoes ELSE '' END
    || format(E'\n\nSegurados pelo fusível (confira): %s', COALESCE(r.total_segurados,0))
    || CASE WHEN v_segurados IS NOT NULL THEN E'\n' || v_segurados ELSE '' END
    || CASE WHEN COALESCE(v_sem_efeito,0) > 0
            THEN format(E'\n\n+%s ajuste(s) sem efeito na compra de hoje.', v_sem_efeito) ELSE '' END
    || E'\n\nVeja e reverta em: /admin/reposicao/mudancas-automaticas';

  INSERT INTO public.fornecedor_alerta (tipo, titulo, mensagem, empresa, severidade, status)
    VALUES ('param_auto_resumo', 'Parâmetros de reposição — resumo do dia', v_corpo, r.empresa, 'info', 'pendente_notificacao');
  UPDATE public.reposicao_param_auto_run SET resumo_enviado_em=now() WHERE id=r.id;
END;
$_$;


--
-- Name: reposicao_param_limbo_watchdog(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_param_limbo_watchdog() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_limiar   int := 30;
  v_atual    int;
  v_anterior int;
  v_msg      text;
BEGIN
  SELECT count(*) INTO v_atual
  FROM sku_parametros
  WHERE empresa = 'OBEN' AND habilitado_reposicao_automatica = true
    AND (ponto_pedido IS NULL OR estoque_maximo IS NULL);

  SELECT limbo_count INTO v_anterior
  FROM reposicao_param_limbo_log
  WHERE empresa = 'OBEN' AND medido_em < CURRENT_DATE
  ORDER BY medido_em DESC
  LIMIT 1;

  IF v_anterior IS NOT NULL AND (v_atual - v_anterior) > v_limiar THEN
    v_msg := 'SKUs habilitados SEM parâmetro saltaram de ' || v_anterior || ' para ' || v_atual ||
             ' (+' || (v_atual - v_anterior) || ') em 1 dia — possível regressão: o cron voltou a ZERAR ' ||
             'config (verificar se atualizar_parametros_numericos_skus ainda usa COALESCE — fix #521).';
    INSERT INTO fin_alertas (company, tipo, severidade, mensagem, valor, threshold, contexto)
    VALUES ('oben', 'reposicao_param_limbo_salto', 'critico', v_msg, v_atual, (v_anterior + v_limiar),
            jsonb_build_object('atual', v_atual, 'anterior', v_anterior, 'delta', (v_atual - v_anterior), 'limiar', v_limiar))
    ON CONFLICT (company, tipo) WHERE dismissed_at IS NULL DO NOTHING;
    IF FOUND THEN
      INSERT INTO fornecedor_alerta (empresa, tipo, severidade, titulo, mensagem, status)
      VALUES ('OBEN', 'outro', 'urgente', '[Reposição] Salto de SKUs sem parâmetro', v_msg, 'pendente_notificacao');
    END IF;
  ELSE
    UPDATE fin_alertas SET dismissed_at = now()
    WHERE company = 'oben' AND tipo = 'reposicao_param_limbo_salto' AND dismissed_at IS NULL;
  END IF;

  INSERT INTO reposicao_param_limbo_log (empresa, medido_em, limbo_count)
  VALUES ('OBEN', CURRENT_DATE, v_atual)
  ON CONFLICT (empresa, medido_em) DO UPDATE SET limbo_count = EXCLUDED.limbo_count, criado_em = now();
END;
$$;


--
-- Name: reposicao_pedido_auto_aprovavel(bigint, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_pedido_auto_aprovavel(p_pedido_id bigint, p_threshold numeric, p_delta_max numeric, p_cooldown_horas numeric) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $_$
DECLARE
  p RECORD;
  v_grupo text;
  v_valor numeric;     -- valor REAL (soma dos itens) — fonte de verdade do disparo
  v_ref numeric;       -- v2: MEDIANA dos últimos N eventos de compra do grupo
  v_n int;             -- v2: nº de eventos de referência (mínimo 3)
BEGIN
  -- P1.2: trava a linha. Qualquer promo/regeneração/aprovação concorrente espera este
  -- lock; o claim do tick (mesma transação) vê o estado que esta função validou.
  SELECT * INTO p FROM public.pedido_compra_sugerido WHERE id = p_pedido_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'pedido inexistente');
  END IF;

  -- P1.1: piloto é OBEN-only (spec §1). Sayerlack de outra empresa fica humano.
  IF p.empresa <> 'OBEN' THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'fora do escopo do piloto (só OBEN)');
  END IF;

  IF p.status <> 'pendente_aprovacao' OR p.aprovado_em IS NOT NULL OR p.cancelado_em IS NOT NULL THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'não está pendente');
  END IF;

  IF COALESCE(p.tipo_ciclo, 'normal') <> 'normal' THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'ciclo não-normal (oportunidade/promoção é decisão humana)');
  END IF;

  IF p.split_parent_id IS NOT NULL THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'pedido-filho de split');
  END IF;

  IF COALESCE(p.num_skus, 0) <= 0 THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'sem SKUs');
  END IF;

  v_grupo := COALESCE(p.grupo_codigo, '');

  -- v2 (Codex): veta só 'forward_buying' (infla qtde = aposta de estoque adiantada, decisão
  -- humana; tem o próprio guardrail de delta na geração). LIBERA 'flat' (só desconto de preço,
  -- qtde inalterada — benigno; era a causa de parte da inatividade da v1, que vetava qualquer
  -- modo_promocao). O delta assimétrico abaixo já protege o VALOR final.
  IF EXISTS (
    SELECT 1 FROM public.pedido_compra_item i
    WHERE i.pedido_id = p.id AND i.modo_promocao = 'forward_buying'
  ) THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'item em forward_buying (aposta de estoque — decisão humana)');
  END IF;

  -- P2.11: guard de item que o disparo (#422/#433) barraria. Forma POSITIVA (> 0 AND <
  -- Infinity) p/ rejeitar também NaN/Infinity — "preco<=0" é FALSE p/ NaN e não pegaria.
  -- [PRECO-AUSENTE] NOT COALESCE(..., false): NULL (custo desconhecido vindo do motor) colapsa
  -- p/ false → flagueia como inválido. Sem o COALESCE, NOT(NULL AND ...)=NULL e a linha ESCAPA
  -- do EXISTS → um pedido com item de custo desconhecido poderia AUTO-APROVAR (Codex challenge).
  IF EXISTS (
    SELECT 1 FROM public.pedido_compra_item i
    WHERE i.pedido_id = p.id
      AND NOT COALESCE(i.preco_unitario > 0 AND i.preco_unitario < 'Infinity'::numeric
               AND i.qtde_final > 0 AND i.qtde_final < 'Infinity'::numeric, false)
  ) THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'item com preço/qtde inválido');
  END IF;

  -- P1.2: o VALOR que importa é o que será comprado = soma dos itens, NÃO o cabeçalho
  -- (valor_total pode divergir; o disparo manda os itens). A régua vale sobre ele.
  SELECT SUM(i.qtde_final * i.preco_unitario) INTO v_valor
  FROM public.pedido_compra_item i WHERE i.pedido_id = p.id;
  IF v_valor IS NULL OR NOT (v_valor > 0 AND v_valor < 'Infinity'::numeric) THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'sem itens válidos para somar');
  END IF;
  IF v_valor < p_threshold THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'abaixo da régua (soma dos itens)');
  END IF;

  -- Humano já mexeu → a decisão é dele (trade-off "ajustou → aprova" do #711).
  IF EXISTS (
    SELECT 1 FROM public.pedido_compra_item i
    WHERE i.pedido_id = p.id AND i.ajustado_humano IS TRUE
  ) THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'itens ajustados por humano');
  END IF;

  -- P2.7: cooldown enxerga falha de DISPARO (status='falha_envio') E de PORTAL
  -- (status_envio_portal terminal/ambíguo — SKU sem de-para vira 'erro_nao_retentavel'
  -- sem mexer no status principal). Auto-aprovado do fornecedor que falhou há pouco →
  -- exceção humana resolve antes de a automação voltar ao fornecedor.
  IF EXISTS (
    SELECT 1 FROM public.pedido_compra_sugerido f
    WHERE f.empresa = p.empresa
      AND f.fornecedor_nome = p.fornecedor_nome
      AND f.aprovado_por LIKE 'auto:%'
      AND (f.status = 'falha_envio'
           OR f.status_envio_portal IN ('erro_nao_retentavel', 'falha_envio_portal', 'indeterminado_requer_conciliacao'))
      AND f.atualizado_em > now() - (p_cooldown_horas * interval '1 hour')
  ) THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'cooldown: auto-aprovação recente do fornecedor falhou (disparo/portal)');
  END IF;

  -- P1.6: raio cumulativo — no MÁXIMO 1 auto-aprovado não-disparado por grupo. Sem isto,
  -- N pedidos de SKUs novos do grupo passam cada um contra a mesma referência antiga e a
  -- exposição antes do corte vira ilimitada. O 2º espera o 1º disparar (e virar referência).
  IF EXISTS (
    SELECT 1 FROM public.pedido_compra_sugerido q
    WHERE q.empresa = p.empresa
      AND q.fornecedor_nome = p.fornecedor_nome
      AND COALESCE(q.grupo_codigo, '') = v_grupo
      AND q.aprovado_por LIKE 'auto:%'
      AND q.status = 'aprovado_aguardando_disparo'
      AND q.id <> p.id
  ) THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'já há auto-aprovado do grupo aguardando disparo');
  END IF;

  -- v2: referência = MEDIANA dos últimos 5 EVENTOS de compra do grupo. Cada evento = SUM por
  -- data_ciclo (<90d, compra real) — colapsa o pré-split (pai → filhos na mesma data) como na v1,
  -- mas agora a mediana de VÁRIOS eventos, não o último solto (ruidoso: normal teve R$1031 e
  -- R$7377). MÍNIMO 3 eventos (Codex: percentile_cont com 2 valores interpola a média = falsa
  -- mediana; com [1000,16000] daria 8500).
  -- ⚠️ Codex P2.2 (teórico, sem caminho atual): a referência soma valor_total do CABEÇALHO dos
  -- históricos; o candidato (v_valor) usa a soma dos ITENS. Nos disparados o cabeçalho = itens (a
  -- geração seta valor_total = SUM dos itens e o disparo não muda). Se um dia divergirem (cabeçalho
  -- inflado), o teto poderia subir. Monitorado no piloto; fix futuro = somar itens nos históricos.
  WITH eventos AS (
    SELECT r.data_ciclo, SUM(r.valor_total) AS valor
    FROM public.pedido_compra_sugerido r
    WHERE r.empresa = p.empresa
      AND r.fornecedor_nome = p.fornecedor_nome
      AND COALESCE(r.grupo_codigo, '') = v_grupo
      AND r.id <> p.id
      AND r.criado_em > now() - interval '90 days'
      AND (r.omie_pedido_compra_numero IS NOT NULL OR r.status IN ('disparado', 'concluido_recebido'))
    GROUP BY r.data_ciclo
    ORDER BY r.data_ciclo DESC
    LIMIT 5
  )
  SELECT percentile_cont(0.5) WITHIN GROUP (ORDER BY valor), count(*)
    INTO v_ref, v_n FROM eventos;

  IF v_n < 3 THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'menos de 3 compras de referência do grupo em 90d');
  END IF;
  IF v_ref IS NULL OR NOT (v_ref > 0 AND v_ref < 'Infinity'::numeric) THEN
    RETURN jsonb_build_object('elegivel', false, 'motivo', 'mediana de referência inválida');
  END IF;

  -- v2: delta ASSIMÉTRICO — só trava comprar MAIS que mediana×(1+delta_max). Comprar <= mediana
  -- SEMPRE passa (conservador: menos capital; a régua R$3k já é o piso). O risco money-path da
  -- auto-aprovação é comprar DEMAIS; pedido muito menor que o típico é seguro (Codex: humano
  -- semeia a mediana, a automação alcança depois). delta_pct negativo = comprou menos (ok).
  IF v_valor > v_ref * (1 + p_delta_max) THEN
    RETURN jsonb_build_object('elegivel', false,
      'motivo', 'acima do típico: ' || round(v_valor)::text || ' > mediana ' || round(v_ref)::text
        || ' × ' || round((1 + p_delta_max), 2)::text,
      'valor_anterior', v_ref,
      'delta_pct', round(100.0 * (v_valor - v_ref) / v_ref, 1));
  END IF;

  RETURN jsonb_build_object('elegivel', true,
    'valor_anterior', v_ref,
    'delta_pct', round(100.0 * (v_valor - v_ref) / v_ref, 1),
    'valor_itens', v_valor);
END;
$_$;


--
-- Name: reposicao_persistir_qtde_inteira(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_persistir_qtde_inteira(p_pedido_id bigint) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_ajustados integer;
BEGIN
  UPDATE pedido_compra_item
    SET qtde_sugerida = ceil(qtde_sugerida),
        qtde_final    = ceil(qtde_final),
        valor_linha   = ceil(qtde_final) * preco_unitario
  WHERE pedido_id = p_pedido_id
    AND (qtde_final    IS DISTINCT FROM ceil(qtde_final)
      OR qtde_sugerida IS DISTINCT FROM ceil(qtde_sugerida));
  GET DIAGNOSTICS v_ajustados = ROW_COUNT;

  IF v_ajustados > 0 THEN
    UPDATE pedido_compra_sugerido
      SET valor_total = (
        SELECT COALESCE(sum(valor_linha), 0)
        FROM pedido_compra_item WHERE pedido_id = p_pedido_id
      )
    WHERE id = p_pedido_id;
  END IF;

  RETURN v_ajustados;
END;
$$;


--
-- Name: reposicao_pos_candidatos(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_pos_candidatos(p_empresa text) RETURNS TABLE(pedido_id bigint, omie_codigo_pedido text, data_ciclo date, idade_dias integer, na_janela_7d boolean, valor_total numeric, itens_sem_valor integer, visto_status text, po_no_espelho boolean, fornecedor_nome text, canal_usado text, portal_protocolo text, status_envio_portal text, resposta_canal jsonb, tem_protocolo boolean, tem_status_portal boolean, tem_resposta_canal boolean, tem_canal boolean, algum_sinal_de_canal boolean, marcador_run_id uuid, marcador_seq bigint)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_empresa public.empresa_reposicao := upper(btrim(p_empresa))::public.empresa_reposicao;
BEGIN
  -- Gate cron-or-staff NULL-aware: uid presente exige staff; uid NULL (service_role/cron SQL-local) passa.
  -- ⚠️ NUNCA gatear por auth.role()='service_role' — o pg_cron roda como postgres SEM JWT (auth.role()=NULL)
  -- e o gate mataria o cron em SILÊNCIO (reposicao.md: mordido 2x, migrations 20260627130000/20260627200000).
  IF (SELECT auth.uid()) IS NOT NULL
     -- ⚠️ IS NOT TRUE, não NOT(...): pode_ver_carteira_completa() era TRI-STATE (o gate ANTERIOR; private.cap_compras_ler faz COALESCE e nunca devolve NULL, entao IS NOT TRUE fica como defesa em profundidade). Para um `employee` SEM linha
     -- em commercial_roles ela retorna NULL, e `NOT NULL` = NULL — o IF não entrava e a SECURITY DEFINER
     -- ENTREGAVA TUDO (protocolo, fornecedor, JSON cru). Bypass real (Codex v11), e viola o fail-closed do
     -- CLAUDE.md ("query de role falha → role null, approval false"). IS NOT TRUE trata NULL como negado e
     -- preserva o uid NULL do cron, que é barrado antes pelo primeiro AND.
     AND (SELECT private.cap_compras_ler((SELECT auth.uid()))) IS NOT TRUE THEN
    RAISE EXCEPTION 'reposicao_pos_candidatos: acesso negado' USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  WITH marcador AS (
    -- "último completo válido" = maior fencing seq com volume_ok TRUE. Sem marcador → CROSS JOIN vazio →
    -- retorna VAZIO. Fail-closed: sem base de verdade não se classifica ninguém como ausente.
    SELECT r.run_id, r.seq
    FROM public.reposicao_pedidos_compra_run r
    WHERE r.empresa = v_empresa AND r.status = 'ok' AND r.volume_ok IS TRUE
    ORDER BY r.seq DESC
    LIMIT 1
  ),
  base AS (
    SELECT
      p.id AS pedido_id,
      p.omie_pedido_compra_id AS omie_codigo_pedido,
      p.data_ciclo::date AS data_ciclo,
      (now()::date - p.data_ciclo::date)::integer AS idade_dias,
      p.fornecedor_nome,
      p.canal_usado,
      p.portal_protocolo,
      p.status_envio_portal,
      p.resposta_canal,
      m.run_id AS marcador_run_id,
      m.seq AS marcador_seq,
      ls.run_id AS visto_run_id,
      -- ⚠️ sum() IGNORA NULL: itens (100.00, NULL) davam 100.00, apresentando SUBTOTAL como total apurado —
      -- fabricação de número, o que o money-path.md proíbe ("ausente ≠ zero"). Agora o total só existe se
      -- TODOS os itens têm valor; senão NULL, e itens_sem_valor diz por quê (Codex v8).
      (SELECT CASE WHEN count(*) FILTER (WHERE i.valor_linha IS NULL) = 0
                   THEN sum(i.valor_linha) END
         FROM public.pedido_compra_item i WHERE i.pedido_id = p.id) AS valor_total,
      (SELECT count(*) FILTER (WHERE i.valor_linha IS NULL)
         FROM public.pedido_compra_item i WHERE i.pedido_id = p.id)::integer AS itens_sem_valor,
      -- ⚠️ NULL (não FALSE) quando a identidade é ILEGÍVEL: `EXISTS(... = NULL)` retorna false, e a RPC
      -- estaria AFIRMANDO ausência no espelho sem sequer conseguir identificar o PO (Codex v7).
      -- "Não apurei" ≠ "não há" — a mesma distinção de visto_status='identidade_nao_interpretavel'.
      CASE WHEN public.reposicao__po_id(p.omie_pedido_compra_id) IS NULL THEN NULL ELSE EXISTS (
        SELECT 1 FROM public.purchase_orders_tracking t
        WHERE t.empresa = v_empresa
          -- identidade NUMÉRICA canônica (reposicao__po_id): '00101' e '101' são o MESMO PO; whitespace de
          -- borda tolerado, interno invalida; fora do range de bigint → NULL em vez de derrubar a RPC.
          AND t.omie_codigo_pedido = public.reposicao__po_id(p.omie_pedido_compra_id)
      ) END AS po_no_espelho
    FROM public.pedido_compra_sugerido p
    CROSS JOIN marcador m
    LEFT JOIN public.reposicao_po_last_seen ls
           ON ls.empresa = v_empresa
          AND ls.omie_codigo_pedido = public.reposicao__po_id(p.omie_pedido_compra_id)
    -- ⚠️ `pedido_compra_sugerido.empresa` é **text** ('OBEN'); as outras tabelas usam o ENUM empresa_reposicao.
    -- text = enum direto é erro de TIPO em runtime (PL/pgSQL late-bound: o CREATE passa, quebra ao EXECUTAR).
    WHERE upper(btrim(p.empresa)) = v_empresa::text
      AND p.status IN ('disparado', 'aprovado_aguardando_disparo')
      AND p.omie_pedido_compra_id IS NOT NULL
      AND btrim(p.omie_pedido_compra_id) <> ''
      -- CANDIDATO = o PO não foi visto no marcador atual (carimbado por run ANTERIOR ou NUNCA carimbado).
      AND (ls.run_id IS NULL OR ls.run_id <> m.run_id)
  )
  SELECT
    b.pedido_id,
    b.omie_codigo_pedido,
    b.data_ciclo,
    b.idade_dias,
    -- DANO ATIVO = a CTE em_transito só soma disparados dos últimos 7d. Idade = PRIORIDADE, não verdade.
    -- NOME FACTUAL: a RPC apura a JANELA, nao o dano (um aprovado_aguardando_disparo de 3 dias sem canal
    -- nenhum recebia dano_ativo=true so pela idade — Codex v9). Quem decide se ha dano e o consumidor.
    (b.idade_dias BETWEEN 0 AND 7) AS na_janela_7d,
    b.valor_total,
    b.itens_sem_valor,
    -- ⚠️ identidade ILEGÍVEL não é "nunca visto": o LEFT JOIN não pôde nem comparar. Afirmar ausência aqui
    -- era falha ABERTA (Codex v6 P1) — e o assert J3 chegava a FIXAR esse falso-positivo como esperado.
    CASE
      WHEN public.reposicao__po_id(b.omie_codigo_pedido) IS NULL THEN 'identidade_nao_interpretavel'
      -- 'sem_registro_last_seen', não 'nunca_carimbado': a RPC prova a ausência ATUAL da linha, não que o PO
      -- nunca foi visto — a linha pode ter sido apagada/reconstruída (Codex v10). "Nunca" é afirmação de
      -- histórico, e histórico esta RPC não consulta.
      WHEN b.visto_run_id IS NULL                                THEN 'sem_registro_last_seen'
      -- 'outro_run', não 'anterior': a RPC só prova `run_id <> marcador`. O outro run pode ser POSTERIOR
      -- (seq maior, ainda não promovido a marcador) ou um UUID sem linha na tabela de runs (Codex v11).
      -- Afirmar "anterior" seria temporalidade não apurada.
      ELSE 'visto_em_outro_run'
    END AS visto_status,
    -- SINAL FRACO: o sync do tracking é upsert-only (nunca remove) → ausência do espelho NÃO prova exclusão.
    b.po_no_espelho,
    b.fornecedor_nome,
    b.canal_usado,
    -- 🔑 SEM REGEX SEMÂNTICA (Codex v9). Quatro rodadas seguidas acharam um valor que enganava o rótulo:
    -- 'su cesso' virava sucesso por coerção de whitespace; 'sem sucesso' casava a regex; e a guarda de
    -- negação criou falso-NEGATIVO ('login: sucesso' — o `in` casa no fim de "log-IN") e falso-POSITIVO
    -- ('não houve sucesso' — o [^a-z]* não atravessa "houve"). Interpretar texto LIVRE de terceiro por regex
    -- não converge, e o rótulo não decide nada desde que a coluna `rota` morreu na v4.
    -- Ficam só FATOS BINÁRIOS incontestáveis. O humano/PR3 lê os campos crus (portal_protocolo,
    -- status_envio_portal, resposta_canal, canal_usado) e interpreta com o contexto que a RPC não tem.
    b.portal_protocolo,
    b.status_envio_portal,
    b.resposta_canal,
    (public.reposicao__trim(b.portal_protocolo) <> '')    AS tem_protocolo,
    (public.reposicao__trim(b.status_envio_portal) <> '') AS tem_status_portal,
    -- ⚠️ JSON null ('null'::jsonb) NÃO é SQL NULL: `IS NOT NULL` dava true e a RPC afirmava resposta
    -- existente onde não há nenhuma (Codex v10).
    (b.resposta_canal IS NOT NULL AND jsonb_typeof(b.resposta_canal) <> 'null') AS tem_resposta_canal,
    (public.reposicao__trim(b.canal_usado) <> '')         AS tem_canal,
    -- "há algum indício de que o fornecedor foi acionado?" — OR simples, sem inferência.
    (public.reposicao__trim(b.portal_protocolo) <> ''
      OR public.reposicao__trim(b.status_envio_portal) <> ''
      OR (b.resposta_canal IS NOT NULL AND jsonb_typeof(b.resposta_canal) <> 'null')
      OR public.reposicao__trim(b.canal_usado) <> '')     AS algum_sinal_de_canal,
    b.marcador_run_id,
    b.marcador_seq
  FROM base b
  ORDER BY (b.idade_dias BETWEEN 0 AND 7) DESC, b.valor_total DESC NULLS LAST, b.pedido_id;
END;
$$;


--
-- Name: FUNCTION reposicao_pos_candidatos(p_empresa text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.reposicao_pos_candidatos(p_empresa text) IS 'PR2 (NÃO-MUTANTE): pedidos disparado/aprovado cujo PO não apareceu no último run VÁLIDO. LISTA e EVIDENCIA — NÃO decide. Deliberadamente SEM rota automática: em prod 59/59 dos disparados acionaram portal do fornecedor (46 sayerlack + 13 b2b, 0 sem sinal), então "elegível a auto-cancelamento" é logicamente vazio; e canal/status/resposta são text/jsonb livres onde regex prova presença, nunca ausência. Todo candidato exige decisão humana; o PR3 deve provar por ID no Omie e tratar o compromisso com o fornecedor (provável: RECRIAR o PO, não cancelar). Sem marcador válido retorna VAZIO (fail-closed).';


--
-- Name: reposicao_publicar_run_completo(text, uuid, bigint, date, date, bigint[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_publicar_run_completo(p_empresa text, p_run_id uuid, p_seq bigint, p_janela_de date, p_janela_ate date, p_ids bigint[]) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_empresa       public.empresa_reposicao := upper(btrim(p_empresa))::public.empresa_reposicao;
  v_ids_distintos integer;
  v_baseline      numeric;
  v_volume_ok     boolean;
  v_agora         timestamptz;
BEGIN
  IF p_seq IS NULL OR p_seq <= 0 THEN
    RAISE EXCEPTION 'reposicao_publicar_run_completo: p_seq inválido (%) — fencing token deve ser > 0', p_seq
      USING ERRCODE = 'check_violation';
  END IF;
  PERFORM pg_advisory_xact_lock(hashtext('reposicao_run:' || lower(btrim(p_empresa))));
  v_agora := clock_timestamp();

  SELECT count(DISTINCT x) INTO v_ids_distintos
  FROM unnest(COALESCE(p_ids, ARRAY[]::bigint[])) AS x
  WHERE x IS NOT NULL AND x > 0;

  SELECT percentile_cont(0.5) WITHIN GROUP (ORDER BY r.ids_distintos)
  INTO v_baseline
  FROM (
    SELECT ids_distintos
    FROM public.reposicao_pedidos_compra_run
    WHERE empresa = v_empresa
      AND status = 'ok'
      AND ids_distintos > 0
      AND volume_ok IS NOT FALSE
      AND (janela_ate - janela_de) = (p_janela_ate - p_janela_de)
      AND finalizado_em > now() - interval '10 days'
    ORDER BY seq DESC
    LIMIT 5
  ) r;

  IF v_ids_distintos = 0 THEN
    v_volume_ok := TRUE;
  ELSIF v_baseline IS NULL OR v_baseline <= 0 THEN
    v_volume_ok := NULL;
  ELSE
    v_volume_ok := (v_ids_distintos::numeric >= 0.9 * v_baseline);
  END IF;

  INSERT INTO public.reposicao_pedidos_compra_run
    (run_id, seq, empresa, janela_de, janela_ate, ids_distintos, volume_baseline, volume_ok, status, finalizado_em)
  VALUES
    (p_run_id, p_seq, v_empresa, p_janela_de, p_janela_ate, v_ids_distintos,
     CASE WHEN v_baseline IS NULL THEN NULL ELSE round(v_baseline)::integer END,
     v_volume_ok, 'ok', v_agora);

  IF v_volume_ok IS TRUE THEN
    INSERT INTO public.reposicao_po_last_seen (empresa, omie_codigo_pedido, run_id, visto_seq, visto_em)
    SELECT v_empresa, x, p_run_id, p_seq, v_agora
    FROM unnest(p_ids) AS x
    WHERE x IS NOT NULL AND x > 0
    ON CONFLICT (empresa, omie_codigo_pedido) DO UPDATE
      SET run_id = EXCLUDED.run_id, visto_seq = EXCLUDED.visto_seq, visto_em = EXCLUDED.visto_em
      WHERE public.reposicao_po_last_seen.visto_seq < EXCLUDED.visto_seq;
  END IF;

  RETURN v_volume_ok;
END;
$$;


--
-- Name: reposicao_sincronizar_embalagem_wp(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reposicao_sincronizar_embalagem_wp(p_empresa text DEFAULT 'oben'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_disparado_por text;
  v_cores int := 0;
  v_linhas int := 0;
  v_ins int;
  r record;
  v_grupo uuid;
BEGIN
  -- Gate cron-or-staff: usuário logado exige staff; cron (auth.uid()=NULL) passa.
  IF v_uid IS NOT NULL
     AND NOT (has_role(v_uid,'employee'::app_role) OR has_role(v_uid,'master'::app_role)) THEN
    RAISE EXCEPTION 'não autorizado' USING ERRCODE = '42501';
  END IF;
  v_disparado_por := CASE WHEN v_uid IS NULL THEN 'cron' ELSE 'manual:'||v_uid::text END;

  FOR r IN
    WITH wp AS (
      SELECT substring(descricao FROM '^(WP[0-9]+\.[0-9]+)') AS cor,
             substring(descricao FROM '^WP[0-9]+\.[0-9]+([A-Z0-9]+)') AS sufixo,
             omie_codigo_produto
      FROM public.omie_products
      WHERE account = p_empresa AND ativo
        AND descricao ~ '^WP[0-9]+\.[0-9]+(QT|GL) '
    )
    SELECT cor,
           max(omie_codigo_produto) FILTER (WHERE sufixo='QT') AS qt,
           max(omie_codigo_produto) FILTER (WHERE sufixo='GL') AS gl
    FROM wp GROUP BY cor
    HAVING count(*) FILTER (WHERE sufixo='QT') = 1
       AND count(*) FILTER (WHERE sufixo='GL') = 1
  LOOP
    v_cores := v_cores + 1;
    -- Reusa o grupo da cor se já cadastrada; senão gera novo.
    SELECT grupo_id INTO v_grupo
    FROM public.sku_embalagem_equivalencia
    WHERE empresa = p_empresa AND ativo AND sku_codigo_omie IN (r.qt::text, r.gl::text)
    LIMIT 1;
    IF v_grupo IS NULL THEN v_grupo := gen_random_uuid(); END IF;

    -- Insere só as embalagens faltantes (idempotente; ON CONFLICT é atômico no índice).
    INSERT INTO public.sku_embalagem_equivalencia
      (empresa, grupo_id, sku_codigo_omie, unidade_base, fator_para_base, fornecedor_nome, ativo, criado_por)
    SELECT p_empresa, v_grupo, x.sku::text, 'QT', x.fator, 'Sayerlack', true, 'auto:embalagem-wp'
    FROM (VALUES (r.qt, 1::numeric), (r.gl, 4::numeric)) AS x(sku, fator)
    ON CONFLICT (empresa, sku_codigo_omie) WHERE ativo DO NOTHING;
    GET DIAGNOSTICS v_ins = ROW_COUNT;
    v_linhas := v_linhas + v_ins;
  END LOOP;

  INSERT INTO public.reposicao_embalagem_sync_log (empresa, disparado_por, cores_elegiveis, linhas_inseridas)
  VALUES (p_empresa, v_disparado_por, v_cores, v_linhas);

  RETURN jsonb_build_object('empresa', p_empresa, 'cores_elegiveis', v_cores, 'linhas_inseridas', v_linhas);
END $$;


--
-- Name: request_customer_metrics_refresh(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.request_customer_metrics_refresh() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
DECLARE v_uid uuid := auth.uid();
BEGIN
  IF v_uid IS NULL
     OR NOT (COALESCE(public.has_role(v_uid, 'employee'::public.app_role), false)
          OR COALESCE(public.has_role(v_uid, 'master'::public.app_role),   false)) THEN
    RAISE EXCEPTION 'Acesso negado: requer perfil staff' USING ERRCODE = '42501';
  END IF;
  PERFORM public.refresh_customer_metrics();
END;
$$;


--
-- Name: resgatar_recompensa(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.resgatar_recompensa(p_reward_key text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_points integer; v_name text; v_saldo bigint; v_redemption_id uuid;
BEGIN
  IF v_uid IS NULL THEN RAISE EXCEPTION 'nao autenticado'; END IF;
  CASE p_reward_key
    WHEN 'frete_10'       THEN v_points := 100; v_name := '10% desconto no frete';
    WHEN 'afiacao_gratis' THEN v_points := 300; v_name := 'Afiação grátis (1 ferramenta)';
    WHEN 'kit_manutencao' THEN v_points := 500; v_name := 'Kit de manutenção';
    WHEN 'desconto_20'    THEN v_points := 750; v_name := 'Desconto 20% no próximo pedido';
    ELSE RAISE EXCEPTION 'recompensa desconhecida: %', p_reward_key;
  END CASE;
  PERFORM pg_advisory_xact_lock(hashtextextended('loyalty_resgate:' || v_uid::text, 0));
  SELECT COALESCE(SUM(points), 0) INTO v_saldo FROM public.loyalty_points WHERE user_id = v_uid;
  IF v_saldo < v_points THEN RAISE EXCEPTION 'saldo insuficiente: % < %', v_saldo, v_points; END IF;
  INSERT INTO public.loyalty_redemptions (user_id, reward_name, points_spent, status)
  VALUES (v_uid, v_name, v_points, 'pendente') RETURNING id INTO v_redemption_id;
  INSERT INTO public.loyalty_points (user_id, points, type, description)
  VALUES (v_uid, -v_points, 'resgate', 'Resgate: ' || v_name);
  RETURN v_redemption_id;
END;
$$;


--
-- Name: resolve_markup_policy(text, bigint, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.resolve_markup_policy(p_empresa text, p_codigo bigint, p_familia text, p_tier text DEFAULT NULL::text) RETURNS TABLE(piso_markup numeric, meta_markup numeric)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  WITH produto AS (
    SELECT mp.piso_markup, mp.meta_markup FROM public.markup_policy mp
    WHERE mp.account = lower(p_empresa) AND mp.tier IS NULL
      AND ((mp.escopo='sku' AND mp.sku_codigo=p_codigo) OR (mp.escopo='familia' AND p_familia IS NOT NULL AND mp.familia=p_familia) OR (mp.escopo='conta'))
    ORDER BY CASE mp.escopo WHEN 'sku' THEN 1 WHEN 'familia' THEN 2 ELSE 3 END LIMIT 1
  ),
  por_tier AS (
    SELECT mp.piso_markup, mp.meta_markup FROM public.markup_policy mp
    WHERE mp.account = lower(p_empresa) AND p_tier IS NOT NULL AND mp.tier=p_tier
      AND ((mp.escopo='sku' AND mp.sku_codigo=p_codigo) OR (mp.escopo='familia' AND p_familia IS NOT NULL AND mp.familia=p_familia) OR (mp.escopo='conta'))
    ORDER BY CASE mp.escopo WHEN 'sku' THEN 1 WHEN 'familia' THEN 2 ELSE 3 END LIMIT 1
  )
  SELECT GREATEST((SELECT piso_markup FROM produto),(SELECT piso_markup FROM por_tier)) AS piso_markup,
         GREATEST((SELECT meta_markup FROM produto),(SELECT meta_markup FROM por_tier)) AS meta_markup
  WHERE (SELECT piso_markup FROM produto) IS NOT NULL OR (SELECT piso_markup FROM por_tier) IS NOT NULL;
$$;


--
-- Name: resolver_outlier(bigint, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.resolver_outlier(p_evento_id bigint, p_decisao text, p_justificativa text DEFAULT NULL::text, p_usuario_email text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_evento RECORD;
BEGIN
  -- Gate de staff: byte-a-byte o da prod.
  IF auth.uid() IS NULL OR NOT (public.has_role(auth.uid(), 'employee'::app_role) OR public.has_role(auth.uid(), 'master'::app_role)) THEN
    RAISE EXCEPTION 'Acesso negado: requer perfil staff' USING ERRCODE = '42501';
  END IF;

  -- 'aceitar' é a única decisão. Rejeição EXPLÍCITA (não normalizar silenciosamente para
  -- 'aceitar'): na janela entre o apply e o Publish, a tela velha ainda mostra os botões
  -- antigos — ela tem de FALHAR FECHADA em vez de gravar sob semântica que não existe mais.
  -- ERRCODE explícito para o teste negativo capturar a condição certa e re-lançar o resto.
  IF p_decisao <> 'aceitar' THEN
    RAISE EXCEPTION 'Decisão inválida: %. Esta tela é de revisão: a observação permanece no cálculo — use aceitar.', p_decisao
      USING ERRCODE = '22023';
  END IF;

  SELECT * INTO v_evento FROM eventos_outlier WHERE id = p_evento_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Evento outlier % não encontrado', p_evento_id;
  END IF;
  IF v_evento.status != 'pendente' THEN
    RAISE EXCEPTION 'Evento já resolvido com status: %', v_evento.status;
  END IF;

  UPDATE eventos_outlier
  SET status = 'aceito', decidido_em = now(),
      decidido_por = p_usuario_email, justificativa_decisao = p_justificativa
  WHERE id = p_evento_id;

  RETURN jsonb_build_object('evento_id', p_evento_id, 'novo_status', 'aceito', 'decisao', p_decisao);
END;
$$;


--
-- Name: FUNCTION resolver_outlier(p_evento_id bigint, p_decisao text, p_justificativa text, p_usuario_email text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.resolver_outlier(p_evento_id bigint, p_decisao text, p_justificativa text, p_usuario_email text) IS 'Registra a revisão humana de um evento de outlier. ACEITAR é a única decisão: a observação permanece no cálculo. ''excluir'' e ''ignorar'' foram REMOVIDOS (2026-07-16). ''excluir'' nunca alcançou o motor (observacoes_excluidas não entra na cadeia de estatística) e, medido em prod, não há efeito para ligar no leadtime (ss/pp invariantes); no lado da venda o efeito seria grande demais para um botão sem gate. ''ignorar'' arquivava igual a ''aceitar'' e nunca foi usado. Spec: docs/superpowers/specs/2026-07-16-reposicao-exclusao-outlier-escopo-design.md';


--
-- Name: resolver_sku_por_codigo_fornecedor(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.resolver_sku_por_codigo_fornecedor(p_empresa text, p_codigo_fornecedor text) RETURNS jsonb
    LANGUAGE plpgsql STABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_count int;
  v_unico record;
  v_candidatos jsonb;
  v_empresa text := lower(coalesce(p_empresa, ''));
BEGIN
  IF p_codigo_fornecedor IS NULL OR TRIM(p_codigo_fornecedor) = '' THEN
    RETURN jsonb_build_object('qualidade', 'nao_encontrado', 'motivo', 'codigo_vazio');
  END IF;

  SELECT COUNT(*) INTO v_count
  FROM omie_products op
  WHERE lower(op.account) = v_empresa
    AND COALESCE(op.ativo, true) = true
    AND op.descricao ILIKE '%' || p_codigo_fornecedor || '%';

  IF v_count = 0 THEN
    RETURN jsonb_build_object('qualidade', 'nao_encontrado');
  END IF;

  IF v_count = 1 THEN
    SELECT op.omie_codigo_produto, op.descricao INTO v_unico
    FROM omie_products op
    WHERE lower(op.account) = v_empresa
      AND COALESCE(op.ativo, true) = true
      AND op.descricao ILIKE '%' || p_codigo_fornecedor || '%'
    LIMIT 1;

    RETURN jsonb_build_object(
      'qualidade', 'unico',
      'omie_codigo_produto', v_unico.omie_codigo_produto,
      'descricao', v_unico.descricao
    );
  END IF;

  SELECT jsonb_agg(
    jsonb_build_object(
      'omie_codigo_produto', op.omie_codigo_produto,
      'descricao', op.descricao,
      'codigo_interno', op.codigo
    )
    ORDER BY op.descricao
  )
  INTO v_candidatos
  FROM (
    SELECT omie_codigo_produto, descricao, codigo
    FROM omie_products
    WHERE lower(account) = v_empresa
      AND COALESCE(ativo, true) = true
      AND descricao ILIKE '%' || p_codigo_fornecedor || '%'
    LIMIT 5
  ) op;

  RETURN jsonb_build_object(
    'qualidade', 'ambiguo',
    'total_matches', v_count,
    'candidatos', v_candidatos
  );
END;
$$;


--
-- Name: FUNCTION resolver_sku_por_codigo_fornecedor(p_empresa text, p_codigo_fornecedor text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.resolver_sku_por_codigo_fornecedor(p_empresa text, p_codigo_fornecedor text) IS 'Busca código do fornecedor (ex: DR.4403) na descrição dos produtos Omie. Retorna JSON com qualidade do match e dados relevantes.';


--
-- Name: reverter_exclusao_fornecedor(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reverter_exclusao_fornecedor(p_user_id uuid, p_motivo text DEFAULT 'reversão manual'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE v_enfileirados int; v_tmp int;
BEGIN
  IF NOT public.has_role(auth.uid(), 'master'::public.app_role) THEN
    RAISE EXCEPTION 'apenas master pode reverter exclusão de fornecedor';
  END IF;
  INSERT INTO public.fornecedor_excecao (user_id, motivo, criado_por)
  VALUES (p_user_id, p_motivo, auth.uid()) ON CONFLICT (user_id) DO NOTHING;
  UPDATE public.cliente_classificacao SET excluir_da_carteira = false, updated_at = now() WHERE user_id = p_user_id;
  UPDATE public.carteira_assignments
     SET eligible = NOT EXISTS (
           SELECT 1 FROM public.customer_canonical_alias cca
           WHERE cca.alias_user_id = p_user_id AND cca.status = 'active'),
         updated_at = now()
   WHERE customer_user_id = p_user_id;
  INSERT INTO public.visit_score_recalc_queue (customer_user_id, farmer_id, reason)
  SELECT ca.customer_user_id, ca.owner_user_id, 'reversao_fornecedor'
    FROM public.carteira_assignments ca WHERE ca.customer_user_id = p_user_id
  ON CONFLICT DO NOTHING;
  GET DIAGNOSTICS v_enfileirados = ROW_COUNT;
  INSERT INTO public.score_recalc_queue (customer_user_id, farmer_id, reason)
  SELECT ca.customer_user_id, ca.owner_user_id, 'reversao_fornecedor'
    FROM public.carteira_assignments ca WHERE ca.customer_user_id = p_user_id
  ON CONFLICT DO NOTHING;
  GET DIAGNOSTICS v_tmp = ROW_COUNT;
  v_enfileirados := v_enfileirados + v_tmp;
  RETURN jsonb_build_object('revertido', p_user_id, 'recalc_enfileirado', v_enfileirados);
END $$;


--
-- Name: reverter_parametro_auto(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reverter_parametro_auto(p_log_id uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE r record; v_uid uuid := auth.uid();
BEGIN
  IF private.cap_compras_escrever(v_uid) IS NOT TRUE THEN RAISE EXCEPTION 'sem permissão'; END IF;
  SELECT * INTO r FROM public.reposicao_param_auto_log
    WHERE id=p_log_id AND status='aplicado' AND revertido_em IS NULL;
  IF NOT FOUND THEN RETURN 'nao_encontrado'; END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public.sku_parametros sp
    WHERE sp.empresa=r.empresa AND sp.sku_codigo_omie::text=r.sku_codigo_omie
      AND round(COALESCE(sp.ponto_pedido,-1))      = round(COALESCE(r.ponto_pedido_depois,-1))
      AND round(COALESCE(sp.estoque_maximo,-1))    = round(COALESCE(r.estoque_maximo_depois,-1))
      AND round(COALESCE(sp.estoque_minimo,-1))    = round(COALESCE(r.estoque_minimo_depois,-1))
      AND round(COALESCE(sp.estoque_seguranca,-1)) = round(COALESCE(r.estoque_seguranca_depois,-1))
      AND round(COALESCE(sp.cobertura_alvo_dias,-1))= round(COALESCE(r.cobertura_depois,-1))
  ) THEN RETURN 'conflito'; END IF;
  UPDATE public.sku_parametros sp SET
    ponto_pedido=r.ponto_pedido_antes, estoque_minimo=r.estoque_minimo_antes,
    estoque_maximo=r.estoque_maximo_antes, estoque_seguranca=r.estoque_seguranca_antes,
    cobertura_alvo_dias=r.cobertura_antes, ultima_atualizacao_calculo=now()
  WHERE sp.empresa=r.empresa AND sp.sku_codigo_omie::text=r.sku_codigo_omie;
  INSERT INTO public.reposicao_param_pin (empresa, sku_codigo_omie, ponto_pedido_rejeitado, estoque_maximo_rejeitado, pinado_por)
    VALUES (r.empresa, r.sku_codigo_omie, round(r.ponto_pedido_depois), round(r.estoque_maximo_depois), v_uid)
    ON CONFLICT (empresa, sku_codigo_omie) DO UPDATE
      SET ponto_pedido_rejeitado=excluded.ponto_pedido_rejeitado,
          estoque_maximo_rejeitado=excluded.estoque_maximo_rejeitado, pinado_em=now(), pinado_por=v_uid;
  UPDATE public.reposicao_param_auto_log SET revertido_em=now(), revertido_por=v_uid WHERE id=p_log_id;
  RETURN 'revertido';
END;
$$;


--
-- Name: reverter_run_auto(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reverter_run_auto(p_run_id uuid) RETURNS TABLE(revertidos integer, conflitos integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE r record; v_rev int := 0; v_conf int := 0; res text;
BEGIN
  IF private.cap_compras_escrever(auth.uid()) IS NOT TRUE THEN RAISE EXCEPTION 'sem permissão'; END IF;
  FOR r IN SELECT id FROM public.reposicao_param_auto_log
           WHERE run_id=p_run_id AND status='aplicado' AND revertido_em IS NULL LOOP
    res := public.reverter_parametro_auto(r.id);
    IF res='revertido' THEN v_rev := v_rev+1; ELSIF res='conflito' THEN v_conf := v_conf+1; END IF;
  END LOOP;
  revertidos := v_rev; conflitos := v_conf; RETURN NEXT;
END;
$$;


--
-- Name: rodar_bateria_simulacao(text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.rodar_bateria_simulacao(p_empresa text, p_top_n integer DEFAULT 30) RETURNS TABLE(skus_simulados integer, candidatos_testados integer, simulacoes_total integer, valor_coberto_rs numeric, tempo_execucao_seg numeric)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_sku RECORD;
  v_cand TEXT;
  v_inicio TIMESTAMPTZ := CLOCK_TIMESTAMP();
  v_skus INT := 0;
  v_sims INT := 0;
  v_valor NUMERIC := 0;
BEGIN
  DELETE FROM simulacao_estoque_resultados WHERE empresa = p_empresa;

  FOR v_sku IN
    SELECT sku_codigo_omie::text AS sku_codigo_omie, valor_total_180d
    FROM v_sku_parametros_sugeridos
    WHERE empresa = p_empresa AND status_sugestao = 'OK'
    ORDER BY valor_total_180d DESC NULLS LAST
    LIMIT p_top_n
  LOOP
    v_skus := v_skus + 1;
    v_valor := v_valor + COALESCE(v_sku.valor_total_180d, 0);
    FOREACH v_cand IN ARRAY ARRAY['C1','C2','C3','C4','C5'] LOOP
      PERFORM simular_formula_estoque(p_empresa, v_sku.sku_codigo_omie, v_cand, 180);
      v_sims := v_sims + 1;
    END LOOP;
  END LOOP;

  RETURN QUERY SELECT v_skus, 5, v_sims, ROUND(v_valor, 2),
    ROUND(EXTRACT(EPOCH FROM (CLOCK_TIMESTAMP() - v_inicio))::numeric, 2);
END;
$$;


--
-- Name: route_city_norm(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.route_city_norm(raw text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE PARALLEL SAFE
    SET search_path TO ''
    AS $_$
DECLARE
  s text;
BEGIN
  IF raw IS NULL THEN
    RETURN NULL;
  END IF;
  -- Espacos unicode que o \s do JS reconhece (e o [[:space:]] POSIX nao) ->
  -- espaco ASCII, pra paridade com o split/replace(\s) do TS (route-city.ts).
  -- Os \uXXXX sao interpretados pelo motor de regex ARE do Postgres.
  s := regexp_replace(raw, '[\u00A0\u1680\u2000-\u200A\u2028\u2029\u202F\u205F\u3000\uFEFF]', ' ', 'g');
  -- stripAccents (NFD + remove combining marks U+0300..U+036F) -> UPPER ->
  -- trim (ordem identica ao TS).
  s := btrim(upper(regexp_replace(normalize(s, NFD), '[\u0300-\u036F]', '', 'g')));
  IF s = '' THEN
    RETURN NULL;
  END IF;
  -- Extracao de UF (mesma precedencia do TS) -- descartada: city_norm e so a cidade.
  IF s ~ '\([A-Z]{2}\)\s*$' THEN
    s := btrim(regexp_replace(s, '\([A-Z]{2}\)\s*$', ''));
  ELSIF s ~ '/\s*[A-Z]{2}\s*$' THEN
    s := btrim(regexp_replace(s, '/\s*[A-Z]{2}\s*$', ''));
  ELSIF s ~ '\s[A-Z]{2}$' THEN
    s := btrim(regexp_replace(s, '\s+[A-Z]{2}$', ''));
  END IF;
  s := btrim(regexp_replace(s, '\s+', ' ', 'g'));
  RETURN nullif(s, '');
END
$_$;


--
-- Name: sayerlack_retry_orfaos(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sayerlack_retry_orfaos() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_pedido record;
  v_cron_secret text;
  v_request_id bigint;
  v_url constant text := 'https://fzvklzpomgnyikkfkzai.supabase.co/functions/v1/disparar-pedidos-aprovados';
BEGIN
  IF NOT pg_try_advisory_xact_lock(hashtext('sayerlack_retry_orfaos')) THEN
    RETURN jsonb_build_object('skipped', 'lock_indisponivel');
  END IF;

  SELECT id, COALESCE(portal_tentativas, 0) AS tent, status_envio_portal, aprovado_em
    INTO v_pedido
  FROM public.pedido_compra_sugerido
  WHERE empresa = 'OBEN'
    AND fornecedor_nome ILIKE '%SAYERLACK%'
    AND status IN ('aprovado_aguardando_disparo', 'falha_envio')
    AND status_envio_portal IN ('pendente_envio_portal', 'erro_retentavel')
    AND COALESCE(portal_tentativas, 0) < 3
    AND (portal_proximo_retry_em IS NULL OR portal_proximo_retry_em <= now())
    AND aprovado_em >= now() - INTERVAL '3 days'
  ORDER BY aprovado_em ASC
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('candidatos', 0);
  END IF;

  SELECT decrypted_secret INTO v_cron_secret
  FROM vault.decrypted_secrets WHERE name = 'CRON_SECRET' LIMIT 1;

  SELECT net.http_post(
    url := v_url,
    headers := jsonb_build_object('Content-Type', 'application/json', 'x-cron-secret', v_cron_secret),
    body := jsonb_build_object('empresa', 'OBEN', 'pedido_id', v_pedido.id),
    timeout_milliseconds := 60000
  ) INTO v_request_id;

  INSERT INTO public.sayerlack_retry_motor_log
    (pedido_id, tentativa_no_disparo, status_envio_portal_no_disparo, aprovado_em, request_id)
  VALUES (v_pedido.id, v_pedido.tent, v_pedido.status_envio_portal, v_pedido.aprovado_em, v_request_id);

  RETURN jsonb_build_object('disparado', v_pedido.id, 'tentativa', v_pedido.tent, 'request_id', v_request_id);
END;
$$;


