--
-- Name: simular_formula_estoque(text, text, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.simular_formula_estoque(p_empresa text, p_sku text, p_candidato text, p_dias_simulacao integer DEFAULT 180) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_p RECORD;
  v_em NUMERIC; v_pp NUMERIC; v_qc NUMERIC; v_emax NUMERIC;
  v_lt NUMERIC;
  v_pior_janela_lt NUMERIC := NULL;
  v_preco_medio NUMERIC;
  v_estoque NUMERIC;
  v_dia DATE;
  v_qtde_dia NUMERIC;
  v_pedido_chegada DATE := NULL;
  v_pedido_qtde NUMERIC := 0;
  v_dias_rupt INT := 0;
  v_qtde_rupt NUMERIC := 0;
  v_qtde_dem NUMERIC := 0;
  v_soma_estoque NUMERIC := 0;
  v_max_est NUMERIC := 0;
  v_min_est NUMERIC := NULL;
  v_num_pedidos INT := 0;
  v_srl NUMERIC;
  v_giros NUMERIC;
  v_valor_emi NUMERIC;
  v_valor_rupt NUMERIC;
  v_sub_formula TEXT := NULL;  -- para C6: qual sub-fórmula vai usar
BEGIN
  SELECT
    sku_descricao, classe_consolidada, classe_abc_proposta,
    classe_xyz_proposta,
    demanda_media_diaria AS d, p95_diario, p90_quando_vende,
    pico_maximo_dia AS pico, lead_time_medio AS lt,
    dias_seguranca AS ds, cobertura_alvo_dias AS cob, minimo_operacional AS mop
  INTO v_p
  FROM v_sku_parametros_sugeridos
  WHERE empresa = p_empresa
    AND sku_codigo_omie::text = p_sku
    AND status_sugestao = 'OK';

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'SKU sem status OK', 'sku', p_sku);
  END IF;

  v_lt := GREATEST(COALESCE(v_p.lt, 10), 1);

  SELECT ROUND(AVG(valor_total / NULLIF(quantidade, 0))::numeric, 2)
  INTO v_preco_medio
  FROM venda_items_history
  WHERE empresa = p_empresa
    AND sku_codigo_omie::text = p_sku
    AND data_emissao >= CURRENT_DATE - (p_dias_simulacao || ' days')::interval
    AND quantidade > 0;
  v_preco_medio := COALESCE(v_preco_medio, 0);

  -- Pior janela LT para C3 e C6 (Y/Z)
  IF p_candidato IN ('C3', 'C6') THEN
    WITH diario AS (
      SELECT d.dt::date AS dt, COALESCE(SUM(v.quantidade), 0) AS qtde
      FROM generate_series(
        CURRENT_DATE - (p_dias_simulacao || ' days')::interval,
        CURRENT_DATE - INTERVAL '1 day', INTERVAL '1 day') d(dt)
      LEFT JOIN venda_items_history v
        ON v.empresa = p_empresa
       AND v.sku_codigo_omie::text = p_sku
       AND v.data_emissao::date = d.dt::date
      GROUP BY d.dt
    ),
    janelas AS (
      SELECT SUM(qtde) OVER (ORDER BY dt
        ROWS BETWEEN (v_lt::int - 1) PRECEDING AND CURRENT ROW) AS soma
      FROM diario
    )
    SELECT MAX(soma) INTO v_pior_janela_lt FROM janelas;
    v_pior_janela_lt := COALESCE(v_pior_janela_lt, v_p.d * v_lt);
  END IF;

  -- Sub-fórmula para C6
  IF p_candidato = 'C6' THEN
    IF v_p.classe_xyz_proposta = 'X' THEN
      v_sub_formula := 'C1';
    ELSE
      v_sub_formula := 'C3';
    END IF;
  END IF;

  CASE p_candidato
    WHEN 'C1' THEN
      v_em := GREATEST(CEIL(v_p.d * v_p.ds), COALESCE(v_p.mop, 0));
      v_pp := GREATEST(CEIL(v_p.d * (v_lt + v_p.ds)), v_em + 1);
      v_qc := GREATEST(CEIL(v_p.d * v_p.cob), 1);
    WHEN 'C2' THEN
      v_em := GREATEST(CEIL(COALESCE(v_p.p95_diario, v_p.d) * v_p.ds),
        CEIL(v_p.d * v_p.ds), COALESCE(v_p.mop, 0));
      v_pp := GREATEST(
        CEIL(COALESCE(v_p.p95_diario, v_p.d) * v_lt
             + COALESCE(v_p.p95_diario, v_p.d) * v_p.ds * 0.5), v_em + 1);
      v_qc := GREATEST(CEIL(v_p.d * v_p.cob), 1);
    WHEN 'C3' THEN
      v_em := GREATEST(CEIL(v_p.d * v_p.ds), COALESCE(v_p.mop, 0));
      v_pp := GREATEST(CEIL(v_pior_janela_lt + v_p.d * v_p.ds), v_em + 1);
      v_qc := GREATEST(CEIL(v_p.d * v_p.cob), 1);
    WHEN 'C4' THEN
      v_em := GREATEST(CEIL(v_p.pico * 1.5), COALESCE(v_p.mop, 0));
      v_pp := GREATEST(CEIL(v_p.pico * (v_lt + 1)), v_em + 1);
      v_qc := GREATEST(CEIL(v_p.pico * v_p.ds), 1);
    WHEN 'C5' THEN
      IF v_p.classe_abc_proposta = 'A' THEN
        v_em := GREATEST(CEIL(COALESCE(v_p.p95_diario, v_p.d) * v_p.ds),
          CEIL(v_p.d * v_p.ds), COALESCE(v_p.mop, 0));
        v_pp := GREATEST(
          CEIL(COALESCE(v_p.p95_diario, v_p.d) * v_lt
               + COALESCE(v_p.p95_diario, v_p.d) * v_p.ds * 0.5), v_em + 1);
        v_qc := GREATEST(CEIL(v_p.d * v_p.cob), 1);
      ELSIF v_p.classe_abc_proposta = 'B' THEN
        v_em := GREATEST(CEIL(v_p.d * v_p.ds), COALESCE(v_p.mop, 0));
        v_pp := GREATEST(CEIL(v_p.d * (v_lt + v_p.ds)), v_em + 1);
        v_qc := GREATEST(CEIL(v_p.d * v_p.cob), 1);
      ELSE
        v_em := GREATEST(CEIL(v_p.pico * 1.5), COALESCE(v_p.mop, 0));
        v_pp := GREATEST(CEIL(v_p.pico * (v_lt + 1)), v_em + 1);
        v_qc := GREATEST(CEIL(v_p.pico * v_p.ds), 1);
      END IF;
    WHEN 'C6' THEN
      IF v_sub_formula = 'C1' THEN
        -- X: fórmula econômica
        v_em := GREATEST(CEIL(v_p.d * v_p.ds), COALESCE(v_p.mop, 0));
        v_pp := GREATEST(CEIL(v_p.d * (v_lt + v_p.ds)), v_em + 1);
        v_qc := GREATEST(CEIL(v_p.d * v_p.cob), 1);
      ELSE
        -- Y/Z: rolling pessimista
        v_em := GREATEST(CEIL(v_p.d * v_p.ds), COALESCE(v_p.mop, 0));
        v_pp := GREATEST(CEIL(v_pior_janela_lt + v_p.d * v_p.ds), v_em + 1);
        v_qc := GREATEST(CEIL(v_p.d * v_p.cob), 1);
      END IF;
    ELSE
      RETURN jsonb_build_object('error', 'Candidato inválido: ' || p_candidato);
  END CASE;

  v_emax := v_pp + v_qc;
  v_estoque := v_emax;
  v_max_est := v_emax;
  v_min_est := v_emax;

  FOR v_dia IN
    SELECT dt::date FROM generate_series(
      CURRENT_DATE - (p_dias_simulacao || ' days')::interval,
      CURRENT_DATE - INTERVAL '1 day', INTERVAL '1 day') AS t(dt)
    ORDER BY 1
  LOOP
    IF v_pedido_chegada IS NOT NULL AND v_dia >= v_pedido_chegada THEN
      v_estoque := v_estoque + v_pedido_qtde;
      v_pedido_chegada := NULL; v_pedido_qtde := 0;
    END IF;

    SELECT COALESCE(SUM(quantidade), 0) INTO v_qtde_dia
    FROM venda_items_history
    WHERE empresa = p_empresa AND sku_codigo_omie::text = p_sku
      AND data_emissao::date = v_dia;

    v_qtde_dem := v_qtde_dem + v_qtde_dia;

    IF v_estoque >= v_qtde_dia THEN
      v_estoque := v_estoque - v_qtde_dia;
    ELSE
      v_qtde_rupt := v_qtde_rupt + (v_qtde_dia - v_estoque);
      v_estoque := 0;
      IF v_qtde_dia > 0 THEN v_dias_rupt := v_dias_rupt + 1; END IF;
    END IF;

    IF v_estoque <= v_pp AND v_pedido_chegada IS NULL THEN
      v_pedido_qtde := v_qc;
      SELECT dt::date INTO v_pedido_chegada
      FROM generate_series(
        (v_dia + INTERVAL '1 day')::date,
        (v_dia + INTERVAL '30 days')::date,
        INTERVAL '1 day') AS g(dt)
      WHERE dias_uteis_entre(v_dia, dt::date) >= v_lt
      ORDER BY dt LIMIT 1;
      IF v_pedido_chegada IS NULL THEN
        v_pedido_chegada := v_dia + CEIL(v_lt * 1.4)::int;
      END IF;
      v_num_pedidos := v_num_pedidos + 1;
    END IF;

    v_soma_estoque := v_soma_estoque + v_estoque;
    IF v_estoque > v_max_est THEN v_max_est := v_estoque; END IF;
    IF v_estoque < v_min_est THEN v_min_est := v_estoque; END IF;
  END LOOP;

  v_srl := CASE WHEN v_qtde_dem > 0 THEN ROUND((1 - v_qtde_rupt / v_qtde_dem) * 100, 2) ELSE 100 END;
  v_valor_emi := ROUND((v_soma_estoque / p_dias_simulacao::numeric) * v_preco_medio, 2);
  v_valor_rupt := ROUND(v_qtde_rupt * v_preco_medio, 2);
  v_giros := CASE WHEN v_soma_estoque > 0 THEN
    ROUND((v_qtde_dem / (v_soma_estoque / p_dias_simulacao::numeric)) * (365.0 / p_dias_simulacao), 2)
    ELSE 0 END;

  INSERT INTO simulacao_estoque_resultados (
    empresa, sku_codigo_omie, sku_descricao, classe_consolidada, classe_abc, candidato,
    estoque_min_aplicado, ponto_pedido_aplicado, qtde_compra_aplicada, estoque_max_aplicado,
    lead_time_aplicado, dias_simulados, dias_em_ruptura, srl_perc, qtde_ruptura_total,
    qtde_demandada_total, estoque_medio, estoque_max_observado, estoque_min_observado,
    num_pedidos_disparados, giros_ano, valor_emi, valor_ruptura_estimado, metadata
  ) VALUES (
    p_empresa, p_sku, v_p.sku_descricao, v_p.classe_consolidada, v_p.classe_abc_proposta, p_candidato,
    v_em, v_pp, v_qc, v_emax, v_lt, p_dias_simulacao, v_dias_rupt, v_srl, v_qtde_rupt, v_qtde_dem,
    ROUND(v_soma_estoque / p_dias_simulacao::numeric, 2), v_max_est, COALESCE(v_min_est, 0),
    v_num_pedidos, v_giros, v_valor_emi, v_valor_rupt,
    jsonb_build_object('D', v_p.d, 'LT_dias_uteis', v_lt, 'pico', v_p.pico,
      'p95_diario', v_p.p95_diario, 'p90_quando_vende', v_p.p90_quando_vende,
      'preco_medio', v_preco_medio, 'pior_janela_lt', v_pior_janela_lt,
      'ds', v_p.ds, 'cob', v_p.cob,
      'classe_xyz', v_p.classe_xyz_proposta,
      'c6_sub', v_sub_formula));

  RETURN jsonb_build_object('sku', p_sku, 'candidato', p_candidato, 'srl_perc', v_srl,
    'dias_rupt', v_dias_rupt, 'estoque_medio', ROUND(v_soma_estoque / p_dias_simulacao::numeric, 2),
    'giros_ano', v_giros, 'valor_emi', v_valor_emi, 'em', v_em, 'pp', v_pp, 'qc', v_qc);
END;
$$;


--
-- Name: simular_puxar_volume_trimestre(text, integer, integer, numeric, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.simular_puxar_volume_trimestre(p_empresa text DEFAULT 'OBEN'::text, p_ano integer DEFAULT NULL::integer, p_trimestre integer DEFAULT NULL::integer, p_valor_extra numeric DEFAULT 0, p_prazo_pagamento_codigo text DEFAULT 'antecipado'::text, p_dias_estoque_extra integer DEFAULT 60) RETURNS jsonb
    LANGUAGE plpgsql STABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_ano int;
  v_trimestre int;
  v_posicao_atual numeric;
  v_posicao_com_extra numeric;
  v_faixa_atual record;
  v_faixa_nova record;
  v_desc_atual_total numeric;
  v_desc_novo_total numeric;
  v_delta_percentual numeric;
  v_projecao_proximo_trimestre numeric;
  v_ganho_proximo_trimestre numeric;
  v_perda_antecipado numeric;
  v_encargo_prazo numeric;
  v_custo_frete numeric;
  v_custo_capital numeric;
  v_cm_anual numeric;
  v_perda_total numeric;
  v_saldo_liquido numeric;
  v_prazo_atual record;
  v_prazo_novo record;
  v_checkin record;
  v_fator_inflacao_nominal numeric;
  v_nominal_adicional_na_nf numeric;
BEGIN
  -- Defaults: trimestre atual se não especificado
  v_ano := COALESCE(p_ano, EXTRACT(YEAR FROM CURRENT_DATE)::int);
  v_trimestre := COALESCE(p_trimestre, EXTRACT(QUARTER FROM CURRENT_DATE)::int);
  
  -- Posição atual
  SELECT posicao_ao_vivo_conservadora INTO v_posicao_atual
  FROM v_des_posicao_trimestre_ao_vivo
  WHERE empresa = p_empresa AND ano = v_ano AND trimestre = v_trimestre;
  
  IF v_posicao_atual IS NULL THEN v_posicao_atual := 0; END IF;
  
  -- Prazo de pagamento escolhido
  SELECT * INTO v_prazo_novo
  FROM fornecedor_prazo_pagamento_config
  WHERE empresa = p_empresa 
    AND fornecedor_nome = 'RENNER SAYERLACK S/A'
    AND codigo = p_prazo_pagamento_codigo;
  
  -- Prazo padrão (antecipado default)
  SELECT * INTO v_prazo_atual
  FROM fornecedor_prazo_pagamento_config
  WHERE empresa = p_empresa 
    AND fornecedor_nome = 'RENNER SAYERLACK S/A'
    AND padrao = true;
  
  -- Fator de inflação da NF: 
  -- - se prazo escolhido é antecipado, NF = valor pedido
  -- - se prazo é 28/42/56, NF = valor pedido × (1 + encargo_abs)
  -- encargo_abs = abs(desconto_ou_encargo_perc) / 100 se valor negativo
  v_fator_inflacao_nominal := 1.0;
  IF v_prazo_novo.desconto_ou_encargo_perc < 0 THEN
    v_fator_inflacao_nominal := 1.0 + (ABS(v_prazo_novo.desconto_ou_encargo_perc) / 100.0);
  END IF;
  
  -- Valor adicional na NF (o que conta para DES)
  v_nominal_adicional_na_nf := p_valor_extra * v_fator_inflacao_nominal;
  
  -- Nova posição
  v_posicao_com_extra := v_posicao_atual + v_nominal_adicional_na_nf;
  
  -- Faixas: atual e nova
  SELECT * INTO v_faixa_atual FROM des_determinar_faixa(v_posicao_atual);
  SELECT * INTO v_faixa_nova FROM des_determinar_faixa(v_posicao_com_extra);
  
  -- Checkin mais recente para saber quais qualitativos estão ativos
  SELECT * INTO v_checkin 
  FROM v_des_desconto_por_checkin
  WHERE empresa = p_empresa AND ano = v_ano AND trimestre = v_trimestre
  LIMIT 1;
  
  -- Desconto total atual (sem puxar)
  v_desc_atual_total := COALESCE(
    (SELECT desconto_total_projetado FROM v_des_desconto_por_checkin
     WHERE empresa = p_empresa AND ano = v_ano AND trimestre = v_trimestre),
    COALESCE(v_faixa_atual.desconto_padrao_perc, 0)
  );
  
  -- Desconto total na nova faixa (reaplica qualitativos do checkin)
  IF v_faixa_nova.faixa_id IS NOT NULL THEN
    v_desc_novo_total := v_faixa_nova.desconto_padrao_perc +
      COALESCE((
        SELECT SUM(cp.percentual)
        FROM des_checkin_qualitativo_resposta qr
        JOIN des_checkin_qualitativo ck ON ck.id = qr.checkin_id
        JOIN des_criterio_percentual cp 
          ON cp.criterio_id = qr.criterio_id 
         AND cp.faixa_id = v_faixa_nova.faixa_id
        WHERE qr.atingido = true
          AND ck.empresa = p_empresa 
          AND ck.ano = v_ano 
          AND ck.trimestre = v_trimestre
          AND ck.id = (SELECT MAX(id) FROM des_checkin_qualitativo 
                       WHERE empresa = p_empresa 
                         AND ano = v_ano 
                         AND trimestre = v_trimestre)
      ), 0);
  ELSE
    v_desc_novo_total := v_desc_atual_total;
  END IF;
  
  v_delta_percentual := v_desc_novo_total - v_desc_atual_total;
  
  -- Projeção de faturamento do próximo trimestre (meta pessoal)
  SELECT meta_faturamento INTO v_projecao_proximo_trimestre
  FROM des_meta_empresa
  WHERE empresa = p_empresa 
    AND ano = v_ano 
    AND trimestre = CASE WHEN v_trimestre = 4 THEN 1 ELSE v_trimestre + 1 END;
  
  IF v_projecao_proximo_trimestre IS NULL THEN
    -- Fallback: usa meta do trimestre corrente
    v_projecao_proximo_trimestre := COALESCE(
      (SELECT meta_faturamento FROM des_meta_empresa 
       WHERE empresa = p_empresa AND ano = v_ano AND trimestre = v_trimestre),
      400000
    );
  END IF;
  
  -- Ganho no próximo trimestre = delta_perc × projeção_próximo
  v_ganho_proximo_trimestre := (v_delta_percentual / 100.0) * v_projecao_proximo_trimestre;
  
  -- Perdas no pedido atual
  -- 1. Perda de antecipado (se mudou para prazo)
  v_perda_antecipado := 0;
  IF v_prazo_atual.codigo <> v_prazo_novo.codigo 
     AND v_prazo_atual.desconto_ou_encargo_perc > 0 THEN
    v_perda_antecipado := p_valor_extra * (v_prazo_atual.desconto_ou_encargo_perc / 100.0);
  END IF;
  
  -- 2. Encargo do prazo (se negativo)
  v_encargo_prazo := 0;
  IF v_prazo_novo.desconto_ou_encargo_perc < 0 THEN
    v_encargo_prazo := p_valor_extra * (ABS(v_prazo_novo.desconto_ou_encargo_perc) / 100.0);
  END IF;
  
  -- 3. Frete adicional sobre o valor extra
  v_custo_frete := p_valor_extra * (COALESCE(
    (SELECT valor FROM fornecedor_custo_adicional_config 
     WHERE empresa = p_empresa 
       AND fornecedor_nome = 'RENNER SAYERLACK S/A' 
       AND tipo = 'frete_perc_valor' 
       AND ativo = true LIMIT 1), 
    2.5
  ) / 100.0);
  
  -- 4. Custo de capital do estoque extra
  v_cm_anual := COALESCE(
    (SELECT (selic_anual + spread_oportunidade + armazenagem_fisica) / 100.0 
     FROM empresa_configuracao_custos WHERE empresa = p_empresa LIMIT 1),
    0.20
  );
  v_custo_capital := p_valor_extra * v_cm_anual * (p_dias_estoque_extra::numeric / 365.0);
  
  -- Perda total no pedido
  v_perda_total := v_perda_antecipado + v_encargo_prazo + v_custo_frete + v_custo_capital;
  
  -- Saldo líquido
  v_saldo_liquido := v_ganho_proximo_trimestre - v_perda_total;
  
  -- Retorno estruturado
  RETURN jsonb_build_object(
    'parametros', jsonb_build_object(
      'empresa', p_empresa,
      'ano', v_ano,
      'trimestre', v_trimestre,
      'valor_extra', p_valor_extra,
      'prazo_pagamento', p_prazo_pagamento_codigo,
      'dias_estoque_extra', p_dias_estoque_extra
    ),
    'posicao', jsonb_build_object(
      'atual', v_posicao_atual,
      'com_extra', v_posicao_com_extra,
      'nominal_adicional_na_nf', v_nominal_adicional_na_nf,
      'fator_inflacao', v_fator_inflacao_nominal
    ),
    'faixas', jsonb_build_object(
      'atual', row_to_json(v_faixa_atual),
      'nova', row_to_json(v_faixa_nova),
      'mudou_faixa', (COALESCE(v_faixa_atual.faixa_numero, 0) <> COALESCE(v_faixa_nova.faixa_numero, 0))
    ),
    'descontos', jsonb_build_object(
      'atual_total_perc', v_desc_atual_total,
      'novo_total_perc', v_desc_novo_total,
      'delta_perc', v_delta_percentual
    ),
    'projecao', jsonb_build_object(
      'proximo_trimestre_projetado', v_projecao_proximo_trimestre,
      'ganho_futuro_rs', ROUND(v_ganho_proximo_trimestre, 2)
    ),
    'perdas_pedido_atual', jsonb_build_object(
      'antecipado_rs', ROUND(v_perda_antecipado, 2),
      'encargo_prazo_rs', ROUND(v_encargo_prazo, 2),
      'frete_rs', ROUND(v_custo_frete, 2),
      'custo_capital_rs', ROUND(v_custo_capital, 2),
      'total_rs', ROUND(v_perda_total, 2)
    ),
    'saldo_liquido_rs', ROUND(v_saldo_liquido, 2),
    'recomendacao', CASE 
      WHEN v_saldo_liquido > 1000 THEN 'compensa'
      WHEN v_saldo_liquido > 0 THEN 'compensa_marginalmente'
      WHEN v_saldo_liquido > -1000 THEN 'indiferente'
      ELSE 'nao_compensa'
    END
  );
END;
$$;


--
-- Name: FUNCTION simular_puxar_volume_trimestre(p_empresa text, p_ano integer, p_trimestre integer, p_valor_extra numeric, p_prazo_pagamento_codigo text, p_dias_estoque_extra integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.simular_puxar_volume_trimestre(p_empresa text, p_ano integer, p_trimestre integer, p_valor_extra numeric, p_prazo_pagamento_codigo text, p_dias_estoque_extra integer) IS 'Simulador de impacto financeiro de puxar volume extra em um trimestre. Retorna JSON estruturado com: posição atual e projetada, faixas atingidas, descontos envolvidos, ganho futuro, perdas no pedido, saldo líquido e recomendação. Usado pela UI de simulação.';


--
-- Name: sincronizar_ativo_omie_para_reposicao(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sincronizar_ativo_omie_para_reposicao() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Se virou inativo, desabilita reposição + gera alerta
  IF NEW.ativo = false AND (OLD.ativo IS NULL OR OLD.ativo = true) THEN
    UPDATE sku_parametros sp
    SET habilitado_reposicao_automatica = FALSE
    WHERE sp.sku_codigo_omie::text = NEW.omie_codigo_produto::text
      AND sp.habilitado_reposicao_automatica = TRUE;
    
    -- Registra evento pra Lucas decidir merge
    INSERT INTO eventos_outlier (
      empresa, sku_codigo_omie, sku_descricao,
      tipo, severidade, data_evento, detalhes
    )
    SELECT 
      sp.empresa, sp.sku_codigo_omie::text, sp.sku_descricao,
      'sku_inativado_omie', 'atencao', CURRENT_DATE,
      jsonb_build_object(
        'mensagem', 'SKU foi inativado no Omie. Reposição automática desligada. Decida: (1) merge histórico com outro SKU, (2) manter desabilitado, (3) reativar no Omie.',
        'familia', NEW.familia,
        'valor_unitario', NEW.valor_unitario
      )
    FROM sku_parametros sp
    WHERE sp.sku_codigo_omie::text = NEW.omie_codigo_produto::text
      AND NOT EXISTS (
        SELECT 1 FROM eventos_outlier eo
        WHERE eo.empresa = sp.empresa
          AND eo.sku_codigo_omie = sp.sku_codigo_omie::text
          AND eo.tipo = 'sku_inativado_omie'
          AND eo.status = 'pendente'
      );
  END IF;
  
  -- Se voltou a ser ativo, regrava observação (mas não reabilita automático)
  IF NEW.ativo = true AND OLD.ativo = false THEN
    INSERT INTO eventos_outlier (
      empresa, sku_codigo_omie, sku_descricao,
      tipo, severidade, data_evento, detalhes
    )
    SELECT 
      sp.empresa, sp.sku_codigo_omie::text, sp.sku_descricao,
      'sku_reativado_omie', 'info', CURRENT_DATE,
      jsonb_build_object(
        'mensagem', 'SKU foi reativado no Omie. Revisar se deseja habilitar reposição automática novamente.'
      )
    FROM sku_parametros sp
    WHERE sp.sku_codigo_omie::text = NEW.omie_codigo_produto::text;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: ss_allowlist_forca_autor(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ss_allowlist_forca_autor() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  NEW.updated_at := now();
  IF NEW.enabled IS TRUE AND (TG_OP='INSERT' OR OLD.enabled IS DISTINCT FROM true) THEN
    IF auth.uid() IS NOT NULL THEN NEW.enabled_by := auth.uid(); END IF;
    NEW.enabled_at := now();
  ELSIF TG_OP='UPDATE' AND OLD.enabled IS TRUE AND NEW.enabled IS TRUE THEN
    NEW.enabled_by := OLD.enabled_by;
    NEW.enabled_at := OLD.enabled_at;
  END IF;
  RETURN NEW;
END; $$;


--
-- Name: staff_get_sales_order_payload(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.staff_get_sales_order_payload(p_order_ids uuid[]) RETURNS TABLE(id uuid, omie_payload jsonb, omie_response jsonb)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NOT (
    auth.role() = 'service_role'
    OR public.has_role(auth.uid(), 'employee'::app_role)
    OR public.has_role(auth.uid(), 'master'::app_role)
  ) THEN
    RAISE EXCEPTION 'Acesso negado: requer perfil de staff (employee/master)'
      USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  SELECT so.id, so.omie_payload, so.omie_response
  FROM public.sales_orders so
  WHERE so.id = ANY(p_order_ids);
END;
$$;


--
-- Name: sugerir_negociacao_paralela_hoje(text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sugerir_negociacao_paralela_hoje(p_empresa text DEFAULT 'OBEN'::text, p_limite integer DEFAULT 10) RETURNS TABLE(out_sugestao_id bigint, out_sku_codigo_omie text, out_sku_descricao text, out_motivo text, out_score_final numeric, out_volume_financeiro_12m numeric, out_preco_medio_unitario numeric, out_categoria text, out_motivo_legivel text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'private'
    AS $$
DECLARE
  v_dia_mes int;
  v_eh_fim_mes boolean;
BEGIN
  IF NOT (
    public.has_role(auth.uid(), 'employee'::app_role)
    OR public.has_role(auth.uid(), 'master'::app_role)
    OR nullif(current_setting('request.jwt.claims', true), '') IS NULL
  ) THEN
    RAISE EXCEPTION 'Acesso negado: requer perfil staff' USING ERRCODE = '42501';
  END IF;

  v_dia_mes := EXTRACT(DAY FROM CURRENT_DATE)::int;
  v_eh_fim_mes := v_dia_mes >= 20;

  UPDATE sugestao_negociacao_paralela
     SET status = 'ignorada'
   WHERE empresa = p_empresa
     AND status IN ('nova', 'visualizada')
     AND valido_ate < CURRENT_DATE;

  RETURN QUERY
  WITH candidatos AS (
    SELECT r.sku_codigo_omie AS sku_cod,
           r.sku_descricao AS sku_desc,
           r.score_final AS score_val,
           r.volume_financeiro_12m AS vol_12m,
           r.preco_medio_unitario AS preco_med,
           r.promocoes_12m AS promo_12m,
           r.perc_meses_com_promo AS perc_promo,
           r.categoria AS cat,
           CASE
             WHEN r.categoria IN ('prioritario', 'forte') AND r.perc_meses_com_promo < 30 AND v_eh_fim_mes THEN 'combinacao_heuristica'
             WHEN r.categoria IN ('prioritario', 'forte') AND r.perc_meses_com_promo < 30 THEN 'candidato_forte_sem_promo_recente'
             WHEN v_eh_fim_mes AND r.categoria IN ('prioritario', 'forte', 'moderado') THEN 'consumo_abaixo_tipico_fim_de_mes'
             ELSE 'score_alto_ciclo_semanal'
           END AS motivo_comp
      FROM mv_sku_ranking_negociacao_paralela r
     WHERE r.empresa = p_empresa
       AND r.categoria IN ('prioritario', 'forte', 'moderado')
       AND NOT EXISTS (
         SELECT 1 FROM promocao_item pi
           JOIN promocao_campanha pc ON pc.id = pi.campanha_id
          WHERE pc.empresa = r.empresa
            AND pc.tipo_origem = 'desconto_flat_condicional'
            AND pc.estado IN ('ativa', 'negociando')
            AND pi.sku_codigo_omie::text = r.sku_codigo_omie
            AND pi.ativo = true
       )
       AND NOT EXISTS (
         SELECT 1 FROM sugestao_negociacao_paralela sng
          WHERE sng.empresa = r.empresa
            AND sng.sku_codigo_omie = r.sku_codigo_omie
            AND sng.status IN ('nova', 'visualizada', 'acao_tomada')
            AND sng.valido_ate >= CURRENT_DATE
       )
     ORDER BY r.score_final DESC
     LIMIT p_limite
  ),
  inserted AS (
    INSERT INTO sugestao_negociacao_paralela (
      empresa, sku_codigo_omie, sku_descricao, motivo, motivo_detalhes,
      score_final, volume_financeiro_12m, preco_medio_unitario,
      promocoes_12m, perc_meses_com_promo, valido_ate
    )
    SELECT p_empresa, c.sku_cod, c.sku_desc, c.motivo_comp,
           jsonb_build_object('dia_mes', v_dia_mes, 'eh_fim_mes', v_eh_fim_mes, 'categoria_ranking', c.cat, 'heuristica_disparou', c.motivo_comp),
           c.score_val, c.vol_12m, c.preco_med, c.promo_12m, c.perc_promo,
           CURRENT_DATE + interval '14 days'
      FROM candidatos c
    RETURNING id, sku_codigo_omie, sku_descricao, motivo, score_final, volume_financeiro_12m, preco_medio_unitario
  )
  SELECT ins.id, ins.sku_codigo_omie, ins.sku_descricao, ins.motivo, ins.score_final, ins.volume_financeiro_12m, ins.preco_medio_unitario,
         c.cat,
         CASE ins.motivo
           WHEN 'combinacao_heuristica' THEN format('Candidato %s (score %s) sem promoção nos últimos %s%% dos meses, estamos em fim de mês (dia %s). Momento ótimo para negociar.', c.cat, ins.score_final, ROUND(c.perc_promo, 0), v_dia_mes)
           WHEN 'candidato_forte_sem_promo_recente' THEN format('Candidato %s (score %s) que raramente entra em promoção (%s%% dos últimos 12 meses). Provavelmente aceita desconto paralelo.', c.cat, ins.score_final, ROUND(c.perc_promo, 0))
           WHEN 'consumo_abaixo_tipico_fim_de_mes' THEN format('Dia %s. SKU categoria %s, consumo recorrente, vale completar volume do mês negociando desconto condicional.', v_dia_mes, c.cat)
           ELSE format('Top candidato do ranking (score %s, categoria %s). Vale avaliar para negociação.', ins.score_final, c.cat)
         END
    FROM inserted ins
    JOIN candidatos c ON c.sku_cod = ins.sku_codigo_omie;
END;
$$;


--
-- Name: tactical_plan_recusa_cliente_mascarado(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tactical_plan_recusa_cliente_mascarado() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  _eligible boolean;
BEGIN
  -- FOR UPDATE: fecha a corrida "eligible vira false entre a checagem e o INSERT" também
  -- para quem NÃO passa pela criar_plano_tatico (que já tem o seu próprio lock).
  SELECT a.eligible INTO _eligible
  FROM public.carteira_assignments a
  WHERE a.customer_user_id = NEW.customer_user_id
  FOR UPDATE;

  IF _eligible IS NOT TRUE THEN
    RAISE EXCEPTION 'Cliente % está mascarado na carteira (eligible) — plano tático não é materializado', NEW.customer_user_id
      USING ERRCODE = '42501';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: FUNCTION tactical_plan_recusa_cliente_mascarado(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.tactical_plan_recusa_cliente_mascarado() IS 'Trigger BEFORE INSERT em farmer_tactical_plans: recusa cliente mascarado (eligible IS NOT TRUE), inclusive sem assignment. Barreira final — alcança escrita de função SECURITY DEFINER futura, que roda como postgres e o REVOKE não pega.';


--
-- Name: tarefas_escalonamento_tick(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tarefas_escalonamento_tick() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  r record;
  v_nome text;
  v_titulo text;
  v_msg text;
begin
  for r in
    select v.responsavel_efetivo, v.empresa,
           array_agg(v.id) as ids,
           count(*) as n,
           string_agg(
             case when not v.tem_sugestao_pendente then
               format('- %s (%s, venceu %s)%s', v.descricao, v.categoria, v.effective_due,
                      case when v.motivo_adiamento is not null and btrim(v.motivo_adiamento) <> ''
                           then ' · adiada: '||v.motivo_adiamento else '' end)
             end, E'\n' order by v.effective_due
           ) as linhas_sem_sinal,
           string_agg(
             case when v.tem_sugestao_pendente then
               format('- %s (%s, venceu %s)', v.descricao, v.categoria, v.effective_due)
             end, E'\n' order by v.effective_due
           ) as linhas_detectado
    from public.v_tarefas_estado v
    where v.escalavel
    group by v.responsavel_efetivo, v.empresa
  loop
    select name into v_nome from public.profiles where user_id = r.responsavel_efetivo;
    v_nome := coalesce(nullif(btrim(v_nome), ''), 'A vendedora');

    v_titulo := format('%s tarefa(s) atrasada(s) — %s', r.n, v_nome);

    v_msg := format('%s tem %s tarefa(s) atrasada(s) (vencidas além da tolerância).', v_nome, r.n);
    if r.linhas_sem_sinal is not null then
      v_msg := v_msg || E'\n\nNão tocou (nenhum sinal detectado):\n' || r.linhas_sem_sinal;
    end if;
    if r.linhas_detectado is not null then
      v_msg := v_msg
        || E'\n\nPossível cumprimento NÃO confirmado (o app detectou menção numa interação, mas a vendedora não confirmou — verifique):\n'
        || r.linhas_detectado;
    end if;

    insert into public.fornecedor_alerta (tipo, empresa, severidade, status, titulo, mensagem)
    values ('tarefa_atrasada', r.empresa, 'atencao', 'pendente_notificacao', v_titulo, v_msg);

    insert into public.tarefa_eventos (tarefa_id, tipo_evento, ator, payload)
    select unnest(r.ids), 'escalada', null, jsonb_build_object('responsavel', r.responsavel_efetivo);

    update public.tarefas set escalado_em = now(), updated_at = now()
    where id = any(r.ids) and escalado_em is null;
  end loop;
end $$;


--
-- Name: tarefas_guard_comprovacao(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tarefas_guard_comprovacao() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
begin
  if coalesce(new.requer_comprovacao, false) or coalesce(old.requer_comprovacao, false) then
    if new.status = 'concluida' and old.status is distinct from 'concluida'
       and current_user not in ('postgres','service_role','supabase_admin') then
      raise exception 'Tarefa com comprovação só conclui via concluir_com_comprovacao()';
    end if;
    if current_user not in ('postgres','service_role','supabase_admin') and (
         new.comprovacao_url       is distinct from old.comprovacao_url
      or new.comprovacao_leitura   is distinct from old.comprovacao_leitura
      or new.comprovacao_em        is distinct from old.comprovacao_em
      or new.auditoria_status      is distinct from old.auditoria_status
      or new.auditada_por          is distinct from old.auditada_por
      or new.requer_comprovacao    is distinct from old.requer_comprovacao
    ) then
      raise exception 'Campos de comprovação/auditoria só mudam via RPC';
    end if;
  end if;
  return new;
end $$;


--
-- Name: tarefas_matcher_tick(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tarefas_matcher_tick() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
begin
  with fechadas as (
    update public.tarefas t
    set status='concluida', concluida_em=now(), conclusao_origem='auto_interacao', updated_at=now()
    from public.farmer_calls fc
    where t.status='aberta' and t.auto_satisfy_mode='interacao' and t.interacao_tipo='ligacao'
      and fc.customer_user_id = t.customer_user_id
      and fc.created_at > t.created_at
      and fc.created_at > now() - interval '1 day'
      and fc.call_result is not null
      and fc.call_result not in ('sem_resposta','ocupado','caixa_postal','numero_invalido')
      and ( fc.farmer_id = t.assigned_to
            or exists (select 1 from public.carteira_coverage cc
                       where cc.covered_user_id=t.assigned_to and cc.covering_user_id=fc.farmer_id
                         and cc.active and now()>=cc.valid_from and (cc.valid_until is null or now()<=cc.valid_until)) )
    returning t.id, t.assigned_to, fc.id as fonte, fc.farmer_id as fechou
  )
  insert into public.tarefa_eventos (tarefa_id, tipo_evento, ator, payload)
  select id, 'concluida_auto', fechou,
         jsonb_build_object('via','ligacao','source_id',fonte,'responsavel_efetivo',fechou,'assigned_to',assigned_to)
  from fechadas;

  with fechadas_v as (
    update public.tarefas t
    set status='concluida', concluida_em=now(), conclusao_origem='auto_interacao', updated_at=now()
    from public.route_visits rv
    where t.status='aberta' and t.auto_satisfy_mode='interacao' and t.interacao_tipo in ('visita','entrega')
      and rv.customer_user_id = t.customer_user_id
      and rv.check_in_at > t.created_at
      and rv.check_in_at > now() - interval '1 day'
      and ( (t.interacao_tipo='visita' and rv.visit_type='comercial')
            or (t.interacao_tipo='entrega' and rv.visit_type='entrega') )
      and ( rv.visited_by = t.assigned_to
            or exists (select 1 from public.carteira_coverage cc
                       where cc.covered_user_id=t.assigned_to and cc.covering_user_id=rv.visited_by
                         and cc.active and now()>=cc.valid_from and (cc.valid_until is null or now()<=cc.valid_until)) )
    returning t.id, t.assigned_to, rv.id as fonte, rv.visited_by as fechou
  )
  insert into public.tarefa_eventos (tarefa_id, tipo_evento, ator, payload)
  select id, 'concluida_auto', fechou,
         jsonb_build_object('via','visita_entrega','source_id',fonte,'responsavel_efetivo',fechou,'assigned_to',assigned_to)
  from fechadas_v;

  with novos as (
    insert into public.tarefa_satisfacao_candidatos
      (tarefa_id, source_type, source_id, mode, confidence, motivo, matched_payload, status)
    select t.id, 'farmer_call', fc.id, 'conteudo',
           coalesce(m.confidence, 0.0),
           case when m.value is not null then 'Mencionou na ligação: '||m.value
                else 'Ligação aconteceu — confirmar se ofereceu' end,
           case when m.value is not null
                then jsonb_build_object('entity_type', m.etype, 'value', m.value, 'context', m.context)
                else null end,
           'pending'
    from public.tarefas t
    join public.farmer_calls fc
      on fc.customer_user_id = t.customer_user_id
     and fc.created_at > t.created_at
     and fc.created_at > now() - interval '1 day'
     and ( fc.farmer_id = t.assigned_to
           or exists (select 1 from public.carteira_coverage cc
                      where cc.covered_user_id=t.assigned_to and cc.covering_user_id=fc.farmer_id
                        and cc.active and now()>=cc.valid_from and (cc.valid_until is null or now()<=cc.valid_until)) )
    left join lateral (
      select e->>'value' as value, e->>'type' as etype, e->>'context' as context,
             (e->>'confidence')::numeric as confidence
      from jsonb_array_elements(coalesce(fc.entities_extracted, '[]'::jsonb)) e
      where e->>'type' in ('product','price')
        and t.target_texto is not null
        and e->>'value' ilike '%'||t.target_texto||'%'
      order by (e->>'confidence')::numeric desc nulls last
      limit 1
    ) m on true
    where t.status='aberta' and t.auto_satisfy_mode='conteudo' and t.interacao_tipo='ligacao'
    on conflict (tarefa_id, source_type, source_id) do nothing
    returning tarefa_id, id
  )
  insert into public.tarefa_eventos (tarefa_id, tipo_evento, ator, payload)
  select tarefa_id, 'sugestao_criada', null, jsonb_build_object('candidato_id', id) from novos;

  update public.tarefa_satisfacao_candidatos
  set status='expired', resolved_at=now()
  where status='pending' and created_at < now() - interval '14 days';
end $$;


--
-- Name: tarefas_materializar_recorrentes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tarefas_materializar_recorrentes() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare tpl record; d date; hoje date := (now() at time zone 'America/Sao_Paulo')::date; dispara boolean;
begin
  for tpl in select * from public.tarefa_templates where ativo loop
    if not exists (select 1 from public.profiles p where p.user_id = tpl.assigned_to) then
      insert into public.tarefa_eventos (tarefa_id, tipo_evento, ator, payload)
      values (null, 'materializacao_pulada', null, jsonb_build_object('template_id', tpl.id, 'motivo', 'assignee_sem_perfil'));
      continue;
    end if;
    d := hoje - 6;
    while d <= hoje loop
      dispara := case tpl.cadencia
        when 'diaria' then true
        when 'dias_uteis' then (extract(dow from d) between 1 and 5)
                               and not exists (select 1 from public.calendario_feriados f where f.data = d)
        when 'semanal' then extract(dow from d)::int = any(tpl.dias_semana)
        when 'dias_especificos' then extract(dow from d)::int = any(tpl.dias_semana)
        else false end;
      if dispara then
        insert into public.tarefas
          (descricao, categoria, customer_user_id, assigned_to, created_by, empresa, modo, due_date,
           backstop_days, tolerancia_dias, auto_satisfy_mode, status, template_id,
           requer_comprovacao, tipo_comprovacao, janela_fim, supervisor_user_id, auditoria_status,
           leitura_min, leitura_max, leitura_unidade)
        select tpl.descricao, tpl.categoria, tpl.customer_user_id, tpl.assigned_to, tpl.created_by, tpl.empresa,
           'data', d, 7, tpl.tolerancia_dias, 'off', 'aberta', tpl.id,
           tpl.requer_comprovacao, tpl.tipo_comprovacao, tpl.janela_fim, tpl.supervisor_user_id,
           case when tpl.requer_comprovacao then 'dispensada' else 'nao_requer' end,
           tpl.leitura_min, tpl.leitura_max, tpl.leitura_unidade
        where not exists (select 1 from public.tarefas t
                          where t.template_id = tpl.id and t.assigned_to = tpl.assigned_to and t.due_date = d);
      end if;
      d := d + 1;
    end loop;
  end loop;
end $$;


--
-- Name: tg_omie_clientes_to_ledger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tg_omie_clientes_to_ledger() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  INSERT INTO public.carteira_membership_ledger (user_id, first_seen_at, source)
  VALUES (NEW.user_id, COALESCE(NEW.created_at, now()), 'trigger')
  ON CONFLICT (user_id) DO NOTHING;
  RETURN NEW;
END;
$$;


--
-- Name: tint_apply_keys_snapshot(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tint_apply_keys_snapshot(p_snapshot_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_meta        record;
  v_chunks_recv int;
  v_account     text;
  v_store       text;
  v_setting_id  uuid;
  v_generated   timestamptz;
  v_total_chunks int;
  v_last_applied timestamptz;
  v_total_ativas int;
  v_chaves_snap  int;
  v_desativariam int;
  v_run_id       uuid;
BEGIN
  -- Metadados do snapshot (entity 'formulas' v1).
  SELECT account, store_code, setting_id, generated_at, total_chunks
    INTO v_account, v_store, v_setting_id, v_generated, v_total_chunks
  FROM tint_keys_snapshots
  WHERE snapshot_id = p_snapshot_id AND entity = 'formulas'
  ORDER BY created_at DESC, id DESC
  LIMIT 1;
  IF v_account IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'snapshot inexistente');
  END IF;

  -- S1 (codex P1-7): serializa com a promoção do mesmo (account+store) — a desativação lê o oficial
  -- ATIVO e a promoção o reescreve. Mesma chave de lock que tint_promote_sync_run.
  PERFORM pg_advisory_xact_lock(hashtext('tint_sync:' || v_account || ':' || v_store));

  -- Para registrar erros precisamos de um sync_run (sync_run_id é NOT NULL em tint_sync_errors).
  INSERT INTO tint_sync_runs (setting_id, account, store_code, sync_type, status, source)
  VALUES (v_setting_id, v_account, v_store, 'keys_snapshot', 'running', 'agent')
  RETURNING id INTO v_run_id;

  -- 1) Snapshot COMPLETO? (count distinct chunk_index == total_chunks)
  SELECT count(DISTINCT chunk_index) INTO v_chunks_recv
  FROM tint_keys_snapshots WHERE snapshot_id = p_snapshot_id AND entity = 'formulas';
  IF v_chunks_recv <> v_total_chunks THEN
    INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
    VALUES (v_run_id, 'keys_snapshot', p_snapshot_id::text, 'chunks incompletos',
            jsonb_build_object('recebidos', v_chunks_recv, 'esperados', v_total_chunks));
    UPDATE tint_sync_runs SET status='error', completed_at=now() WHERE id=v_run_id;
    RETURN jsonb_build_object('ok', false, 'error', 'chunks incompletos', 'recebidos', v_chunks_recv, 'esperados', v_total_chunks);
  END IF;

  -- 2) Fora de ordem? (generated_at <= último aplicado)
  SELECT last_keys_snapshot_at INTO v_last_applied FROM tint_integration_settings WHERE id = v_setting_id;
  IF v_last_applied IS NOT NULL AND v_generated <= v_last_applied THEN
    UPDATE tint_sync_runs SET status='complete', completed_at=now(),
      metadata = jsonb_build_object('skipped', 'fora de ordem') WHERE id=v_run_id;
    RETURN jsonb_build_object('ok', true, 'skipped', 'snapshot fora de ordem', 'generated_at', v_generated);
  END IF;

  -- Conjunto de chaves do snapshot (montado de todos os chunks).
  CREATE TEMP TABLE _snap_keys ON COMMIT DROP AS
  SELECT DISTINCT chave
  FROM tint_keys_snapshots, jsonb_array_elements_text(keys) AS chave
  WHERE snapshot_id = p_snapshot_id AND entity = 'formulas';

  -- S4: chave-fonte de 4 PARTES = cor_id|cod_produto|id_base|personalizada (SEM embalagem; ids SAYER,
  -- via joins). O conector v0.1.1 manda 1 chave por fórmula-FONTE; o servidor expande a fonte em N
  -- embalagens vendáveis → a chave por-embalagem nunca casaria (deleção abortava por blast radius).
  -- Uma fórmula-fonte oficial aparece N vezes (1 por embalagem) com a MESMA chave; mantemos f.id por
  -- linha (p/ a desativação marcar TODAS as expansões), mas os counts são sobre chaves DISTINTAS.
  CREATE TEMP TABLE _oficial_ativas ON COMMIT DROP AS
  SELECT f.id,
         (f.cor_id || '|' || p.cod_produto || '|' || b.id_base_sayersystem || '|'
          || (CASE WHEN f.personalizada THEN 'true' ELSE 'false' END)) AS chave
  FROM tint_formulas f
  JOIN tint_produtos   p ON p.id = f.produto_id
  JOIN tint_bases      b ON b.id = f.base_id
  WHERE f.account = v_account AND f.desativada_em IS NULL;

  -- Blast radius sobre chaves DISTINTAS (1 fonte = 1 chave, não N embalagens).
  SELECT count(DISTINCT chave) INTO v_total_ativas FROM _oficial_ativas;
  SELECT count(*)              INTO v_chaves_snap  FROM _snap_keys;
  SELECT count(DISTINCT o.chave) INTO v_desativariam FROM _oficial_ativas o
    WHERE NOT EXISTS (SELECT 1 FROM _snap_keys s WHERE s.chave = o.chave);

  -- 3) Blast radius (espelho validarSnapshotKeys). Oficial vazio = primeira carga → ok.
  IF v_total_ativas > 0 THEN
    IF v_chaves_snap < v_total_ativas * 0.5 THEN
      INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
      VALUES (v_run_id, 'keys_snapshot', p_snapshot_id::text,
              'blast radius: snapshot menor que 50% do oficial ativo (provável chunk perdido)',
              jsonb_build_object('chaves_snapshot', v_chaves_snap, 'oficial_ativas', v_total_ativas));
      UPDATE tint_sync_runs SET status='error', completed_at=now() WHERE id=v_run_id;
      RETURN jsonb_build_object('ok', false, 'error', 'blast radius: snapshot < 50% do oficial ativo',
        'chaves_snapshot', v_chaves_snap, 'oficial_ativas', v_total_ativas);
    END IF;
    IF v_desativariam > v_total_ativas * 0.2 THEN
      INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
      VALUES (v_run_id, 'keys_snapshot', p_snapshot_id::text,
              'blast radius: desativaria >20% das fórmulas ativas',
              jsonb_build_object('desativariam', v_desativariam, 'oficial_ativas', v_total_ativas));
      UPDATE tint_sync_runs SET status='error', completed_at=now() WHERE id=v_run_id;
      RETURN jsonb_build_object('ok', false, 'error', 'blast radius: desativaria >20% das fórmulas ativas',
        'desativariam', v_desativariam, 'oficial_ativas', v_total_ativas);
    END IF;
  END IF;

  -- 4) Desativa (soft) TODAS as expansões cuja CHAVE-FONTE está fora do snapshot.
  --    (Reativação é responsabilidade da promoção.)
  UPDATE tint_formulas SET desativada_em = now(), updated_at = now()
  WHERE id IN (
    SELECT o.id FROM _oficial_ativas o
    WHERE NOT EXISTS (SELECT 1 FROM _snap_keys s WHERE s.chave = o.chave)
  );

  -- 5) Avança o marcador de ordem + fecha o run. deletes/desativadas = chaves DISTINTAS desativadas.
  UPDATE tint_integration_settings SET last_keys_snapshot_at = v_generated, updated_at = now()
  WHERE id = v_setting_id;
  UPDATE tint_sync_runs
    SET status='complete', completed_at=now(), deletes = v_desativariam,
        metadata = jsonb_build_object('desativadas', v_desativariam, 'oficial_ativas', v_total_ativas, 'chaves_snapshot', v_chaves_snap)
  WHERE id = v_run_id;

  RETURN jsonb_build_object('ok', true, 'desativadas', v_desativariam,
    'oficial_ativas', v_total_ativas, 'chaves_snapshot', v_chaves_snap);
END $$;


--
-- Name: tint_calc_preco_final(text, text, text, text, text, uuid, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tint_calc_preco_final(p_account text, p_store_code text, p_cod_produto text, p_id_base text, p_id_embalagem text, p_staging_formula_id uuid, p_fator numeric) RETURNS numeric
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_base       record;
  v_preco_base numeric;
  v_soma       numeric := 0;
  it           record;
  v_cor        record;
BEGIN
  -- Insumo da base p/ ESTA embalagem de destino (latest staging precos_base COM custo).
  -- S2: AND store_code = p_store_code. S3: AND custo IS NOT NULL.
  SELECT custo, imposto_pct, margem_pct INTO v_base
  FROM tint_staging_precos_base
  WHERE account = p_account AND store_code = p_store_code
    AND cod_produto = p_cod_produto AND id_base = p_id_base AND id_embalagem = p_id_embalagem
    AND custo IS NOT NULL
  ORDER BY created_at DESC, id DESC
  LIMIT 1;

  -- base ausente OU custo não-finito → NULL (espelho: base==null || !isFinite(custo)).
  IF v_base IS NULL OR v_base.custo IS NULL OR NOT (v_base.custo > '-Infinity'::numeric AND v_base.custo < 'Infinity'::numeric) THEN
    RETURN NULL;
  END IF;
  v_preco_base := v_base.custo
                  * (1 + COALESCE(v_base.imposto_pct, 0) / 100)
                  * (1 + COALESCE(v_base.margem_pct, 0) / 100);

  -- Σ corantes: itens da formulação × fator; cada corante precisa de custo finito + volume>0.
  FOR it IN
    SELECT id_corante, (qtd_ml * p_fator) AS qtd_exp
    FROM tint_staging_formula_itens
    WHERE staging_formula_id = p_staging_formula_id
      AND id_corante IS NOT NULL AND id_corante <> '' AND COALESCE(qtd_ml, 0) > 0
  LOOP
    -- S2: AND store_code = p_store_code. S3: AND custo IS NOT NULL AND volume_ml IS NOT NULL.
    SELECT custo, volume_ml INTO v_cor
    FROM tint_staging_corantes
    WHERE account = p_account AND store_code = p_store_code AND id_corante_sayersystem = it.id_corante
      AND custo IS NOT NULL AND volume_ml IS NOT NULL
    ORDER BY created_at DESC, id DESC
    LIMIT 1;
    IF v_cor IS NULL OR v_cor.custo IS NULL
       OR NOT (v_cor.custo > '-Infinity'::numeric AND v_cor.custo < 'Infinity'::numeric)
       OR v_cor.volume_ml IS NULL OR v_cor.volume_ml <= 0 THEN
      RETURN NULL;
    END IF;
    v_soma := v_soma + (v_cor.custo / v_cor.volume_ml) * it.qtd_exp;
  END LOOP;

  RETURN round((v_preco_base + v_soma)::numeric, 2);
END $$;


--
-- Name: tint_ensure_corante_stub(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tint_ensure_corante_stub(p_account text, p_id_corante text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE v_id uuid;
BEGIN
  SELECT id INTO v_id FROM tint_corantes WHERE account = p_account AND id_corante_sayersystem = p_id_corante;
  IF v_id IS NOT NULL THEN RETURN v_id; END IF;
  INSERT INTO tint_corantes (account, id_corante_sayersystem, descricao, volume_total_ml)
  VALUES (p_account, p_id_corante, p_id_corante, 1000)
  ON CONFLICT (account, id_corante_sayersystem) DO UPDATE SET descricao = tint_corantes.descricao
  RETURNING id INTO v_id;
  RETURN v_id;
END $$;


--
-- Name: tint_gate_revalida(text, uuid, uuid, text, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tint_gate_revalida(p_account text, p_customer_user_id uuid, p_sales_order_id uuid, p_contexto text, p_items jsonb) RETURNS jsonb
    LANGUAGE plpgsql STABLE
    SET search_path TO 'public', 'pg_temp'
    AS $_$
DECLARE
  v_bloqueios jsonb := '[]'::jsonb;
  v_warnings  jsonb := '[]'::jsonb;
  v_baseline  jsonb;
  v_base_sigs jsonb;              -- {assinatura: count} do baseline
  v_usados    jsonb := '{}'::jsonb; -- {assinatura: count} já consumidos do payload
  v_item      jsonb;
  v_idx       int;
  v_cor       text;
  v_cod_txt   text;
  v_sig       text;
  v_base_n    int;
  v_uso_n     int;
  v_declarada uuid;
  v_declarada_coerente boolean;
  v_prod_id   uuid;
  v_is_base_tint boolean;
  v_n_skus    int;
  v_can_id    uuid;
  v_can_csv   numeric;
  v_can_piso  numeric;            -- 14ª coluna: piso conservador (NULL-preserving)
  v_price     jsonb;
  v_calc_raw  float8;
  v_calc      float8;
  v_tab       float8;
  v_piso      float8;             -- ceil10 do v_can_piso (espelha v_tab)
  v_vu        float8;
  v_fonte     text;
  v_desc      float8;
  v_esperado  float8;
  v_floor     float8;
  v_ult       jsonb;
  v_motivo    text;
  v_legado_ok boolean;

  -- espelhos JS (float8 de ponta a ponta — ver cabeçalho da 20260722100001):
  --   ceil10(v) ≡ Math.ceil(v*10)/10 · round2(v) ≡ floor(v*100+0.5)/100
BEGIN
  IF p_contexto NOT IN ('criacao', 'edicao') THEN
    RETURN jsonb_build_object('ok', false, 'bloqueios', jsonb_build_array(
      jsonb_build_object('index', -1, 'motivo', 'payload_invalido',
                         'detalhe', 'contexto desconhecido: ' || COALESCE(p_contexto, 'NULL'))),
      'warnings', v_warnings);
  END IF;
  IF p_items IS NULL OR jsonb_typeof(p_items) <> 'array' THEN
    RETURN jsonb_build_object('ok', false, 'bloqueios', jsonb_build_array(
      jsonb_build_object('index', -1, 'motivo', 'payload_invalido',
                         'detalhe', 'items ausente ou não é array')),
      'warnings', v_warnings);
  END IF;

  -- Baseline PERSISTIDO (fonte de proveniência/intocabilidade — o caller não
  -- controla; a edição só persiste APÓS o gate). Linha ausente ⇒ '[]'.
  SELECT CASE WHEN jsonb_typeof(so.items) = 'array' THEN so.items ELSE '[]'::jsonb END
    INTO v_baseline
  FROM public.sales_orders so WHERE so.id = p_sales_order_id;
  v_baseline := COALESCE(v_baseline, '[]'::jsonb);

  -- Assinaturas do baseline (com contagem): T|produto|cor|qtd|valor|fonte|desc
  -- para item tint; B|produto|qtd|valor para base-sem-cor. Números
  -- canonicalizados via float8::text; campo malformado vira '?' (nunca erro).
  SELECT COALESCE(jsonb_object_agg(sig, n), '{}'::jsonb) INTO v_base_sigs
  FROM (
    SELECT
      CASE WHEN bi.item->>'tint_cor_id' IS NOT NULL AND bi.item->>'tint_cor_id' <> '' THEN
        'T|' || COALESCE(bi.item->>'omie_codigo_produto', '?') || '|' || (bi.item->>'tint_cor_id') || '|'
             || CASE WHEN jsonb_typeof(bi.item->'quantidade') = 'number'
                     THEN ((bi.item->>'quantidade')::float8)::text ELSE '?' END || '|'
             || CASE WHEN jsonb_typeof(bi.item->'valor_unitario') = 'number'
                     THEN ((bi.item->>'valor_unitario')::float8)::text ELSE '?' END || '|'
             || COALESCE(bi.item->>'tint_price_source', '-') || '|'
             || CASE WHEN jsonb_typeof(bi.item->'tint_discount_pct') = 'number'
                     THEN ((bi.item->>'tint_discount_pct')::float8)::text ELSE '0' END
      ELSE
        'B|' || COALESCE(bi.item->>'omie_codigo_produto', '?') || '|'
             || CASE WHEN jsonb_typeof(bi.item->'quantidade') = 'number'
                     THEN ((bi.item->>'quantidade')::float8)::text ELSE '?' END || '|'
             || CASE WHEN jsonb_typeof(bi.item->'valor_unitario') = 'number'
                     THEN ((bi.item->>'valor_unitario')::float8)::text ELSE '?' END
      END AS sig,
      count(*) AS n
    FROM jsonb_array_elements(v_baseline) AS bi(item)
    GROUP BY 1
  ) s;

  FOR v_idx, v_item IN
    SELECT (ord - 1)::int, val
    FROM jsonb_array_elements(p_items) WITH ORDINALITY AS t(val, ord)
  LOOP
    v_cor := NULLIF(v_item->>'tint_cor_id', '');

    -- valor_unitario numérico (o edge já barrou ≤0/NaN antes; defesa em profundidade)
    IF jsonb_typeof(v_item->'valor_unitario') <> 'number' THEN
      v_bloqueios := v_bloqueios || jsonb_build_object(
        'index', v_idx, 'cor_id', v_cor, 'motivo', 'payload_invalido',
        'detalhe', 'valor_unitario não numérico');
      CONTINUE;
    END IF;
    v_vu := (v_item->>'valor_unitario')::float8;

    -- Código do produto: number OU string numérica (o edge trafega os dois —
    -- Codex P1 do diff: "900001" string escapava da classificação). Código
    -- ilegível NUNCA vira "não-tint": é payload_invalido (fail-closed).
    v_cod_txt := v_item->>'omie_codigo_produto';
    IF v_cod_txt IS NULL OR v_cod_txt !~ '^[0-9]{1,15}$' THEN
      v_bloqueios := v_bloqueios || jsonb_build_object(
        'index', v_idx, 'cor_id', v_cor, 'motivo', 'payload_invalido',
        'detalhe', 'omie_codigo_produto ausente/não numérico: ' || COALESCE(v_cod_txt, 'NULL'));
      CONTINUE;
    END IF;

    v_prod_id := NULL; v_is_base_tint := false;
    SELECT op.id, COALESCE(op.is_tintometric, false) AND op.tint_type = 'base'
      INTO v_prod_id, v_is_base_tint
    FROM public.omie_products op
    WHERE op.omie_codigo_produto = v_cod_txt::bigint
      AND op.account = p_account;

    IF v_cor IS NULL THEN
      -- Item SEM marcador tint: só interessa se o PRODUTO é base tintométrica
      -- (classificação server-side — a ausência do marcador NÃO decide sozinha;
      -- Codex P1: omitir tint_cor_id não pode desligar o gate).
      CONTINUE WHEN NOT v_is_base_tint;
      IF p_contexto = 'criacao' THEN
        -- Push nunca produziu base sem cor (0 na história) — omissão = bloqueio.
        v_bloqueios := v_bloqueios || jsonb_build_object(
          'index', v_idx, 'motivo', 'base_sem_cor',
          'detalhe', 'base tintométrica sem cor não é vendável pelo app — escolha a cor no balcão de tinta');
        CONTINUE;
      END IF;
      -- Edição: linha inbound (balcão físico, importada do Omie) é legítima —
      -- mas SÓ intocada (mesma assinatura B| com contagem no baseline).
      v_sig := 'B|' || v_cod_txt || '|'
            || CASE WHEN jsonb_typeof(v_item->'quantidade') = 'number'
                    THEN ((v_item->>'quantidade')::float8)::text ELSE '?' END || '|'
            || (v_vu)::text;
      v_base_n := COALESCE((v_base_sigs->>v_sig)::int, 0);
      v_uso_n  := COALESCE((v_usados->>v_sig)::int, 0);
      IF v_uso_n < v_base_n THEN
        v_usados := jsonb_set(v_usados, ARRAY[v_sig], to_jsonb(v_uso_n + 1));
        CONTINUE; -- inbound preservada
      END IF;
      v_bloqueios := v_bloqueios || jsonb_build_object(
        'index', v_idx, 'motivo', 'base_sem_cor_alterada',
        'detalhe', 'base tintométrica sem cor alterada/nova na edição — reprecifique pela tela de tinta');
      CONTINUE;
    END IF;

    -- ── item COM tint_cor_id ──
    IF v_prod_id IS NULL THEN
      v_bloqueios := v_bloqueios || jsonb_build_object(
        'index', v_idx, 'cor_id', v_cor, 'motivo', 'produto_nao_encontrado',
        'detalhe', 'produto do item tint não existe na conta ' || p_account);
      CONTINUE;
    END IF;

    -- Edição: item IDÊNTICO ao baseline (assinatura completa, com contagem)
    -- passa com warning — o valor já está no Omie; barrar impediria editar
    -- parcela/observação. Item novo/alterado segue para a validação.
    IF p_contexto = 'edicao' THEN
      v_sig := 'T|' || v_cod_txt || '|' || v_cor || '|'
            || CASE WHEN jsonb_typeof(v_item->'quantidade') = 'number'
                    THEN ((v_item->>'quantidade')::float8)::text ELSE '?' END || '|'
            || (v_vu)::text || '|'
            || COALESCE(v_item->>'tint_price_source', '-') || '|'
            || CASE WHEN jsonb_typeof(v_item->'tint_discount_pct') = 'number'
                    THEN ((v_item->>'tint_discount_pct')::float8)::text ELSE '0' END;
      v_base_n := COALESCE((v_base_sigs->>v_sig)::int, 0);
      v_uso_n  := COALESCE((v_usados->>v_sig)::int, 0);
      IF v_uso_n < v_base_n THEN
        v_usados := jsonb_set(v_usados, ARRAY[v_sig], to_jsonb(v_uso_n + 1));
        v_warnings := v_warnings || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'aviso', 'tint_intocado',
          'detalhe', 'item tint idêntico ao pedido persistido — preço não revalidado (já está no Omie)');
        CONTINUE;
      END IF;
    END IF;

    -- fórmula declarada (cast defensivo — uuid inválido vira NULL)
    v_declarada := NULL;
    IF (v_item->>'tint_formula_id') ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' THEN
      v_declarada := (v_item->>'tint_formula_id')::uuid;
    END IF;
    -- fórmula declarada COERENTE = existe em tint_formulas para (conta, cor) —
    -- qualquer geração (a declarada pode ser a gêmea re-canonizada). Fórmula
    -- ALHEIA (outra conta/cor) ou inexistente NÃO desambigua nem audita nada.
    v_declarada_coerente := false;
    IF v_declarada IS NOT NULL THEN
      SELECT EXISTS (
        SELECT 1 FROM public.tint_formulas tf
        WHERE tf.id = v_declarada AND tf.account = p_account AND tf.cor_id = v_cor
      ) INTO v_declarada_coerente;
    END IF;

    v_fonte := v_item->>'tint_price_source';

    -- Fonte declarada pelo PICKER exige a fórmula que o picker viu (anti-
    -- adulteração — Codex P1 do diff). 'manual' (edição humana) e legado não
    -- têm picker por trás, então não exigem.
    IF v_fonte IN ('calculado', 'tabela', 'cliente') AND NOT v_declarada_coerente THEN
      v_bloqueios := v_bloqueios || jsonb_build_object(
        'index', v_idx, 'cor_id', v_cor, 'motivo', 'payload_invalido',
        'detalhe', 'fonte declarada sem tint_formula_id válido de (conta, cor) — reprecifique no balcão de tinta');
      CONTINUE;
    END IF;

    -- Canônicas candidatas da célula: produto pode ter MAIS de um SKU com a
    -- cor. Sem fórmula declarada que desambigue, célula ambígua BLOQUEIA
    -- (nunca desempatar preço por UUID — Codex P1 do diff).
    SELECT count(*) INTO v_n_skus
    FROM public.tint_skus s
    JOIN public.v_tint_formula_canonica c
      ON c.account = p_account AND c.sku_id = s.id AND c.cor_id = v_cor
    WHERE s.omie_product_id = v_prod_id
      AND s.account = p_account;

    IF v_n_skus = 0 THEN
      v_bloqueios := v_bloqueios || jsonb_build_object(
        'index', v_idx, 'cor_id', v_cor, 'motivo', 'formula_morta',
        'detalhe', 'não há fórmula ativa/canônica desta cor para o produto — reprecifique no balcão de tinta');
      CONTINUE;
    END IF;

    v_can_id := NULL; v_can_csv := NULL; v_can_piso := NULL;
    IF v_n_skus > 1 THEN
      -- só a fórmula declarada (do picker) desambigua a célula
      SELECT c.id, c.preco_csv_legado, c.preco_piso_legado
        INTO v_can_id, v_can_csv, v_can_piso
      FROM public.tint_skus s
      JOIN public.v_tint_formula_canonica c
        ON c.account = p_account AND c.sku_id = s.id AND c.cor_id = v_cor
      WHERE s.omie_product_id = v_prod_id
        AND s.account = p_account
        AND c.id = v_declarada;
      IF v_can_id IS NULL THEN
        v_bloqueios := v_bloqueios || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'motivo', 'formula_ambigua',
          'detalhe', 'o produto tem mais de um SKU com esta cor e a fórmula declarada não resolve — reprecifique no balcão de tinta');
        CONTINUE;
      END IF;
    ELSE
      SELECT c.id, c.preco_csv_legado, c.preco_piso_legado
        INTO v_can_id, v_can_csv, v_can_piso
      FROM public.tint_skus s
      JOIN public.v_tint_formula_canonica c
        ON c.account = p_account AND c.sku_id = s.id AND c.cor_id = v_cor
      WHERE s.omie_product_id = v_prod_id
        AND s.account = p_account;
    END IF;

    IF v_declarada_coerente AND v_declarada <> v_can_id THEN
      -- geração trocou (ex.: Fase 5 desativar a SAYERLACK) — informa, não barra;
      -- o PREÇO é validado contra a canônica atual de qualquer forma.
      v_warnings := v_warnings || jsonb_build_object(
        'index', v_idx, 'cor_id', v_cor, 'aviso', 'formula_recanonizada',
        'declarada', v_declarada, 'canonica', v_can_id);
    END IF;

    -- motor de preço AGORA (get_tint_price REAL — sem cache de 5min)
    v_price := public.get_tint_price(v_can_id);
    v_calc_raw := (v_price->>'precoFinal')::float8;
    IF v_calc_raw IS NULL THEN
      -- paridade com selectTintPrice regra 1: motor sem preço bloqueia TODAS
      -- as fontes (inclusive tabela/cliente) — nunca vender o que a RPC barra.
      v_motivo := CASE
        WHEN NOT COALESCE((v_price->>'baseDisponivel')::boolean, false) THEN 'base'
        WHEN NOT COALESCE((v_price->>'corantesCompletos')::boolean, false) THEN 'corante'
        ELSE 'receita' END;
      v_bloqueios := v_bloqueios || jsonb_build_object(
        'index', v_idx, 'cor_id', v_cor, 'motivo', 'sem_preco_motor',
        'detalhe', 'motor honesto sem preço (' || v_motivo || ') — corrija no Omie/tintométrico antes de vender');
      CONTINUE;
    END IF;

    v_calc := ceil(v_calc_raw * 10) / 10;                       -- ceil10 (≡ JS)
    -- RÓTULO (fonte 'tabela'): allowlist, proveniência provada.
    v_tab  := CASE WHEN v_can_csv IS NOT NULL AND v_can_csv > 0
                   THEN ceil((v_can_csv)::float8 * 10) / 10 ELSE NULL END;
    -- PISO (fontes 'manual' e legado): conservador.
    -- ⚠️ ELEGIBILIDADE ACOPLADA a v_tab (achado P1 do challenge Codex xhigh,
    -- 2026-07-21). O NULL-preserving da view garante os invariantes sobre os
    -- valores CRUS — mas o guard `> 0` aqui cria uma SEGUNDA forma de "ausente"
    -- que a view não conhece, e por ela a monotonicidade vazava:
    --   csv = 0 (≠ NULL) e piso = 90, calc = 102.5
    --   ⇒ I1 passa (nenhum é NULL) e I2 passa (90 >= 0) — os dois invariantes
    --     provados ficam VERDES — mas v_tab vira NULL e v_piso vira 90, então
    --     o piso EFETIVO cai de 102.5 para 90 e um manual de 95 passa a ser
    --     aceito onde hoje bloqueia. Afrouxamento pela porta dos fundos.
    -- Gatear v_piso em v_tab restaura a monotonicidade no nível EFETIVO:
    --   v_tab IS NULL ⇒ v_piso IS NULL   ·   ambos presentes ⇒ v_piso >= v_tab
    --   ⇒ v_floor novo >= v_floor de hoje SEMPRE. Sem isto a alegação é falsa.
    -- (Classe medida em prod 2026-07-21: 0 chaves — latente, como o resto.)
    v_piso := CASE WHEN v_tab IS NOT NULL AND v_can_piso IS NOT NULL AND v_can_piso > 0
                   THEN ceil((v_can_piso)::float8 * 10) / 10 ELSE NULL END;

    -- desconto declarado (0 ≤ d < 100; ausente = 0). d=100 é incompatível com
    -- o guard global preço>0 do edge — contrato alinhado (Codex).
    v_desc := 0;
    IF v_item ? 'tint_discount_pct' THEN
      IF jsonb_typeof(v_item->'tint_discount_pct') <> 'number' THEN
        v_bloqueios := v_bloqueios || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'motivo', 'desconto_invalido',
          'detalhe', 'tint_discount_pct não numérico');
        CONTINUE;
      END IF;
      v_desc := (v_item->>'tint_discount_pct')::float8;
      IF v_desc < 0 OR v_desc >= 100 THEN
        v_bloqueios := v_bloqueios || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'motivo', 'desconto_invalido',
          'detalhe', 'tint_discount_pct fora de 0–99.99: ' || v_desc);
        CONTINUE;
      END IF;
    END IF;

    IF v_fonte = 'calculado' THEN
      v_esperado := floor(v_calc * (1 - v_desc/100) * 100 + 0.5) / 100;

    ELSIF v_fonte = 'tabela' THEN
      -- ⚠️ a fonte 'tabela' valida contra o RÓTULO (v_tab), NÃO contra o piso:
      -- a escolha da vendedora é sobre PROVENIÊNCIA ("versão anterior"), e
      -- validar contra o piso conservador barraria a escolha legítima.
      IF v_tab IS NULL THEN
        v_bloqueios := v_bloqueios || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'motivo', 'fonte_tabela_indisponivel',
          'detalhe', 'a fonte "tabela" foi escolhida mas a chave não tem mais CSV — reprecifique no balcão');
        CONTINUE;
      END IF;
      v_esperado := floor(v_tab * (1 - v_desc/100) * 100 + 0.5) / 100;

    ELSIF v_fonte = 'cliente' THEN
      v_ult := public.tint_ultimo_preco_cliente(
        p_customer_user_id, v_prod_id, v_cor, p_sales_order_id);
      IF v_ult IS NULL OR jsonb_typeof(v_ult->'price') <> 'number' THEN
        v_bloqueios := v_bloqueios || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'motivo', 'preco_cliente_sem_historico',
          'detalhe', 'a fonte "cliente" exige pedido real no Omie (não-cancelado, últimos 180 dias) — não encontrado');
        CONTINUE;
      END IF;
      v_esperado := floor((v_ult->>'price')::float8 * (1 - v_desc/100) * 100 + 0.5) / 100;

    ELSIF v_fonte = 'manual' THEN
      -- Preço digitado pelo humano na EDIÇÃO (o front seta 'manual' ao editar
      -- valor de item tint): subir é livre; baixar além do piso atual das
      -- fontes legítimas bloqueia. Nada abaixo do que 'tabela'/'calculado'
      -- sem desconto já permitiriam (Codex P1 do diff: sem esta fonte, todo
      -- aumento manual legítimo caía em metadados_ausentes).
      -- ⚠️ v_piso (conservador), NÃO v_tab (allowlist): encolher o conjunto do
      -- max para dar precisão AO RÓTULO não pode afrouxar o PISO.
      v_floor := LEAST(v_calc, COALESCE(v_piso, v_calc));
      IF v_vu < v_floor - 0.005 THEN
        v_bloqueios := v_bloqueios || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'motivo', 'preco_obsoleto',
          'detalhe', 'preço manual abaixo do piso atual das fontes (calc/tabela) — reprecifique no balcão de tinta',
          'esperado_minimo', v_floor, 'recebido', v_vu);
      END IF;
      CONTINUE;

    ELSIF v_fonte IS NULL THEN
      -- SEM metadados: o fallback legado (piso) EXIGE prova de proveniência —
      -- existe no baseline persistido um item da MESMA célula TAMBÉM sem fonte
      -- (orçamento/pedido pré-Fase-3). Sem essa prova, item novo que omite
      -- metadados é bloqueado (o fallback não é controlável pelo caller).
      SELECT EXISTS (
        SELECT 1 FROM jsonb_array_elements(v_baseline) AS bi(item)
        WHERE bi.item->>'omie_codigo_produto' = v_cod_txt
          AND bi.item->>'tint_cor_id' = v_cor
          AND bi.item->>'tint_price_source' IS NULL
      ) INTO v_legado_ok;
      IF NOT v_legado_ok THEN
        v_bloqueios := v_bloqueios || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'motivo', 'metadados_ausentes',
          'detalhe', 'item tint sem fonte de preço declarada e sem lastro legado no pedido — reprecifique no balcão de tinta');
        CONTINUE;
      END IF;
      -- mesmo piso conservador da fonte 'manual' (ver nota acima)
      v_floor := LEAST(v_calc, COALESCE(v_piso, v_calc));
      IF v_vu < v_floor - 0.005 THEN
        v_bloqueios := v_bloqueios || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'motivo', 'preco_obsoleto',
          'detalhe', 'preço abaixo do piso atual das fontes (calc/tabela) — reprecifique no balcão de tinta',
          'esperado_minimo', v_floor, 'recebido', v_vu);
      END IF;
      CONTINUE;

    ELSE
      -- fonte desconhecida (typo/adulteração) — nunca cair no fallback
      v_bloqueios := v_bloqueios || jsonb_build_object(
        'index', v_idx, 'cor_id', v_cor, 'motivo', 'fonte_invalida',
        'detalhe', 'tint_price_source desconhecida: ' || v_fonte);
      CONTINUE;
    END IF;

    -- Auditoria: preco_sem_desconto declarado divergente da fonte recomputada
    -- vira WARNING (o preço COBRADO já é validado acima — bloquear aqui só
    -- criaria falso positivo sem proteção extra).
    IF jsonb_typeof(v_item->'tint_preco_sem_desconto') = 'number' THEN
      IF abs((v_item->>'tint_preco_sem_desconto')::float8 -
             CASE v_fonte
               WHEN 'calculado' THEN v_calc
               WHEN 'tabela'    THEN v_tab
               ELSE (v_ult->>'price')::float8
             END) > 0.005 THEN
        v_warnings := v_warnings || jsonb_build_object(
          'index', v_idx, 'cor_id', v_cor, 'aviso', 'preco_sem_desconto_divergente',
          'declarado', (v_item->>'tint_preco_sem_desconto')::float8);
      END IF;
    END IF;

    IF abs(v_vu - v_esperado) > 0.005 THEN
      v_bloqueios := v_bloqueios || jsonb_build_object(
        'index', v_idx, 'cor_id', v_cor, 'motivo', 'preco_divergente',
        'detalhe', 'o preço da fonte "' || v_fonte || '" mudou desde a montagem do pedido — reprecifique no balcão de tinta',
        'fonte', v_fonte, 'esperado', v_esperado, 'recebido', v_vu);
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'ok', jsonb_array_length(v_bloqueios) = 0,
    'bloqueios', v_bloqueios,
    'warnings', v_warnings);
END;
$_$;


--
-- Name: FUNCTION tint_gate_revalida(p_account text, p_customer_user_id uuid, p_sales_order_id uuid, p_contexto text, p_items jsonb); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.tint_gate_revalida(p_account text, p_customer_user_id uuid, p_sales_order_id uuid, p_contexto text, p_items jsonb) IS 'Fase 3 tint: gate da fronteira omie-vendas-sync (criar_pedido/alterar_pedido). Revalida item tint contra o estado ATUAL (canônica viva + preço recomputado + fonte declarada, aritmética float8 ≡ JS). Baseline persistido decide proveniência (legado=piso) e intocabilidade (edição). Fontes: calculado/tabela/cliente (exigem tint_formula_id coerente) · manual (piso) · ausente (legado com lastro). Base tint sem cor: bloqueia na criação; na edição só intocada (inbound). Multi-SKU sem fórmula que desambigue: bloqueia. service_role-only. Bloqueio ⇒ {ok:false,bloqueios:[…]} — o edge NÃO toca o Omie. 2026-07-21: o PISO ("manual"/legado) passou a ler preco_piso_legado (max CONSERVADOR de todas as ativas da chave); a fonte "tabela" segue lendo preco_csv_legado (RÓTULO, allowlist). Separar os dois impede que dar precisão de proveniência ao rótulo afrouxe o piso do submit.';


--
-- Name: tint_marcar_bases_mixmachine(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tint_marcar_bases_mixmachine() RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_count integer;
begin
  with alvo as (
    select op.id,
      case lower(btrim(op.familia))
        when 'bases mixmachine' then 'base'
        when 'concentrados mixmachine' then 'concentrado'
      end as tipo_esperado
    from public.omie_products op
    where op.account = 'oben'
      and op.ativo = true
      and lower(btrim(op.familia)) in ('bases mixmachine', 'concentrados mixmachine')
  )
  update public.omie_products op
  set is_tintometric = true,
      tint_type = alvo.tipo_esperado,
      updated_at = now()
  from alvo
  where op.id = alvo.id
    and (op.is_tintometric is not true or op.tint_type is distinct from alvo.tipo_esperado);
  get diagnostics v_count = row_count;
  return coalesce(v_count, 0);
end;
$$;


--
-- Name: tint_promote_sync_run(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tint_promote_sync_run(p_sync_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    SET statement_timeout TO '300s'
    AS $_$
DECLARE
  v_run            record;
  v_account        text;
  v_store          text;
  v_importacao_id  uuid;
  v_promovidas     int := 0;
  v_erros          int := 0;
  v_recalc         int := 0;
  v_tmp            int := 0;
  v_zero_uuid      constant uuid := '00000000-0000-0000-0000-000000000000';
  r                record;
  v_produto_id     uuid;
  v_base_id        uuid;
  v_subcolecao_id  uuid;
  v_sku_id         uuid;
  v_emb_id         uuid;
  v_formula_id     uuid;
  v_fator          numeric;
  v_preco          numeric;
  v_qtd_vendaveis  int;
  -- [1d] transições p/ base pura executadas neste run + cap anti-limpeza-em-massa.
  -- O cap é ACUMULADO em janela de 24h por (account,store) — Codex P0 2026-07-20: um cap
  -- por-promote era contornável em catraca (run A limpa 50, run B limpa as 2 restantes —
  -- as já-limpas deixavam de contar) e célula a célula. A soma durável vem do próprio
  -- rastro dos promotes (tint_sync_runs.metadata->>'receitas_limpas').
  v_limpezas       int := 0;
  v_limpezas_24h   int := 0;
  v_cap_limpezas   constant int := 50;
BEGIN
  SELECT * INTO v_run FROM tint_sync_runs WHERE id = p_sync_run_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'run não encontrado');
  END IF;
  v_account := v_run.account;
  v_store   := v_run.store_code;

  -- S1 (codex P1-7): serializa promoções concorrentes do mesmo (account+store). Sem isto, dois
  -- runs simultâneos do mesmo par leem o latest-staging e escrevem o oficial interleavados (o mais
  -- VELHO podia vencer). Lock de transação → libera automaticamente no commit/rollback.
  PERFORM pg_advisory_xact_lock(hashtext('tint_sync:' || v_account || ':' || v_store));

  -- Cria/reusa o registro de importação (reusa a tela de histórico). arquivo_hash = run_id
  -- colide com UNIQUE(account, arquivo_hash) em re-execução → ON CONFLICT reusa a linha (idempotente).
  INSERT INTO tint_importacoes (account, tipo, arquivo_nome, arquivo_hash, status)
  VALUES (v_account, 'sync_agent', 'sync:' || p_sync_run_id::text, p_sync_run_id::text, 'processando')
  ON CONFLICT (account, arquivo_hash) DO UPDATE
    SET status = 'processando', registros_importados = 0, registros_erro = 0
  RETURNING id INTO v_importacao_id;

  -- ──────────────────────────────────────────────────────────────────────────
  -- LATEST-STAGING-POR-CHAVE: views temporárias com a linha mais recente por chave
  -- natural (across TODOS os runs do mesmo account+store), restritas às chaves
  -- tocadas POR ESTE run (§11 P1-C). DISTINCT ON (chave) ORDER BY created_at DESC, id DESC.
  -- ──────────────────────────────────────────────────────────────────────────

  -- Produtos tocados pelo run → latest (descrição mais recente; stub se ausente).
  CREATE TEMP TABLE _tp_prod ON COMMIT DROP AS
  WITH chaves AS (
    SELECT DISTINCT cod_produto FROM tint_staging_produtos
    WHERE sync_run_id = p_sync_run_id AND cod_produto IS NOT NULL
  ),
  latest AS (
    SELECT DISTINCT ON (s.cod_produto) s.cod_produto, s.descricao
    FROM tint_staging_produtos s
    JOIN chaves c ON c.cod_produto = s.cod_produto
    WHERE s.account = v_account AND s.store_code = v_store
    ORDER BY s.cod_produto, s.created_at DESC, s.id DESC
  )
  SELECT cod_produto, descricao FROM latest;

  CREATE TEMP TABLE _tp_base ON COMMIT DROP AS
  WITH chaves AS (
    SELECT DISTINCT id_base_sayersystem FROM tint_staging_bases
    WHERE sync_run_id = p_sync_run_id AND id_base_sayersystem IS NOT NULL
  ),
  latest AS (
    SELECT DISTINCT ON (s.id_base_sayersystem) s.id_base_sayersystem, s.descricao
    FROM tint_staging_bases s
    JOIN chaves c ON c.id_base_sayersystem = s.id_base_sayersystem
    WHERE s.account = v_account AND s.store_code = v_store
    ORDER BY s.id_base_sayersystem, s.created_at DESC, s.id DESC
  )
  SELECT id_base_sayersystem, descricao FROM latest;

  CREATE TEMP TABLE _tp_emb ON COMMIT DROP AS
  WITH chaves AS (
    SELECT DISTINCT id_embalagem_sayersystem FROM tint_staging_embalagens
    WHERE sync_run_id = p_sync_run_id AND id_embalagem_sayersystem IS NOT NULL
  ),
  latest AS (
    SELECT DISTINCT ON (s.id_embalagem_sayersystem) s.id_embalagem_sayersystem, s.descricao, s.volume_ml
    FROM tint_staging_embalagens s
    JOIN chaves c ON c.id_embalagem_sayersystem = s.id_embalagem_sayersystem
    WHERE s.account = v_account AND s.store_code = v_store
    ORDER BY s.id_embalagem_sayersystem, s.created_at DESC, s.id DESC
  )
  SELECT id_embalagem_sayersystem, descricao, volume_ml FROM latest;

  -- Corantes tocados → latest (descricao + preco_litro + custo/volume p/ preço).
  CREATE TEMP TABLE _tp_cor ON COMMIT DROP AS
  WITH chaves AS (
    SELECT DISTINCT id_corante_sayersystem FROM tint_staging_corantes
    WHERE sync_run_id = p_sync_run_id AND id_corante_sayersystem IS NOT NULL
  ),
  latest AS (
    SELECT DISTINCT ON (s.id_corante_sayersystem)
           s.id_corante_sayersystem, s.descricao, s.preco_litro, s.custo, s.volume_ml
    FROM tint_staging_corantes s
    JOIN chaves c ON c.id_corante_sayersystem = s.id_corante_sayersystem
    WHERE s.account = v_account AND s.store_code = v_store
    ORDER BY s.id_corante_sayersystem, s.created_at DESC, s.id DESC
  )
  SELECT id_corante_sayersystem, descricao, preco_litro, custo, volume_ml FROM latest;

  -- Skus tocados → latest por (cod_produto,id_base,id_embalagem).
  CREATE TEMP TABLE _tp_sku ON COMMIT DROP AS
  WITH chaves AS (
    SELECT DISTINCT cod_produto, id_base, id_embalagem FROM tint_staging_skus
    WHERE sync_run_id = p_sync_run_id
      AND cod_produto IS NOT NULL AND id_base IS NOT NULL AND id_embalagem IS NOT NULL
  ),
  latest AS (
    SELECT DISTINCT ON (s.cod_produto, s.id_base, s.id_embalagem)
           s.cod_produto, s.id_base, s.id_embalagem
    FROM tint_staging_skus s
    JOIN chaves c ON c.cod_produto = s.cod_produto AND c.id_base = s.id_base AND c.id_embalagem = s.id_embalagem
    WHERE s.account = v_account AND s.store_code = v_store
    ORDER BY s.cod_produto, s.id_base, s.id_embalagem, s.created_at DESC, s.id DESC
  )
  SELECT cod_produto, id_base, id_embalagem FROM latest;

  -- 20260617 (fix CARGA): pares de skus REALMENTE NOVOS (ainda não existem no oficial). SÓ esses
  -- precisam re-expandir (embalagem nova p/ o par). Capturado ANTES do upsert de skus (E1/loop) —
  -- depois eles já existiriam. Sem isto, um run de catalogs com TODOS os skus re-expandiria TODAS as
  -- fórmulas de uma vez → gateway timeout → advisory lock preso → lock timeout (incidente 17/06).
  CREATE TEMP TABLE _skus_novos ON COMMIT DROP AS
  SELECT DISTINCT t.cod_produto, t.id_base
  FROM _tp_sku t
  WHERE NOT EXISTS (
    SELECT 1 FROM tint_skus sk
    JOIN tint_produtos   p ON p.id = sk.produto_id  AND p.account = v_account AND p.cod_produto             = t.cod_produto
    JOIN tint_bases      b ON b.id = sk.base_id      AND b.account = v_account AND b.id_base_sayersystem     = t.id_base
    JOIN tint_embalagens e ON e.id = sk.embalagem_id AND e.account = v_account AND e.id_embalagem_sayersystem = t.id_embalagem
  );

  -- ──────────────────────────────────────────────────────────────────────────
  -- E1) Catálogo: upsert oficial a partir do latest-staging (espelha onConflict do tint-import).
  -- ──────────────────────────────────────────────────────────────────────────
  INSERT INTO tint_produtos (account, cod_produto, descricao)
  SELECT v_account, cod_produto, COALESCE(descricao, cod_produto) FROM _tp_prod
  ON CONFLICT (account, cod_produto) DO UPDATE SET descricao = EXCLUDED.descricao;

  INSERT INTO tint_bases (account, id_base_sayersystem, descricao)
  SELECT v_account, id_base_sayersystem, COALESCE(descricao, id_base_sayersystem) FROM _tp_base
  ON CONFLICT (account, id_base_sayersystem) DO UPDATE SET descricao = EXCLUDED.descricao;

  -- volume_ml NULL/0 do staging NUNCA rebaixa o volume oficial existente (espelha o
  -- COALESCE/NULLIF do corante): senão a expansão (guard volume_ml>0) dropa as fórmulas
  -- da embalagem silenciosamente. INSERT de embalagem nova com volume NULL → stub 0 (não
  -- vendável, não satisfaz o guard de expansão). descricao idem (NULL não apaga a oficial).
  INSERT INTO tint_embalagens (account, id_embalagem_sayersystem, descricao, volume_ml)
  SELECT v_account, id_embalagem_sayersystem, COALESCE(descricao, id_embalagem_sayersystem), COALESCE(volume_ml, 0) FROM _tp_emb
  ON CONFLICT (account, id_embalagem_sayersystem) DO UPDATE
    SET descricao = COALESCE(EXCLUDED.descricao, tint_embalagens.descricao),
        volume_ml = COALESCE(NULLIF(EXCLUDED.volume_ml, 0), tint_embalagens.volume_ml);

  -- Corantes: volume_total_ml é NOT NULL no oficial → preferir staging volume_ml, senão preservar
  -- o existente, senão 1000 (default do CSV-import p/ stub). preco_litro derivado de custo/volume
  -- (R$/L) quando os dois presentes; senão preserva o staging.preco_litro.
  INSERT INTO tint_corantes (account, id_corante_sayersystem, descricao, volume_total_ml, preco_litro)
  SELECT
    v_account,
    c.id_corante_sayersystem,
    COALESCE(c.descricao, c.id_corante_sayersystem),
    COALESCE(c.volume_ml, ex.volume_total_ml, 1000),
    CASE
      WHEN c.custo IS NOT NULL AND c.volume_ml IS NOT NULL AND c.volume_ml > 0
        THEN round((c.custo / c.volume_ml * 1000)::numeric, 2)
      ELSE c.preco_litro
    END
  FROM _tp_cor c
  LEFT JOIN tint_corantes ex ON ex.account = v_account AND ex.id_corante_sayersystem = c.id_corante_sayersystem
  ON CONFLICT (account, id_corante_sayersystem) DO UPDATE
    SET descricao        = EXCLUDED.descricao,
        volume_total_ml  = EXCLUDED.volume_total_ml,
        preco_litro      = COALESCE(EXCLUDED.preco_litro, tint_corantes.preco_litro);

  -- Skus de produto_base_embalagem: resolve FKs (cria stub de produto/base/embalagem se a
  -- linha do sku referenciar id ainda não-visto no run — espelha ensure* do CSV).
  FOR r IN SELECT cod_produto, id_base, id_embalagem FROM _tp_sku LOOP
    INSERT INTO tint_produtos (account, cod_produto, descricao)
    VALUES (v_account, r.cod_produto, r.cod_produto)
    ON CONFLICT (account, cod_produto) DO NOTHING;
    INSERT INTO tint_bases (account, id_base_sayersystem, descricao)
    VALUES (v_account, r.id_base, r.id_base)
    ON CONFLICT (account, id_base_sayersystem) DO NOTHING;
    INSERT INTO tint_embalagens (account, id_embalagem_sayersystem, descricao, volume_ml)
    VALUES (v_account, r.id_embalagem, r.id_embalagem, 0)
    ON CONFLICT (account, id_embalagem_sayersystem) DO NOTHING;

    SELECT id INTO v_produto_id FROM tint_produtos WHERE account = v_account AND cod_produto = r.cod_produto;
    SELECT id INTO v_base_id    FROM tint_bases    WHERE account = v_account AND id_base_sayersystem = r.id_base;
    SELECT id INTO v_emb_id     FROM tint_embalagens WHERE account = v_account AND id_embalagem_sayersystem = r.id_embalagem;

    INSERT INTO tint_skus (account, produto_id, base_id, embalagem_id)
    VALUES (v_account, v_produto_id, v_base_id, v_emb_id)
    ON CONFLICT (account, produto_id, base_id, embalagem_id) DO NOTHING;
  END LOOP;

  -- ══════════════════════════════════════════════════════════════════════════
  -- E2/E3) Fórmulas — SET-BASED (substitui o FOR LOOP aninhado procedural).
  --   Mesma regra de negócio do loop, em massa. Pares afetados + latest-staging por chave de
  --   fórmula são VERBATIM do loop; o que muda é a expansão/preço/upsert/itens (INSERT...SELECT).
  -- ══════════════════════════════════════════════════════════════════════════

  -- Pares (cod_produto, id_base) afetados = pares com fórmula tocada NESTE run ∪ pares de sku
  -- NOVO (§11 P1-C: embalagem nova ⇒ re-expandir). 20260617 (fix CARGA): _skus_novos no lugar de
  -- _tp_sku — sku re-enviado (já existente) NÃO dispara re-expansão; senão um run de catalogs com
  -- todos os skus re-expandiria TODAS as fórmulas de uma vez (lock timeout, incidente 17/06).
  CREATE TEMP TABLE _pares ON COMMIT DROP AS
  SELECT DISTINCT cod_produto, id_base FROM (
    SELECT cod_produto, id_base FROM tint_staging_formulas
      WHERE sync_run_id = p_sync_run_id AND cod_produto IS NOT NULL AND id_base IS NOT NULL
    UNION
    SELECT cod_produto, id_base FROM _skus_novos
  ) u;

  -- Latest staging de fórmula por (cor_id, cod_produto, id_base, sub_norm, personalizada),
  -- restrita aos pares afetados — across TODOS os runs.
  CREATE TEMP TABLE _formulas_latest ON COMMIT DROP AS
  WITH alvo AS (
    SELECT s.*
    FROM tint_staging_formulas s
    JOIN _pares p ON p.cod_produto = s.cod_produto AND p.id_base = s.id_base
    WHERE s.account = v_account AND s.store_code = v_store
      AND s.cor_id IS NOT NULL AND s.cod_produto IS NOT NULL AND s.id_base IS NOT NULL
  )
  SELECT DISTINCT ON (cor_id, cod_produto, id_base, COALESCE(subcolecao, ''), personalizada)
         id AS staging_formula_id, cor_id,
         -- 20260622 (fix nome_cor NULL): nome de cor PERSONALIZADA pode vir VAZIO do conector (lookup
         -- CorPerson não resolveu) → a constraint NOT NULL de tint_formulas.nome_cor derrubava o RUN
         -- INTEIRO (23502). Fallback p/ cor_id (stub, espelha o corante stub). Nunca abortar a promoção
         -- por um campo de DISPLAY ausente; o nome real entra no próximo upsert quando o conector resolver.
         -- Codex 22/06: CASE (não COALESCE+btrim) p/ NÃO trimar nome legítimo com espaço — só
         -- substitui quando NULL/vazio, preservando o nome_cor original VERBATIM.
         CASE WHEN nome_cor IS NULL OR btrim(nome_cor) = '' THEN cor_id ELSE nome_cor END AS nome_cor,
         cod_produto, id_base, id_embalagem,
         subcolecao, volume_final_ml, personalizada,
         -- [1c-A] protocolo Fase 1c: o nº de itens DECLARADO acompanha o header latest; o run DONO
         -- do header viaja junto p/ o log do gate (a promoção pode estar rodando por OUTRO run).
         expected_item_count,
         -- [1d-A] sinal semântico da FONTE acompanha o header latest (NULL = não-declarado).
         is_base_pura,
         sync_run_id AS header_sync_run_id
  FROM alvo
  ORDER BY cor_id, cod_produto, id_base, COALESCE(subcolecao, ''), personalizada,
           created_at DESC, id DESC;

  -- Resolve FK produto/base por JOIN (não SELECT por linha). LEFT JOIN p/ separar os não-resolvidos.
  CREATE TEMP TABLE _fl_resolved ON COMMIT DROP AS
  SELECT fl.*, p.id AS produto_id, b.id AS base_id
  FROM _formulas_latest fl
  LEFT JOIN tint_produtos p ON p.account = v_account AND p.cod_produto = fl.cod_produto
  LEFT JOIN tint_bases    b ON b.account = v_account AND b.id_base_sayersystem = fl.id_base;

  -- Guard 1 — produto/base não resolvido (catálogo incompleto). Espelha o 1º CONTINUE do loop.
  INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
  SELECT p_sync_run_id, 'formula_promote', fl.cor_id,
         'produto/base não resolvido (catálogo incompleto)',
         jsonb_build_object('cod_produto', fl.cod_produto, 'id_base', fl.id_base)
  FROM _fl_resolved fl
  WHERE fl.produto_id IS NULL OR fl.base_id IS NULL;
  GET DIAGNOSTICS v_tmp = ROW_COUNT; v_erros := v_erros + v_tmp;

  -- Subcoleções: ensure p/ fórmulas com produto/base resolvido e subcoleção não-vazia (o loop
  -- ensura DEPOIS do guard de produto/base, ANTES dos guards de volume/vendável). id = texto CRU.
  INSERT INTO tint_subcolecoes (account, id_subcolecao_sayersystem, descricao)
  SELECT DISTINCT v_account, fl.subcolecao, fl.subcolecao
  FROM _fl_resolved fl
  WHERE fl.produto_id IS NOT NULL AND fl.base_id IS NOT NULL
    AND fl.subcolecao IS NOT NULL AND btrim(fl.subcolecao) <> ''
  ON CONFLICT (account, id_subcolecao_sayersystem) DO NOTHING;

  -- Guard 2 — volume de formulação <= 0/nulo (entre os resolvidos). Espelha o 2º CONTINUE.
  INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
  SELECT p_sync_run_id, 'formula_promote', fl.cor_id,
         'volume de formulação <= 0 ou nulo',
         jsonb_build_object('volume_final_ml', fl.volume_final_ml)
  FROM _fl_resolved fl
  WHERE fl.produto_id IS NOT NULL AND fl.base_id IS NOT NULL
    AND (fl.volume_final_ml IS NULL OR fl.volume_final_ml <= 0);
  GET DIAGNOSTICS v_tmp = ROW_COUNT; v_erros := v_erros + v_tmp;

  -- Guard 3 — zero embalagens vendáveis para o par (entre resolvidos com volume OK). 3º CONTINUE.
  INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
  SELECT p_sync_run_id, 'formula_promote', fl.cor_id,
         'zero embalagens vendáveis para o par (produto,base)',
         jsonb_build_object('cod_produto', fl.cod_produto, 'id_base', fl.id_base)
  FROM _fl_resolved fl
  WHERE fl.produto_id IS NOT NULL AND fl.base_id IS NOT NULL
    AND fl.volume_final_ml IS NOT NULL AND fl.volume_final_ml > 0
    AND NOT EXISTS (
      SELECT 1 FROM tint_skus sk
      JOIN tint_embalagens e ON e.id = sk.embalagem_id
      WHERE sk.account = v_account AND sk.produto_id = fl.produto_id AND sk.base_id = fl.base_id
        AND e.volume_ml IS NOT NULL AND e.volume_ml > 0
    );
  GET DIAGNOSTICS v_tmp = ROW_COUNT; v_erros := v_erros + v_tmp;

  -- ══════════════════════════════════════════════════════════════════════════
  -- Guard 4 (FASE 1 money-path — fail-closed por-linha, RECEITA CORROMPIDA) — ALL-OR-NOTHING por fórmula.
  --   Um corante PRESENTE (id_corante não-vazio) cujo conjunto de linhas NÃO tem NENHUMA dose válida
  --   (bool_and(COALESCE(qtd_ml,0) <= 0)) seria FILTRADO pelo INSERT de tint_formula_itens
  --   (WHERE id_corante<>'' AND qtd_ml>0) → a fórmula gravaria receita PARCIAL (subfaturamento silencioso:
  --   get_tint_price/bool_and sobre os corantes PRESENTES pode devolver preço BAIXO válido) ou ZERO.
  --   Fail-OPEN. AQUI a fórmula inteira NÃO é promovida (o NOT EXISTS no _expand a remove) → fora de
  --   _promoted → o DELETE...USING _promoted não a toca → a RECEITA ANTERIOR é 100% preservada; o erro
  --   vai a tint_sync_errors. bool_and POR (formula,corante) — não "≥1 linha ruim" — para NÃO barrar a
  --   dosagem em 2 etapas legítima (mesmo corante em 2 ordens ambas >0, 20260622210000): ali o corante
  --   TEM dose válida → NÃO dispara. Base pura (todos os slots com id_corante vazio) → nenhum corante
  --   presente → NÃO dispara. Money-path: precisão>recall, ausente≠zero, nunca gravar número parcial.
  -- PREDICADO ÚNICO de DOSE VÁLIDA (positiva E FINITA), reusado no guard, no itens_dedup do preço, no
  -- stub de corante e no INSERT de itens:  COALESCE(qtd_ml > 0 AND qtd_ml < 'Infinity'::numeric, false)
  -- Em `numeric` o NaN ordena ACIMA de tudo: `NaN <= 0` é FALSO e `NaN > 0` é VERDADEIRO — o critério
  -- ingênuo dava NaN como dose VÁLIDA no guard E no INSERT, e NaN entrava na receita contaminando preço.
  -- `< 'Infinity'` derruba NaN e +Inf; `> 0` derruba -Inf/zero/negativo; o COALESCE derruba NULL.
  -- [DIAG-A] A CULPA vira dado de PRIMEIRA CLASSE. Os 3 ramos abaixo têm predicado VERBATIM da v5 —
  -- só a PROJEÇÃO cresceu (motivo + ids das linhas culpadas), então o conjunto de staging_formula_id
  -- que eles produzem é idêntico e NENHUMA fórmula muda de lado. O log passa a ser SUBPRODUTO da
  -- decisão em vez de uma reconstrução dela (que seria um espelho livre para divergir em silêncio).
  -- ⚠️ item_ids é PAYLOAD PURO: a decisão (_fl_corrompida, logo abaixo) é o DISTINCT das LINHAS de
  -- _fl_culpa e NUNCA passa por unnest(item_ids) — se passasse, um array vazio/NULL faria a fórmula
  -- sumir do guard e PROMOVER corrompida (fail-OPEN, subfaturamento silencioso). Direção de falha:
  -- bug no payload degrada o LOG; jamais solta a promoção. Provado por Flog-4.
  CREATE TEMP TABLE _fl_culpa ON COMMIT DROP AS
  SELECT * FROM (
    -- (a) corante PRESENTE cujo conjunto de linhas não tem NENHUMA dose válida → o INSERT filtraria esse
    --     corante → receita PARCIAL (subfaturamento silencioso) ou ZERO. bool_and POR (formula,corante)
    --     preserva a dosagem em 2 etapas legítima (mesmo corante em 2 ordens, ambas válidas).
    --     Culpadas são TODAS as linhas daquele corante (nenhuma tem dose válida — a violação é do
    --     CONJUNTO, não de uma linha): array_agg dentro do próprio grupo.
    SELECT si.staging_formula_id,
           'corante_sem_dose_valida'::text AS motivo,
           array_agg(si.id) AS item_ids
    FROM tint_staging_formula_itens si
    JOIN _fl_resolved fl ON fl.staging_formula_id = si.staging_formula_id
    WHERE fl.produto_id IS NOT NULL AND fl.base_id IS NOT NULL
      AND fl.volume_final_ml IS NOT NULL AND fl.volume_final_ml > 0
      AND btrim(COALESCE(si.id_corante, '')) <> ''
    GROUP BY si.staging_formula_id, si.id_corante
    HAVING bool_and(NOT COALESCE(si.qtd_ml > 0 AND si.qtd_ml < 'Infinity'::numeric, false))
    UNION ALL
    -- (b) ITEM ÓRFÃO: dose sem corante identificado. O edge converte ID ausente em '' PRESERVANDO a dose
    --     (tint-sync-agent :506) — ignorar a linha perdia um componente da receita. ⚠️ O critério é
    --     `qtd_ml IS NOT NULL AND qtd_ml <> 0` — NÃO "dose válida": um órfão com dose NaN/Infinity/negativa
    --     cairia FORA dos dois ramos (o ramo (a) exige corante presente; um ramo (b) que exigisse dose
    --     positiva-finita não pegaria o não-finito) e a fórmula promoveria PARCIAL. Só NULL/0 é placeholder
    --     legítimo de slot vazio; qualquer outra quantidade sem corante é corrupção. (`NaN <> 0` é TRUE.)
    --     ⚠️ É EXATAMENTE esta classe de linha que o error_details da v5 escondia (o filtro de
    --     id_corante no subselect de itens): o ramo que pega o órfão era o único cujo culpado
    --     jamais aparecia no log. NB.9142, 2026-07-21.
    SELECT si.staging_formula_id,
           'dose_sem_corante'::text,
           ARRAY[si.id]
    FROM tint_staging_formula_itens si
    JOIN _fl_resolved fl ON fl.staging_formula_id = si.staging_formula_id
    WHERE fl.produto_id IS NOT NULL AND fl.base_id IS NOT NULL
      AND fl.volume_final_ml IS NOT NULL AND fl.volume_final_ml > 0
      AND btrim(COALESCE(si.id_corante, '')) = ''
      AND si.qtd_ml IS NOT NULL AND si.qtd_ml <> 0
    UNION ALL
    -- (c) [1d-E] PROTOCOLO 1d (expected declarado): o conector novo emite TODAS as linhas da
    --     fonte, inclusive as inválidas — logo QUALQUER linha que não seja {corante presente +
    --     dose válida} é corrupção transportada e barra a fórmula INTEIRA (all-or-nothing
    --     estrito por linha). Sem isto, 3 parciais mascaradas passavam (Codex P0/P1 2026-07-20):
    --     mesmo corante com dose válida + linha inválida (o bool_and POR corante do ramo (a)
    --     mascara e o INSERT faz fallback silencioso p/ outra ordem); placeholder real com irmão
    --     válido; slot flat ilegível emitido. Headers LEGADOS (expected NULL) mantêm o ramo (a)
    --     (dosagem em 2 etapas com linha zerada segue promovendo pela dose válida — C16).
    SELECT si.staging_formula_id,
           'linha_invalida_protocolo_1d'::text,
           ARRAY[si.id]
    FROM tint_staging_formula_itens si
    JOIN _fl_resolved fl ON fl.staging_formula_id = si.staging_formula_id
    WHERE fl.produto_id IS NOT NULL AND fl.base_id IS NOT NULL
      AND fl.volume_final_ml IS NOT NULL AND fl.volume_final_ml > 0
      AND fl.expected_item_count IS NOT NULL
      AND NOT (
        btrim(COALESCE(si.id_corante, '')) <> ''
        AND COALESCE(si.qtd_ml > 0 AND si.qtd_ml < 'Infinity'::numeric, false)
      )
  ) q;

  -- DECISÃO: o DISTINCT das LINHAS de _fl_culpa — NUNCA do unnest(item_ids) (ver [DIAG-A]).
  -- Conjunto idêntico ao da v5: mesmos 3 ramos, mesmos predicados, mesma cardinalidade de grupos.
  CREATE TEMP TABLE _fl_corrompida ON COMMIT DROP AS
  SELECT DISTINCT staging_formula_id FROM _fl_culpa;

  -- Loga UMA linha de erro por fórmula corrompida (espelha os guards 1-3; entity_id = cor_id).
  -- [DIAG-C] mensagem derivada dos motivos que REALMENTE dispararam. A v5 afirmava sempre o ramo (a);
  --   na NB.9142 dispararam (b)+(c) e a mensagem acusava o único ramo que NÃO disparou. O prefixo
  --   'receita corrompida: ' é preservado — asserts do harness e a UI casam por LIKE '%corrompida%'.
  --   ⚠️ O COALESCE não é decorativo: em SQL `'texto' || NULL` é NULL, então uma fórmula sem linha
  --   em _fl_culpa (impossível hoje — _fl_corrompida deriva dela) zeraria a mensagem INTEIRA e o
  --   LIKE '%corrompida%' deixaria de casar. Fail-closed do diagnóstico.
  -- [DIAG-B] itens: TODOS (sem o filtro de id_corante que escondia o órfão), cada um marcado com
  --   `viola` + `motivos`. Os itens VÁLIDOS preservam id_corante/ordem/qtd_ml verbatim (compat).
  --   `ordem` é NULLABLE e agora órfãos entram → ORDER BY ... NULLS LAST, si.id (determinístico).
  INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
  SELECT p_sync_run_id, 'formula_promote', fl.cor_id,
         'receita corrompida: ' || COALESCE((
           SELECT string_agg(m.txt, ' + ' ORDER BY m.txt)
           FROM (
             SELECT DISTINCT CASE c2.motivo
                      WHEN 'corante_sem_dose_valida'     THEN 'corante presente sem dose válida (qtd_ml <= 0/nula/não-finita)'
                      WHEN 'dose_sem_corante'            THEN 'dose sem corante identificado (item órfão)'
                      WHEN 'linha_invalida_protocolo_1d' THEN 'linha inválida sob protocolo declarado (1d-E)'
                      ELSE c2.motivo
                    END AS txt
             FROM _fl_culpa c2
             WHERE c2.staging_formula_id = fl.staging_formula_id
           ) m
         ), 'motivo não determinado') || ' — fórmula NÃO promovida, receita anterior preservada',
         jsonb_build_object(
           'cod_produto', fl.cod_produto, 'id_base', fl.id_base,
           'motivos', (
             SELECT to_jsonb(array_agg(DISTINCT c2.motivo ORDER BY c2.motivo))
             FROM _fl_culpa c2
             WHERE c2.staging_formula_id = fl.staging_formula_id
           ),
           'itens', (
             SELECT jsonb_agg(jsonb_build_object(
                      'id_corante', si.id_corante,
                      'ordem',      si.ordem,
                      'qtd_ml',     si.qtd_ml,
                      'viola',      (cul.motivos IS NOT NULL),
                      'motivos',    to_jsonb(cul.motivos)
                    ) ORDER BY si.ordem NULLS LAST, si.id)
             FROM tint_staging_formula_itens si
             LEFT JOIN LATERAL (
               SELECT array_agg(DISTINCT c2.motivo ORDER BY c2.motivo) AS motivos
               FROM _fl_culpa c2
               WHERE c2.staging_formula_id = si.staging_formula_id
                 AND si.id = ANY(c2.item_ids)
             ) cul ON true
             WHERE si.staging_formula_id = fl.staging_formula_id
           ))
  FROM _fl_resolved fl
  JOIN _fl_corrompida c ON c.staging_formula_id = fl.staging_formula_id;
  GET DIAGNOSTICS v_tmp = ROW_COUNT; v_erros := v_erros + v_tmp;

  -- Expansão (regra de 3): 1 linha por (fórmula que passou TODOS os guards × embalagem vendável).
  -- fator = vol_destino / vol_formulacao (espelho expandirFormula). subcolecao_id resolvido por
  -- LEFT JOIN (NULL quando vazio). eid = chave surrogate p/ casar o preço.
  CREATE TEMP TABLE _expand ON COMMIT DROP AS
  SELECT
    row_number() OVER () AS eid,
    fl.staging_formula_id, fl.cor_id, fl.nome_cor, fl.cod_produto, fl.id_base, fl.personalizada,
    fl.subcolecao,  -- texto CRU (p/ o desempate espelhar a ordem do loop; ver _expand_uniq)
    fl.produto_id, fl.base_id,
    sub.id AS subcolecao_id,
    sk.id  AS sku_id,
    sk.embalagem_id AS emb_id,
    e.id_embalagem_sayersystem AS id_emb,
    e.volume_ml AS vol_destino,
    (e.volume_ml / fl.volume_final_ml) AS fator
  FROM _fl_resolved fl
  JOIN tint_skus sk ON sk.account = v_account AND sk.produto_id = fl.produto_id AND sk.base_id = fl.base_id
  JOIN tint_embalagens e ON e.id = sk.embalagem_id
  LEFT JOIN tint_subcolecoes sub
    ON sub.account = v_account
   AND fl.subcolecao IS NOT NULL AND btrim(fl.subcolecao) <> ''
   AND sub.id_subcolecao_sayersystem = fl.subcolecao
  WHERE fl.produto_id IS NOT NULL AND fl.base_id IS NOT NULL
    AND fl.volume_final_ml IS NOT NULL AND fl.volume_final_ml > 0
    AND e.volume_ml IS NOT NULL AND e.volume_ml > 0
    -- fator não-finito (P1-7): volume 'Infinity'/'NaN' geraria fator 0/NaN e dose expandida corrompida
    -- mesmo com a dose bruta finita. A finitude tem de valer para TODOS os operandos, não só qtd_ml.
    AND fl.volume_final_ml < 'Infinity'::numeric
    AND e.volume_ml < 'Infinity'::numeric;
  -- ⚠️ O Guard 4 deliberadamente NÃO filtra AQUI. Vários candidatos de _formulas_latest (separados por
  -- subcoleção crua/personalizada) podem COLAPSAR na mesma chave oficial; remover o candidato corrompido
  -- ANTES do _expand_uniq fazia o PERDEDOR da colisão virar vencedor e substituir header/preço/receita da
  -- chave oficial em vez de PRESERVAR o oficial. O guard é aplicado DEPOIS da escolha do vencedor.

  -- Preço pág 9 por expansão — SET-BASED, NULL-honesto (espelho precoFinalSayer + S2 store + S3
  -- latest não-nulo). base ausente OU qualquer corante sem custo/volume(>0)/finito → preço NULL.
  CREATE TEMP TABLE _preco ON COMMIT DROP AS
  WITH base_latest AS (   -- S2: store_code; S3: custo IS NOT NULL. Latest por chave de base.
    SELECT DISTINCT ON (cod_produto, id_base, id_embalagem)
           cod_produto, id_base, id_embalagem, custo, imposto_pct, margem_pct
    FROM tint_staging_precos_base
    WHERE account = v_account AND store_code = v_store AND custo IS NOT NULL
    ORDER BY cod_produto, id_base, id_embalagem, created_at DESC, id DESC
  ),
  cor_latest AS (         -- S2: store_code; S3: custo+volume NÃO-NULOS. Latest por corante.
    SELECT DISTINCT ON (id_corante_sayersystem)
           id_corante_sayersystem, custo, volume_ml
    FROM tint_staging_corantes
    WHERE account = v_account AND store_code = v_store
      AND custo IS NOT NULL AND volume_ml IS NOT NULL
    ORDER BY id_corante_sayersystem, created_at DESC, id DESC
  ),
  -- 20260622210000 (Codex P1 — consistência item↔preço): deduplica os itens por
  -- (staging_formula_id, id_corante) = MAX-ordem, IGUAL ao INSERT de tint_formula_itens. Senão o preço
  -- somaria o corante repetido (BOM "todos os itens") enquanto o item ARMAZENADO guarda só o max-ordem
  -- (BOM "1 por corante") — duas definições de fórmula na mesma promoção. Hoje é dead-code em prod
  -- (precos_base vazio → soma NULL → COALESCE preserva o piso), mas alinha os 2 caminhos para o dia em
  -- que precos_base for populado. Mesma ordem de desempate do INSERT de itens.
  itens_dedup AS (
    -- MESMO predicado de dose válida do guard/stub/INSERT (positiva E finita): sem isto o preço somaria
    -- um item NaN/Infinity que o guard já considera inválido — duas definições da mesma fórmula.
    SELECT DISTINCT ON (staging_formula_id, id_corante) staging_formula_id, id_corante, qtd_ml
      FROM tint_staging_formula_itens
     WHERE btrim(COALESCE(id_corante, '')) <> ''
       AND COALESCE(qtd_ml > 0 AND qtd_ml < 'Infinity'::numeric, false)
     ORDER BY staging_formula_id, id_corante, ordem DESC, qtd_ml DESC, id DESC
  ),
  itens AS (              -- Σ corantes por expansão; flag de corante faltante (NULL-honesto).
    SELECT ex.eid,
           bool_or(
             cl.id_corante_sayersystem IS NULL
             OR cl.volume_ml IS NULL OR cl.volume_ml <= 0
             OR NOT (cl.custo > '-Infinity'::numeric AND cl.custo < 'Infinity'::numeric)
           ) AS faltante,
           sum(CASE WHEN cl.volume_ml > 0 THEN (cl.custo / cl.volume_ml) * (si.qtd_ml * ex.fator) ELSE 0 END) AS soma
    FROM _expand ex
    JOIN itens_dedup si ON si.staging_formula_id = ex.staging_formula_id
    LEFT JOIN cor_latest cl ON cl.id_corante_sayersystem = si.id_corante
    GROUP BY ex.eid
  )
  SELECT
    ex.eid,
    CASE
      WHEN bl.custo IS NULL THEN NULL                                                   -- base ausente
      WHEN NOT (bl.custo > '-Infinity'::numeric AND bl.custo < 'Infinity'::numeric) THEN NULL  -- custo não-finito
      WHEN COALESCE(it.faltante, false) THEN NULL                                       -- corante sem preço
      ELSE round(
        ( bl.custo * (1 + COALESCE(bl.imposto_pct, 0) / 100) * (1 + COALESCE(bl.margem_pct, 0) / 100) )
        + COALESCE(it.soma, 0)
      , 2)
    END AS preco
  FROM _expand ex
  LEFT JOIN base_latest bl
    ON bl.cod_produto = ex.cod_produto AND bl.id_base = ex.id_base AND bl.id_embalagem = ex.id_emb
  LEFT JOIN itens it ON it.eid = ex.eid;

  -- Dedup pela CHAVE OFICIAL (uq_tint_formulas_chave — SEM personalizada): INSERT...SELECT não pode
  -- ter a mesma chave 2× no mesmo comando (cardinality violation). O loop processa _formulas_latest
  -- em ORDER BY ... COALESCE(subcolecao,'') ASC, personalizada ASC e o ÚLTIMO vence o upsert. A chave
  -- oficial COLAPSA subcoleções que resolvem ao MESMO subcolecao_id (NULL e whitespace-only viram
  -- NULL → btrim vazio), então a colisão pode ser entre linhas com COALESCE(subcolecao,'') DIFERENTE
  -- (não só personalizada). Para escolher o MESMO vencedor do loop, desempata por COALESCE(subcolecao,
  -- '') DESC PRIMEIRO, depois personalizada DESC (= o último que o loop processaria), eid DESC final.
  CREATE TEMP TABLE _expand_uniq ON COMMIT DROP AS
  SELECT DISTINCT ON (ex.cor_id, ex.produto_id, ex.base_id, COALESCE(ex.subcolecao_id, v_zero_uuid), ex.emb_id)
         ex.staging_formula_id, ex.cor_id, ex.nome_cor, ex.personalizada,
         ex.produto_id, ex.base_id, ex.subcolecao_id, ex.sku_id, ex.emb_id, ex.vol_destino, ex.fator,
         pr.preco
  FROM _expand ex
  JOIN _preco pr ON pr.eid = ex.eid
  ORDER BY ex.cor_id, ex.produto_id, ex.base_id, COALESCE(ex.subcolecao_id, v_zero_uuid), ex.emb_id,
           COALESCE(ex.subcolecao, '') DESC, ex.personalizada DESC, ex.eid DESC;

  -- ══════════════════════════════════════════════════════════════════════════
  -- GUARD 4 APLICADO AQUI — DEPOIS de o vencedor da chave oficial estar escolhido. Se o VENCEDOR está
  -- corrompido, a chave oficial INTEIRA sai: sem fallback pro perdedor da colisão. Consequência (a
  -- desejada): aquela tint_formulas não entra em _promoted → não sofre o upsert de header NEM o DELETE
  -- de itens → header (preço, importacao_id, desativada_em) E receita ficam INTACTOS e COERENTES.
  DELETE FROM _expand_uniq eu
  USING _fl_corrompida c
  WHERE c.staging_formula_id = eu.staging_formula_id;

  -- ══════════════════════════════════════════════════════════════════════════
  -- [1c-B] GATE 1c (_eu_incompleta) — INTEGRIDADE DE TRANSPORTE do conjunto de itens. O header
  -- declara quantas linhas de item a fonte enviou (expected_item_count, edge handleFormulas); se o
  -- COUNT(*) BRUTO ingerido difere, o conjunto NÃO chegou inteiro (itens atravessam a fronteira de
  -- chunk de 1000 e o cleanup do edge pode falhar silencioso — tint-sync-agent :523) OU a promoção
  -- concorrente leu a ingestão a meio caminho. A fórmula INTEIRA sai (todas as embalagens), receita
  -- anterior preservada; em chave NOVA, nem header nasce (fecha o "fórmula vazia/parcial ativa" que
  -- o guard (c) não cobre — ele exige oficial COM receita). COUNT BRUTO de propósito (transporte ≠
  -- validade): dose inválida é papel dos guards 4a/4b, camadas independentes. NULL = protocolo
  -- legado/simulação → não entra aqui (caminho v3 intacto; 59% dos headers legítimos vivem em runs
  -- 'error' — gatear por status de run segue PROIBIDO). Posição: DEPOIS do vencedor da colisão
  -- (mesma lição do Guard 4 — sem fallback ao perdedor) e SEM fallback ao header completo mais
  -- antigo (promoveria estado velho como se fosse novo). Fail-closed transitório numa corrida com
  -- ingestão em curso se auto-resolve no promote seguinte (o latest fica íntegro).
  CREATE TEMP TABLE _eu_incompleta ON COMMIT DROP AS
  SELECT DISTINCT eu.staging_formula_id, fl.cor_id, fl.cod_produto, fl.id_base,
         fl.header_sync_run_id,
         fl.expected_item_count AS declarados,
         COALESCE(si.n, 0)      AS ingeridos
  FROM _expand_uniq eu
  JOIN _fl_resolved fl ON fl.staging_formula_id = eu.staging_formula_id
  LEFT JOIN LATERAL (
    SELECT count(*) AS n FROM tint_staging_formula_itens si
    WHERE si.staging_formula_id = eu.staging_formula_id
  ) si ON true
  WHERE fl.expected_item_count IS NOT NULL
    AND fl.expected_item_count <> COALESCE(si.n, 0);

  -- header_sync_run_id (Codex P2): a promoção pode rodar por OUTRO run (B) e esbarrar no header
  -- incompleto do run A — o erro é atribuído ao promotor (sync_run_id) mas carrega o run DONO do
  -- header, senão métricas/investigação acusam o run errado. O re-log a cada promote enquanto o
  -- latest seguir incompleto é sinal HONESTO (padrão do Guard 4), não ruído a deduplicar.
  INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
  SELECT DISTINCT p_sync_run_id, 'formula_promote', inc.cor_id,
         'staging incompleto: itens ingeridos ≠ declarados (expected_item_count) — fórmula NÃO promovida, receita anterior preservada',
         jsonb_build_object('staging_formula_id', inc.staging_formula_id,
                            'cod_produto', inc.cod_produto, 'id_base', inc.id_base,
                            'header_sync_run_id', inc.header_sync_run_id,
                            'declarados', inc.declarados, 'ingeridos', inc.ingeridos)
  FROM _eu_incompleta inc;
  GET DIAGNOSTICS v_tmp = ROW_COUNT; v_erros := v_erros + v_tmp;

  DELETE FROM _expand_uniq eu
  USING _eu_incompleta inc
  WHERE inc.staging_formula_id = eu.staging_formula_id;

  -- ══════════════════════════════════════════════════════════════════════════
  -- [1d-B] SINAL DE BASE PURA CONTRADITÓRIO — fail-closed. is_base_pura=true só é
  -- coerente com a tríade (expected=0 E COUNT bruto=0). O gate 1c já barrou
  -- expected<>COUNT; aqui caem os residuais: declarada-pura COM itens presentes
  -- (expected=COUNT=N>0) e declarada-pura com expected NULL (edge novo sempre
  -- grava expected junto — NULL+true é artefato/protocolo misto). Promover como
  -- pigmentada ignoraria a declaração; limpar ignoraria os itens → barra + loga.
  CREATE TEMP TABLE _eu_pura_contraditoria ON COMMIT DROP AS
  SELECT DISTINCT eu.staging_formula_id, fl.cor_id, fl.cod_produto, fl.id_base,
         fl.header_sync_run_id, fl.expected_item_count AS declarados,
         COALESCE(si.n, 0) AS ingeridos
  FROM _expand_uniq eu
  JOIN _fl_resolved fl ON fl.staging_formula_id = eu.staging_formula_id
  LEFT JOIN LATERAL (
    SELECT count(*) AS n FROM tint_staging_formula_itens si
    WHERE si.staging_formula_id = eu.staging_formula_id
  ) si ON true
  WHERE fl.is_base_pura IS TRUE
    AND (fl.expected_item_count IS NULL
         OR fl.expected_item_count <> 0
         OR COALESCE(si.n, 0) <> 0);

  INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
  SELECT DISTINCT p_sync_run_id, 'formula_promote', c.cor_id,
         'sinal de base pura contraditório: is_base_pura=true exige expected_item_count=0 e 0 itens ingeridos — fórmula NÃO promovida, receita anterior preservada',
         jsonb_build_object('staging_formula_id', c.staging_formula_id,
                            'cod_produto', c.cod_produto, 'id_base', c.id_base,
                            'header_sync_run_id', c.header_sync_run_id,
                            'declarados', c.declarados, 'ingeridos', c.ingeridos)
  FROM _eu_pura_contraditoria c;
  GET DIAGNOSTICS v_tmp = ROW_COUNT; v_erros := v_erros + v_tmp;

  DELETE FROM _expand_uniq eu
  USING _eu_pura_contraditoria c
  WHERE c.staging_formula_id = eu.staging_formula_id;

  -- (c') STAGING SEM RECEITA VÁLIDA → all-or-nothing, com UMA exceção DECLARADA [1d-C].
  --   v3/v4: barrava vazio APENAS sobre oficial COM receita; chave nova vazia PROMOVIA header
  --   vazio ativo (C15a) — com o conector velho filtrando inválidos antes do POST, uma fórmula
  --   nova toda-quebrada chegava como vazio "íntegro" e virava fórmula vazia ativa (o mal das
  --   28.609). v5 ENDURECE: vazio sem declaração barra SEMPRE (oficial com receita OU chave
  --   nova/sem receita — mensagens distintas p/ diagnóstico), e a TRÍADE DECLARADA
  --   (is_base_pura=true AND expected_item_count=0 AND 0 linhas brutas de item) libera:
  --   transição legítima pigmentada→pura LIMPA a receita (DELETE sem re-INSERT) e base pura
  --   NOVA cria header vazio legítimo. Fatos de prod que autorizam o endurecimento
  --   (psql-ro 2026-07-20): 0 fórmulas vazias na geração SL viva em 1 mês de sync;
  --   0 headers com expected=0 na história do staging.
  --   A tríade é re-checada INTEIRA aqui (não só is_base_pura): defesa em profundidade — o
  --   predicado não pode depender da ordem dos gates anteriores ([1d-B] já removeu as
  --   contraditórias, mas este WHERE tem de ser correto sozinho).
  CREATE TEMP TABLE _eu_sem_receita ON COMMIT DROP AS
  SELECT eu.staging_formula_id, eu.cor_id, eu.emb_id,
         EXISTS (
           SELECT 1 FROM tint_formulas f
           JOIN tint_formula_itens fi ON fi.formula_id = f.id
           WHERE f.account = v_account
             AND f.cor_id = eu.cor_id AND f.produto_id = eu.produto_id AND f.base_id = eu.base_id
             AND COALESCE(f.subcolecao_id, v_zero_uuid) = COALESCE(eu.subcolecao_id, v_zero_uuid)
             AND f.embalagem_id = eu.emb_id
         ) AS oficial_tem_receita
  FROM _expand_uniq eu
  JOIN _fl_resolved fl ON fl.staging_formula_id = eu.staging_formula_id
  WHERE NOT EXISTS (
      SELECT 1 FROM tint_staging_formula_itens si
      WHERE si.staging_formula_id = eu.staging_formula_id
        AND btrim(COALESCE(si.id_corante, '')) <> ''
        AND COALESCE(si.qtd_ml > 0 AND si.qtd_ml < 'Infinity'::numeric, false)
    )
    AND NOT (
      fl.is_base_pura IS TRUE
      AND fl.expected_item_count = 0
      AND NOT EXISTS (
        SELECT 1 FROM tint_staging_formula_itens si2
        WHERE si2.staging_formula_id = eu.staging_formula_id
      )
    );

  -- Mensagem VERBATIM da v3/v4 p/ o caso "oficial tem receita" (asserts e dashboards
  -- que casam '%sem receita%' seguem válidos); mensagem NOVA p/ o vazio em chave nova.
  INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
  SELECT DISTINCT p_sync_run_id, 'formula_promote', s.cor_id,
         'staging sem receita sobre fórmula que TEM receita — fórmula NÃO promovida (receita anterior preservada; transição p/ base pura exige sinal explícito da fonte)',
         jsonb_build_object('staging_formula_id', s.staging_formula_id)
  FROM _eu_sem_receita s
  WHERE s.oficial_tem_receita;
  GET DIAGNOSTICS v_tmp = ROW_COUNT; v_erros := v_erros + v_tmp;

  INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
  SELECT DISTINCT p_sync_run_id, 'formula_promote', s.cor_id,
         'staging vazio sem declaração de base pura — header NÃO criado (fórmula vazia ativa é o mal das 28.609; a fonte declara is_base_pura ou corrige a receita)',
         jsonb_build_object('staging_formula_id', s.staging_formula_id)
  FROM _eu_sem_receita s
  WHERE NOT s.oficial_tem_receita;
  GET DIAGNOSTICS v_tmp = ROW_COUNT; v_erros := v_erros + v_tmp;

  DELETE FROM _expand_uniq eu
  USING _eu_sem_receita s
  WHERE s.staging_formula_id = eu.staging_formula_id AND s.emb_id = eu.emb_id;

  -- ══════════════════════════════════════════════════════════════════════════
  -- [1d-D] CAP ANTI-LIMPEZA-EM-MASSA, ACUMULADO EM JANELA (defesa em profundidade).
  -- O apocalipse: no shape child, a tabela filha da ORIGEM esvaziada por glitch/wipe faria
  -- o conector declarar is_base_pura em TODAS as fórmulas → limparia a receita do catálogo,
  -- batch a batch. Transição p/ base pura é evento RARO (medido: 0 em 1 mês de fluxo vivo).
  -- ⚠️ Codex P0 (2026-07-20): cap POR PROMOTE era contornável em "catraca" — run A limpa 50,
  -- run B limpa as 2 restantes (as já-limpas deixam de satisfazer EXISTS e saem da conta), e
  -- células <51 destravavam uma a uma. O cap agora é ACUMULADO: candidatas deste promote +
  -- receitas JÁ LIMPAS nas últimas 24h no mesmo (account,store), lidas do rastro durável que
  -- o próprio promote grava (tint_sync_runs.metadata->>'receitas_limpas'). Estourou → NENHUMA
  -- limpeza executa (nem as 50 "de dentro do teto": fonte doente não ganha fatia), tudo barra
  -- + loga. A conta é por RECEITA OFICIAL (chave com embalagem) — 1 fórmula-fonte pode limpar
  -- N embalagens e o dano se mede em receitas. Base pura NOVA (sem receita oficial) não conta
  -- nem é barrada — criar N bases puras novas não destrói nada. Precisar limpar >50/24h
  -- legitimamente (reforma de catálogo) é decisão humana: migration pontual, não sync.
  CREATE TEMP TABLE _eu_limpezas ON COMMIT DROP AS
  SELECT DISTINCT eu.staging_formula_id, eu.cor_id, eu.emb_id
  FROM _expand_uniq eu
  JOIN _fl_resolved fl ON fl.staging_formula_id = eu.staging_formula_id
  WHERE fl.is_base_pura IS TRUE
    AND NOT EXISTS (
      SELECT 1 FROM tint_staging_formula_itens si
      WHERE si.staging_formula_id = eu.staging_formula_id
    )
    AND EXISTS (
      SELECT 1 FROM tint_formulas f
      JOIN tint_formula_itens fi ON fi.formula_id = f.id
      WHERE f.account = v_account
        AND f.cor_id = eu.cor_id AND f.produto_id = eu.produto_id AND f.base_id = eu.base_id
        AND COALESCE(f.subcolecao_id, v_zero_uuid) = COALESCE(eu.subcolecao_id, v_zero_uuid)
        AND f.embalagem_id = eu.emb_id
    );

  SELECT count(*) INTO v_limpezas FROM _eu_limpezas;

  -- Receitas já limpas na janela por promotes anteriores DESTE (account,store). O run atual
  -- ainda não gravou metadata (grava no E5) → não se conta em dobro.
  -- Alias 'tr' de propósito: 'r' é variável record da função e VENCERIA o alias
  -- (compila, explode em runtime — armadilha plpgsql documentada em tintometrico.md).
  SELECT COALESCE(sum((tr.metadata->>'receitas_limpas')::int), 0) INTO v_limpezas_24h
  FROM tint_sync_runs tr
  WHERE tr.account = v_account AND tr.store_code = v_store
    AND tr.started_at > now() - interval '24 hours'
    AND tr.metadata ? 'receitas_limpas';

  IF v_limpezas > 0 AND (v_limpezas + v_limpezas_24h) > v_cap_limpezas THEN
    INSERT INTO tint_sync_errors (sync_run_id, entity_type, entity_id, error_message, error_details)
    SELECT p_sync_run_id, 'formula_promote', l.cor_id,
           'limpeza em massa suspeita: ' || v_limpezas || ' receita(s) limpariam agora + ' || v_limpezas_24h || ' já limpas em 24h > cap ' || v_cap_limpezas || ' — NENHUMA limpeza executada, receitas preservadas; confira a tabela filha da ORIGEM',
           jsonb_build_object('staging_formula_id', l.staging_formula_id,
                              'limpezas_no_run', v_limpezas, 'limpezas_24h', v_limpezas_24h,
                              'cap', v_cap_limpezas)
    FROM _eu_limpezas l;
    GET DIAGNOSTICS v_tmp = ROW_COUNT; v_erros := v_erros + v_tmp;

    DELETE FROM _expand_uniq eu
    USING _eu_limpezas l
    WHERE l.staging_formula_id = eu.staging_formula_id;

    v_limpezas := 0;
  END IF;

  -- v_promovidas conta o que REALMENTE será gravado (linhas oficiais upsertadas), não as expansões
  -- pré-dedup: com o guard aqui, contar _expand reportaria como "promovida" uma fórmula barrada —
  -- número fabricado num contador money-path (registros_importados / tint_sync_runs.inserts).
  SELECT count(*) INTO v_promovidas FROM _expand_uniq;

  -- Corante stubs em massa ANTES dos itens (espelha tint_ensure_corante_stub: volume 1000).
  -- A partir de _expand_uniq (PÓS-guard) — não materializa corante de fórmula barrada. Mesmo predicado
  -- de dose válida do guard/INSERT (NaN/Infinity fora).
  INSERT INTO tint_corantes (account, id_corante_sayersystem, descricao, volume_total_ml)
  SELECT DISTINCT v_account, si.id_corante, si.id_corante, 1000
  FROM tint_staging_formula_itens si
  WHERE si.staging_formula_id IN (SELECT DISTINCT staging_formula_id FROM _expand_uniq)
    AND btrim(COALESCE(si.id_corante, '')) <> ''
    AND COALESCE(si.qtd_ml > 0 AND si.qtd_ml < 'Infinity'::numeric, false)
  ON CONFLICT (account, id_corante_sayersystem) DO NOTHING;

  -- Upsert oficial em massa por uq_tint_formulas_chave; desativada_em = NULL (reativa). Captura
  -- formula_id ↔ (staging_formula_id, fator) p/ os itens (RETURNING casado de volta ao _expand_uniq).
  CREATE TEMP TABLE _promoted ON COMMIT DROP AS
  WITH ups AS (
    INSERT INTO tint_formulas (
      account, cor_id, nome_cor, produto_id, base_id, embalagem_id, subcolecao_id, sku_id,
      volume_final_ml, preco_final_sayersystem, personalizada, importacao_id, updated_at, desativada_em
    )
    SELECT
      v_account, eu.cor_id, eu.nome_cor, eu.produto_id, eu.base_id, eu.emb_id, eu.subcolecao_id, eu.sku_id,
      eu.vol_destino, eu.preco, eu.personalizada, v_importacao_id, now(), NULL
    FROM _expand_uniq eu
    ON CONFLICT (account, cor_id, produto_id, base_id, COALESCE(subcolecao_id, '00000000-0000-0000-0000-000000000000'::uuid), embalagem_id)
    DO UPDATE SET
      nome_cor                = EXCLUDED.nome_cor,
      sku_id                  = EXCLUDED.sku_id,
      volume_final_ml         = EXCLUDED.volume_final_ml,
      -- 20260617: PRESERVA o preço existente quando o novo é NULL (precos_base vazio → eu.preco NULL).
      -- Sem isto o flip zeraria o piso de ~19k cores (calc<CSV). Espelha o COALESCE de preco_litro acima.
      preco_final_sayersystem = COALESCE(EXCLUDED.preco_final_sayersystem, tint_formulas.preco_final_sayersystem),
      personalizada           = EXCLUDED.personalizada,
      importacao_id           = EXCLUDED.importacao_id,
      updated_at              = now(),
      desativada_em           = NULL
    RETURNING id, cor_id, produto_id, base_id, subcolecao_id, embalagem_id
  )
  SELECT u.id AS formula_id, eu.staging_formula_id, eu.fator
  FROM ups u
  JOIN _expand_uniq eu
    ON eu.cor_id = u.cor_id AND eu.produto_id = u.produto_id AND eu.base_id = u.base_id
   AND COALESCE(eu.subcolecao_id, v_zero_uuid) = COALESCE(u.subcolecao_id, v_zero_uuid)
   AND eu.emb_id = u.embalagem_id;

  -- Itens em massa: limpa + reinsere (espelha o delete+insert por fórmula do loop). qtd expandida
  -- = qtd_formulacao × fator, arredondada a 6 casas (sub-µL — elimina artefato de escala da divisão
  -- numeric sem mudar o valor prático). Corante já garantido (stub acima) → JOIN resolve o id.
  DELETE FROM tint_formula_itens fi USING _promoted pr WHERE fi.formula_id = pr.formula_id;

  INSERT INTO tint_formula_itens (formula_id, corante_id, ordem, qtd_ml)
  -- 20260622210000 (estanca RE-LOOP): DEDUP por (formula_id, corante_id). A FORMULA do SayerSystem
  -- pode trazer o MESMO corante em 2 slots/ordens (dosagem em 2 etapas; ex. 997M corante 3 = 0.385 +
  -- 14.09). aggregateFlatFormulaItems envia 2 itens; SEM dedup o INSERT viola o unique
  -- tint_formula_itens_formula_id_corante_id_key (23505) → ROLLBACK do batch → edge 500 → o conector
  -- não cacheia o lote → re-envia o batch CHEIO p/ sempre (re-loop). DISTINCT ON ... ORDER BY ordem DESC
  -- = MAIOR ORDEM VENCE: idêntico ao que o CSV-import já gravou no oficial (validado em prod: 344M
  -- c1=ordem3, 997M c3=ordem5, 638S) → IDEMPOTENTE, zero mudança de dosagem. NÃO somar (mudaria a
  -- dosagem/preço de cor ativa; somar dosagens distintas é decisão de domínio separada).
  SELECT DISTINCT ON (pr.formula_id, co.id)
         pr.formula_id, co.id, si.ordem, round((si.qtd_ml * pr.fator)::numeric, 6)
  FROM _promoted pr
  JOIN tint_staging_formula_itens si ON si.staging_formula_id = pr.staging_formula_id
  JOIN tint_corantes co ON co.account = v_account AND co.id_corante_sayersystem = si.id_corante
  -- MESMO predicado de dose válida (positiva E finita). O antigo `COALESCE(qtd_ml,0) > 0` deixava NaN
  -- entrar na receita: em numeric, `NaN > 0` é VERDADEIRO.
  WHERE btrim(COALESCE(si.id_corante, '')) <> ''
    AND COALESCE(si.qtd_ml > 0 AND si.qtd_ml < 'Infinity'::numeric, false)
  -- tie-break determinístico (Codex P2): se 2 itens compartilham (formula,corante,ordem) — dado sujo —
  -- qtd_ml DESC, id DESC torna o pick estável em vez de não-determinístico num caminho money-path.
  ORDER BY pr.formula_id, co.id, si.ordem DESC, si.qtd_ml DESC, si.id DESC;

  -- ──────────────────────────────────────────────────────────────────────────
  -- E4) Recálculo de preço por mudança de INSUMO (§11 P1-A — caso de uso PRINCIPAL).
  --   Run tocou precos_base/corantes → recalcula preco_final_sayersystem das fórmulas
  --   oficiais ATIVAS afetadas, SEM re-expandir itens. NÃO mexe nas fórmulas que E2 já
  --   tocou (importacao_id = v_importacao_id) — essas já saíram com o preço novo.
  -- ──────────────────────────────────────────────────────────────────────────
  -- Pares (produto,base,embalagem oficial) afetados por precos_base deste run.
  FOR r IN
    SELECT DISTINCT f.id AS formula_id, f.cor_id, p.cod_produto, b.id_base_sayersystem AS id_base, e.id_embalagem_sayersystem AS id_emb
    FROM tint_staging_precos_base sp
    JOIN tint_produtos   p ON p.account = v_account AND p.cod_produto = sp.cod_produto
    JOIN tint_bases      b ON b.account = v_account AND b.id_base_sayersystem = sp.id_base
    JOIN tint_embalagens e ON e.account = v_account AND e.id_embalagem_sayersystem = sp.id_embalagem
    JOIN tint_formulas   f ON f.account = v_account AND f.produto_id = p.id AND f.base_id = b.id AND f.embalagem_id = e.id
    WHERE sp.sync_run_id = p_sync_run_id
      AND f.desativada_em IS NULL
      AND (f.importacao_id IS DISTINCT FROM v_importacao_id)
  LOOP
    -- S2: +v_store.
    v_preco := tint_recalc_preco_oficial(v_account, v_store, r.formula_id, r.cod_produto, r.id_base, r.id_emb);
    -- 20260617: só baixa/sobe se o recálculo deu valor; NULL (sem precos_base) PRESERVA o piso atual.
    UPDATE tint_formulas SET preco_final_sayersystem = COALESCE(v_preco, preco_final_sayersystem), updated_at = now() WHERE id = r.formula_id;
    v_recalc := v_recalc + 1;
  END LOOP;

  -- Fórmulas que usam um corante cujo CUSTO mudou neste run (volume sem custo → preço NULL: inútil).
  FOR r IN
    SELECT DISTINCT f.id AS formula_id, f.cor_id, pr.cod_produto, ba.id_base_sayersystem AS id_base, em.id_embalagem_sayersystem AS id_emb
    FROM tint_staging_corantes sc
    JOIN tint_corantes      co ON co.account = v_account AND co.id_corante_sayersystem = sc.id_corante_sayersystem
    JOIN tint_formula_itens fi ON fi.corante_id = co.id
    JOIN tint_formulas      f  ON f.id = fi.formula_id
    JOIN tint_produtos      pr ON pr.id = f.produto_id
    JOIN tint_bases         ba ON ba.id = f.base_id
    JOIN tint_embalagens    em ON em.id = f.embalagem_id
    WHERE sc.sync_run_id = p_sync_run_id
      -- 20260618 (fix CARGA E4): SÓ recalcula quando há CUSTO. O SayerSystem não manda custo (preço vem
      -- do Omie, §14) → sem isto o re-envio (volume_ml sempre presente) recalculava ~481k fórmulas por
      -- corante, uma a uma, num único run → gateway timeout → advisory lock preso → cascata (incidente
      -- 18/06). Sem custo o recálculo dá NULL e o COALESCE preserva o piso — ou seja, seria carga inútil.
      AND sc.custo IS NOT NULL
      AND f.account = v_account
      AND f.desativada_em IS NULL
      AND (f.importacao_id IS DISTINCT FROM v_importacao_id)
  LOOP
    -- S2: +v_store.
    v_preco := tint_recalc_preco_oficial(v_account, v_store, r.formula_id, r.cod_produto, r.id_base, r.id_emb);
    -- 20260617: só baixa/sobe se o recálculo deu valor; NULL (sem precos_base) PRESERVA o piso atual.
    UPDATE tint_formulas SET preco_final_sayersystem = COALESCE(v_preco, preco_final_sayersystem), updated_at = now() WHERE id = r.formula_id;
    v_recalc := v_recalc + 1;
  END LOOP;

  -- ──────────────────────────────────────────────────────────────────────────
  -- E5) Contadores + purge staging SUPERSEDED >30d (preserva latest-per-key) +
  --     runs órfãos >30min → error.
  -- ──────────────────────────────────────────────────────────────────────────
  UPDATE tint_importacoes
    SET status = 'concluido', registros_importados = v_promovidas, registros_erro = v_erros
  WHERE id = v_importacao_id;

  UPDATE tint_sync_runs
    SET inserts = v_promovidas, errors = v_erros, metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object('recalculadas', v_recalc, 'receitas_limpas', v_limpezas)
  WHERE id = p_sync_run_id;

  -- PURGE: NUNCA apaga a linha MAIS RECENTE por chave natural (account+store) — a promoção
  -- lê latest-staging-por-chave PRA SEMPRE (recalc por insumo + re-expansão por sku novo
  -- dependem dela mesmo que o insumo não mude por >30d → nunca é re-enviado). Só remove
  -- linhas SUPERSEDED (>30d E com uma linha mais nova da MESMA chave). §11 P2-1.
  -- Ordem de chave: (created_at, id) — idêntica ao DISTINCT ON da promoção.
  DELETE FROM tint_staging_produtos s
  WHERE s.created_at < now() - interval '30 days'
    AND EXISTS (SELECT 1 FROM tint_staging_produtos n
      WHERE n.account = s.account AND n.store_code = s.store_code
        AND n.cod_produto = s.cod_produto
        AND (n.created_at, n.id) > (s.created_at, s.id));

  DELETE FROM tint_staging_bases s
  WHERE s.created_at < now() - interval '30 days'
    AND EXISTS (SELECT 1 FROM tint_staging_bases n
      WHERE n.account = s.account AND n.store_code = s.store_code
        AND n.id_base_sayersystem = s.id_base_sayersystem
        AND (n.created_at, n.id) > (s.created_at, s.id));

  DELETE FROM tint_staging_embalagens s
  WHERE s.created_at < now() - interval '30 days'
    AND EXISTS (SELECT 1 FROM tint_staging_embalagens n
      WHERE n.account = s.account AND n.store_code = s.store_code
        AND n.id_embalagem_sayersystem = s.id_embalagem_sayersystem
        AND (n.created_at, n.id) > (s.created_at, s.id));

  DELETE FROM tint_staging_corantes s
  WHERE s.created_at < now() - interval '30 days'
    AND EXISTS (SELECT 1 FROM tint_staging_corantes n
      WHERE n.account = s.account AND n.store_code = s.store_code
        AND n.id_corante_sayersystem = s.id_corante_sayersystem
        AND (n.created_at, n.id) > (s.created_at, s.id));

  DELETE FROM tint_staging_skus s
  WHERE s.created_at < now() - interval '30 days'
    AND EXISTS (SELECT 1 FROM tint_staging_skus n
      WHERE n.account = s.account AND n.store_code = s.store_code
        AND n.cod_produto = s.cod_produto AND n.id_base = s.id_base AND n.id_embalagem = s.id_embalagem
        AND (n.created_at, n.id) > (s.created_at, s.id));

  -- Fórmulas: chave = (cod_produto,id_base,cor_id,COALESCE(subcolecao,''),personalizada),
  -- idêntica ao DISTINCT ON de _formulas_latest. Itens cascateiam pela formula-pai apagada.
  DELETE FROM tint_staging_formula_itens si
  WHERE si.staging_formula_id IN (
    SELECT s.id FROM tint_staging_formulas s
    WHERE s.created_at < now() - interval '30 days'
      AND EXISTS (SELECT 1 FROM tint_staging_formulas n
        WHERE n.account = s.account AND n.store_code = s.store_code
          AND n.cor_id = s.cor_id AND n.cod_produto = s.cod_produto AND n.id_base = s.id_base
          AND COALESCE(n.subcolecao, '') = COALESCE(s.subcolecao, '')
          AND n.personalizada = s.personalizada
          AND (n.created_at, n.id) > (s.created_at, s.id)));

  DELETE FROM tint_staging_formulas s
  WHERE s.created_at < now() - interval '30 days'
    AND EXISTS (SELECT 1 FROM tint_staging_formulas n
      WHERE n.account = s.account AND n.store_code = s.store_code
        AND n.cor_id = s.cor_id AND n.cod_produto = s.cod_produto AND n.id_base = s.id_base
        AND COALESCE(n.subcolecao, '') = COALESCE(s.subcolecao, '')
        AND n.personalizada = s.personalizada
        AND (n.created_at, n.id) > (s.created_at, s.id));

  DELETE FROM tint_staging_precos_base s
  WHERE s.created_at < now() - interval '30 days'
    AND EXISTS (SELECT 1 FROM tint_staging_precos_base n
      WHERE n.account = s.account AND n.store_code = s.store_code
        AND n.cod_produto = s.cod_produto AND n.id_base = s.id_base AND n.id_embalagem = s.id_embalagem
        AND (n.created_at, n.id) > (s.created_at, s.id));

  -- keys-snapshot: point-in-time (não latest-per-key) → purge por tempo é correto.
  DELETE FROM tint_keys_snapshots          WHERE created_at < now() - interval '30 days';

  UPDATE tint_sync_runs
    SET status = 'error', completed_at = COALESCE(completed_at, now())
  WHERE status = 'running' AND started_at < now() - interval '30 minutes';

  RETURN jsonb_build_object(
    'ok', true, 'promovidas', v_promovidas, 'recalculadas', v_recalc,
    'receitas_limpas', v_limpezas,
    'erros', v_erros, 'importacao_id', v_importacao_id);
END $_$;


--
-- Name: tint_recalc_preco_oficial(text, text, uuid, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tint_recalc_preco_oficial(p_account text, p_store_code text, p_formula_id uuid, p_cod_produto text, p_id_base text, p_id_embalagem text) RETURNS numeric
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_base       record;
  v_preco_base numeric;
  v_soma       numeric := 0;
  it           record;
  v_cor        record;
BEGIN
  -- S2: AND store_code = p_store_code. S3: AND custo IS NOT NULL.
  SELECT custo, imposto_pct, margem_pct INTO v_base
  FROM tint_staging_precos_base
  WHERE account = p_account AND store_code = p_store_code
    AND cod_produto = p_cod_produto AND id_base = p_id_base AND id_embalagem = p_id_embalagem
    AND custo IS NOT NULL
  ORDER BY created_at DESC, id DESC
  LIMIT 1;

  IF v_base IS NULL OR v_base.custo IS NULL OR NOT (v_base.custo > '-Infinity'::numeric AND v_base.custo < 'Infinity'::numeric) THEN
    RETURN NULL;
  END IF;
  v_preco_base := v_base.custo
                  * (1 + COALESCE(v_base.imposto_pct, 0) / 100)
                  * (1 + COALESCE(v_base.margem_pct, 0) / 100);

  FOR it IN
    SELECT co.id_corante_sayersystem AS id_corante, fi.qtd_ml AS qtd_exp
    FROM tint_formula_itens fi
    JOIN tint_corantes co ON co.id = fi.corante_id
    WHERE fi.formula_id = p_formula_id AND COALESCE(fi.qtd_ml, 0) > 0
  LOOP
    -- S2: AND store_code = p_store_code. S3: AND custo IS NOT NULL AND volume_ml IS NOT NULL.
    SELECT custo, volume_ml INTO v_cor
    FROM tint_staging_corantes
    WHERE account = p_account AND store_code = p_store_code AND id_corante_sayersystem = it.id_corante
      AND custo IS NOT NULL AND volume_ml IS NOT NULL
    ORDER BY created_at DESC, id DESC
    LIMIT 1;
    IF v_cor IS NULL OR v_cor.custo IS NULL
       OR NOT (v_cor.custo > '-Infinity'::numeric AND v_cor.custo < 'Infinity'::numeric)
       OR v_cor.volume_ml IS NULL OR v_cor.volume_ml <= 0 THEN
      RETURN NULL;
    END IF;
    v_soma := v_soma + (v_cor.custo / v_cor.volume_ml) * it.qtd_exp;
  END LOOP;

  RETURN round((v_preco_base + v_soma)::numeric, 2);
END $$;


--
-- Name: tint_run_reconciliation(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tint_run_reconciliation(p_sync_run_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_run record;
  v_recon_id uuid;
  v_matches int := 0;
  v_divergences int := 0;
  v_only_csv int := 0;
  v_only_sync int := 0;
  v_total int := 0;
  r record;
BEGIN
  IF auth.uid() IS NULL OR NOT (public.has_role(auth.uid(), 'employee'::app_role) OR public.has_role(auth.uid(), 'master'::app_role)) THEN
    RAISE EXCEPTION 'Acesso negado: requer perfil staff' USING ERRCODE = '42501';
  END IF;
  SELECT * INTO v_run FROM tint_sync_runs WHERE id = p_sync_run_id;
  IF v_run IS NULL THEN
    RETURN jsonb_build_object('error', 'Sync run not found');
  END IF;

  INSERT INTO tint_reconciliation_runs (account, store_code, sync_run_id, status)
  VALUES (v_run.account, v_run.store_code, p_sync_run_id, 'running')
  RETURNING id INTO v_recon_id;

  FOR r IN
    SELECT sf.id, sf.cor_id, sf.nome_cor, sf.cod_produto, sf.id_base, sf.id_embalagem,
           sf.volume_final_ml AS stg_vol, sf.preco_final AS stg_preco,
           tf.id AS official_id, tf.volume_final_ml AS off_vol, tf.preco_final_sayersystem AS off_preco,
           tf.nome_cor AS off_nome
    FROM tint_staging_formulas sf
    LEFT JOIN tint_formulas tf ON tf.account = sf.account AND tf.cor_id = sf.cor_id
      AND tf.produto_id = (SELECT tp.id FROM tint_produtos tp WHERE tp.account = sf.account AND tp.cod_produto = sf.cod_produto LIMIT 1)
      AND tf.base_id = (SELECT tb.id FROM tint_bases tb WHERE tb.account = sf.account AND tb.id_base_sayersystem = sf.id_base LIMIT 1)
      AND tf.embalagem_id = (SELECT te.id FROM tint_embalagens te WHERE te.account = sf.account AND te.id_embalagem_sayersystem = sf.id_embalagem LIMIT 1)
    WHERE sf.sync_run_id = p_sync_run_id
  LOOP
    v_total := v_total + 1;
    IF r.official_id IS NULL THEN
      v_only_sync := v_only_sync + 1;
      INSERT INTO tint_reconciliation_items (reconciliation_run_id, entity_type, entity_key, sync_value, diff_type)
      VALUES (v_recon_id, 'formula', r.cor_id || '|' || COALESCE(r.cod_produto,'') || '|' || COALESCE(r.id_base,'') || '|' || COALESCE(r.id_embalagem,''),
              jsonb_build_object('cor_id', r.cor_id, 'nome_cor', r.nome_cor, 'volume', r.stg_vol, 'preco', r.stg_preco),
              'only_sync');
    ELSE
      DECLARE
        v_diffs text[] := ARRAY[]::text[];
      BEGIN
        IF COALESCE(r.stg_vol,0) != COALESCE(r.off_vol,0) THEN v_diffs := array_append(v_diffs, 'volume_final_ml'); END IF;
        IF COALESCE(r.stg_preco,0) != COALESCE(r.off_preco,0) THEN v_diffs := array_append(v_diffs, 'preco_final'); END IF;
        IF COALESCE(r.nome_cor,'') != COALESCE(r.off_nome,'') THEN v_diffs := array_append(v_diffs, 'nome_cor'); END IF;

        IF array_length(v_diffs, 1) IS NULL OR array_length(v_diffs, 1) = 0 THEN
          v_matches := v_matches + 1;
          INSERT INTO tint_reconciliation_items (reconciliation_run_id, entity_type, entity_key, diff_type)
          VALUES (v_recon_id, 'formula', r.cor_id || '|' || COALESCE(r.cod_produto,''), 'match');
        ELSE
          v_divergences := v_divergences + 1;
          INSERT INTO tint_reconciliation_items (reconciliation_run_id, entity_type, entity_key,
            csv_value, sync_value, diff_type, diff_fields, diff_details)
          VALUES (v_recon_id, 'formula', r.cor_id || '|' || COALESCE(r.cod_produto,''),
            jsonb_build_object('volume', r.off_vol, 'preco', r.off_preco, 'nome_cor', r.off_nome),
            jsonb_build_object('volume', r.stg_vol, 'preco', r.stg_preco, 'nome_cor', r.nome_cor),
            'divergence', v_diffs,
            jsonb_build_object('fields', v_diffs));
        END IF;
      END;
    END IF;

    UPDATE tint_staging_formulas SET staging_status = 
      CASE WHEN r.official_id IS NULL THEN 'only_sync'
           WHEN (SELECT count(*) FROM tint_reconciliation_items WHERE reconciliation_run_id = v_recon_id AND entity_key = r.cor_id || '|' || COALESCE(r.cod_produto,'') AND diff_type = 'match') > 0 THEN 'matched'
           ELSE 'divergent' END
    WHERE id = r.id;
  END LOOP;

  FOR r IN
    SELECT sc.id, sc.id_corante_sayersystem, sc.descricao AS stg_desc, sc.preco_litro AS stg_preco,
           tc.id AS official_id, tc.descricao AS off_desc, tc.preco_litro AS off_preco
    FROM tint_staging_corantes sc
    LEFT JOIN tint_corantes tc ON tc.account = sc.account AND tc.id_corante_sayersystem = sc.id_corante_sayersystem
    WHERE sc.sync_run_id = p_sync_run_id
  LOOP
    v_total := v_total + 1;
    IF r.official_id IS NULL THEN
      v_only_sync := v_only_sync + 1;
      INSERT INTO tint_reconciliation_items (reconciliation_run_id, entity_type, entity_key, sync_value, diff_type)
      VALUES (v_recon_id, 'corante', r.id_corante_sayersystem,
              jsonb_build_object('descricao', r.stg_desc, 'preco_litro', r.stg_preco), 'only_sync');
    ELSE
      DECLARE v_diffs2 text[] := ARRAY[]::text[];
      BEGIN
        IF COALESCE(r.stg_preco,0) != COALESCE(r.off_preco,0) THEN v_diffs2 := array_append(v_diffs2, 'preco_litro'); END IF;
        IF COALESCE(r.stg_desc,'') != COALESCE(r.off_desc,'') THEN v_diffs2 := array_append(v_diffs2, 'descricao'); END IF;
        IF array_length(v_diffs2, 1) IS NULL OR array_length(v_diffs2, 1) = 0 THEN
          v_matches := v_matches + 1;
          INSERT INTO tint_reconciliation_items (reconciliation_run_id, entity_type, entity_key, diff_type)
          VALUES (v_recon_id, 'corante', r.id_corante_sayersystem, 'match');
        ELSE
          v_divergences := v_divergences + 1;
          INSERT INTO tint_reconciliation_items (reconciliation_run_id, entity_type, entity_key,
            csv_value, sync_value, diff_type, diff_fields)
          VALUES (v_recon_id, 'corante', r.id_corante_sayersystem,
            jsonb_build_object('descricao', r.off_desc, 'preco_litro', r.off_preco),
            jsonb_build_object('descricao', r.stg_desc, 'preco_litro', r.stg_preco),
            'divergence', v_diffs2);
        END IF;
      END;
    END IF;
  END LOOP;

  UPDATE tint_reconciliation_runs SET
    status = 'complete', completed_at = now(),
    total_compared = v_total, matches = v_matches, divergences = v_divergences,
    only_csv = v_only_csv, only_sync = v_only_sync
  WHERE id = v_recon_id;

  RETURN jsonb_build_object(
    'reconciliation_run_id', v_recon_id,
    'total', v_total, 'matches', v_matches,
    'divergences', v_divergences, 'only_csv', v_only_csv, 'only_sync', v_only_sync
  );
END;
$$;


--
-- Name: tint_ultimo_preco_cliente(uuid, uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tint_ultimo_preco_cliente(p_customer_user_id uuid, p_product_id uuid, p_cor_id text, p_exclude_sales_order_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE sql STABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
  SELECT jsonb_build_object(
    'price', (it.item->>'valor_unitario')::float8,
    'date',  so.created_at,
    'sales_order_id', so.id
  )
  FROM public.sales_orders so
  -- CASE defensivo: linha histórica com items não-array NÃO pode derrubar a
  -- RPC (a ordem de avaliação WHERE×LATERAL não é garantida pelo planner —
  -- um typeof no WHERE não protegeria o jsonb_array_elements).
  CROSS JOIN LATERAL jsonb_array_elements(
    CASE WHEN jsonb_typeof(so.items) = 'array' THEN so.items ELSE '[]'::jsonb END
  ) AS it(item)
  WHERE so.customer_user_id = p_customer_user_id
    AND so.account = 'oben'
    -- acordo comercial só conta se virou pedido REAL no Omie…
    AND so.omie_pedido_id IS NOT NULL
    -- …não-cancelado…
    AND so.status IS DISTINCT FROM 'cancelado'
    -- …recente (validade da inferência; fora da janela = renegociar)…
    AND so.created_at >= now() - interval '180 days'
    -- …e NUNCA o pedido que está sendo validado (anti-autovalidação)
    AND (p_exclude_sales_order_id IS NULL OR so.id <> p_exclude_sales_order_id)
    AND it.item->>'product_id' = p_product_id::text
    AND it.item->>'tint_cor_id' = p_cor_id
    AND jsonb_typeof(it.item->'valor_unitario') = 'number'
    AND (it.item->>'valor_unitario')::float8 > 0
  ORDER BY so.created_at DESC
  LIMIT 1
$$;


--
-- Name: FUNCTION tint_ultimo_preco_cliente(p_customer_user_id uuid, p_product_id uuid, p_cor_id text, p_exclude_sales_order_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.tint_ultimo_preco_cliente(p_customer_user_id uuid, p_product_id uuid, p_cor_id text, p_exclude_sales_order_id uuid) IS 'Fase 3 tint: último preço praticado do cliente para (produto omie, cor) — só pedido real no Omie, não-cancelado, janela 180d, excluindo o pedido corrente (anti-autovalidação). Fonte ÚNICA da fonte "cliente": o picker (INVOKER, sob RLS) e o gate do submit usam a mesma função. NULL = sem acordo comprovado na janela.';


