--
-- Name: venda_gate_credito(text, bigint, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.venda_gate_credito(p_company text, p_codigo bigint, p_sales_order_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
  v_corte date;
  v_vencido numeric;
  v_titulos integer;
  v_mais_antigo date;
  v_excecao_id uuid;
BEGIN
  -- Sem código não há evidência possível → não bloqueia (precisão > recall).
  IF p_codigo IS NULL OR p_codigo <= 0 OR p_company IS NULL THEN
    RETURN jsonb_build_object('bloqueado', false, 'vencido', null, 'titulos', 0,
                              'vencimento_mais_antigo', null, 'excecao_id', null,
                              'motivo', 'sem_codigo');
  END IF;

  -- Corte em data civil de São Paulo (não UTC da sessão) — P2 Codex.
  v_corte := ((now() AT TIME ZONE 'America/Sao_Paulo')::date - 60);

  -- Vocabulário de status espelha OPEN_TITLE_STATUSES de
  -- src/lib/financeiro/titulo-status.ts (paridade garantida por teste vitest).
  SELECT COALESCE(sum(saldo), 0), count(*), min(data_vencimento)
    INTO v_vencido, v_titulos, v_mais_antigo
    FROM public.fin_contas_receber
   WHERE company = p_company
     AND omie_codigo_cliente = p_codigo
     AND status_titulo IN ('A VENCER', 'ATRASADO', 'VENCE HOJE', 'ABERTO', 'VENCIDO', 'PARCIAL')
     AND saldo > 0
     AND data_vencimento < v_corte;

  IF v_vencido <= 0 THEN
    RETURN jsonb_build_object('bloqueado', false, 'vencido', 0, 'titulos', 0,
                              'vencimento_mais_antigo', null, 'excecao_id', null,
                              'motivo', 'sem_vencido_60d');
  END IF;

  -- Exceção aprovada PARA ESTE PEDIDO **E ESTE PAR** (company + código), dentro
  -- da validade — exceção de um pedido não libera outro cliente/conta.
  SELECT id INTO v_excecao_id
    FROM public.venda_excecao_credito
   WHERE sales_order_id = p_sales_order_id
     AND company = p_company
     AND omie_codigo_cliente = p_codigo
     AND valido_ate > now()
   ORDER BY created_at DESC
   LIMIT 1;

  RETURN jsonb_build_object(
    'bloqueado', v_excecao_id IS NULL,
    'vencido', v_vencido,
    'titulos', v_titulos,
    'vencimento_mais_antigo', v_mais_antigo,
    'excecao_id', v_excecao_id,
    'motivo', CASE WHEN v_excecao_id IS NULL THEN 'vencido_60d_sem_excecao' ELSE 'excecao_valida' END
  );
END;
$$;


--
-- Name: vendas_sync_finish(text, date, date, boolean, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.vendas_sync_finish(p_account text, p_date_from date, p_date_to date, p_complete boolean, p_next_page integer, p_last_error_kind text) RETURNS void
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
  UPDATE public.vendas_sync_cursor
     SET next_page       = CASE WHEN p_complete THEN NULL ELSE p_next_page END,
         completed_at     = CASE WHEN p_complete THEN now() ELSE completed_at END,
         last_error_kind  = CASE WHEN p_complete THEN NULL ELSE p_last_error_kind END,
         running_since    = NULL,
         heartbeat_at     = now(),
         updated_at       = now()
   WHERE account = p_account AND date_from = p_date_from AND date_to = p_date_to;
$$;


--
-- Name: vendas_sync_heartbeat(text, date, date, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.vendas_sync_heartbeat(p_account text, p_date_from date, p_date_to date, p_page integer) RETURNS void
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
  UPDATE public.vendas_sync_cursor
     SET heartbeat_at = now(), next_page = p_page, updated_at = now()
   WHERE account = p_account AND date_from = p_date_from AND date_to = p_date_to
     AND running_since IS NOT NULL;
$$;


--
-- Name: vendas_sync_lease_acquire(text, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.vendas_sync_lease_acquire(p_account text, p_date_from date, p_date_to date) RETURNS integer
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
  UPDATE public.vendas_sync_cursor
     SET running_since = now(), heartbeat_at = now(), updated_at = now()
   WHERE account = p_account AND date_from = p_date_from AND date_to = p_date_to
     AND completed_at IS NULL
     AND (running_since IS NULL OR heartbeat_at < now() - interval '3 minutes')
  RETURNING COALESCE(next_page, 1);
$$;


--
-- Name: vendas_sync_release(text, date, date, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.vendas_sync_release(p_account text, p_date_from date, p_date_to date, p_last_error_kind text) RETURNS void
    LANGUAGE sql SECURITY DEFINER
