    AS $$
  UPDATE public.vendas_sync_cursor
     SET running_since = NULL, last_error_kind = p_last_error_kind,
         heartbeat_at = now(), updated_at = now()
   WHERE account = p_account AND date_from = p_date_from AND date_to = p_date_to;
$$;


--
-- Name: vendas_sync_semear_janela(date, date, text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.vendas_sync_semear_janela(p_date_from date, p_date_to date, p_accounts text[] DEFAULT ARRAY['oben'::text, 'colacor'::text]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $$
DECLARE
  v_uid         uuid := auth.uid();
  v_account     text;
  v_contas      jsonb := '[]'::jsonb;
  v_desfecho    text;
  v_next        integer;
  v_done        timestamptz;
  v_aberta_from date;
  v_aberta_to   date;
BEGIN
  -- Gate staff/master na fronteira (fail-closed: uid nulo NUNCA passa) —
  -- mesmo gate de public.request_customer_metrics_refresh.
  IF v_uid IS NULL
     OR NOT (COALESCE(public.has_role(v_uid, 'employee'::public.app_role), false)
          OR COALESCE(public.has_role(v_uid, 'master'::public.app_role),   false)) THEN
    RAISE EXCEPTION 'Acesso negado: requer perfil staff' USING ERRCODE = '42501';
  END IF;

  -- Validação de janela (money-path: melhor recusar do que semear lixo).
  IF p_accounts IS NULL OR array_length(p_accounts, 1) IS NULL THEN
    RAISE EXCEPTION 'p_accounts vazio' USING ERRCODE = '22023';
  END IF;
  IF p_date_from IS NULL OR p_date_to IS NULL OR p_date_from > p_date_to THEN
    RAISE EXCEPTION 'janela invalida: date_from (%) deve ser <= date_to (%)', p_date_from, p_date_to
      USING ERRCODE = '22023';
  END IF;
  IF p_date_to > current_date THEN
    RAISE EXCEPTION 'janela invalida: date_to (%) no futuro', p_date_to
      USING ERRCODE = '22023';
  END IF;
  IF p_date_from < DATE '2015-01-01' THEN
    RAISE EXCEPTION 'janela invalida: date_from (%) anterior a 2015-01-01', p_date_from
      USING ERRCODE = '22023';
  END IF;

  -- Contas em ordem determinística → advisory locks sempre na mesma ordem (anti-deadlock).
  FOR v_account IN SELECT DISTINCT a FROM unnest(p_accounts) AS a ORDER BY a
  LOOP
    IF v_account IS NULL OR v_account NOT IN ('oben', 'colacor') THEN
      RAISE EXCEPTION 'conta invalida: % (esperado oben|colacor)', COALESCE(v_account, 'NULL')
        USING ERRCODE = '22023';
    END IF;

    -- Serializa semeadores concorrentes da MESMA conta (xact-lock: solta sozinho no fim/abort).
    PERFORM pg_advisory_xact_lock(hashtext('vendas_sync_semear_' || v_account));

    SELECT c.date_from, c.date_to
      INTO v_aberta_from, v_aberta_to
      FROM public.vendas_sync_cursor c
     WHERE c.account = v_account
       AND c.completed_at IS NULL
       AND NOT (c.date_from = p_date_from AND c.date_to = p_date_to)
     ORDER BY c.date_from
     LIMIT 1;

    IF FOUND THEN
      v_desfecho := 'ja_pendente_outra';
      v_next := NULL;
      v_done := NULL;
    ELSE
      INSERT INTO public.vendas_sync_cursor (account, date_from, date_to)
      VALUES (v_account, p_date_from, p_date_to)
      ON CONFLICT (account, date_from, date_to) DO NOTHING;
      IF FOUND THEN
        v_desfecho := 'semeada';
      END IF;
      SELECT c.next_page, c.completed_at
        INTO v_next, v_done
        FROM public.vendas_sync_cursor c
       WHERE c.account = v_account AND c.date_from = p_date_from AND c.date_to = p_date_to;
      IF v_desfecho IS NULL THEN
        v_desfecho := CASE WHEN v_done IS NOT NULL THEN 'ja_concluida' ELSE 'ja_pendente' END;
      END IF;
    END IF;

    v_contas := v_contas || jsonb_build_object(
      'account',           v_account,
      'desfecho',          v_desfecho,
      'next_page',         v_next,
      'completed_at',      v_done,
      'janela_aberta_de',  v_aberta_from,
      'janela_aberta_ate', v_aberta_to
    );

    v_desfecho := NULL; v_next := NULL; v_done := NULL;
    v_aberta_from := NULL; v_aberta_to := NULL;
  END LOOP;

  RETURN jsonb_build_object('date_from', p_date_from, 'date_to', p_date_to, 'contas', v_contas);
END;
$$;


--
-- Name: FUNCTION vendas_sync_semear_janela(p_date_from date, p_date_to date, p_accounts text[]); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.vendas_sync_semear_janela(p_date_from date, p_date_to date, p_accounts text[]) IS 'Arma janelas de backfill de pedidos no vendas_sync_cursor (staff/master; fail-closed), TODAS as contas na mesma transação (atômico) com advisory lock por conta. ON CONFLICT DO NOTHING: nunca toca janela existente; conta com OUTRA janela aberta recebe ja_pendente_outra. O cron vendas-sync-continuacao-6min pega a pendente mais antiga por conta e o edge omie-vendas-sync importa com lease+heartbeat.';


--
-- Name: wa_is_stop_keyword(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.wa_is_stop_keyword(p_body text) RETURNS boolean
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'public'
    AS $$
  select case
    when p_body is null then false
    else trim(upper(regexp_replace(
           translate(p_body,
             'àáâãäåèéêëìíîïòóôõöùúûüçñÀÁÂÃÄÅÈÉÊËÌÍÎÏÒÓÔÕÖÙÚÛÜÇÑ',
             'aaaaaaeeeeiiiiooooouuuucnAAAAAAEEEEIIIIOOOOOUUUUCN'),
           '[^A-Za-z ]', '', 'g')))
         in ('PARAR','SAIR','STOP','CANCELAR','DESCADASTRAR')
  end;
$$;


--
-- Name: wa_msg_touch_last_outbound(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.wa_msg_touch_last_outbound() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
BEGIN
  IF NEW.direction = 'out' THEN
    UPDATE public.whatsapp_conversations
       SET last_outbound_at = greatest(last_outbound_at, NEW.created_at)
     WHERE id = NEW.conversation_id;
  END IF;
  RETURN NEW;
END $$;


--
-- Name: wa_owner_efetivo(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.wa_owner_efetivo(p_customer uuid) RETURNS uuid
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  select coalesce(
    (select cc.covering_user_id from public.carteira_coverage cc
      where cc.covered_user_id = ca.owner_user_id and cc.active
        and now() >= cc.valid_from and (cc.valid_until is null or now() <= cc.valid_until)
      order by cc.valid_from desc limit 1),
    ca.owner_user_id)
  from public.carteira_assignments ca
  where ca.customer_user_id = p_customer and ca.eligible
  order by ca.valid_from desc limit 1;
$$;


--
-- Name: whatsapp_minutos_uteis(timestamp with time zone, timestamp with time zone, time without time zone, time without time zone, integer[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.whatsapp_minutos_uteis(p_desde timestamp with time zone, p_ate timestamp with time zone, p_h_inicio time without time zone DEFAULT '07:30:00'::time without time zone, p_h_fim time without time zone DEFAULT '17:30:00'::time without time zone, p_dias integer[] DEFAULT ARRAY[1, 2, 3, 4, 5]) RETURNS integer
    LANGUAGE plpgsql STABLE
    SET search_path TO 'public'
    AS $$
declare
  v_total interval := interval '0'; v_dia date; v_dia_fim date;
  v_jan_ini timestamptz; v_jan_fim timestamptz; v_ov_ini timestamptz; v_ov_fim timestamptz; v_guard int := 0;
begin
  if p_desde is null or p_ate is null or p_desde >= p_ate then return 0; end if;
  v_dia := (p_desde at time zone 'America/Sao_Paulo')::date;
  v_dia_fim := (p_ate at time zone 'America/Sao_Paulo')::date;
  while v_dia <= v_dia_fim loop
    v_guard := v_guard + 1; exit when v_guard > 400;
    if extract(isodow from v_dia)::int = any(p_dias) then
      v_jan_ini := (v_dia + p_h_inicio) at time zone 'America/Sao_Paulo';
      v_jan_fim := (v_dia + p_h_fim) at time zone 'America/Sao_Paulo';
      v_ov_ini := greatest(p_desde, v_jan_ini); v_ov_fim := least(p_ate, v_jan_fim);
      if v_ov_fim > v_ov_ini then v_total := v_total + (v_ov_fim - v_ov_ini); end if;
    end if;
    v_dia := v_dia + 1;
  end loop;
  return floor(extract(epoch from v_total) / 60)::int;
end; $$;


--
-- Name: whatsapp_sla_digest_tick(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.whatsapp_sla_digest_tick() RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
declare
  v_hoje date := (now() at time zone 'America/Sao_Paulo')::date;
  v_habil text; v_vermelhos int; v_titulo text; v_msg text;
begin
  select value into v_habil from public.company_config where key='whatsapp_sla_digest_habilitado';
  if coalesce(v_habil,'true') <> 'true' then return; end if;
  insert into public.whatsapp_sla_digest_log(data_local) values (v_hoje) on conflict do nothing;
  if not found then return; end if;
  select count(*) into v_vermelhos from public.v_whatsapp_sla where nivel='vermelho';
  if v_vermelhos = 0 then return; end if;
  select string_agg(linha, E'\n' order by ord) into v_msg from (
    select
      coalesce(p.name, '⚠️ Sem dono (cliente sem carteira)') || ': '
        || count(*) || ' esperando, '
        || count(*) filter (where s.nivel='vermelho') || ' atrasado(s), pior '
        || max(s.minutos_uteis_aguardando) || ' min' as linha,
      (case when s.owner_user_id is null then 1 else 0 end) * 1000000
        - count(*) filter (where s.nivel='vermelho') as ord
    from public.v_whatsapp_sla s
    left join public.profiles p on p.user_id = s.owner_user_id
    group by s.owner_user_id, p.name
  ) t;
  v_titulo := 'WhatsApp: ' || v_vermelhos || ' cliente(s) atrasado(s) hoje';
  insert into public.fornecedor_alerta(tipo, empresa, severidade, status, titulo, mensagem)
  values ('whatsapp_sla', 'oben', 'atencao', 'pendente_notificacao', v_titulo, v_msg);
end;
$$;


