--
-- Name: v_caca_candidatos; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_caca_candidatos WITH (security_invoker='on') AS
 WITH cli AS (
         SELECT p.user_id,
            p.name,
            p.phone,
            p.cnae,
                CASE
                    WHEN (length(regexp_replace(COALESCE(p.document, ''::text), '\D'::text, ''::text, 'g'::text)) = ANY (ARRAY[11, 14])) THEN regexp_replace(COALESCE(p.document, ''::text), '\D'::text, ''::text, 'g'::text)
                    WHEN (length(regexp_replace(COALESCE(p.cnpj, ''::text), '\D'::text, ''::text, 'g'::text)) = ANY (ARRAY[11, 14])) THEN regexp_replace(COALESCE(p.cnpj, ''::text), '\D'::text, ''::text, 'g'::text)
                    ELSE NULL::text
                END AS documento
           FROM public.profiles p
          WHERE (COALESCE(p.is_employee, false) = false)
        ), cli_valid AS (
         SELECT DISTINCT ON (cli.user_id) cli.user_id,
            cli.documento,
            cli.name,
            cli.phone,
            cli.cnae
           FROM cli
          WHERE (cli.documento IS NOT NULL)
          ORDER BY cli.user_id, cli.documento
        ), cli_doc AS (
         SELECT DISTINCT ON (cli_valid.documento) cli_valid.documento,
            cli_valid.user_id,
            cli_valid.name,
            cli_valid.phone,
            cli_valid.cnae
           FROM cli_valid
          ORDER BY cli_valid.documento, cli_valid.user_id
        ), so_ok AS (
         SELECT so.id,
            so.account,
            so.total,
            COALESCE(so.order_date_kpi, (so.created_at)::date) AS dt,
            cv.documento
           FROM (public.sales_orders so
             JOIN cli_valid cv ON ((cv.user_id = so.customer_user_id)))
          WHERE ((so.deleted_at IS NULL) AND (so.status <> ALL (ARRAY['cancelado'::text, 'rascunho'::text])) AND (so.account = ANY (ARRAY['oben'::text, 'colacor'::text])))
        ), ativ AS (
         SELECT so_ok.documento,
            so_ok.account,
            (max(so_ok.dt) >= ((now() - '6 mons'::interval))::date) AS ativo_6m
           FROM so_ok
          GROUP BY so_ok.documento, so_ok.account
        ), grupo AS (
         SELECT so_ok.documento,
            max(so_ok.dt) AS ultima_grupo,
            sum(so_ok.total) AS volume_grupo,
            count(*) AS pedidos_grupo
           FROM so_ok
          GROUP BY so_ok.documento
        ), oi_dedup AS (
         SELECT DISTINCT ON (oi.sales_order_id, oi.omie_codigo_produto) oi.sales_order_id,
            oi.product_id
           FROM public.order_items oi
          ORDER BY oi.sales_order_id, oi.omie_codigo_produto, oi.id
        ), fam_grupo AS (
         SELECT s.documento,
            array_agg(DISTINCT op.familia) FILTER (WHERE ((op.familia IS NOT NULL) AND (op.familia <> ''::text))) AS familias
           FROM ((so_ok s
             JOIN oi_dedup d ON ((d.sales_order_id = s.id)))
             JOIN public.omie_products op ON (((op.id = d.product_id) AND (op.account = s.account))))
          GROUP BY s.documento
        ), cid AS (
         SELECT DISTINCT ON (addresses.user_id) addresses.user_id,
            ((addresses.city || '-'::text) || addresses.state) AS cidade_uf
           FROM public.addresses
          WHERE ((COALESCE(addresses.city, ''::text) <> ''::text) AND (COALESCE(addresses.state, ''::text) <> ''::text))
          ORDER BY addresses.user_id, addresses.is_default DESC NULLS LAST, addresses.created_at DESC NULLS LAST
        ), optout_doc AS (
         SELECT DISTINCT cv.documento
           FROM (public.whatsapp_conversations wc
             JOIN cli_valid cv ON ((cv.user_id = wc.customer_user_id)))
          WHERE (wc.opt_in_status = 'opt_out'::text)
        UNION
         SELECT DISTINCT cv.documento
           FROM (public.whatsapp_conversations wc
             JOIN cli_valid cv ON (("right"(regexp_replace(COALESCE(cv.phone, ''::text), '\D'::text, ''::text, 'g'::text), 11) = "right"(regexp_replace(COALESCE(wc.phone_e164, wc.phone_key, ''::text), '\D'::text, ''::text, 'g'::text), 11))))
          WHERE ((wc.opt_in_status = 'opt_out'::text) AND (length(regexp_replace(COALESCE(cv.phone, ''::text), '\D'::text, ''::text, 'g'::text)) >= 10))
        ), alvos AS (
         SELECT unnest(ARRAY['oben'::text, 'colacor'::text]) AS empresa_alvo
        ), cand AS (
         SELECT cd.documento,
            a.empresa_alvo,
            cd.user_id,
            cd.name,
            cd.phone,
            cd.cnae
           FROM (cli_doc cd
             CROSS JOIN alvos a)
          WHERE ((NOT (EXISTS ( SELECT 1
                   FROM ativ av
                  WHERE ((av.documento = cd.documento) AND (av.account = a.empresa_alvo) AND av.ativo_6m)))) AND (NOT (EXISTS ( SELECT 1
                   FROM optout_doc oo
                  WHERE (oo.documento = cd.documento)))))
        )
 SELECT cand.documento,
    cand.empresa_alvo,
    cid.cidade_uf,
    cand.cnae AS ramo,
        CASE
            WHEN (g.pedidos_grupo > 0) THEN round((g.volume_grupo / (g.pedidos_grupo)::numeric), 2)
            ELSE NULL::numeric
        END AS ticket_faixa,
    COALESCE(fg.familias, ARRAY[]::text[]) AS familias,
    (EXISTS ( SELECT 1
           FROM ativ av2
          WHERE ((av2.documento = cand.documento) AND (av2.account <> cand.empresa_alvo) AND av2.ativo_6m))) AS compra_em_outra_empresa,
        CASE
            WHEN (g.ultima_grupo IS NOT NULL) THEN ((now())::date - g.ultima_grupo)
            ELSE NULL::integer
        END AS ultima_compra_grupo_dias,
    cand.name AS nome,
    cand.phone AS telefone,
    cand.user_id AS cliente_user_id
   FROM (((cand
     LEFT JOIN grupo g ON ((g.documento = cand.documento)))
     LEFT JOIN fam_grupo fg ON ((fg.documento = cand.documento)))
     LEFT JOIN cid ON ((cid.user_id = cand.user_id)));


--
-- Name: v_caca_compradores; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_caca_compradores WITH (security_invoker='on') AS
 WITH cli AS (
         SELECT p.user_id,
            p.name,
            p.phone,
            p.cnae,
                CASE
                    WHEN (length(regexp_replace(COALESCE(p.document, ''::text), '\D'::text, ''::text, 'g'::text)) = ANY (ARRAY[11, 14])) THEN regexp_replace(COALESCE(p.document, ''::text), '\D'::text, ''::text, 'g'::text)
                    WHEN (length(regexp_replace(COALESCE(p.cnpj, ''::text), '\D'::text, ''::text, 'g'::text)) = ANY (ARRAY[11, 14])) THEN regexp_replace(COALESCE(p.cnpj, ''::text), '\D'::text, ''::text, 'g'::text)
                    ELSE NULL::text
                END AS documento
           FROM public.profiles p
          WHERE (COALESCE(p.is_employee, false) = false)
        ), cli_valid AS (
         SELECT DISTINCT ON (cli.user_id) cli.user_id,
            cli.documento,
            cli.name,
            cli.phone,
            cli.cnae
           FROM cli
          WHERE (cli.documento IS NOT NULL)
          ORDER BY cli.user_id, cli.documento
        ), cli_doc AS (
         SELECT DISTINCT ON (cli_valid.documento) cli_valid.documento,
            cli_valid.user_id,
            cli_valid.name,
            cli_valid.phone,
            cli_valid.cnae
           FROM cli_valid
          ORDER BY cli_valid.documento, cli_valid.user_id
        ), so_ok AS (
         SELECT so.id,
            so.account,
            so.total,
            COALESCE(so.order_date_kpi, (so.created_at)::date) AS dt,
            cv.documento
           FROM (public.sales_orders so
             JOIN cli_valid cv ON ((cv.user_id = so.customer_user_id)))
          WHERE ((so.deleted_at IS NULL) AND (so.status <> ALL (ARRAY['cancelado'::text, 'rascunho'::text])) AND (so.account = ANY (ARRAY['oben'::text, 'colacor'::text])))
        ), compras AS (
         SELECT so_ok.documento,
            so_ok.account,
            count(*) AS n_pedidos,
            sum(so_ok.total) AS volume,
            max(so_ok.dt) AS ultima
           FROM so_ok
          GROUP BY so_ok.documento, so_ok.account
        ), oi_dedup AS (
         SELECT DISTINCT ON (oi.sales_order_id, oi.omie_codigo_produto) oi.sales_order_id,
            oi.product_id,
            oi.quantity,
            oi.unit_price
           FROM public.order_items oi
          ORDER BY oi.sales_order_id, oi.omie_codigo_produto, oi.id
        ), itens AS (
         SELECT s.documento,
            s.account,
            d.quantity,
            d.unit_price,
            op.familia,
            COALESCE(
                CASE
                    WHEN (pc.custo_producao_status = 'ok'::text) THEN pc.custo_producao
                    ELSE NULL::numeric
                END, NULLIF(pc.cmc, (0)::numeric)) AS custo_efetivo
           FROM (((so_ok s
             JOIN oi_dedup d ON ((d.sales_order_id = s.id)))
             JOIN public.omie_products op ON (((op.id = d.product_id) AND (op.account = s.account))))
             LEFT JOIN public.product_costs pc ON ((pc.product_id = op.id)))
        ), fam AS (
         SELECT itens.documento,
            itens.account,
            array_agg(DISTINCT itens.familia) FILTER (WHERE ((itens.familia IS NOT NULL) AND (itens.familia <> ''::text))) AS familias
           FROM itens
          GROUP BY itens.documento, itens.account
        ), luc AS (
         SELECT itens.documento,
            itens.account,
            sum(((itens.quantity * itens.unit_price) - (itens.quantity * itens.custo_efetivo))) FILTER (WHERE (itens.custo_efetivo > (0)::numeric)) AS lucro_com_custo,
            sum((itens.quantity * itens.unit_price)) AS receita,
            sum((itens.quantity * itens.unit_price)) FILTER (WHERE (itens.custo_efetivo > (0)::numeric)) AS receita_com_custo
           FROM itens
          GROUP BY itens.documento, itens.account
        ), cid AS (
         SELECT DISTINCT ON (addresses.user_id) addresses.user_id,
            ((addresses.city || '-'::text) || addresses.state) AS cidade_uf
           FROM public.addresses
          WHERE ((COALESCE(addresses.city, ''::text) <> ''::text) AND (COALESCE(addresses.state, ''::text) <> ''::text))
          ORDER BY addresses.user_id, addresses.is_default DESC NULLS LAST, addresses.created_at DESC NULLS LAST
        )
 SELECT c.documento,
    c.account AS empresa,
    cid.cidade_uf,
    cd.cnae AS ramo,
        CASE
            WHEN (c.n_pedidos > 0) THEN round((c.volume / (c.n_pedidos)::numeric), 2)
            ELSE NULL::numeric
        END AS ticket_faixa,
    COALESCE(f.familias, ARRAY[]::text[]) AS familias,
    c.volume,
    c.n_pedidos,
    ((now())::date - c.ultima) AS recencia_dias,
        CASE
            WHEN (l.lucro_com_custo IS NOT NULL) THEN round(l.lucro_com_custo, 2)
            ELSE NULL::numeric
        END AS lucro_proxy,
        CASE
            WHEN (COALESCE(l.receita, (0)::numeric) > (0)::numeric) THEN round((COALESCE(l.receita_com_custo, (0)::numeric) / l.receita), 2)
            ELSE (0)::numeric
        END AS lucro_cobertura
   FROM ((((compras c
     JOIN cli_doc cd ON ((cd.documento = c.documento)))
     LEFT JOIN fam f ON (((f.documento = c.documento) AND (f.account = c.account))))
     LEFT JOIN luc l ON (((l.documento = c.documento) AND (l.account = c.account))))
     LEFT JOIN cid ON ((cid.user_id = cd.user_id)));


--
-- Name: v_titulo_baixas; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_titulo_baixas WITH (security_invoker='on') AS
 WITH mov AS (
         SELECT fin_movimentacoes.company,
            fin_movimentacoes.omie_codigo_lancamento AS cod,
            fin_movimentacoes.tipo,
            fin_movimentacoes.data_movimento,
            fin_movimentacoes.valor
           FROM public.fin_movimentacoes
          WHERE ((fin_movimentacoes.omie_codigo_lancamento IS NOT NULL) AND (fin_movimentacoes.data_movimento IS NOT NULL) AND (fin_movimentacoes.tipo = ANY (ARRAY['E'::text, 'S'::text])) AND (fin_movimentacoes.valor > (0)::numeric))
        )
 SELECT cr.company,
    cr.omie_codigo_lancamento,
    'CR'::text AS tipo,
    max(m.data_movimento) AS data_baixa_final,
    sum(m.valor) AS valor_baixado,
    (count(*))::integer AS n_movimentos,
        CASE
            WHEN ((cr.data_emissao IS NOT NULL) AND (sum(m.valor) > (0)::numeric)) THEN round((sum((m.valor * ((m.data_movimento - cr.data_emissao))::numeric)) / sum(m.valor)))
            ELSE NULL::numeric
        END AS prazo_ponderado_dias
   FROM (public.fin_contas_receber cr
     JOIN mov m ON (((m.company = cr.company) AND (m.cod = cr.omie_codigo_lancamento) AND (m.tipo = 'E'::text))))
  WHERE ((cr.omie_codigo_lancamento IS NOT NULL) AND (cr.status_titulo = ANY (ARRAY['RECEBIDO'::text, 'LIQUIDADO'::text])))
  GROUP BY cr.company, cr.omie_codigo_lancamento, cr.data_emissao
UNION ALL
 SELECT cp.company,
    cp.omie_codigo_lancamento,
    'CP'::text AS tipo,
    max(m.data_movimento) AS data_baixa_final,
    sum(m.valor) AS valor_baixado,
    (count(*))::integer AS n_movimentos,
        CASE
            WHEN ((cp.data_emissao IS NOT NULL) AND (sum(m.valor) > (0)::numeric)) THEN round((sum((m.valor * ((m.data_movimento - cp.data_emissao))::numeric)) / sum(m.valor)))
            ELSE NULL::numeric
        END AS prazo_ponderado_dias
   FROM (public.fin_contas_pagar cp
     JOIN mov m ON (((m.company = cp.company) AND (m.cod = cp.omie_codigo_lancamento) AND (m.tipo = 'S'::text))))
  WHERE ((cp.omie_codigo_lancamento IS NOT NULL) AND (cp.status_titulo = ANY (ARRAY['PAGO'::text, 'LIQUIDADO'::text])))
  GROUP BY cp.company, cp.omie_codigo_lancamento, cp.data_emissao;


--
-- Name: v_capital_giro_prazos; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_capital_giro_prazos WITH (security_invoker='on') AS
 WITH companies AS (
         SELECT DISTINCT fin_contas_receber.company
           FROM public.fin_contas_receber
        UNION
         SELECT DISTINCT fin_contas_pagar.company
           FROM public.fin_contas_pagar
        ), cr_baixa AS (
         SELECT v_titulo_baixas.company,
            round((sum((v_titulo_baixas.prazo_ponderado_dias * v_titulo_baixas.valor_baixado)) / NULLIF(sum(v_titulo_baixas.valor_baixado), (0)::numeric))) AS pmr,
            count(*) AS n
           FROM public.v_titulo_baixas
          WHERE ((v_titulo_baixas.tipo = 'CR'::text) AND (v_titulo_baixas.prazo_ponderado_dias IS NOT NULL))
          GROUP BY v_titulo_baixas.company
        ), cp_baixa AS (
         SELECT v_titulo_baixas.company,
            round((sum((v_titulo_baixas.prazo_ponderado_dias * v_titulo_baixas.valor_baixado)) / NULLIF(sum(v_titulo_baixas.valor_baixado), (0)::numeric))) AS pmp,
            count(*) AS n
           FROM public.v_titulo_baixas
          WHERE ((v_titulo_baixas.tipo = 'CP'::text) AND (v_titulo_baixas.prazo_ponderado_dias IS NOT NULL))
          GROUP BY v_titulo_baixas.company
        ), cr_set AS (
         SELECT fin_contas_receber.company,
            count(*) AS n
           FROM public.fin_contas_receber
          WHERE (fin_contas_receber.status_titulo = ANY (ARRAY['RECEBIDO'::text, 'LIQUIDADO'::text]))
          GROUP BY fin_contas_receber.company
        ), cp_set AS (
         SELECT fin_contas_pagar.company,
            count(*) AS n
           FROM public.fin_contas_pagar
          WHERE (fin_contas_pagar.status_titulo = ANY (ARRAY['PAGO'::text, 'LIQUIDADO'::text]))
          GROUP BY fin_contas_pagar.company
        )
 SELECT c.company,
    crb.pmr,
    cpb.pmp,
    round(((COALESCE(crb.n, (0)::bigint))::numeric / (NULLIF(crs.n, 0))::numeric), 3) AS pmr_cobertura,
    round(((COALESCE(cpb.n, (0)::bigint))::numeric / (NULLIF(cps.n, 0))::numeric), 3) AS pmp_cobertura
   FROM ((((companies c
     LEFT JOIN cr_baixa crb ON ((crb.company = c.company)))
     LEFT JOIN cp_baixa cpb ON ((cpb.company = c.company)))
     LEFT JOIN cr_set crs ON ((crs.company = c.company)))
     LEFT JOIN cp_set cps ON ((cps.company = c.company)));


--
-- Name: v_carteira_sla; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_carteira_sla WITH (security_invoker='true') AS
 WITH sla AS (
         SELECT (COALESCE(( SELECT farmer_algorithm_config.value
                   FROM public.farmer_algorithm_config
                  WHERE (farmer_algorithm_config.key = 'sla_contact_days'::text)), (14)::numeric))::integer AS dias
        ), ultimo_contato AS (
         SELECT x.customer_user_id,
            max(x.at) AS last_contact_at
           FROM ( SELECT farmer_calls.customer_user_id,
                    COALESCE(farmer_calls.started_at, farmer_calls.created_at) AS at
                   FROM public.farmer_calls
                  WHERE ((farmer_calls.customer_user_id IS NOT NULL) AND (farmer_calls.call_result = 'contato_sucesso'::public.farmer_call_result))
                UNION ALL
                 SELECT route_visits.customer_user_id,
                    route_visits.check_in_at AS at
                   FROM public.route_visits
                  WHERE ((route_visits.customer_user_id IS NOT NULL) AND (route_visits.check_in_at IS NOT NULL))) x
          GROUP BY x.customer_user_id
        )
 SELECT fcs.customer_user_id,
    fcs.farmer_id,
    fcs.health_class,
    fcs.churn_risk,
    fcs.priority_score,
    uc.last_contact_at,
        CASE
            WHEN (uc.last_contact_at IS NULL) THEN NULL::integer
            ELSE (floor((EXTRACT(epoch FROM (now() - uc.last_contact_at)) / (86400)::numeric)))::integer
        END AS dias_sem_contato,
    sla.dias AS sla_dias,
    ((uc.last_contact_at IS NULL) OR ((now() - uc.last_contact_at) > make_interval(days => sla.dias))) AS vencido
   FROM ((public.farmer_client_scores fcs
     CROSS JOIN sla)
     LEFT JOIN ultimo_contato uc ON ((uc.customer_user_id = fcs.customer_user_id)))
  WHERE ((fcs.health_class = ANY (ARRAY['atencao'::text, 'critico'::text])) OR (uc.last_contact_at IS NULL) OR ((now() - uc.last_contact_at) > make_interval(days => sla.dias)));


--
-- Name: v_cliente_interacoes; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_cliente_interacoes WITH (security_invoker='true') AS
 SELECT fc.customer_user_id,
    COALESCE(fc.started_at, fc.created_at) AS at,
        CASE
            WHEN fc.is_whatsapp THEN 'whatsapp'::text
            ELSE 'ligacao'::text
        END AS canal,
        CASE fc.call_type
            WHEN 'reativacao'::public.farmer_call_type THEN 'Reativação'::text
            WHEN 'cross_sell'::public.farmer_call_type THEN 'Cross-sell'::text
            WHEN 'up_sell'::public.farmer_call_type THEN 'Up-sell'::text
            WHEN 'follow_up'::public.farmer_call_type THEN 'Follow-up'::text
            ELSE 'Contato'::text
        END AS titulo,
    NULLIF(fc.notes, ''::text) AS resumo,
    'farmer_calls'::text AS ref_tabela,
    fc.id AS ref_id,
    fc.farmer_id AS autor_id,
    fc.revenue_generated AS revenue
   FROM public.farmer_calls fc
  WHERE ((fc.customer_user_id IS NOT NULL) AND (private.pode_ver_carteira_completa(auth.uid()) OR (fc.farmer_id = auth.uid()) OR private.carteira_visivel_para(fc.customer_user_id, auth.uid())))
UNION ALL
 SELECT rv.customer_user_id,
    COALESCE(rv.check_in_at, (rv.visit_date)::timestamp with time zone, rv.created_at) AS at,
    'visita'::text AS canal,
    COALESCE(NULLIF(rv.visit_type, ''::text), 'Visita'::text) AS titulo,
    NULLIF(rv.notes, ''::text) AS resumo,
    'route_visits'::text AS ref_tabela,
    rv.id AS ref_id,
    rv.visited_by AS autor_id,
    rv.revenue_generated AS revenue
   FROM public.route_visits rv
  WHERE ((rv.customer_user_id IS NOT NULL) AND (private.pode_ver_carteira_completa(auth.uid()) OR (rv.visited_by = auth.uid()) OR private.carteira_visivel_para(rv.customer_user_id, auth.uid())))
UNION ALL
 SELECT t.customer_user_id,
    COALESCE(t.concluida_em, t.created_at) AS at,
    'tarefa'::text AS canal,
    COALESCE(NULLIF(t.categoria, ''::text), 'Tarefa'::text) AS titulo,
    COALESCE(NULLIF(t.nota_conclusao, ''::text), NULLIF(t.descricao, ''::text)) AS resumo,
    'tarefas'::text AS ref_tabela,
    t.id AS ref_id,
    t.assigned_to AS autor_id,
    NULL::numeric AS revenue
   FROM public.tarefas t
  WHERE ((t.customer_user_id IS NOT NULL) AND (private.pode_ver_carteira_completa(auth.uid()) OR private.carteira_visivel_para(t.customer_user_id, auth.uid())))
UNION ALL
 SELECT o.user_id AS customer_user_id,
    om.created_at AS at,
    'mensagem_pedido'::text AS canal,
        CASE
            WHEN om.is_staff THEN 'Mensagem da equipe'::text
            ELSE 'Mensagem do cliente'::text
        END AS titulo,
    NULLIF(om.message, ''::text) AS resumo,
    'order_messages'::text AS ref_tabela,
    om.id AS ref_id,
    om.sender_id AS autor_id,
    NULL::numeric AS revenue
   FROM (public.order_messages om
     JOIN public.orders o ON ((o.id = om.order_id)))
  WHERE ((o.user_id IS NOT NULL) AND (private.pode_ver_carteira_completa(auth.uid()) OR private.carteira_visivel_para(o.user_id, auth.uid())));


--
-- Name: v_clientes_nao_vinculados_atual; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_clientes_nao_vinculados_atual WITH (security_invoker='on') AS
 SELECT nv.id,
    nv.empresa,
    nv.omie_codigo_cliente,
    nv.cnpj_cpf,
    nv.razao_social,
    nv.nome_fantasia,
    nv.cidade,
    nv.uf,
    nv.codigo_vendedor,
    nv.synced_at
   FROM (public.omie_clientes_nao_vinculados nv
     JOIN public.omie_nao_vinculados_state st ON (((st.empresa = nv.empresa) AND (st.last_complete_synced_at = nv.synced_at))));


--
-- Name: v_cron_jobs_falhas; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_cron_jobs_falhas WITH (security_invoker='on') AS
 SELECT j.jobname,
    jrd.jobid,
    jrd.runid,
    jrd.start_time,
    jrd.end_time,
    (EXTRACT(epoch FROM (jrd.end_time - jrd.start_time)))::numeric(10,2) AS duracao_segundos,
    jrd.return_message,
    jrd.status
   FROM (cron.job_run_details jrd
     JOIN cron.job j ON ((j.jobid = jrd.jobid)))
  WHERE ((jrd.status = 'failed'::text) AND (jrd.start_time > (now() - '7 days'::interval)) AND (j.jobname ~~ 'afiacao_%'::text))
  ORDER BY jrd.start_time DESC;


--
-- Name: VIEW v_cron_jobs_falhas; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_cron_jobs_falhas IS 'Execuções de cron jobs que falharam nos últimos 7 dias. Se esta view retornar linhas, investigar return_message para entender a causa.';


--
-- Name: v_cron_jobs_status; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_cron_jobs_status WITH (security_invoker='on') AS
 WITH ultima_execucao AS (
         SELECT DISTINCT ON (job_run_details.jobid) job_run_details.jobid,
            job_run_details.start_time,
            job_run_details.end_time,
            job_run_details.status,
            job_run_details.return_message,
            EXTRACT(epoch FROM (job_run_details.end_time - job_run_details.start_time)) AS duracao_segundos
           FROM cron.job_run_details
          WHERE (job_run_details.start_time > (now() - '30 days'::interval))
          ORDER BY job_run_details.jobid, job_run_details.start_time DESC
        ), historico_7d AS (
         SELECT job_run_details.jobid,
            count(*) AS execucoes_7d,
            count(*) FILTER (WHERE (job_run_details.status = 'succeeded'::text)) AS sucessos_7d,
            count(*) FILTER (WHERE (job_run_details.status = 'failed'::text)) AS falhas_7d,
            (avg(EXTRACT(epoch FROM (job_run_details.end_time - job_run_details.start_time))))::numeric(10,2) AS duracao_media_segundos
           FROM cron.job_run_details
          WHERE (job_run_details.start_time > (now() - '7 days'::interval))
          GROUP BY job_run_details.jobid
        )
 SELECT j.jobid,
    j.jobname,
    j.schedule,
    j.command,
    j.active,
    ue.start_time AS ultima_execucao,
    ue.status AS ultimo_status,
    ue.duracao_segundos AS ultima_duracao_seg,
    ue.return_message AS ultima_mensagem,
    h.execucoes_7d,
    h.sucessos_7d,
    h.falhas_7d,
    h.duracao_media_segundos
   FROM ((cron.job j
     LEFT JOIN ultima_execucao ue ON ((ue.jobid = j.jobid)))
     LEFT JOIN historico_7d h ON ((h.jobid = j.jobid)))
  WHERE (j.jobname ~~ 'afiacao_%'::text)
  ORDER BY j.jobname;


--
-- Name: VIEW v_cron_jobs_status; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_cron_jobs_status IS 'Monitoramento de cron jobs do Afiação. Mostra última execução, status, duração e histórico dos últimos 7 dias. Útil para diagnosticar se algum job parou de rodar ou está falhando.';


--
-- Name: v_des_checkin_atual; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_des_checkin_atual WITH (security_invoker='on') AS
 WITH checkin_mais_recente AS (
         SELECT DISTINCT ON (des_checkin_qualitativo.empresa, des_checkin_qualitativo.ano, des_checkin_qualitativo.trimestre) des_checkin_qualitativo.id,
            des_checkin_qualitativo.empresa,
            des_checkin_qualitativo.ano,
            des_checkin_qualitativo.trimestre,
            des_checkin_qualitativo.data_avaliacao,
            des_checkin_qualitativo.tipo,
            des_checkin_qualitativo.avaliado_com,
            des_checkin_qualitativo.avaliado_por,
            des_checkin_qualitativo.observacoes_gerais
           FROM public.des_checkin_qualitativo
          ORDER BY des_checkin_qualitativo.empresa, des_checkin_qualitativo.ano, des_checkin_qualitativo.trimestre, des_checkin_qualitativo.data_avaliacao DESC, des_checkin_qualitativo.criado_em DESC
        )
 SELECT cr.empresa,
    cr.ano,
    cr.trimestre,
    cr.id AS checkin_id,
    cr.data_avaliacao,
    cr.tipo,
    cr.avaliado_com,
    cr.avaliado_por,
    cq.codigo,
    cq.nome,
    cq.tipo AS criterio_tipo,
    COALESCE(cr_resp.atingido, false) AS atingido,
    cr_resp.observacao AS observacao_criterio
   FROM ((checkin_mais_recente cr
     CROSS JOIN public.des_criterio_qualitativo cq)
     LEFT JOIN public.des_checkin_qualitativo_resposta cr_resp ON (((cr_resp.checkin_id = cr.id) AND (cr_resp.criterio_id = cq.id))))
  WHERE (cq.contrato_versao_id = ( SELECT des_contrato_versao.id
           FROM public.des_contrato_versao
          WHERE (des_contrato_versao.versao = '2026'::text)));


--
-- Name: v_des_pedidos_em_transito; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_des_pedidos_em_transito WITH (security_invoker='on') AS
 WITH trimestre_info AS (
         SELECT (EXTRACT(year FROM CURRENT_DATE))::integer AS ano_atual,
            (EXTRACT(quarter FROM CURRENT_DATE))::integer AS trimestre_atual,
            (date_trunc('quarter'::text, (CURRENT_DATE)::timestamp with time zone))::date AS inicio_trimestre,
            ((date_trunc('quarter'::text, (CURRENT_DATE)::timestamp with time zone) + '3 mons -1 days'::interval))::date AS fim_trimestre
        ), pedidos AS (
         SELECT pcs.id AS pedido_id,
            pcs.empresa,
            pcs.fornecedor_nome,
            pcs.grupo_codigo,
            pcs.data_ciclo,
            pcs.horario_disparo_real,
            pcs.valor_total,
            pcs.status,
            pcs.tipo_ciclo,
            COALESCE((pcs.horario_disparo_real)::date, pcs.data_ciclo) AS data_emissao,
            public.des_data_faturamento_prevista(COALESCE((pcs.horario_disparo_real)::date, pcs.data_ciclo), pcs.grupo_codigo, pcs.empresa) AS data_faturamento_prevista
           FROM public.pedido_compra_sugerido pcs
          WHERE ((pcs.fornecedor_nome = 'RENNER SAYERLACK S/A'::text) AND (pcs.status = ANY (ARRAY['pendente_aprovacao'::text, 'aprovado'::text, 'disparado'::text])))
        )
 SELECT p.pedido_id,
    p.empresa,
    p.fornecedor_nome,
    p.grupo_codigo,
    p.data_ciclo,
    p.horario_disparo_real,
    p.valor_total,
    p.status,
    p.tipo_ciclo,
    p.data_emissao,
    p.data_faturamento_prevista,
    ti.ano_atual,
    ti.trimestre_atual,
    ti.inicio_trimestre,
    ti.fim_trimestre,
    ((p.data_faturamento_prevista >= ti.inicio_trimestre) AND (p.data_faturamento_prevista <= ti.fim_trimestre)) AS fatura_no_trimestre,
        CASE
            WHEN (p.data_faturamento_prevista > ti.fim_trimestre) THEN 'fora'::text
            WHEN (((ti.fim_trimestre - p.data_emissao))::numeric >= (((COALESCE(( SELECT fgp.lt_producao_dias
               FROM public.fornecedor_grupo_producao fgp
              WHERE (fgp.grupo_codigo = p.grupo_codigo)
             LIMIT 1), 8))::numeric * 1.4) * 1.2)) THEN 'verde'::text
            WHEN (((ti.fim_trimestre - p.data_emissao))::numeric >= ((COALESCE(( SELECT fgp.lt_producao_dias
               FROM public.fornecedor_grupo_producao fgp
              WHERE (fgp.grupo_codigo = p.grupo_codigo)
             LIMIT 1), 8))::numeric * 1.4)) THEN 'amarelo'::text
            ELSE 'vermelho'::text
        END AS zona_confianca
   FROM (pedidos p
     CROSS JOIN trimestre_info ti);


--
-- Name: VIEW v_des_pedidos_em_transito; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_des_pedidos_em_transito IS 'Pedidos Sayerlack ainda não faturados. Mostra a data prevista de faturamento e se cai dentro do trimestre corrente. Zona de confiança sinaliza o risco de o faturamento escapar para o próximo trimestre.';


--
-- Name: v_des_snapshot_mais_recente; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_des_snapshot_mais_recente WITH (security_invoker='on') AS
 SELECT DISTINCT ON (empresa, ano, trimestre) id,
    empresa,
    ano,
    trimestre,
    data_referencia,
    objetivo_valor,
    fat_bruto_valor,
    objetivo_qtde,
    fat_bruto_qtde,
    pedidos_abertos_valor,
    pedidos_abertos_qtde,
    criado_em
   FROM public.des_trimestre_snapshot
  ORDER BY empresa, ano, trimestre, data_referencia DESC;


--
-- Name: v_des_posicao_trimestre_ao_vivo; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_des_posicao_trimestre_ao_vivo WITH (security_invoker='on') AS
 WITH snapshot AS (
         SELECT v_des_snapshot_mais_recente.empresa,
            v_des_snapshot_mais_recente.ano,
            v_des_snapshot_mais_recente.trimestre,
            v_des_snapshot_mais_recente.data_referencia,
            v_des_snapshot_mais_recente.objetivo_valor,
            v_des_snapshot_mais_recente.fat_bruto_valor,
            v_des_snapshot_mais_recente.pedidos_abertos_valor
           FROM public.v_des_snapshot_mais_recente
        ), pedidos_apos_snapshot AS (
         SELECT t.empresa,
            t.ano_atual AS ano,
            t.trimestre_atual AS trimestre,
            sum(
                CASE
                    WHEN (t.fatura_no_trimestre AND (t.zona_confianca = ANY (ARRAY['verde'::text, 'amarelo'::text]))) THEN t.valor_total
                    ELSE (0)::numeric
                END) AS valor_em_transito_seguro,
            sum(
                CASE
                    WHEN (t.fatura_no_trimestre AND (t.zona_confianca = 'vermelho'::text)) THEN t.valor_total
                    ELSE (0)::numeric
                END) AS valor_em_transito_risco,
            sum(
                CASE
                    WHEN (NOT t.fatura_no_trimestre) THEN t.valor_total
                    ELSE (0)::numeric
                END) AS valor_fora_trimestre,
            count(*) FILTER (WHERE t.fatura_no_trimestre) AS pedidos_no_trimestre,
            count(*) FILTER (WHERE (NOT t.fatura_no_trimestre)) AS pedidos_fora_trimestre
           FROM (public.v_des_pedidos_em_transito t
             LEFT JOIN snapshot s_1 ON (((s_1.empresa = t.empresa) AND (s_1.ano = t.ano_atual) AND (s_1.trimestre = t.trimestre_atual))))
          WHERE (t.data_emissao > COALESCE(s_1.data_referencia, '1900-01-01'::date))
          GROUP BY t.empresa, t.ano_atual, t.trimestre_atual
        ), meta AS (
         SELECT des_meta_empresa.empresa,
            des_meta_empresa.ano,
            des_meta_empresa.trimestre,
            des_meta_empresa.meta_faturamento,
            des_meta_empresa.faixa_des_objetivo
           FROM public.des_meta_empresa
        )
 SELECT COALESCE(s.empresa, p.empresa, m.empresa) AS empresa,
    COALESCE(s.ano, p.ano, m.ano) AS ano,
    COALESCE(s.trimestre, p.trimestre, m.trimestre) AS trimestre,
    s.data_referencia AS gooddata_data_referencia,
    s.objetivo_valor AS gooddata_objetivo,
    s.fat_bruto_valor AS fat_bruto_confirmado,
    s.pedidos_abertos_valor AS gooddata_pedidos_abertos,
    m.meta_faturamento AS meta_pessoal,
    m.faixa_des_objetivo AS faixa_des_alvo,
    COALESCE(p.valor_em_transito_seguro, (0)::numeric) AS valor_em_transito_seguro,
    COALESCE(p.valor_em_transito_risco, (0)::numeric) AS valor_em_transito_risco,
    COALESCE(p.valor_fora_trimestre, (0)::numeric) AS valor_fora_trimestre,
    COALESCE(p.pedidos_no_trimestre, (0)::bigint) AS qtd_pedidos_no_trimestre,
    COALESCE(p.pedidos_fora_trimestre, (0)::bigint) AS qtd_pedidos_fora_trimestre,
    round((COALESCE(s.fat_bruto_valor, (0)::numeric) + COALESCE(p.valor_em_transito_seguro, (0)::numeric)), 2) AS posicao_ao_vivo_conservadora,
    round(((COALESCE(s.fat_bruto_valor, (0)::numeric) + COALESCE(p.valor_em_transito_seguro, (0)::numeric)) + COALESCE(p.valor_em_transito_risco, (0)::numeric)), 2) AS posicao_ao_vivo_otimista,
    ( SELECT row_to_json(r.*) AS row_to_json
           FROM ( SELECT des_determinar_faixa.faixa_id,
                    des_determinar_faixa.faixa_numero,
                    des_determinar_faixa.estrelas,
                    des_determinar_faixa.desconto_padrao_perc,
                    des_determinar_faixa.volume_min,
                    des_determinar_faixa.volume_max
                   FROM public.des_determinar_faixa((COALESCE(s.fat_bruto_valor, (0)::numeric) + COALESCE(p.valor_em_transito_seguro, (0)::numeric))) des_determinar_faixa(faixa_id, faixa_numero, estrelas, desconto_padrao_perc, volume_min, volume_max)) r) AS faixa_conservadora,
    ( SELECT row_to_json(r.*) AS row_to_json
           FROM ( SELECT des_determinar_faixa.faixa_id,
                    des_determinar_faixa.faixa_numero,
                    des_determinar_faixa.estrelas,
                    des_determinar_faixa.desconto_padrao_perc,
                    des_determinar_faixa.volume_min,
                    des_determinar_faixa.volume_max
                   FROM public.des_determinar_faixa(((COALESCE(s.fat_bruto_valor, (0)::numeric) + COALESCE(p.valor_em_transito_seguro, (0)::numeric)) + COALESCE(p.valor_em_transito_risco, (0)::numeric))) des_determinar_faixa(faixa_id, faixa_numero, estrelas, desconto_padrao_perc, volume_min, volume_max)) r) AS faixa_otimista,
    round(GREATEST((0)::numeric, (COALESCE(m.meta_faturamento, (0)::numeric) - (COALESCE(s.fat_bruto_valor, (0)::numeric) + COALESCE(p.valor_em_transito_seguro, (0)::numeric)))), 2) AS gap_para_meta_pessoal,
    CURRENT_DATE AS calculado_em,
    (date_trunc('quarter'::text, (CURRENT_DATE)::timestamp with time zone))::date AS inicio_trimestre,
    ((date_trunc('quarter'::text, (CURRENT_DATE)::timestamp with time zone) + '3 mons -1 days'::interval))::date AS fim_trimestre,
    (((date_trunc('quarter'::text, (CURRENT_DATE)::timestamp with time zone) + '3 mons -1 days'::interval))::date - CURRENT_DATE) AS dias_restantes
   FROM ((snapshot s
     FULL JOIN pedidos_apos_snapshot p ON (((p.empresa = s.empresa) AND (p.ano = s.ano) AND (p.trimestre = s.trimestre))))
     FULL JOIN meta m ON (((m.empresa = COALESCE(s.empresa, p.empresa)) AND (m.ano = COALESCE(s.ano, p.ano)) AND (m.trimestre = COALESCE(s.trimestre, p.trimestre)))));


--
-- Name: VIEW v_des_posicao_trimestre_ao_vivo; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_des_posicao_trimestre_ao_vivo IS 'Posição atualizada do trimestre. Soma snapshot GoodData (verdade até sábado anterior) com pedidos Omie emitidos depois. Versões conservadora (apenas pedidos com zona segura) e otimista (inclui zona de risco). Gap para meta pessoal e faixa atingida calculados a partir dessas.';


--
-- Name: v_des_desconto_por_checkin; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_des_desconto_por_checkin WITH (security_invoker='on') AS
 WITH checkin_com_faixa AS (
         SELECT vca.empresa,
            vca.ano,
            vca.trimestre,
            vca.checkin_id,
            vca.data_avaliacao,
            vca.tipo,
            vca.codigo AS criterio_codigo,
            vca.nome AS criterio_nome,
            vca.criterio_tipo,
            vca.atingido,
            cp.percentual AS percentual_da_faixa,
            ((vptr.faixa_conservadora ->> 'faixa_id'::text))::bigint AS faixa_id,
            ((vptr.faixa_conservadora ->> 'faixa_numero'::text))::integer AS faixa_numero,
            ((vptr.faixa_conservadora ->> 'estrelas'::text))::integer AS estrelas,
            ((vptr.faixa_conservadora ->> 'desconto_padrao_perc'::text))::numeric AS desconto_padrao
           FROM (((public.v_des_checkin_atual vca
             LEFT JOIN public.v_des_posicao_trimestre_ao_vivo vptr ON (((vptr.empresa = vca.empresa) AND (vptr.ano = vca.ano) AND (vptr.trimestre = vca.trimestre))))
             LEFT JOIN public.des_criterio_qualitativo cq_full ON (((cq_full.codigo = vca.codigo) AND (cq_full.contrato_versao_id = ( SELECT des_contrato_versao.id
                   FROM public.des_contrato_versao
                  WHERE (des_contrato_versao.versao = '2026'::text))))))
             LEFT JOIN public.des_criterio_percentual cp ON (((cp.criterio_id = cq_full.id) AND (cp.faixa_id = ((vptr.faixa_conservadora ->> 'faixa_id'::text))::bigint))))
        )
 SELECT empresa,
    ano,
    trimestre,
    checkin_id,
    data_avaliacao,
    tipo,
    faixa_numero,
    estrelas,
    desconto_padrao,
    sum(
        CASE
            WHEN ((criterio_tipo = 'qualitativo'::text) AND atingido) THEN percentual_da_faixa
            ELSE (0)::numeric
        END) AS qualitativos_atingidos_perc,
    sum(
        CASE
            WHEN ((criterio_tipo = 'bonus'::text) AND atingido) THEN percentual_da_faixa
            ELSE (0)::numeric
        END) AS bonus_atingido_perc,
    round(((desconto_padrao + sum(
        CASE
            WHEN ((criterio_tipo = 'qualitativo'::text) AND atingido) THEN percentual_da_faixa
            ELSE (0)::numeric
        END)) + sum(
        CASE
            WHEN ((criterio_tipo = 'bonus'::text) AND atingido) THEN percentual_da_faixa
            ELSE (0)::numeric
        END)), 2) AS desconto_total_projetado,
    (desconto_padrao + ( SELECT sum(cp2.percentual) AS sum
           FROM (public.des_criterio_percentual cp2
             JOIN public.des_criterio_qualitativo cq2 ON ((cq2.id = cp2.criterio_id)))
          WHERE (cp2.faixa_id = cp2.faixa_id))) AS desconto_total_maximo
   FROM checkin_com_faixa
  WHERE (faixa_id IS NOT NULL)
  GROUP BY empresa, ano, trimestre, checkin_id, data_avaliacao, tipo, faixa_id, faixa_numero, estrelas, desconto_padrao;


--
-- Name: v_desconto_flat_condicional_ativo; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_desconto_flat_condicional_ativo WITH (security_invoker='on') AS
 SELECT id AS campanha_id,
    empresa,
    fornecedor_nome,
    nome,
    tipo_origem,
    estado,
    data_inicio,
    data_fim,
    data_corte_pedido,
    responsavel_oferta_nome,
    responsavel_oferta_email,
    canal_oferta,
    data_oferta,
    volume_minimo_condicional,
    volume_minimo_unidade,
    status_aceite,
    observacoes_negociacao,
    ( SELECT count(*) AS count
           FROM public.promocao_item pi
          WHERE ((pi.campanha_id = pc.id) AND pi.ativo)) AS qtd_itens,
    (data_fim - CURRENT_DATE) AS dias_restantes,
        CASE
            WHEN (data_fim < CURRENT_DATE) THEN 'expirada'::text
            WHEN ((data_fim - CURRENT_DATE) <= 3) THEN 'urgente'::text
            WHEN ((data_fim - CURRENT_DATE) <= 7) THEN 'atencao'::text
            ELSE 'confortavel'::text
        END AS urgencia
   FROM public.promocao_campanha pc
  WHERE ((tipo_origem = 'desconto_flat_condicional'::text) AND (estado = ANY (ARRAY['negociando'::text, 'ativa'::text, 'rascunho'::text])));


--
-- Name: v_envios_portal_status; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_envios_portal_status WITH (security_invoker='on') AS
 SELECT (date_trunc('day'::text, COALESCE(enviado_portal_em, criado_em)))::date AS dia,
    fornecedor_nome,
    status_envio_portal,
    count(*) AS total,
    count(*) FILTER (WHERE (portal_tentativas >= 3)) AS esgotados,
    (avg(portal_tentativas))::numeric(10,2) AS media_tentativas
   FROM public.pedido_compra_sugerido
  WHERE ((COALESCE(enviado_portal_em, criado_em) >= (now() - '30 days'::interval)) AND (status_envio_portal <> 'nao_aplicavel'::text))
  GROUP BY ((date_trunc('day'::text, COALESCE(enviado_portal_em, criado_em)))::date), fornecedor_nome, status_envio_portal
  ORDER BY ((date_trunc('day'::text, COALESCE(enviado_portal_em, criado_em)))::date) DESC, fornecedor_nome, status_envio_portal;


--
-- Name: v_sku_sla_compliance; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sku_sla_compliance WITH (security_invoker='on') AS
 WITH lt_observado AS (
         SELECT (v_sku_leadtime_efetivo.empresa)::text AS empresa,
            (v_sku_leadtime_efetivo.sku_codigo_omie)::text AS sku_codigo_omie,
            avg(v_sku_leadtime_efetivo.lt_bruto_dias_uteis) AS lt_medio_observado,
            stddev_samp(v_sku_leadtime_efetivo.lt_bruto_dias_uteis) AS lt_desvio_observado,
            percentile_cont((0.50)::double precision) WITHIN GROUP (ORDER BY ((v_sku_leadtime_efetivo.lt_bruto_dias_uteis)::double precision)) AS lt_mediana_observada,
            percentile_cont((0.95)::double precision) WITHIN GROUP (ORDER BY ((v_sku_leadtime_efetivo.lt_bruto_dias_uteis)::double precision)) AS lt_p95_observado,
            min(v_sku_leadtime_efetivo.lt_bruto_dias_uteis) AS lt_min,
            max(v_sku_leadtime_efetivo.lt_bruto_dias_uteis) AS lt_max,
            count(*) AS n_observacoes,
            max((v_sku_leadtime_efetivo.t4_data_recebimento)::date) AS ultimo_recebimento,
            avg(v_sku_leadtime_efetivo.lt_faturamento_dias_uteis) AS lt_faturamento_medio,
            avg(v_sku_leadtime_efetivo.lt_logistica_dias_uteis) AS lt_logistica_medio
           FROM public.v_sku_leadtime_efetivo
          WHERE (v_sku_leadtime_efetivo.lt_bruto_dias_uteis IS NOT NULL)
          GROUP BY (v_sku_leadtime_efetivo.empresa)::text, (v_sku_leadtime_efetivo.sku_codigo_omie)::text
        ), lt_recente AS (
         SELECT (ranked.empresa)::text AS empresa,
            (ranked.sku_codigo_omie)::text AS sku_codigo_omie,
            avg(ranked.lt_bruto_dias_uteis) AS lt_medio_recente,
            count(*) AS n_recentes
           FROM ( SELECT slh.empresa,
                    slh.sku_codigo_omie,
                    slh.lt_bruto_dias_uteis,
                    row_number() OVER (PARTITION BY slh.empresa, slh.sku_codigo_omie ORDER BY slh.t4_data_recebimento DESC) AS rn
                   FROM public.v_sku_leadtime_efetivo slh
                  WHERE ((slh.lt_bruto_dias_uteis IS NOT NULL) AND (slh.t4_data_recebimento IS NOT NULL))) ranked
          WHERE (ranked.rn <= 5)
          GROUP BY (ranked.empresa)::text, (ranked.sku_codigo_omie)::text
        )
 SELECT sp.empresa,
    (sp.sku_codigo_omie)::text AS sku_codigo_omie,
    sp.sku_descricao,
    sp.fornecedor_nome,
    sg.grupo_codigo,
    lts.lt_total_teorico_dias_uteis AS lt_teorico,
    round(lo.lt_medio_observado, 2) AS lt_observado_medio,
    round(lo.lt_desvio_observado, 2) AS lt_observado_desvio,
    round((lo.lt_mediana_observada)::numeric, 1) AS lt_observado_mediana,
    round((lo.lt_p95_observado)::numeric, 1) AS lt_observado_p95,
    lo.lt_min,
    lo.lt_max,
    lo.n_observacoes,
    lo.ultimo_recebimento,
    round(lo.lt_faturamento_medio, 2) AS lt_faturamento_medio,
    round(lo.lt_logistica_medio, 2) AS lt_logistica_medio,
    round(lr.lt_medio_recente, 2) AS lt_recente_medio,
    lr.n_recentes,
    round((lo.lt_medio_observado - (lts.lt_total_teorico_dias_uteis)::numeric), 2) AS desvio_absoluto,
    round((((lo.lt_medio_observado - (lts.lt_total_teorico_dias_uteis)::numeric) / (NULLIF(lts.lt_total_teorico_dias_uteis, 0))::numeric) * (100)::numeric), 1) AS desvio_perc,
        CASE
            WHEN ((lr.lt_medio_recente IS NULL) OR (lo.lt_medio_observado IS NULL)) THEN 'sem_dados'::text
            WHEN (lr.lt_medio_recente < (lo.lt_medio_observado * 0.9)) THEN 'melhorando'::text
            WHEN (lr.lt_medio_recente > (lo.lt_medio_observado * 1.1)) THEN 'piorando'::text
            ELSE 'estavel'::text
        END AS tendencia,
        CASE
            WHEN (lts.lt_total_teorico_dias_uteis IS NULL) THEN 'sem_sla_teorico'::text
            WHEN ((lo.n_observacoes IS NULL) OR (lo.n_observacoes < 3)) THEN 'poucos_dados'::text
            WHEN (lo.lt_medio_observado <= ((lts.lt_total_teorico_dias_uteis)::numeric * 1.05)) THEN 'cumprindo'::text
            WHEN (lo.lt_medio_observado <= ((lts.lt_total_teorico_dias_uteis)::numeric * 1.20)) THEN 'limite'::text
            WHEN (lo.lt_medio_observado <= ((lts.lt_total_teorico_dias_uteis)::numeric * 1.50)) THEN 'violando'::text
            ELSE 'critico'::text
        END AS status_sla
   FROM ((((public.sku_parametros sp
     LEFT JOIN public.sku_grupo_producao sg ON (((sg.empresa = sp.empresa) AND (sg.sku_codigo_omie = (sp.sku_codigo_omie)::text))))
     LEFT JOIN public.v_sku_lt_teorico lts ON (((lts.empresa = sp.empresa) AND (lts.sku_codigo_omie = (sp.sku_codigo_omie)::text))))
     LEFT JOIN lt_observado lo ON (((lo.empresa = sp.empresa) AND (lo.sku_codigo_omie = (sp.sku_codigo_omie)::text))))
     LEFT JOIN lt_recente lr ON (((lr.empresa = sp.empresa) AND (lr.sku_codigo_omie = (sp.sku_codigo_omie)::text))))
  ORDER BY
        CASE
            WHEN (lts.lt_total_teorico_dias_uteis IS NULL) THEN 5
            WHEN ((lo.n_observacoes IS NULL) OR (lo.n_observacoes < 3)) THEN 4
            WHEN (lo.lt_medio_observado <= ((lts.lt_total_teorico_dias_uteis)::numeric * 1.05)) THEN 3
            WHEN (lo.lt_medio_observado <= ((lts.lt_total_teorico_dias_uteis)::numeric * 1.20)) THEN 2
            ELSE 1
        END, (round((((lo.lt_medio_observado - (lts.lt_total_teorico_dias_uteis)::numeric) / (NULLIF(lts.lt_total_teorico_dias_uteis, 0))::numeric) * (100)::numeric), 1)) DESC NULLS LAST;


--
-- Name: VIEW v_sku_sla_compliance; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_sku_sla_compliance IS 'SLA de leadtime por SKU. Lê v_sku_leadtime_efetivo (NÃO a tabela crua): n_observacoes conta NFe, não linha — uma NFe que fatura N pedidos gera N cópias do item e cruzaria o gate `>= 3` do status_sla com desvio zero (confiança fabricada). O Top-5 de lt_recente exige t4 conhecido: ORDER BY t4 DESC é NULLS FIRST no Postgres, e a view efetiva emite t4 NULL quando as cópias divergem — sem o filtro, a observação de data indeterminada viraria "a mais recente" e falsearia a tendencia.';


--
-- Name: v_fornecedor_sla_compliance; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_fornecedor_sla_compliance WITH (security_invoker='on') AS
 SELECT empresa,
    fornecedor_nome,
    count(*) AS skus_total,
    count(*) FILTER (WHERE (status_sla = 'cumprindo'::text)) AS skus_cumprindo,
    count(*) FILTER (WHERE (status_sla = 'limite'::text)) AS skus_limite,
    count(*) FILTER (WHERE (status_sla = 'violando'::text)) AS skus_violando,
    count(*) FILTER (WHERE (status_sla = 'critico'::text)) AS skus_criticos,
    round(avg(desvio_perc), 1) AS desvio_medio_perc,
    round(avg(lt_observado_medio), 2) AS lt_medio_observado_agregado,
    round(avg(lt_teorico), 2) AS lt_teorico_agregado,
    round(((100.0 * (count(*) FILTER (WHERE (status_sla = 'cumprindo'::text)))::numeric) / (NULLIF(count(*) FILTER (WHERE (status_sla = ANY (ARRAY['cumprindo'::text, 'limite'::text, 'violando'::text, 'critico'::text]))), 0))::numeric), 1) AS perc_sla_compliance
   FROM public.v_sku_sla_compliance
  WHERE (status_sla = ANY (ARRAY['cumprindo'::text, 'limite'::text, 'violando'::text, 'critico'::text]))
  GROUP BY empresa, fornecedor_nome
  ORDER BY (round(((100.0 * (count(*) FILTER (WHERE (status_sla = 'cumprindo'::text)))::numeric) / (NULLIF(count(*) FILTER (WHERE (status_sla = ANY (ARRAY['cumprindo'::text, 'limite'::text, 'violando'::text, 'critico'::text]))), 0))::numeric), 1)) DESC;


--
-- Name: v_grupo_comercial; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_grupo_comercial WITH (security_invoker='true') AS
 WITH ped AS (
         SELECT regexp_replace(COALESCE(p.cnpj, p.document, ''::text), '\D'::text, ''::text, 'g'::text) AS doc,
            (so.created_at)::date AS data,
            COALESCE(so.total, ( SELECT sum((((it.value ->> 'quantity'::text))::numeric * ((it.value ->> 'unit_price'::text))::numeric)) AS sum
                   FROM jsonb_array_elements(so.items) it(value))) AS valor
           FROM (public.sales_orders so
             JOIN public.profiles p ON ((p.user_id = so.customer_user_id)))
          WHERE ((so.status = ANY (ARRAY['faturado'::text, 'importado'::text, 'separacao'::text, 'enviado'::text])) AND (so.deleted_at IS NULL))
        )
 SELECT m.grupo_id,
    count(DISTINCT ped.doc) FILTER (WHERE (ped.doc IS NOT NULL)) AS documentos_com_compra,
    count(ped.data) AS qtd_pedidos,
    max(ped.data) AS ultima_compra,
    (CURRENT_DATE - max(ped.data)) AS dias_desde_ultima,
    COALESCE(sum(ped.valor), (0)::numeric) AS faturamento_total,
    COALESCE(sum(ped.valor) FILTER (WHERE (ped.data > (CURRENT_DATE - 90))), (0)::numeric) AS fat_90d,
    COALESCE(sum(ped.valor) FILTER (WHERE ((ped.data <= (CURRENT_DATE - 90)) AND (ped.data > (CURRENT_DATE - 180)))), (0)::numeric) AS fat_90d_anterior,
    round((COALESCE(sum(ped.valor) FILTER (WHERE (ped.data > (CURRENT_DATE - 180))), (0)::numeric) / 6.0), 2) AS media_mensal_6m
   FROM (public.cliente_grupo_membros m
     LEFT JOIN ped ON ((ped.doc = m.documento)))
  GROUP BY m.grupo_id;


--
-- Name: v_grupo_contas_receber; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_grupo_contas_receber WITH (security_invoker='true') AS
 WITH tit AS (
         SELECT regexp_replace(fcr.cnpj_cpf, '\D'::text, ''::text, 'g'::text) AS doc,
            fcr.saldo,
            fcr.data_vencimento
           FROM public.fin_contas_receber fcr
          WHERE (fcr.status_titulo <> ALL (ARRAY['RECEBIDO'::text, 'CANCELADO'::text]))
        )
 SELECT g.id AS grupo_id,
    g.nome,
    count(DISTINCT m.documento) FILTER (WHERE (t.doc IS NOT NULL)) AS documentos_com_titulo,
    COALESCE(sum(t.saldo), (0)::numeric) AS total_aberto,
    COALESCE(sum(t.saldo) FILTER (WHERE (t.data_vencimento >= CURRENT_DATE)), (0)::numeric) AS a_vencer,
    COALESCE(sum(t.saldo) FILTER (WHERE (((CURRENT_DATE - t.data_vencimento) >= 1) AND ((CURRENT_DATE - t.data_vencimento) <= 30))), (0)::numeric) AS venc_1_30,
    COALESCE(sum(t.saldo) FILTER (WHERE (((CURRENT_DATE - t.data_vencimento) >= 31) AND ((CURRENT_DATE - t.data_vencimento) <= 60))), (0)::numeric) AS venc_31_60,
    COALESCE(sum(t.saldo) FILTER (WHERE (((CURRENT_DATE - t.data_vencimento) >= 61) AND ((CURRENT_DATE - t.data_vencimento) <= 90))), (0)::numeric) AS venc_61_90,
    COALESCE(sum(t.saldo) FILTER (WHERE ((CURRENT_DATE - t.data_vencimento) > 90)), (0)::numeric) AS venc_90_mais
   FROM ((public.cliente_grupos g
     JOIN public.cliente_grupo_membros m ON ((m.grupo_id = g.id)))
     LEFT JOIN tit t ON ((t.doc = m.documento)))
  WHERE (g.ativo = true)
  GROUP BY g.id, g.nome;


--
-- Name: v_grupo_contas_receber_por_doc; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_grupo_contas_receber_por_doc WITH (security_invoker='true') AS
 WITH tit AS (
         SELECT regexp_replace(fcr.cnpj_cpf, '\D'::text, ''::text, 'g'::text) AS doc,
            fcr.company,
            fcr.nome_cliente,
            fcr.saldo,
            fcr.data_vencimento
           FROM public.fin_contas_receber fcr
          WHERE (fcr.status_titulo <> ALL (ARRAY['RECEBIDO'::text, 'CANCELADO'::text]))
        )
 SELECT m.grupo_id,
    m.documento,
    t.company,
    max(t.nome_cliente) AS nome_cliente,
    COALESCE(sum(t.saldo), (0)::numeric) AS total_aberto,
    COALESCE(sum(t.saldo) FILTER (WHERE ((CURRENT_DATE - t.data_vencimento) > 0)), (0)::numeric) AS vencido
   FROM (public.cliente_grupo_membros m
     LEFT JOIN tit t ON ((t.doc = m.documento)))
  GROUP BY m.grupo_id, m.documento, t.company;


--
-- Name: v_grupo_contatos; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_grupo_contatos WITH (security_invoker='true') AS
 SELECT m.grupo_id,
    m.documento,
    p.user_id,
    COALESCE(p.razao_social, p.name) AS nome,
    p.phone,
    p.email,
    a.city AS cidade,
    a.state AS uf,
    NULLIF(TRIM(BOTH FROM ((COALESCE(a.street, ''::text) || ' '::text) || COALESCE(a.number, ''::text))), ''::text) AS endereco,
    oc.omie_codigo_vendedor,
    oc.account AS empresa_omie
   FROM (((public.cliente_grupo_membros m
     JOIN public.profiles p ON ((regexp_replace(COALESCE(p.cnpj, p.document, ''::text), '\D'::text, ''::text, 'g'::text) = m.documento)))
     LEFT JOIN public.addresses a ON (((a.user_id = p.user_id) AND (a.is_default = true))))
     LEFT JOIN public.omie_customer_account_map_fresco oc ON (((oc.user_id = p.user_id) AND (oc.account = 'oben'::text))));


--
-- Name: v_leadtime_por_grupo; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_leadtime_por_grupo WITH (security_invoker='on') AS
 SELECT empresa,
    grupo_leadtime,
    count(*) AS n_pedidos,
    round(avg(lt_bruto_dias_uteis), 2) AS lt_bruto_medio,
    round(avg(lt_faturamento_dias_uteis), 2) AS lt_faturamento_medio,
    round(avg(lt_logistica_dias_uteis), 2) AS lt_logistica_medio,
    round(stddev(lt_bruto_dias_uteis), 2) AS lt_bruto_stddev,
    percentile_cont((0.95)::double precision) WITHIN GROUP (ORDER BY ((lt_bruto_dias_uteis)::double precision)) AS lt_bruto_p95,
    max(lt_bruto_dias_uteis) AS lt_bruto_max
   FROM public.purchase_orders_tracking
  WHERE ((status = 'RECEBIDO'::public.status_pedido_compra) AND (t1_data_pedido >= (now() - '90 days'::interval)))
  GROUP BY empresa, grupo_leadtime;


--
-- Name: VIEW v_leadtime_por_grupo; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_leadtime_por_grupo IS 'Dashboard: lead time médio, desvio e percentil 95 por grupo nos últimos 90 dias';


--
-- Name: v_notificacoes_status; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_notificacoes_status WITH (security_invoker='on') AS
 SELECT (date_trunc('day'::text, criado_em))::date AS dia,
    status,
    count(*) AS total,
    count(*) FILTER (WHERE (tentativas >= 3)) AS esgotados,
    count(*) FILTER (WHERE (data_evento IS NOT NULL)) AS com_calendar_event
   FROM public.fornecedor_alerta
  WHERE (criado_em >= (now() - '30 days'::interval))
  GROUP BY ((date_trunc('day'::text, criado_em))::date), status
  ORDER BY ((date_trunc('day'::text, criado_em))::date) DESC, status;


--
-- Name: v_omie_product_current_spec; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_omie_product_current_spec WITH (security_invoker='on') AS
 SELECT l.account,
    l.omie_codigo_produto,
    l.kb_product_spec_id,
    s.product_code,
    s.product_name,
    s.supplier,
    s.product_category,
    s.rendimento_m2_por_litro,
    s.demaos_recomendadas,
    s.pot_life_horas,
    s.validade_dias,
    s.catalisador_codigo,
    s.catalisador_proporcao_pct,
    s.diluente_codigo,
    s.substrato,
    s.equipamentos_aplicacao,
    s.diferenciais_chave,
    s.uso_recomendado
   FROM (public.omie_product_spec_links l
     JOIN public.kb_product_specs s ON ((s.id = l.kb_product_spec_id)))
  WHERE ((l.status = 'confirmed'::text) AND (s.approved_at IS NOT NULL));


--
-- Name: v_oportunidade_economica_hoje_badge_cached; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_oportunidade_economica_hoje_badge_cached WITH (security_invoker='false', security_barrier='true') AS
 SELECT empresa,
    oportunidade_count,
    refreshed_at
   FROM private.mv_oportunidade_badge
  WHERE ((( SELECT auth.role() AS role) = 'service_role'::text) OR COALESCE(( SELECT public.has_role(( SELECT auth.uid() AS uid), 'master'::public.app_role) AS has_role), false) OR COALESCE(( SELECT public.has_role(( SELECT auth.uid() AS uid), 'employee'::public.app_role) AS has_role), false));


--
-- Name: v_otimizador_compras_insumos; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_otimizador_compras_insumos WITH (security_invoker='on') AS
 WITH frete AS (
         SELECT cac.empresa,
            cac.fornecedor_nome,
            max(cac.valor) FILTER (WHERE (cac.tipo = 'frete_perc_valor'::text)) AS frete_perc_valor,
            max(cac.valor) FILTER (WHERE (cac.tipo = 'frete_fixo'::text)) AS frete_fixo,
            max(cac.valor) FILTER (WHERE (cac.tipo = 'taxa_pedido'::text)) AS frete_taxa_pedido
           FROM public.fornecedor_custo_adicional_config cac
          WHERE (cac.ativo = true)
          GROUP BY cac.empresa, cac.fornecedor_nome
        ), prazo AS (
         SELECT ppc.empresa,
            ppc.fornecedor_nome,
            max(ppc.desconto_ou_encargo_perc) AS prazo_padrao_perc
           FROM public.fornecedor_prazo_pagamento_config ppc
          WHERE ((ppc.padrao = true) AND (ppc.ativo = true))
          GROUP BY ppc.empresa, ppc.fornecedor_nome
        )
 SELECT o.empresa,
    o.sku_codigo_omie,
    o.sku_descricao,
    o.fornecedor_nome,
    o.cenario,
    o.desconto_total_perc,
    o.desconto_promo_perc,
    o.aumento_evitado_perc,
    o.tem_negociacao_extra,
    o.campanha_id,
    o.campanha_nome,
    o.promo_item_id,
    o.modo_promo,
    o.promo_data_corte_pedido,
    o.promo_data_corte_faturamento,
    o.proxima_vigencia_aumento,
    o.aumentos_json,
    o.data_limite_acao,
    o.dias_ate_limite,
    o.demanda_diaria,
    o.qtde_base,
    o.qtde_oportunidade,
    o.preco_item_eoq,
    o.economia_bruta_estimada,
    o.custo_capital_efetivo_perc,
    sp.lote_minimo_fornecedor,
    sp.fornecedor_codigo_omie,
    p.prazo_padrao_perc,
    f.frete_perc_valor,
    f.frete_fixo,
    f.frete_taxa_pedido,
    sp.minimo_forcado_manual
   FROM ((((public.v_oportunidade_economica_hoje o
     LEFT JOIN public.sku_parametros sp ON (((sp.empresa = o.empresa) AND (sp.sku_codigo_omie = o.sku_codigo_omie))))
     LEFT JOIN prazo p ON (((p.empresa = o.empresa) AND (p.fornecedor_nome = o.fornecedor_nome))))
     LEFT JOIN frete f ON (((f.empresa = o.empresa) AND (f.fornecedor_nome = o.fornecedor_nome))))
     LEFT JOIN public.omie_products op ON ((((op.omie_codigo_produto)::text = (o.sku_codigo_omie)::text) AND (op.account = lower(o.empresa)))))
  WHERE ((COALESCE(op.descricao, ''::text) !~~* '%405ML'::text) AND (COALESCE(op.descricao, ''::text) !~~* '%450ML'::text));


--
-- Name: v_pcp_malha_oben_quarentena; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_pcp_malha_oben_quarentena WITH (security_invoker='true') AS
 WITH classif AS (
         SELECT c.pai_codigo,
            c.componente_codigo,
            c.quantidade,
            c.un_ficha,
            c.perc_perda,
            c.n_pai_oben,
            c.n_comp_oben,
            c.pai_oben,
            c.comp_oben,
            c.un_estoque,
            c.comp_ativo,
            c.pai_codigo_prd,
            c.comp_codigo_prd,
                CASE
                    WHEN (c.pai_codigo_prd IS NULL) THEN 'pai_nao_resolvido_colacor'::text
                    WHEN (c.comp_codigo_prd IS NULL) THEN 'componente_nao_resolvido_colacor'::text
                    WHEN ((c.n_pai_oben IS NULL) OR (c.n_pai_oben = 0)) THEN 'pai_sem_par_oben_ativo'::text
                    WHEN (c.n_pai_oben > 1) THEN 'pai_ambiguo_oben'::text
                    WHEN ((c.n_comp_oben IS NULL) OR (c.n_comp_oben = 0)) THEN 'componente_sem_par_oben_ativo'::text
                    WHEN (c.n_comp_oben > 1) THEN 'componente_ambiguo_oben'::text
                    WHEN (NOT COALESCE(c.comp_ativo, false)) THEN 'componente_inativo_oben'::text
                    WHEN (c.pai_oben = c.comp_oben) THEN 'auto_referencia'::text
                    WHEN ((c.quantidade IS NULL) OR (c.quantidade <= (0)::numeric)) THEN 'quantidade_invalida'::text
                    WHEN (c.perc_perda <> (0)::numeric) THEN 'perc_perda_nao_suportada'::text
                    WHEN (btrim(upper(c.un_ficha)) IS DISTINCT FROM btrim(upper(c.un_estoque))) THEN 'unidade_divergente'::text
                    ELSE NULL::text
                END AS motivo
           FROM public.v_pcp_malha_oben_cand c
        )
 SELECT classif.pai_codigo,
    classif.componente_codigo,
    classif.pai_oben,
    classif.comp_oben,
    classif.quantidade,
    classif.un_ficha,
    classif.un_estoque,
    classif.perc_perda,
    classif.motivo
   FROM classif
  WHERE (classif.motivo IS NOT NULL)
UNION ALL
 SELECT c.pai_codigo,
    c.componente_codigo,
    c.pai_oben,
    c.comp_oben,
    c.quantidade,
    c.un_ficha,
    c.un_estoque,
    c.perc_perda,
    'quantidade_divergente_no_par'::text AS motivo
   FROM classif c
  WHERE ((c.motivo IS NULL) AND ((c.pai_oben, c.comp_oben) IN ( SELECT classif.pai_oben,
            classif.comp_oben
           FROM classif
          WHERE (classif.motivo IS NULL)
          GROUP BY classif.pai_oben, classif.comp_oben
         HAVING ((count(DISTINCT classif.quantidade) > 1) AND (count(DISTINCT classif.componente_codigo) = 1)))))
UNION ALL
 SELECT c.pai_codigo,
    c.componente_codigo,
    c.pai_oben,
    c.comp_oben,
    c.quantidade,
    c.un_ficha,
    c.un_estoque,
    c.perc_perda,
    'multiplos_componentes_mesmo_insumo'::text AS motivo
   FROM classif c
  WHERE ((c.motivo IS NULL) AND ((c.pai_oben, c.comp_oben) IN ( SELECT classif.pai_oben,
            classif.comp_oben
           FROM classif
          WHERE (classif.motivo IS NULL)
          GROUP BY classif.pai_oben, classif.comp_oben
         HAVING (count(DISTINCT classif.componente_codigo) > 1))));


--
-- Name: VIEW v_pcp_malha_oben_quarentena; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_pcp_malha_oben_quarentena IS 'Pares da ficha EXCLUÍDOS da explosão, com motivo. Fila de exceção: precisão>recall — insumo com unidade divergente ou cardinalidade ambígua não vira compra, mas fica visível aqui.';


--
-- Name: v_pedidos_em_aberto; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_pedidos_em_aberto WITH (security_invoker='on') AS
 SELECT id,
    empresa,
    omie_codigo_pedido,
    fornecedor_nome,
    grupo_leadtime,
    status,
    t1_data_pedido,
    t2_data_faturamento,
    t3_data_cte,
    t4_data_recebimento,
    (EXTRACT(day FROM (now() - t1_data_pedido)))::integer AS dias_desde_pedido,
        CASE
            WHEN (t2_data_faturamento IS NULL) THEN 'AGUARDANDO_FATURAMENTO'::text
            WHEN (t3_data_cte IS NULL) THEN 'AGUARDANDO_CTE'::text
            WHEN (t4_data_recebimento IS NULL) THEN 'AGUARDANDO_ENTRADA'::text
            ELSE 'COMPLETO'::text
        END AS estagio
   FROM public.purchase_orders_tracking
  WHERE (status <> ALL (ARRAY['RECEBIDO'::public.status_pedido_compra, 'CANCELADO'::public.status_pedido_compra]));


--
-- Name: v_prime_extrato_mensal; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_prime_extrato_mensal WITH (security_invoker='true') AS
 WITH meses AS (
         SELECT a.id AS assinatura_id,
            a.customer_user_id,
            a.status,
            a.preco_contratado,
            a.franquia_dentes_contratada,
            (generate_series(date_trunc('month'::text, (a.data_inicio)::timestamp without time zone), LEAST(date_trunc('month'::text, (now() AT TIME ZONE 'America/Sao_Paulo'::text)), date_trunc('month'::text, COALESCE((a.data_fim)::timestamp without time zone, 'infinity'::timestamp without time zone)), date_trunc('month'::text, COALESCE((a.suspensa_em)::timestamp without time zone, 'infinity'::timestamp without time zone))), '1 mon'::interval))::date AS competencia
           FROM public.prime_assinaturas a
        ), uso AS (
         SELECT prime_beneficio_uso.assinatura_id,
            prime_beneficio_uso.competencia,
            sum(prime_beneficio_uso.valor_tabela) FILTER (WHERE (prime_beneficio_uso.tipo = ANY (ARRAY['afiacao_dentes'::text, 'desconto_abrasivo'::text]))) AS monetizado_total,
            sum(prime_beneficio_uso.quantidade) FILTER (WHERE (prime_beneficio_uso.tipo = 'afiacao_dentes'::text)) AS dentes_usados,
            sum(prime_beneficio_uso.quantidade) FILTER (WHERE (prime_beneficio_uso.tipo = 'bonus_dentes'::text)) AS dentes_bonus,
            count(*) FILTER (WHERE (prime_beneficio_uso.tipo <> ALL (ARRAY['afiacao_dentes'::text, 'desconto_abrasivo'::text, 'bonus_dentes'::text]))) AS usos_operacionais,
            count(*) AS n_registros
           FROM public.prime_beneficio_uso
          WHERE (prime_beneficio_uso.estornado_em IS NULL)
          GROUP BY prime_beneficio_uso.assinatura_id, prime_beneficio_uso.competencia
        )
 SELECT m.assinatura_id,
    m.customer_user_id,
    m.status,
    m.competencia,
    m.preco_contratado AS mensalidade_contratada,
    u.monetizado_total,
    u.dentes_usados,
    u.dentes_bonus,
    ((m.franquia_dentes_contratada)::numeric + COALESCE(u.dentes_bonus, (0)::numeric)) AS franquia_total,
    GREATEST((0)::numeric, (((m.franquia_dentes_contratada)::numeric + COALESCE(u.dentes_bonus, (0)::numeric)) - COALESCE(u.dentes_usados, (0)::numeric))) AS dentes_restantes,
    GREATEST((0)::numeric, (COALESCE(u.dentes_usados, (0)::numeric) - ((m.franquia_dentes_contratada)::numeric + COALESCE(u.dentes_bonus, (0)::numeric)))) AS dentes_excedentes,
    COALESCE(u.usos_operacionais, (0)::bigint) AS usos_operacionais,
    COALESCE(u.n_registros, (0)::bigint) AS n_registros
   FROM (meses m
     LEFT JOIN uso u USING (assinatura_id, competencia));


--
-- Name: v_promocao_avaliacao_hoje; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_promocao_avaliacao_hoje WITH (security_invoker='on') AS
 WITH campanhas_ativas AS (
         SELECT pc.id AS campanha_id,
            pc.empresa,
            pc.fornecedor_nome,
            pc.nome AS campanha_nome,
            pc.data_inicio,
            pc.data_fim,
            pc.tipo_origem
           FROM public.promocao_campanha pc
          WHERE ((pc.estado = 'ativa'::text) AND ((CURRENT_DATE >= pc.data_inicio) AND (CURRENT_DATE <= pc.data_fim)))
        ), itens_ativos AS (
         SELECT ca.campanha_id,
            ca.empresa,
            ca.fornecedor_nome,
            ca.campanha_nome,
            ca.data_inicio,
            ca.data_fim,
            ca.tipo_origem,
            pi.id AS item_id,
            pi.sku_codigo_fornecedor,
            pi.sku_codigo_omie,
            ef.desconto_efetivo AS desconto_perc,
            ef.desconto_base,
            ef.desconto_extra,
            ef.tem_negociacao_extra,
            pi.volume_minimo,
            pi.confirmado
           FROM ((campanhas_ativas ca
             JOIN public.promocao_item pi ON ((pi.campanha_id = ca.campanha_id)))
             JOIN public.v_promocao_item_efetivo ef ON ((ef.id = pi.id)))
          WHERE ((pi.ativo = true) AND (pi.confirmado = true) AND (pi.sku_codigo_omie IS NOT NULL))
        ), com_parametros AS (
         SELECT ia.campanha_id,
            ia.empresa,
            ia.fornecedor_nome,
            ia.campanha_nome,
            ia.data_inicio,
            ia.data_fim,
            ia.tipo_origem,
            ia.item_id,
            ia.sku_codigo_fornecedor,
            ia.sku_codigo_omie,
            ia.desconto_perc,
            ia.desconto_base,
            ia.desconto_extra,
            ia.tem_negociacao_extra,
            ia.volume_minimo,
            ia.confirmado,
            sp.sku_descricao,
            sp.demanda_media_diaria AS d,
            vps.qtde_compra_ciclo_sugerida AS qtde_base,
            vps.custo_capital_efetivo_perc,
            vps.preco_item_eoq,
                CASE
                    WHEN (ia.volume_minimo IS NULL) THEN 'flat'::text
                    ELSE 'forward_buying'::text
                END AS modo_aplicacao
           FROM ((itens_ativos ia
             JOIN public.sku_parametros sp ON (((sp.empresa = ia.empresa) AND (sp.sku_codigo_omie = ia.sku_codigo_omie) AND (sp.ativo = true))))
             LEFT JOIN public.v_sku_parametros_sugeridos vps ON (((vps.empresa = sp.empresa) AND (vps.sku_codigo_omie = sp.sku_codigo_omie))))
        ), com_calculos AS (
         SELECT cp.campanha_id,
            cp.empresa,
            cp.fornecedor_nome,
            cp.campanha_nome,
            cp.data_inicio,
            cp.data_fim,
            cp.tipo_origem,
            cp.item_id,
            cp.sku_codigo_fornecedor,
            cp.sku_codigo_omie,
            cp.desconto_perc,
            cp.desconto_base,
            cp.desconto_extra,
            cp.tem_negociacao_extra,
            cp.volume_minimo,
            cp.confirmado,
            cp.sku_descricao,
            cp.d,
            cp.qtde_base,
            cp.custo_capital_efetivo_perc,
            cp.preco_item_eoq,
            cp.modo_aplicacao,
                CASE
                    WHEN (cp.modo_aplicacao = 'flat'::text) THEN cp.qtde_base
                    ELSE GREATEST(COALESCE(cp.qtde_base, (0)::numeric), COALESCE(cp.volume_minimo, (0)::numeric))
                END AS qtde_com_desconto,
                CASE
                    WHEN (cp.modo_aplicacao = 'flat'::text) THEN (0)::numeric
                    ELSE (GREATEST(COALESCE(cp.qtde_base, (0)::numeric), COALESCE(cp.volume_minimo, (0)::numeric)) - COALESCE(cp.qtde_base, (0)::numeric))
                END AS qtde_extra,
                CASE
                    WHEN ((cp.modo_aplicacao = 'forward_buying'::text) AND (cp.d > (0)::numeric)) THEN round(((GREATEST(COALESCE(cp.qtde_base, (0)::numeric), COALESCE(cp.volume_minimo, (0)::numeric)) - COALESCE(cp.qtde_base, (0)::numeric)) / cp.d), 1)
                    ELSE (0)::numeric
                END AS dias_extra_estoque,
                CASE
                    WHEN ((cp.modo_aplicacao = 'forward_buying'::text) AND (cp.d > (0)::numeric)) THEN round(((cp.custo_capital_efetivo_perc * ((GREATEST(COALESCE(cp.qtde_base, (0)::numeric), COALESCE(cp.volume_minimo, (0)::numeric)) - COALESCE(cp.qtde_base, (0)::numeric)) / cp.d)) / (365)::numeric), 3)
                    ELSE (0)::numeric
                END AS custo_capital_periodo_perc
           FROM com_parametros cp
        ), com_economia AS (
         SELECT com_calculos.campanha_id,
            com_calculos.empresa,
            com_calculos.fornecedor_nome,
            com_calculos.campanha_nome,
            com_calculos.data_inicio,
            com_calculos.data_fim,
            com_calculos.tipo_origem,
            com_calculos.item_id,
            com_calculos.sku_codigo_fornecedor,
            com_calculos.sku_codigo_omie,
            com_calculos.desconto_perc,
            com_calculos.desconto_base,
            com_calculos.desconto_extra,
            com_calculos.tem_negociacao_extra,
            com_calculos.volume_minimo,
            com_calculos.confirmado,
            com_calculos.sku_descricao,
            com_calculos.d,
            com_calculos.qtde_base,
            com_calculos.custo_capital_efetivo_perc,
            com_calculos.preco_item_eoq,
            com_calculos.modo_aplicacao,
            com_calculos.qtde_com_desconto,
            com_calculos.qtde_extra,
            com_calculos.dias_extra_estoque,
            com_calculos.custo_capital_periodo_perc,
            round((com_calculos.desconto_perc - com_calculos.custo_capital_periodo_perc), 2) AS economia_liquida_perc,
                CASE
                    WHEN (com_calculos.preco_item_eoq IS NOT NULL) THEN round((((com_calculos.qtde_com_desconto * com_calculos.preco_item_eoq) * com_calculos.desconto_perc) / (100)::numeric), 2)
                    ELSE NULL::numeric
                END AS economia_bruta_valor,
                CASE
                    WHEN (com_calculos.preco_item_eoq IS NOT NULL) THEN round((((com_calculos.qtde_com_desconto * com_calculos.preco_item_eoq) * (com_calculos.desconto_perc - com_calculos.custo_capital_periodo_perc)) / (100)::numeric), 2)
                    ELSE NULL::numeric
                END AS economia_liquida_valor
           FROM com_calculos
        )
 SELECT DISTINCT ON (empresa, sku_codigo_omie) campanha_id,
    campanha_nome,
    tipo_origem,
    data_inicio,
    data_fim,
    item_id,
    sku_codigo_fornecedor,
    sku_codigo_omie,
    sku_descricao,
    empresa,
    fornecedor_nome,
    modo_aplicacao,
    desconto_perc,
    desconto_base,
    desconto_extra,
    tem_negociacao_extra,
    volume_minimo,
    qtde_base,
    qtde_com_desconto,
    qtde_extra,
    dias_extra_estoque,
    custo_capital_periodo_perc,
    economia_liquida_perc,
    economia_bruta_valor,
    economia_liquida_valor
   FROM com_economia
  WHERE ((modo_aplicacao = 'flat'::text) OR ((modo_aplicacao = 'forward_buying'::text) AND (economia_liquida_perc > (0)::numeric)))
  ORDER BY empresa, sku_codigo_omie, economia_liquida_valor DESC NULLS LAST, desconto_perc DESC;


--
-- Name: v_reposicao_cold_start_elegivel; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_reposicao_cold_start_elegivel WITH (security_invoker='on') AS
 SELECT 'OBEN'::text AS empresa,
    op.omie_codigo_produto AS sku_codigo_omie,
    op.descricao AS sku_descricao,
    fe.fornecedor_nome,
    op.estoque AS estoque_catalogo
   FROM (((public.omie_products op
     JOIN public.sku_fornecedor_externo fe ON (((fe.empresa = 'OBEN'::text) AND (fe.sku_omie = (op.omie_codigo_produto)::text) AND (fe.ativo = true) AND (fe.fornecedor_nome ~~* '%SAYERLACK%'::text))))
     LEFT JOIN public.sku_status_omie sso ON (((sso.empresa = 'OBEN'::text) AND (sso.sku_codigo_omie = (op.omie_codigo_produto)::text))))
     LEFT JOIN public.familia_nao_comprada fnc ON (((fnc.empresa = 'OBEN'::text) AND (fnc.familia = op.familia))))
  WHERE ((op.account = 'oben'::text) AND (op.ativo = true) AND (COALESCE(op.tipo_produto, (op.metadata ->> 'tipo_produto'::text), ''::text) <> '04'::text) AND (COALESCE(op.valor_unitario, (0)::numeric) > (0)::numeric) AND (COALESCE(op.descricao, ''::text) !~~* '%450ML'::text) AND (COALESCE(op.descricao, ''::text) !~~* '%405ML'::text) AND (fnc.id IS NULL) AND (COALESCE(sso.ativo_no_omie, true) = true));


--
-- Name: v_reposicao_depara_sayerlack_elegivel; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_reposicao_depara_sayerlack_elegivel WITH (security_invoker='on') AS
 SELECT 'OBEN'::text AS empresa,
    (op.omie_codigo_produto)::text AS sku_omie,
    op.descricao AS sku_descricao,
    op.familia
   FROM ((public.omie_products op
     LEFT JOIN public.sku_status_omie sso ON (((sso.empresa = 'OBEN'::text) AND (sso.sku_codigo_omie = (op.omie_codigo_produto)::text))))
     LEFT JOIN public.familia_nao_comprada fnc ON (((fnc.empresa = 'OBEN'::text) AND (fnc.familia = op.familia))))
  WHERE ((op.account = 'oben'::text) AND (op.ativo = true) AND (COALESCE(op.tipo_produto, (op.metadata ->> 'tipo_produto'::text), ''::text) <> '04'::text) AND (COALESCE(op.valor_unitario, (0)::numeric) > (0)::numeric) AND (COALESCE(op.descricao, ''::text) !~~* '%450ML'::text) AND (COALESCE(op.descricao, ''::text) !~~* '%405ML'::text) AND (fnc.id IS NULL) AND (COALESCE(sso.ativo_no_omie, true) = true) AND (NOT (EXISTS ( SELECT 1
           FROM public.sku_fornecedor_externo fe
          WHERE ((fe.empresa = 'OBEN'::text) AND (fe.sku_omie = (op.omie_codigo_produto)::text) AND (fe.ativo = true) AND (fe.fornecedor_nome ~~* '%SAYERLACK%'::text))))));


--
-- Name: v_reposicao_sku_sem_fornecedor; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_reposicao_sku_sem_fornecedor WITH (security_invoker='on') AS
 SELECT sp.empresa,
    (sp.sku_codigo_omie)::text AS sku_codigo_omie,
    sp.sku_descricao,
    sp.ponto_pedido,
    sp.estoque_maximo,
    COALESCE(sea.estoque_fisico, (0)::numeric) AS estoque_fisico,
    COALESCE(sea.estoque_pendente_entrada, (0)::numeric) AS estoque_pendente,
    (COALESCE(sea.estoque_fisico, (0)::numeric) + COALESCE(sea.estoque_pendente_entrada, (0)::numeric)) AS estoque_efetivo,
    op.descricao AS omie_descricao
   FROM ((((public.sku_parametros sp
     LEFT JOIN public.sku_estoque_atual sea ON (((sea.empresa = sp.empresa) AND (sea.sku_codigo_omie = (sp.sku_codigo_omie)::text))))
     LEFT JOIN public.omie_products op ON ((((op.omie_codigo_produto)::text = (sp.sku_codigo_omie)::text) AND (op.account = lower(sp.empresa)))))
     LEFT JOIN public.sku_status_omie sso ON (((sso.empresa = sp.empresa) AND (sso.sku_codigo_omie = (sp.sku_codigo_omie)::text))))
     LEFT JOIN public.familia_nao_comprada fnc ON (((fnc.empresa = sp.empresa) AND (fnc.familia = op.familia))))
  WHERE ((sp.habilitado_reposicao_automatica = true) AND (COALESCE(sp.tipo_reposicao, 'automatica'::text) = 'automatica'::text) AND ((sp.fornecedor_nome IS NULL) OR (btrim(sp.fornecedor_nome) = ''::text)) AND (fnc.id IS NULL) AND (COALESCE(op.ativo, true) = true) AND (COALESCE(sso.ativo_no_omie, true) = true) AND (COALESCE(op.descricao, ''::text) !~~* '%450ML'::text) AND (COALESCE(op.descricao, ''::text) !~~* '%405ML'::text) AND (COALESCE(op.tipo_produto, (op.metadata ->> 'tipo_produto'::text), ''::text) <> '04'::text) AND (sp.ponto_pedido IS NOT NULL) AND (sp.estoque_maximo IS NOT NULL) AND ((COALESCE(sea.estoque_fisico, (0)::numeric) + COALESCE(sea.estoque_pendente_entrada, (0)::numeric)) <= sp.ponto_pedido));


--
-- Name: v_simulacao_comparativa; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_simulacao_comparativa WITH (security_invoker='on') AS
 WITH ranked AS (
         SELECT simulacao_estoque_resultados.empresa,
            simulacao_estoque_resultados.sku_codigo_omie,
            simulacao_estoque_resultados.sku_descricao,
            simulacao_estoque_resultados.classe_consolidada,
            simulacao_estoque_resultados.classe_abc,
            simulacao_estoque_resultados.candidato,
            simulacao_estoque_resultados.srl_perc,
            simulacao_estoque_resultados.dias_em_ruptura,
            simulacao_estoque_resultados.qtde_ruptura_total,
            simulacao_estoque_resultados.qtde_demandada_total,
            simulacao_estoque_resultados.estoque_medio,
            simulacao_estoque_resultados.estoque_max_observado,
            simulacao_estoque_resultados.num_pedidos_disparados,
            simulacao_estoque_resultados.giros_ano,
            simulacao_estoque_resultados.valor_emi,
            simulacao_estoque_resultados.valor_ruptura_estimado,
            simulacao_estoque_resultados.estoque_min_aplicado,
            simulacao_estoque_resultados.ponto_pedido_aplicado,
            simulacao_estoque_resultados.qtde_compra_aplicada,
            simulacao_estoque_resultados.estoque_max_aplicado,
            simulacao_estoque_resultados.lead_time_aplicado,
            rank() OVER (PARTITION BY simulacao_estoque_resultados.empresa, simulacao_estoque_resultados.sku_codigo_omie ORDER BY simulacao_estoque_resultados.srl_perc DESC, simulacao_estoque_resultados.valor_emi) AS rank_srl_emi,
            rank() OVER (PARTITION BY simulacao_estoque_resultados.empresa, simulacao_estoque_resultados.sku_codigo_omie ORDER BY simulacao_estoque_resultados.srl_perc DESC) AS rank_srl,
            rank() OVER (PARTITION BY simulacao_estoque_resultados.empresa, simulacao_estoque_resultados.sku_codigo_omie ORDER BY simulacao_estoque_resultados.valor_emi) AS rank_emi,
            rank() OVER (PARTITION BY simulacao_estoque_resultados.empresa, simulacao_estoque_resultados.sku_codigo_omie ORDER BY simulacao_estoque_resultados.giros_ano DESC) AS rank_giros
           FROM public.simulacao_estoque_resultados
        )
 SELECT empresa,
    sku_codigo_omie,
    sku_descricao,
    classe_consolidada,
    classe_abc,
    candidato,
    srl_perc,
    dias_em_ruptura,
    qtde_ruptura_total,
    qtde_demandada_total,
    estoque_medio,
    estoque_max_observado,
    num_pedidos_disparados,
    giros_ano,
    valor_emi,
    valor_ruptura_estimado,
    estoque_min_aplicado,
    ponto_pedido_aplicado,
    qtde_compra_aplicada,
    estoque_max_aplicado,
    lead_time_aplicado,
    rank_srl_emi,
    rank_srl,
    rank_emi,
    rank_giros,
        CASE
            WHEN (rank_srl_emi = 1) THEN '🏆'::text
            ELSE ''::text
        END AS vencedor
   FROM ranked
  ORDER BY empresa, sku_codigo_omie, rank_srl_emi;


--
-- Name: v_simulacao_ranking_global; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_simulacao_ranking_global WITH (security_invoker='on') AS
 SELECT empresa,
    candidato,
    count(*) AS skus_simulados,
    round(avg(srl_perc), 2) AS srl_medio,
    round((percentile_cont((0.5)::double precision) WITHIN GROUP (ORDER BY ((srl_perc)::double precision)))::numeric, 2) AS srl_mediano,
    round(min(srl_perc), 2) AS srl_pior,
    sum(dias_em_ruptura) AS dias_rupt_total,
    round(sum(valor_emi), 2) AS emi_total_rs,
    round(avg(valor_emi), 2) AS emi_medio_rs,
    round(sum(valor_ruptura_estimado), 2) AS perda_ruptura_total_rs,
    round(avg(giros_ano), 2) AS giros_medios,
    sum(num_pedidos_disparados) AS pedidos_disparados_total,
    sum(
        CASE
            WHEN (srl_perc >= (98)::numeric) THEN 1
            ELSE 0
        END) AS skus_srl_98_plus,
    sum(
        CASE
            WHEN (srl_perc >= (95)::numeric) THEN 1
            ELSE 0
        END) AS skus_srl_95_plus,
    sum(
        CASE
            WHEN (srl_perc < (90)::numeric) THEN 1
            ELSE 0
        END) AS skus_srl_criticos
   FROM public.simulacao_estoque_resultados
  GROUP BY empresa, candidato
  ORDER BY empresa, (round(avg(srl_perc), 2)) DESC, (round(sum(valor_emi), 2));


--
-- Name: v_sku_candidatos_primeira_compra; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sku_candidatos_primeira_compra WITH (security_invoker='on') AS
 WITH recorrencia_180d AS (
         SELECT vih.empresa,
            vih.sku_codigo_omie,
            count(DISTINCT vih.nfe_chave_acesso) AS nfs_180d,
            count(DISTINCT to_char((vih.data_emissao)::timestamp with time zone, 'YYYY-MM'::text)) AS meses_180d,
            count(DISTINCT vih.cliente_cnpj_cpf) AS clientes_180d,
            (CURRENT_DATE - max(vih.data_emissao)) AS dias_desde_ultima
           FROM public.v_sku_demanda_efetiva vih
          WHERE ((vih.data_emissao >= (CURRENT_DATE - '180 days'::interval)) AND (vih.quantidade > (0)::numeric))
          GROUP BY vih.empresa, vih.sku_codigo_omie
        ), elegiveis AS (
         SELECT v.empresa,
            v.sku_codigo_omie,
            v.sku_descricao,
            v.fornecedor_nome,
            v.fornecedor_habilitado,
            sp.habilitado_reposicao_automatica AS ja_habilitado,
            v.classe_abc_proposta,
            v.classe_xyz_proposta,
            v.classe_consolidada,
            v.demanda_media_diaria AS d,
            v.lead_time_medio AS lt,
            v.lt_total_teorico_dias_uteis,
            v.demanda_sigma_diario,
            v.coef_variacao_ordem,
            v.dias_com_movimento,
            v.lead_time_desvio,
            v.lt_p95_dias,
            v.fonte_leadtime,
            v.z_aplicado,
            v.preco_item_eoq,
            v.preco_compra_real,
            v.preco_venda_medio,
            v.fonte_preco,
            v.custo_pedido_aplicado,
            v.custo_capital_efetivo_perc,
            v.valor_total_90d,
            v.valor_total_180d,
            v.calculado_em,
            r.nfs_180d,
            r.meses_180d,
            r.clientes_180d,
            r.dias_desde_ultima,
                CASE v.classe_abc_proposta
                    WHEN 'A'::text THEN 30
                    WHEN 'B'::text THEN 21
                    ELSE 14
                END AS cap_dias,
                CASE
                    WHEN ((v.preco_item_eoq > (0)::numeric) AND (v.custo_capital_efetivo_perc > (0)::numeric) AND (v.demanda_media_diaria > (0)::numeric)) THEN ceil(sqrt((((2.0 * (v.demanda_media_diaria * (252)::numeric)) * v.custo_pedido_aplicado) / ((v.custo_capital_efetivo_perc / 100.0) * v.preco_item_eoq))))
                    ELSE (1)::numeric
                END AS qc_eoq
           FROM (((public.v_sku_parametros_sugeridos v
             JOIN recorrencia_180d r ON (((r.empresa = v.empresa) AND (r.sku_codigo_omie = v.sku_codigo_omie))))
             JOIN public.sku_parametros sp ON (((sp.empresa = v.empresa) AND (sp.sku_codigo_omie = v.sku_codigo_omie))))
             LEFT JOIN public.omie_products op ON ((((op.omie_codigo_produto)::text = (v.sku_codigo_omie)::text) AND (op.account = lower(v.empresa)))))
          WHERE ((v.status_sugestao = 'AGUARDANDO_SEGUNDA_ORDEM'::text) AND (v.demanda_media_diaria > (0)::numeric) AND (v.lead_time_medio IS NOT NULL) AND (v.fornecedor_nome IS NOT NULL) AND (v.fornecedor_habilitado IS TRUE) AND (v.preco_item_eoq > (0)::numeric) AND (v.classe_abc_proposta IS NOT NULL) AND ((v.grupo_codigo IS NOT NULL) OR (v.fornecedor_nome <> 'RENNER SAYERLACK S/A'::text)) AND (r.meses_180d >= 2) AND (r.nfs_180d >= 2) AND (r.dias_desde_ultima <= 60) AND (sp.ponto_pedido IS NULL) AND (sp.estoque_maximo IS NULL) AND (COALESCE(op.tipo_produto, (op.metadata ->> 'tipo_produto'::text), ''::text) <> '04'::text))
        ), calc AS (
         SELECT elegiveis.empresa,
            elegiveis.sku_codigo_omie,
            elegiveis.sku_descricao,
            elegiveis.fornecedor_nome,
            elegiveis.fornecedor_habilitado,
            elegiveis.ja_habilitado,
            elegiveis.classe_abc_proposta,
            elegiveis.classe_xyz_proposta,
            elegiveis.classe_consolidada,
            elegiveis.d,
            elegiveis.lt,
            elegiveis.lt_total_teorico_dias_uteis,
            elegiveis.demanda_sigma_diario,
            elegiveis.coef_variacao_ordem,
            elegiveis.dias_com_movimento,
            elegiveis.lead_time_desvio,
            elegiveis.lt_p95_dias,
            elegiveis.fonte_leadtime,
            elegiveis.z_aplicado,
            elegiveis.preco_item_eoq,
            elegiveis.preco_compra_real,
            elegiveis.preco_venda_medio,
            elegiveis.fonte_preco,
            elegiveis.custo_pedido_aplicado,
            elegiveis.custo_capital_efetivo_perc,
            elegiveis.valor_total_90d,
            elegiveis.valor_total_180d,
            elegiveis.calculado_em,
            elegiveis.nfs_180d,
            elegiveis.meses_180d,
            elegiveis.clientes_180d,
            elegiveis.dias_desde_ultima,
            elegiveis.cap_dias,
            elegiveis.qc_eoq,
            ceil((elegiveis.d * (elegiveis.cap_dias)::numeric)) AS cap_cobertura,
            ceil((elegiveis.d * elegiveis.lt)) AS dem_lt
           FROM elegiveis
        )
 SELECT empresa,
    sku_codigo_omie,
    sku_descricao,
    fornecedor_nome,
    fornecedor_habilitado,
    classe_abc_proposta,
    classe_xyz_proposta,
    classe_consolidada,
    d AS demanda_media_diaria,
    lt AS lead_time_medio,
    lt_total_teorico_dias_uteis,
    demanda_sigma_diario,
    coef_variacao_ordem,
    dias_com_movimento,
    lead_time_desvio,
    lt_p95_dias,
    fonte_leadtime,
    z_aplicado,
    preco_item_eoq,
    preco_compra_real,
    preco_venda_medio,
    fonte_preco,
    valor_total_90d,
    valor_total_180d,
    calculado_em,
    'CANDIDATO_PRIMEIRA_COMPRA'::text AS status_sugestao,
    nfs_180d AS recorrencia_nfs_180d,
    meses_180d AS recorrencia_meses_180d,
    clientes_180d AS recorrencia_clientes_180d,
    dias_desde_ultima AS dias_desde_ultima_venda,
    cap_dias AS primeira_compra_cap_dias,
    GREATEST((1)::numeric, LEAST(GREATEST(qc_eoq, (1)::numeric), cap_cobertura)) AS primeira_compra_qtde,
    GREATEST((1)::numeric, LEAST(dem_lt, cap_cobertura)) AS primeira_compra_ponto_pedido,
    (GREATEST((1)::numeric, LEAST(dem_lt, cap_cobertura)) + GREATEST((1)::numeric, LEAST(GREATEST(qc_eoq, (1)::numeric), cap_cobertura))) AS primeira_compra_estoque_maximo,
    ja_habilitado
   FROM calc;


--
-- Name: v_sugestao_negociacao_ativa; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_sugestao_negociacao_ativa WITH (security_invoker='on') AS
 SELECT sng.id,
    sng.empresa,
    sng.sku_codigo_omie,
    sng.sku_descricao,
    sng.motivo,
    sng.motivo_detalhes,
    sng.score_final,
    sng.volume_financeiro_12m,
    sng.preco_medio_unitario,
    sng.promocoes_12m,
    sng.perc_meses_com_promo,
    sng.status,
    sng.data_geracao,
    sng.valido_ate,
    (sng.valido_ate - CURRENT_DATE) AS dias_ate_expirar,
    sng.campanha_id_gerada,
    mv.categoria,
    sp.fornecedor_nome,
    sp.ponto_pedido,
    sp.estoque_maximo,
    (COALESCE(sea.estoque_fisico, (0)::numeric) + COALESCE(sea.estoque_pendente_entrada, (0)::numeric)) AS estoque_efetivo
   FROM (((public.sugestao_negociacao_paralela sng
     LEFT JOIN private.mv_sku_ranking_negociacao_paralela mv ON (((mv.empresa = sng.empresa) AND (mv.sku_codigo_omie = sng.sku_codigo_omie))))
     LEFT JOIN public.sku_parametros sp ON (((sp.empresa = sng.empresa) AND ((sp.sku_codigo_omie)::text = sng.sku_codigo_omie))))
     LEFT JOIN public.sku_estoque_atual sea ON (((sea.empresa = sng.empresa) AND (sea.sku_codigo_omie = sng.sku_codigo_omie))))
  WHERE ((sng.status = ANY (ARRAY['nova'::text, 'visualizada'::text, 'acao_tomada'::text])) AND (sng.valido_ate >= (CURRENT_DATE - '7 days'::interval)));


--
-- Name: v_tarefas_estado; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tarefas_estado WITH (security_invoker='on') AS
 WITH base AS (
         SELECT t.id,
            t.descricao,
            t.categoria,
            t.customer_user_id,
            t.assigned_to,
            t.created_by,
            t.empresa,
            t.modo,
            t.due_date,
            t.interacao_tipo,
            t.backstop_days,
            t.tolerancia_dias,
            t.adiada_para,
            t.motivo_adiamento,
            t.auto_satisfy_mode,
            t.target_produto_id,
            t.target_texto,
            t.target_preco_centavos,
            t.target_tags,
            t.status,
            t.concluida_em,
            t.concluida_por,
            t.conclusao_origem,
            t.nota_conclusao,
            t.escalado_em,
            t.template_id,
            t.requer_comprovacao,
            t.comprovacao_url,
            t.created_at,
            t.updated_at,
            t.tipo_comprovacao,
            t.comprovacao_leitura,
            t.comprovacao_em,
            t.janela_fim,
            t.auditoria_status,
            t.auditoria_motivo,
            t.auditada_por,
            t.auditada_em,
            t.supervisor_user_id,
            t.leitura_min,
            t.leitura_max,
            t.leitura_unidade,
            COALESCE(((t.adiada_para AT TIME ZONE 'America/Sao_Paulo'::text))::date, t.due_date, (((t.created_at AT TIME ZONE 'America/Sao_Paulo'::text))::date + t.backstop_days)) AS effective_due,
            COALESCE(( SELECT cc.covering_user_id
                   FROM public.carteira_coverage cc
                  WHERE ((cc.covered_user_id = t.assigned_to) AND cc.active AND (now() >= cc.valid_from) AND ((cc.valid_until IS NULL) OR (now() <= cc.valid_until)))
                  ORDER BY cc.valid_from DESC
                 LIMIT 1), t.assigned_to) AS responsavel_efetivo
           FROM public.tarefas t
        ), nowsp AS (
         SELECT ((now() AT TIME ZONE 'America/Sao_Paulo'::text))::date AS dia,
            ((now() AT TIME ZONE 'America/Sao_Paulo'::text))::time without time zone AS hora
        )
 SELECT b.id,
    b.descricao,
    b.categoria,
    b.customer_user_id,
    b.assigned_to,
    b.created_by,
    b.empresa,
    b.modo,
    b.due_date,
    b.interacao_tipo,
    b.backstop_days,
    b.tolerancia_dias,
    b.adiada_para,
    b.motivo_adiamento,
    b.auto_satisfy_mode,
    b.target_produto_id,
    b.target_texto,
    b.target_preco_centavos,
    b.target_tags,
    b.status,
    b.concluida_em,
    b.concluida_por,
    b.conclusao_origem,
    b.nota_conclusao,
    b.escalado_em,
    b.template_id,
    b.requer_comprovacao,
    b.comprovacao_url,
    b.created_at,
    b.updated_at,
    b.tipo_comprovacao,
    b.comprovacao_leitura,
    b.comprovacao_em,
    b.janela_fim,
    b.auditoria_status,
    b.auditoria_motivo,
    b.auditada_por,
    b.auditada_em,
    b.supervisor_user_id,
    b.leitura_min,
    b.leitura_max,
    b.leitura_unidade,
    b.effective_due,
    b.responsavel_efetivo,
    ((b.status = 'aberta'::text) AND ((n.dia > b.effective_due) OR ((n.dia = b.effective_due) AND (b.janela_fim IS NOT NULL) AND (n.hora > b.janela_fim)))) AS atrasada,
    ((b.status = 'aberta'::text) AND (b.escalado_em IS NULL) AND ((n.dia > (b.effective_due + b.tolerancia_dias)) OR ((b.tolerancia_dias = 0) AND (n.dia = b.effective_due) AND (b.janela_fim IS NOT NULL) AND (n.hora > b.janela_fim)))) AS escalavel,
    (EXISTS ( SELECT 1
           FROM public.tarefa_satisfacao_candidatos c
          WHERE ((c.tarefa_id = b.id) AND (c.status = 'pending'::text)))) AS tem_sugestao_pendente,
    (b.auditoria_status = 'pendente'::text) AS requer_auditoria
   FROM (base b
     CROSS JOIN nowsp n);


--
-- Name: v_tint_formula_canonica; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_tint_formula_canonica WITH (security_invoker='on') AS
 SELECT f.id,
    f.account,
    f.sku_id,
    f.cor_id,
    f.nome_cor,
    f.preco_final_sayersystem,
    f.subcolecao_id,
    f.personalizada,
    f.updated_at,
    rf.is_sl,
    rf.tem_receita,
    rf.receita_valida,
    lg.csv_legado AS preco_csv_legado,
        CASE
            WHEN (lg.csv_legado IS NULL) THEN NULL::numeric
            ELSE GREATEST(lg.csv_legado, COALESCE(lg.max_ativo, lg.csv_legado))
        END AS preco_piso_legado
   FROM ((public.tint_formulas f
     CROSS JOIN LATERAL ( SELECT v.is_sl,
            v.tem_receita,
            (v.tem_receita AND v.corantes_ok) AS receita_valida,
                CASE
                    WHEN (v.is_sl AND v.tem_receita AND v.corantes_ok) THEN 0
                    WHEN (v.tem_receita AND v.corantes_ok) THEN 1
                    WHEN v.is_sl THEN 2
                    ELSE 3
                END AS rank_pref
           FROM ( SELECT (EXISTS ( SELECT 1
                           FROM public.tint_subcolecoes s
                          WHERE ((s.id = f.subcolecao_id) AND (s.account = f.account) AND (s.id_subcolecao_sayersystem = 'SL'::text)))) AS is_sl,
                    (EXISTS ( SELECT 1
                           FROM public.tint_formula_itens fi
                          WHERE (fi.formula_id = f.id))) AS tem_receita,
                    (NOT (EXISTS ( SELECT 1
                           FROM ((public.tint_formula_itens fi
                             LEFT JOIN public.tint_corantes c ON ((c.id = fi.corante_id)))
                             LEFT JOIN public.omie_products op ON ((op.id = c.omie_product_id)))
                          WHERE ((fi.formula_id = f.id) AND (NOT ((COALESCE(op.valor_unitario, (0)::numeric) > (0)::numeric) AND COALESCE(op.ativo, false) AND (c.volume_total_ml IS NOT NULL) AND (c.volume_total_ml > (0)::numeric))))))) AS corantes_ok) v) rf)
     CROSS JOIN LATERAL ( SELECT ( SELECT max(g2.preco_final_sayersystem) AS max
                   FROM public.tint_formulas g2
                  WHERE ((g2.account = f.account) AND (g2.sku_id = f.sku_id) AND (g2.cor_id = f.cor_id) AND ((g2.desativada_em IS NULL) OR (g2.desativada_motivo = 'fase5_geracao_legada'::text)) AND ((NOT rf.is_sl) OR (EXISTS ( SELECT 1
                           FROM public.tint_subcolecoes s2
                          WHERE ((s2.id = g2.subcolecao_id) AND (s2.account = g2.account) AND (s2.id_subcolecao_sayersystem = '1'::text))))))) AS csv_legado,
            ( SELECT max(g3.preco_final_sayersystem) AS max
                   FROM public.tint_formulas g3
                  WHERE ((g3.account = f.account) AND (g3.sku_id = f.sku_id) AND (g3.cor_id = f.cor_id) AND (g3.desativada_em IS NULL))) AS max_ativo) lg)
  WHERE ((f.desativada_em IS NULL) AND (f.sku_id IS NOT NULL) AND (NOT (EXISTS ( SELECT 1
           FROM (public.tint_formulas g
             CROSS JOIN LATERAL ( SELECT
                        CASE
                            WHEN (w.is_sl AND w.tem_receita AND w.corantes_ok) THEN 0
                            WHEN (w.tem_receita AND w.corantes_ok) THEN 1
                            WHEN w.is_sl THEN 2
                            ELSE 3
                        END AS rank_pref
                   FROM ( SELECT (EXISTS ( SELECT 1
                                   FROM public.tint_subcolecoes s
                                  WHERE ((s.id = g.subcolecao_id) AND (s.account = g.account) AND (s.id_subcolecao_sayersystem = 'SL'::text)))) AS is_sl,
                            (EXISTS ( SELECT 1
                                   FROM public.tint_formula_itens fi
                                  WHERE (fi.formula_id = g.id))) AS tem_receita,
                            (NOT (EXISTS ( SELECT 1
                                   FROM ((public.tint_formula_itens fi
                                     LEFT JOIN public.tint_corantes c ON ((c.id = fi.corante_id)))
                                     LEFT JOIN public.omie_products op ON ((op.id = c.omie_product_id)))
                                  WHERE ((fi.formula_id = g.id) AND (NOT ((COALESCE(op.valor_unitario, (0)::numeric) > (0)::numeric) AND COALESCE(op.ativo, false) AND (c.volume_total_ml IS NOT NULL) AND (c.volume_total_ml > (0)::numeric))))))) AS corantes_ok) w) rg)
          WHERE ((g.account = f.account) AND (g.sku_id = f.sku_id) AND (g.cor_id = f.cor_id) AND (g.desativada_em IS NULL) AND (g.id <> f.id) AND ((rg.rank_pref < rf.rank_pref) OR ((rg.rank_pref = rf.rank_pref) AND (g.id < f.id))))))));


--
-- Name: VIEW v_tint_formula_canonica; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW public.v_tint_formula_canonica IS 'Fase 2 tintométrico: 1 fórmula canônica por (account, sku_id, cor_id) — preferência SL válida, fallback SAYERLACK/personalizada; não desativa nada. receita_valida espelha corantes_completos da RPC get_tint_prices (validade POR FÓRMULA; base_disponivel fica fora — gêmeas compartilham o SKU). preco_csv_legado = RÓTULO "Tabela (versão anterior)" (allowlist da geração ''1'' quando a canônica é SL — precisão de PROVENIÊNCIA). preco_piso_legado = PISO do gate de submit (CONSERVADORISMO) = GREATEST(csv, COALESCE(max das ATIVAS, csv)) — I1 ((csv NULL) ⟺ (piso NULL)) e I2 (piso >= csv) por CONSTRUÇÃO, não por convenção textual. FASE 5 (2026-07-27): o CSV aceita também a linha DESATIVADA carimbada desativada_motivo=''fase5_geracao_legada'' — sobrevive à desativação da geração ''1'' (decisão do founder, opção B); linha desativada por OUTRO motivo (fonte retirou a chave) segue FORA, senão o rótulo afirmaria proveniência de dado aposentado e o piso cairia junto. O max do PISO lê só ATIVAS. O filtro de CANDIDATA a canônica NÃO foi relaxado. security_invoker=on: repetir o WITH em todo replace (#1375).';


